# =========== Admin Dashboard view ==============

@login_required(login_url='login')
def admin_dashboard(request):
    """
    Admin Dashboard View
    
    Renders the admin dashboard page accessible only to superusers.
    This view serves as the main entry point for administrative functions
    and system management.
    
    Args:
        request (HttpRequest): The HTTP request object containing user information
                              and session data.
    
    Returns:
        HttpResponse: Renders admin_dashboard.html template for authorized superusers
        HttpResponseForbidden: Returns 403 Forbidden response for non-superusers
    
    Permission Requirements:
        - User must be authenticated (handled by @login_required decorator)
        - User must have superuser status (is_superuser = True)
    
    Security Notes:
        - Uses Django's built-in login_required decorator to ensure authentication
        - Explicitly checks for superuser status to prevent privilege escalation
        - Returns proper HTTP 403 Forbidden response for unauthorized access attempts
    """
    
    # ------------------------------------------------------------
    # SECTION 1: AUTHORIZATION CHECK
    # ------------------------------------------------------------
    
    # Verify user has superuser privileges
    if not request.user.is_superuser:
        return HttpResponseForbidden(
            "You don't have permission to access the admin dashboard."
        )
    
    # ------------------------------------------------------------
    # SECTION 2: TEMPLATE RENDERING
    # ------------------------------------------------------------
    
    # Render the admin dashboard template for authorized users
    return render(request, 'admin_dashboard.html')

# =========== Submit GRN View ==============
# =========== Submit GRN View ==============
@csrf_exempt
@login_required(login_url='login')
def submit_grn(request):
    """
    Handle GRN submission with inventory updates, PDF generation, and email notifications.
    This function processes GRN data, updates inventory, generates PDF reports, 
    and sends emails to relevant stakeholders.
    
    Args:
        request: HTTP POST request containing GRN data and files
        
    Returns:
        HttpResponse: PDF file for download on success
        JsonResponse: Error response on failure
    """
    print(f"=== GRN Submission Started ===")
    print(f"Request method: {request.method}")
    print(f"User: {request.user.username} ({request.user.employee_code})")
    
    if request.method != "POST":
        print(f"ERROR: Invalid request method. Expected POST, got {request.method}")
        return JsonResponse(
            {"status": "error", "message": "Invalid request method"}, 
            status=400
        )
    
    try:
        print(f"\n--- Starting transaction ---")
        with transaction.atomic():
            # ------------------------------------------------------------
            # SECTION 1: EXTRACT AND VALIDATE REQUEST DATA
            # ------------------------------------------------------------
            print(f"\n=== SECTION 1: Extracting and validating request data ===")
            
            # Extract required fields from POST data
            po_number = request.POST.get("po_number")
            chalan_number = request.POST.get("chalan_number")
            chalan_date = request.POST.get("chalan_date")
            requisition_numbers = request.POST.get("requisition_numbers")
            
            print(f"PO Number: {po_number}")
            print(f"Chalan Number: {chalan_number}")
            print(f"Chalan Date: {chalan_date}")
            print(f"Requisition Numbers: {requisition_numbers}")
            
            # Extract uploaded files
            chalan_file = request.FILES.get("chalan_file")
            approval_file = request.FILES.get("approval_file")
            invoice_file = request.FILES.get("invoice_file")
            
            print(f"Files received - Chalan: {chalan_file}, Approval: {approval_file}, Invoice: {invoice_file}")
            
            # Parse JSON data
            try:
                stock_items = json.loads(request.POST.get("stock_items"))
                print(f"Stock items count: {len(stock_items)}")
                for i, item in enumerate(stock_items):
                    print(f"  Item {i+1}: {item.get('stockItem', 'N/A')} - Qty: {item.get('receivedQuantity', 'N/A')}")
            except json.JSONDecodeError as e:
                print(f"ERROR: Failed to parse stock_items JSON: {e}")
                raise
            
            # Validate required fields
            if not all([po_number, chalan_number, chalan_date, requisition_numbers]):
                missing = []
                if not po_number: missing.append("po_number")
                if not chalan_number: missing.append("chalan_number")
                if not chalan_date: missing.append("chalan_date")
                if not requisition_numbers: missing.append("requisition_numbers")
                print(f"ERROR: Missing required fields: {missing}")
                return JsonResponse(
                    {"status": "error", "message": "Missing required fields"}, 
                    status=400
                )
            if not chalan_file:
                print(f"ERROR: Chalan file is mandatory but not provided")
                return JsonResponse(
                    {
                        "status": "error",
                        "field": "chalan_file",
                        "message": "Chalan / Invoice file is mandatory"
                    },
                    status=400
                )

            # --------------------------------------------------------
            # SUBSECTION: Backdated GRN support
            # --------------------------------------------------------
            # The chalan/invoice date IS the GRN date. When it's in the past the
            # records are stamped with that date (never a future one), so cycle
            # reports like the Sale & Stock Report count the GRN in the right range.
            from django.utils.dateparse import parse_date
            grn_date = parse_date(str(chalan_date)) if chalan_date else None
            today = timezone.localdate()
            if grn_date and grn_date > today:
                print(f"WARNING: Chalan date {grn_date} is in the future; clamping to today")
                grn_date = today
                chalan_date = today.isoformat()
            backdated = bool(grn_date and grn_date < today)
            print(f"GRN date: {grn_date} | backdated: {backdated}")


            # ------------------------------------------------------------
            # SECTION 2: PROCESS UPLOADED FILES
            # ------------------------------------------------------------
            print(f"\n=== SECTION 2: Processing uploaded files ===")
            
            uploaded_files = []
            timestamp = timezone.now().strftime("%Y%m%d%H%M%S")
            print(f"Timestamp for file naming: {timestamp}")
            
            # Process chalan file if provided
            if chalan_file:
                chalan_filename = f"{timestamp}_CHALAN_{chalan_number}_{chalan_file.name}"
                print(f"Processing chalan file: {chalan_file.name} -> {chalan_filename}")
                chalan_file_path = save_file_with_name(
                    chalan_file, "chalan_files", request.user.employee_code, chalan_filename
                )
                uploaded_files.append(('chalan', chalan_file, chalan_file_path))
                print(f"Chalan file saved to: {chalan_file_path}")
            
            # Process approval file if provided
            if approval_file:
                approval_filename = f"{timestamp}_APPROVAL_{approval_file.name}"
                print(f"Processing approval file: {approval_file.name} -> {approval_filename}")
                approval_file_path = save_file_with_name(
                    approval_file, "approval_files", request.user.employee_code, approval_filename
                )
                uploaded_files.append(('approval', approval_file, approval_file_path))
                print(f"Approval file saved to: {approval_file_path}")
            
            # Process invoice file if provided
            if invoice_file:
                invoice_filename = f"{timestamp}_INVOICE_{invoice_file.name}"
                print(f"Processing invoice file: {invoice_file.name} -> {invoice_filename}")
                invoice_file_path = save_file_with_name(
                    invoice_file, "invoice_files", request.user.employee_code, invoice_filename
                )
                uploaded_files.append(('invoice', invoice_file, invoice_file_path))
                print(f"Invoice file saved to: {invoice_file_path}")
            
            print(f"Total uploaded files processed: {len(uploaded_files)}")
            
            # ------------------------------------------------------------
            # SECTION 3: GENERATE GRN NUMBER
            # ------------------------------------------------------------
            print(f"\n=== SECTION 3: Generating GRN number ===")
            
            # Generate next sequential GRN number based on existing records
            last_grn = DoGRN.objects.all().order_by("-id").first()
            if last_grn:
                print(f"Last GRN found: {last_grn.grn_number}")
                if re.match(r"^SMPCL\d{4}$", last_grn.grn_number):
                    next_grn_number = int(last_grn.grn_number.replace("SMPCL", "")) + 1
                    print(f"Extracted number from last GRN: {next_grn_number - 1}")
                else:
                    print(f"Last GRN format doesn't match pattern, starting from 1")
                    next_grn_number = 1
            else:
                print(f"No existing GRNs found, starting from 1")
                next_grn_number = 1
            
            grn_number = f"SMPCL{next_grn_number:04d}"
            print(f"Generated GRN number: {grn_number}")
            
            # ------------------------------------------------------------
            # SECTION 4: PROCESS REQUISITIONS
            # ------------------------------------------------------------
            print(f"\n=== SECTION 4: Processing requisitions ===")
            
            # Convert comma-separated requisition numbers to list
            requisition_numbers_list = requisition_numbers.split(",") if requisition_numbers else []
            print(f"Requisition numbers list: {requisition_numbers_list}")
            
            # Fetch and validate requisitions
            requisitions = PurchaseRequisition.objects.filter(id__in=requisition_numbers_list)
            print(f"Found {requisitions.count()} requisitions")
            
            if not requisitions.exists():
                print(f"ERROR: No requisitions found for IDs: {requisition_numbers_list}")
                return JsonResponse(
                    {"status": "error", "message": "Requisitions not found"},
                    status=404,
                )
            
            # Update requisition status to indicate GRN is done
            for requisition in requisitions:
                print(f"Updating requisition {requisition.requisition_number}: grn_done = True")
                requisition.grn_done = True
                requisition.save()
            
            # ------------------------------------------------------------
            # SECTION 5: PROCESS STOCK ITEMS AND UPDATE INVENTORY
            # ------------------------------------------------------------
            print(f"\n=== SECTION 5: Processing stock items and updating inventory ===")
            
            grn_data = []
            for i, item in enumerate(stock_items):
                print(f"\n--- Processing stock item {i+1}/{len(stock_items)} ---")
                print(f"Item details: {item}")
                
                # Get product mapping information for different systems
                original_product_name = item["stockItem"]
                print(f"Original product name: {original_product_name}")
                
                email_product_info = get_product_mapping_info(original_product_name)      # For email display
                print(f"Email product mapping: {email_product_info}")
                
                inventory_product_info = get_sap_mapped_product_info(original_product_name) # For inventory updates
                print(f"Inventory product mapping: {inventory_product_info}")
                
                # Prepare chalan filename for database storage
                chalan_filename_for_db = chalan_filename if chalan_file else None
                
                # Create GRN record
                print(f"Creating GRN record for requisition: {requisitions[0].requisition_number}")
                grn = DoGRN(
                    grn_number=grn_number,
                    requisition_number=requisitions[0].requisition_number,
                    po_number=po_number,
                    date_of_receipt=chalan_date,
                    time_of_receipt=timezone.now().time(),
                    location=request.user.location,
                    chaalan_number=chalan_number,
                    chaalan_file=chalan_filename_for_db,
                    invoice_file=invoice_filename if invoice_file else None,
                    employee_name=request.user.get_full_name(),
                    employee_code=request.user.employee_code,
                    uom=item.get("uom", ""),
                    stock_item=item["stockItem"],
                    quantity_ordered=item["orderedQuantity"],
                    quantity_received=item["receivedQuantity"],
                    quantity_rejected=item.get("quantityRejected", 0),
                    remarks=item.get("remarks", ""),
                    approval_file=approval_filename if approval_file else None,
                )
                grn.save()
                grn_data.append(grn)
                print(f"GRN record saved with ID: {grn.id}")
                
                # --------------------------------------------------------
                # SUBSECTION: Update Inventory
                # --------------------------------------------------------
                print(f"--- Updating inventory for item {i+1} ---")
                
                # Determine which product name to use for inventory (SAP mapped)
                inventory_product_name = inventory_product_info["mapped_product_name"]
                print(f"Inventory product name (SAP mapped): {inventory_product_name}")
                
                # Find the product in inventory system
                product = Product.objects.filter(name=inventory_product_name).first()
                if not product:
                    print(f"Product not found with SAP mapped name '{inventory_product_name}', trying original name")
                    # Fallback to original product name if SAP mapped product not found
                    product = Product.objects.filter(name=original_product_name).first()
                    if not product:
                        print(f"WARNING: Product not found in inventory with name '{original_product_name}'. Skipping inventory update.")
                        # Skip if product not found in inventory system
                        continue
                print(f"Found product in inventory: {product.name} (ID: {product.id})")
                
                # Get or create inventory record for the user and product
                inventory, created = Inventory.objects.get_or_create(
                    mcc_bmc_user=request.user,
                    product=product,
                    defaults={"quantity": 0},
                )
                if created:
                    print(f"Created new inventory record for user {request.user.employee_code}")
                else:
                    print(f"Found existing inventory record: {inventory.id}")
                
                # Update inventory quantity
                previous_quantity = inventory.quantity
                quantity_to_add = int(item["receivedQuantity"])
                print(f"Updating inventory - Previous: {previous_quantity}, Adding: {quantity_to_add}")
                
                inventory.quantity += quantity_to_add
                inventory.save()
                print(f"Inventory updated - New quantity: {inventory.quantity}")
                
                # Create inventory history record for audit trail
                history_notes = f"GRN for PO: {po_number}, Received: {item['receivedQuantity']} units, Product: {inventory_product_name}"
                if backdated:
                    history_notes += f" | Backdated GRN entered on {today}"
                history = InventoryHistory.objects.create(
                    inventory=inventory,
                    action='GRN',
                    quantity_change=quantity_to_add,
                    previous_quantity=previous_quantity,
                    new_quantity=inventory.quantity,
                    reference_number=grn_number,
                    notes=history_notes,
                    performed_by=request.user
                )
                if backdated:
                    # auto_now_add stamps 'now'; re-stamp with the backdated GRN date so
                    # cycle-ranged reports (Sale & Stock Report) count it in the right cycle.
                    # timetz() carries tzinfo only when USE_TZ is on, so this works either way.
                    backdated_dt = datetime.combine(grn_date, timezone.now().timetz())
                    InventoryHistory.objects.filter(pk=history.pk).update(created_at=backdated_dt)
                    print(f"Inventory history {history.id} backdated to {backdated_dt}")
                print(f"Inventory history record created: {history.id}")
            
            print(f"\nTotal GRN records created: {len(grn_data)}")
            
            # ------------------------------------------------------------
            # SECTION 6: ORGANIZE GRN DATA BY VENDOR FOR PDF GENERATION
            # ------------------------------------------------------------
            print(f"\n=== SECTION 6: Organizing GRN data by vendor ===")
            
            vendor_grn_data = {}
            for i, grn in enumerate(grn_data):
                print(f"\nProcessing GRN {i+1}/{len(grn_data)} for vendor lookup")
                
                # Find vendor associated with this product
                product_vendor = ProductVendor.objects.filter(
                    product__name=grn.stock_item
                ).first()
                
                if product_vendor:
                    vendor = product_vendor.vendor
                    print(f"Found vendor: {vendor.name} for product: {grn.stock_item}")
                    
                    if vendor not in vendor_grn_data:
                        vendor_grn_data[vendor] = {}
                        print(f"Added new vendor to data structure: {vendor.name}")
                    
                    if grn.po_number not in vendor_grn_data[vendor]:
                        vendor_grn_data[vendor][grn.po_number] = []
                        print(f"Added new PO number {grn.po_number} for vendor {vendor.name}")
                    
                    vendor_grn_data[vendor][grn.po_number].append(grn)
                    print(f"Added GRN {grn.grn_number} to vendor {vendor.name}, PO {grn.po_number}")
                else:
                    print(f"WARNING: No vendor found for product: {grn.stock_item}")
            
            print(f"\nTotal vendors found: {len(vendor_grn_data)}")
            for vendor, po_data in vendor_grn_data.items():
                print(f"  Vendor: {vendor.name} - PO count: {len(po_data)}")
            
            # ------------------------------------------------------------
            # SECTION 7: GATHER VENDOR EMAILS FROM PURCHASE DEPARTMENT
            # ------------------------------------------------------------
            print(f"\n=== SECTION 7: Gathering vendor emails ===")
            
            purchase_departments = PurchaseDepartment.objects.filter(
                requisition_id__in=requisition_numbers_list
            )
            print(f"Found {purchase_departments.count()} purchase department records")
            
            vendor_emails = []
            for purchase in purchase_departments:
                if purchase.email:
                    emails = purchase.email.split(",")
                    vendor_emails.extend(emails)
                    print(f"Added emails from purchase record: {emails}")
            
            if not vendor_emails:
                print(f"ERROR: No vendor emails found in purchase department records")
                return JsonResponse(
                    {"status": "error", "message": "No vendor emails found"},
                    status=404,
                )
            
            print(f"Total vendor emails collected: {len(vendor_emails)}")
            print(f"Vendor emails: {vendor_emails}")
            
            # ------------------------------------------------------------
            # SECTION 8: GENERATE GRN PDF REPORT
            # ------------------------------------------------------------
            print(f"\n=== SECTION 8: Generating GRN PDF report ===")
            
            # Prepare context for PDF template
            context = {
                "vendor_grn_data": vendor_grn_data,
                "chaalan_numbers": [chalan_number],
                "date_of_receipts": [chalan_date],
                "logo_url": request.build_absolute_uri(static("images/shwetdharalogo.png")),
                "signature_url": (
                    request.build_absolute_uri(request.user.signature.url)
                    if request.user.signature else None
                ),
                "mohar_url": (
                    request.build_absolute_uri(request.user.mohar.url)
                    if request.user.mohar else None
                ),
                "location": request.user.location,
                "grn_by": request.user.get_full_name(),
                # Add a helper function to check if PO is dummy
                "is_dummy_po": lambda po: po == "0000000000",  # Business rule: exactly 10 zeros
            }
            
            print(f"PDF context prepared with {len(vendor_grn_data)} vendors")
            
            # Render HTML template to string
            html_string = render_to_string("grn_report.html", context)
            print(f"HTML template rendered successfully ({len(html_string)} characters)")
            
            # Convert HTML to PDF
            print("Converting HTML to PDF...")
            pdf_file = HTML(
                string=html_string, base_url=request.build_absolute_uri("/")
            ).write_pdf()
            print(f"PDF generated successfully ({len(pdf_file)} bytes)")
            
            # Save GRN PDF to media storage
            employee_code = request.user.employee_code
            grn_filename = f"{timestamp}_GRN_{grn_number}.pdf"
            grn_file_path = f"grns/{employee_code}/{grn_filename}"
            default_storage.save(grn_file_path, ContentFile(pdf_file))
            print(f"GRN PDF saved to: {grn_file_path}")
            
            # ------------------------------------------------------------
            # SECTION 9: MERGE GRN PDF WITH UPLOADED ATTACHMENTS
            # ------------------------------------------------------------
            print(f"\n=== SECTION 9: Merging PDF with attachments ===")
            
            merger = PdfMerger()
            temp_files_to_cleanup = []
            
            # Add main GRN PDF to merger
            grn_pdf_io = BytesIO(pdf_file)
            merger.append(grn_pdf_io)
            print("Added main GRN PDF to merger")
            
            # Process and add uploaded files to the merged PDF
            for file_type, uploaded_file, file_path in uploaded_files:
                print(f"\nProcessing {file_type} file: {uploaded_file.name}")
                try:
                    actual_file_path = default_storage.path(file_path)
                    file_extension = uploaded_file.name.split('.')[-1].lower()
                    print(f"File extension: {file_extension}, Path: {actual_file_path}")
                    
                    # Handle image files
                    if file_extension in ['png', 'jpg', 'jpeg', 'gif', 'bmp', 'tiff', 'webp']:
                        print(f"Converting image to PDF...")
                        converted_pdf_path = convert_any_image_to_pdf(actual_file_path)
                        if converted_pdf_path and os.path.exists(converted_pdf_path):
                            merger.append(converted_pdf_path)
                            temp_files_to_cleanup.append(converted_pdf_path)
                            print(f"Image converted and added to PDF")
                        else:
                            print(f"WARNING: Image conversion failed or file not found")
                    
                    # Handle PDF files directly
                    elif file_extension == 'pdf':
                        merger.append(actual_file_path)
                        print(f"PDF file added directly")
                    
                    # Convert other document types to PDF
                    else:
                        print(f"Converting document ({file_extension}) to PDF...")
                        converted_pdf_path = convert_document_to_pdf(actual_file_path, file_extension)
                        if converted_pdf_path and os.path.exists(converted_pdf_path):
                            merger.append(converted_pdf_path)
                            temp_files_to_cleanup.append(converted_pdf_path)
                            print(f"Document converted and added to PDF")
                        else:
                            print(f"WARNING: Document conversion failed")
                            
                except Exception as e:
                    print(f"ERROR processing {file_type} file: {e}")
                    # Skip files that cannot be processed
                    continue
            
            # Write merged PDF to BytesIO buffer
            print("Writing merged PDF...")
            merged_pdf_io = BytesIO()
            merger.write(merged_pdf_io)
            merger.close()
            merged_pdf_io.seek(0)
            merged_pdf_content = merged_pdf_io.getvalue()
            print(f"Merged PDF created successfully ({len(merged_pdf_content)} bytes)")
            print(f"Total attachments merged: {len(uploaded_files)}")
            
            # Cleanup temporary conversion files
            print(f"Cleaning up {len(temp_files_to_cleanup)} temporary files...")
            for temp_file in temp_files_to_cleanup:
                try:
                    if os.path.exists(temp_file):
                        os.remove(temp_file)
                        print(f"Cleaned up: {temp_file}")
                except Exception as e:
                    print(f"WARNING: Failed to cleanup temp file {temp_file}: {e}")
            
            # ------------------------------------------------------------
            # SECTION 10: PREPARE AND SEND EMAIL NOTIFICATION
            # ------------------------------------------------------------
            print(f"\n=== SECTION 10: Preparing email notification ===")
            
            # Find vendor for the first stock item
            vendor = ProductVendor.objects.filter(
                product__name=grn_data[0].stock_item
            ).first()
            
            if not vendor:
                print(f"ERROR: Vendor not found for product: {grn_data[0].stock_item}")
                return JsonResponse(
                    {"status": "error", "message": "Vendor not found"}, 
                    status=404
                )
            
            print(f"Found vendor: {vendor.vendor.name}")
            
            # Prepare email recipients
            vendor_emails = vendor.vendor.email.split(",")
            purchase_email = "purchase@shwetdharamilk.com"
            finance_email = "finance@shwetdharamilk.com"
            chhota_purchase = "Sumit.Singhal@shwetdharamilk.com"
            
            recipient_list = [
                purchase_email,
                finance_email,
                chhota_purchase,
            ] + vendor_emails
            
            print(f"Recipient list: {recipient_list}")
            
            # Prepare CC list
            product = Product.objects.filter(name=grn_data[0].stock_item).first()
            hod_email = product.hod.email if product and product.hod else None
            cc_list = [""]
            if hod_email:
                cc_list.append(hod_email)
            
            print(f"CC list: {cc_list}")
            
            # Build email table with NDDB mapped product names
            print("Building email table...")
            email_table_rows = ""
            for requisition, item in zip(requisitions, stock_items):
                # Extract PO number (trim any additional info after colon)
                po_number_trimmed = (
                    requisition.po_number.split(":")[0]
                    if requisition.po_number
                    else "N/A"
                )
                
                # BUSINESS RULE: Replace dummy PO number (0000000000) with "P.O Not Required" in email
                if po_number_trimmed == "0000000000":
                    display_po_number = "P.O Not Required"
                    print(f"Transforming dummy PO {po_number_trimmed} to 'P.O Not Required' for email")
                else:
                    display_po_number = po_number_trimmed
                
                # Get email display product info
                email_product_info = get_product_mapping_info(item["stockItem"])
                email_product_name = email_product_info["mapped_product_name"]
                email_system = email_product_info["mapped_system"]
                
                print(f"Email product mapping: {item['stockItem']} -> {email_product_name} ({email_system})")
                
                # Format system badge and original reference if needed
                system_badge = ""
                if email_system and email_system != 'INDENT_EASY':
                    system_badge = f"<br><small style='color: #666;'>({email_system} Product)</small>"
                
                original_reference = ""
                if email_system != 'INDENT_EASY':
                    original_reference = f"<br><small style='color: #888;'>Original: {item['stockItem']}</small>"
                
                # Build table row
                email_table_rows += f"""
                <tr>
                    <td>{requisition.requisition_number}</td>
                    <td>{requisition.date_of_request.strftime("%b %d, %Y")}</td>
                    <td>
                        {email_product_name}
                        {system_badge}
                        {original_reference}
                    </td>
                    <td>{item['orderedQuantity']}</td>
                    <td>{item['receivedQuantity']}</td>
                    <td>{display_po_number}</td>
                    <td>{item.get('remarks', '')}</td>
                </tr>
                """
            
            print(f"Email table built with {len(stock_items)} rows")
            
            # Build HTML email message
            subject = "GRN Submission for Received Items"
            message = f"""
            <html>
            <head>
                <style>
                    body {{
                        font-family: Arial, sans-serif;
                        line-height: 1.6;
                        color: #333;
                    }}
                    table {{
                        border-collapse: collapse;
                        width: 100%;
                        margin: 20px 0;
                    }}
                    th, td {{
                        border: 1px solid #ddd;
                        padding: 8px;
                        text-align: left;
                    }}
                    th {{
                        background-color: #f2f2f2;
                        font-weight: bold;
                    }}
                </style>
            </head>
            <body>
            <p>Dear Sir,</p>
            <p>We have received the items as per the details mentioned below:</p>
            <table>
                <tr>
                    <th>Request No</th>
                    <th>Request Date</th>
                    <th>Item</th>
                    <th>Request Qty</th>
                    <th>Received Qty</th>
                    <th>PO Number</th>
                    <th>Remarks</th>
                </tr>
                {email_table_rows}
            </table>
            <p>The detailed GRN and required supporting documents are attached for your reference.</p>
            <p>Regards,<br>
            {request.user.get_full_name()}<br>
            {request.user.employee_code}<br>
            {request.user.department} 
            {request.user.location}</p>
            </body>
            </html>
            """
            
            # Create and send email
            print("Creating email message...")
            email = EmailMessage(
                subject, 
                message, 
                settings.DEFAULT_FROM_EMAIL, 
                recipient_list, 
                cc=cc_list
            )
            email.content_subtype = "html"
            email.attach(
                f"GRN_and_Attachments_{grn_number}.pdf",
                merged_pdf_content,
                "application/pdf",
            )
            print(f"Email created with attachment: GRN_and_Attachments_{grn_number}.pdf")
            
            print("Sending email...")
            email.send()
            print("Email sent successfully!")
            
            # ------------------------------------------------------------
            # SECTION 11: RETURN PDF RESPONSE TO CLIENT
            # ------------------------------------------------------------
            print(f"\n=== SECTION 11: Returning PDF response to client ===")
            print(f"Returning merged PDF with filename: GRN_{grn_number}_with_attachments.pdf")
            
            response = HttpResponse(merged_pdf_content, content_type='application/pdf')
            response['Content-Disposition'] = f'attachment; filename="GRN_{grn_number}_with_attachments.pdf"'
            
            print(f"\n=== GRN Submission Completed Successfully ===")
            print(f"GRN Number: {grn_number}")
            print(f"Total items processed: {len(grn_data)}")
            print(f"Emails sent to: {len(recipient_list)} recipients")
            
            return response
            
    except json.JSONDecodeError as e:
        print(f"\n=== CRITICAL ERROR: JSON Decode Error ===")
        print(f"Error: {e}")
        print(f"Failed to parse JSON data")
        return JsonResponse(
            {"status": "error", "message": f"Invalid JSON data: {str(e)}"}, 
            status=400
        )
    except Exception as e:
        print(f"\n=== CRITICAL ERROR: Unexpected Exception ===")
        print(f"Error type: {type(e).__name__}")
        print(f"Error message: {str(e)}")
        
        # Log the error for debugging
        import traceback
        error_traceback = traceback.format_exc()
        print(f"Full traceback:\n{error_traceback}")
        
        return JsonResponse(
            {"status": "error", "message": "An unexpected error occurred"}, 
            status=500
        )

