# =========== SAP Product Mapping Info View ==============

def get_sap_mapped_product_info(product_name):
    print("\n================ DEBUG: get_sap_mapped_product_info ================")
    print("Incoming product_name from Inventory:", repr(product_name))

    try:
        # ------------------------------------------------------------
        # SECTION 1: FIND INDENT_EASY PRODUCT MAPPING
        # ------------------------------------------------------------
        print("\n[STEP 1] Searching INDENT_EASY mapping...")
        
        indent_easy_mapping = ProductMapping.objects.filter(
            system='INDENT_EASY',
            product_name=product_name,
            is_active=True
        ).first()

        print("Query used:",
              "system='INDENT_EASY', product_name=", repr(product_name))

        print("INDENT_EASY mapping found:", indent_easy_mapping)

        if not indent_easy_mapping:
            print("❌ No INDENT_EASY mapping found. Returning fallback.")
            return {
                "mapped_product_name": product_name,
                "mapped_system": 'INDENT_EASY'
            }

        # ------------------------------------------------------------
        # SECTION 2: FIND MAPPING RELATION AND GROUP
        # ------------------------------------------------------------
        print("\n[STEP 2] Finding mapping relation...")

        mapping_relation = ProductMappingRelation.objects.filter(
            product_mapping=indent_easy_mapping
        ).first()

        print("Mapping relation found:", mapping_relation)

        if not mapping_relation:
            print("❌ No mapping relation found. Returning fallback.")
            return {
                "mapped_product_name": product_name,
                "mapped_system": 'INDENT_EASY'
            }

        group = mapping_relation.group
        print("Mapping group identified:", group)

        # ------------------------------------------------------------
        # SECTION 3: FIND CORRESPONDING SAP PRODUCT MAPPING
        # ------------------------------------------------------------
        print("\n[STEP 3] Searching SAP mapping in same group...")

        sap_mapping = ProductMapping.objects.filter(
            system='SAP',
            groups__group=group,
            is_active=True
        ).first()

        print("SAP mapping found:", sap_mapping)

        if sap_mapping:
            print("✅ SAP mapping selected:", sap_mapping.product_name)
            return {
                "mapped_product_name": sap_mapping.product_name,
                "mapped_system": 'SAP'
            }

        # ------------------------------------------------------------
        # SECTION 4: FALLBACK
        # ------------------------------------------------------------
        print("⚠️ No SAP mapping found. Returning INDENT_EASY fallback.")

        return {
            "mapped_product_name": product_name,
            "mapped_system": 'INDENT_EASY'
        }

    except Exception as e:
        print("\n🔥 EXCEPTION in get_sap_mapped_product_info")
        print("Exception type:", type(e))
        print("Exception message:", str(e))

        return {
            "mapped_product_name": product_name,
            "mapped_system": 'INDENT_EASY'
        }


# =========== File Storage Utility Function ==============

def save_file_with_name(file, folder, employee_code, filename):
    """
    Custom File Storage Utility with Structured Naming
    
    Saves uploaded files to Django's default storage with a structured naming convention
    and organized folder hierarchy. This function centralizes file storage logic
    to ensure consistent file organization across the application.
    
    Folder Structure:
        {folder}/{employee_code}/{custom_filename}
    
    Example Path:
        'chalan_files/EMP001/20240115123000_CHALAN_CH12345_invoice.pdf'
    
    Args:
        file (UploadedFile): Django UploadedFile object containing the file data
        folder (str): Base folder name (e.g., 'chalan_files', 'approval_files')
        employee_code (str): Unique employee identifier for user-specific subfolder
        filename (str): Custom filename to use (should include timestamp and type)
    
    Returns:
        str: The relative storage path where the file was saved
        
    Raises:
        StorageError: If Django's default storage fails to save the file
        ValueError: If any required parameters are invalid or empty
    
    Usage Example:
        >>> saved_path = save_file_with_name(
        ...     file=uploaded_file,
        ...     folder='chalan_files',
        ...     employee_code='EMP001',
        ...     filename='20240115123000_CHALAN_CH12345_invoice.pdf'
        ... )
        >>> print(saved_path)
        'chalan_files/EMP001/20240115123000_CHALAN_CH12345_invoice.pdf'
    
    Security Considerations:
        - Validates all input parameters
        - Uses Django's secure file storage system
        - Prevents directory traversal attacks through proper path construction
    """
    
    # ------------------------------------------------------------
    # SECTION 1: INPUT VALIDATION
    # ------------------------------------------------------------
    
    # Validate all required parameters are provided and non-empty
    if not all([file, folder, employee_code, filename]):
        raise ValueError(
            "All parameters (file, folder, employee_code, filename) must be provided and non-empty"
        )
    
    # Ensure folder name is safe (no path traversal attempts)
    if '..' in folder or '..' in employee_code:
        raise ValueError("Invalid characters detected in folder or employee_code")
    
    # ------------------------------------------------------------
    # SECTION 2: CONSTRUCT FILE PATH
    # ------------------------------------------------------------
    
    # Build the structured file path using the folder hierarchy
    file_path = f"{folder}/{employee_code}/{filename}"
    
    # ------------------------------------------------------------
    # SECTION 3: SAVE FILE TO STORAGE
    # ------------------------------------------------------------
    
    # Use Django's default storage system to save the file
    saved_path = default_storage.save(file_path, file)
    
    # ------------------------------------------------------------
    # SECTION 4: RETURN STORAGE PATH
    # ------------------------------------------------------------
    
    # Return the path where the file was saved
    # This path can be used for future retrieval or reference
    return saved_path


