# =========== Image to PDF Conversion Utility ==============

def convert_any_image_to_pdf(image_path):
    """
    Multi-Method Image to PDF Converter
    
    Converts various image formats to PDF using multiple fallback methods.
    Implements progressive degradation to maximize conversion success rate.
    
    Args:
        image_path (str): Full path to the source image file
    
    Returns:
        str or None: Path to converted PDF file, or None if all methods fail
    
    Conversion Methods (in order of attempt):
        1. PIL/Pillow - Primary method for common formats (PNG, JPEG, etc.)
        2. img2pdf - Secondary method for reliability
        3. ReportLab - Fallback for complex cases and vector images
    
    Note: Generated PDF files use '_converted.pdf' suffix in same directory
    """
    
    try:
        # ------------------------------------------------------------
        # METHOD 1: PIL/PILLOW CONVERSION (Primary)
        # ------------------------------------------------------------
        try:
            from PIL import Image
            
            # Open and process image
            image = Image.open(image_path)
            
            # Handle alpha channels and palettes for PDF compatibility
            if image.mode in ('RGBA', 'LA', 'P'):
                background = Image.new('RGB', image.size, (255, 255, 255))
                if image.mode == 'P':
                    image = image.convert('RGBA')
                background.paste(image, mask=image.split()[-1] if image.mode == 'RGBA' else None)
                image = background
            
            # Save as PDF
            pdf_path = image_path.rsplit(".", 1)[0] + "_converted.pdf"
            image.save(pdf_path, "PDF", resolution=100.0)
            
            if os.path.exists(pdf_path):
                return pdf_path
                
        except Exception:
            # PIL conversion failed, continue to next method
            pass
        
        # ------------------------------------------------------------
        # METHOD 2: IMG2PDF CONVERSION (Secondary)
        # ------------------------------------------------------------
        try:
            import img2pdf
            
            pdf_path = image_path.rsplit(".", 1)[0] + "_converted.pdf"
            
            # Convert image bytes directly to PDF
            with open(image_path, "rb") as image_file:
                pdf_bytes = img2pdf.convert(image_file.read())
            
            with open(pdf_path, "wb") as pdf_file:
                pdf_file.write(pdf_bytes)
            
            if os.path.exists(pdf_path):
                return pdf_path
                
        except Exception:
            # img2pdf conversion failed, continue to next method
            pass
        
        # ------------------------------------------------------------
        # METHOD 3: REPORTLAB CONVERSION (Fallback)
        # ------------------------------------------------------------
        try:
            from reportlab.pdfgen import canvas
            from reportlab.lib.pagesizes import A4
            from reportlab.lib.utils import ImageReader
            
            pdf_path = image_path.rsplit(".", 1)[0] + "_converted.pdf"
            
            # Create PDF canvas with A4 page size
            c = canvas.Canvas(pdf_path, pagesize=A4)
            width, height = A4
            
            # Load image and calculate scaling
            img = ImageReader(image_path)
            img_width, img_height = img.getSize()
            
            # Scale to fit 90% of page while maintaining aspect ratio
            scale = min(width/img_width, height/img_height) * 0.9
            new_width = img_width * scale
            new_height = img_height * scale
            
            # Center image on page
            x = (width - new_width) / 2
            y = (height - new_height) / 2
            
            # Draw image and save PDF
            c.drawImage(img, x, y, new_width, new_height)
            c.showPage()
            c.save()
            
            if os.path.exists(pdf_path):
                return pdf_path
                
        except Exception:
            # ReportLab conversion failed
            pass
        
        # ------------------------------------------------------------
        # ALL METHODS FAILED
        # ------------------------------------------------------------
        return None
        
    except Exception:
        # Global exception handler for unexpected errors
        return None


# =========== Document to PDF Conversion Utility ==============

def convert_document_to_pdf(file_path, file_extension):
    """
    Document Format Converter with Expandable Architecture
    
    Currently handles image-to-PDF conversion via delegation to convert_any_image_to_pdf().
    Designed for future expansion to support document formats (DOC, DOCX, XLS, XLSX, etc.)
    
    Args:
        file_path (str): Full path to source document file
        file_extension (str): File extension without dot (e.g., 'jpg', 'docx')
    
    Returns:
        str or None: Path to converted PDF, or None if conversion not supported/fails
    """
    
    try:
        # List of currently supported image formats
        supported_image_formats = ['png', 'jpg', 'jpeg', 'gif', 'bmp', 'tiff', 'webp']
        
        # Check if file is an image format
        if file_extension.lower() in supported_image_formats:
            # Delegate image conversion to specialized function
            return convert_any_image_to_pdf(file_path)
        
        # ------------------------------------------------------------
        # FUTURE EXPANSION AREA
        # ------------------------------------------------------------
        # Add document format handlers here when implemented:
        # - Microsoft Office formats (doc, docx, xls, xlsx, ppt, pptx)
        # - Text formats (txt, rtf)
        # - Other document formats
        
        # Return None for unsupported formats (placeholder for future implementation)
        return None
        
    except Exception:
        # Handle any unexpected errors during conversion process
        return None



# =========== GRN Email with Attachments Service ==============

def send_grn_email_with_attachments(
    request,
    po_number,
    grn_number,
    chaalan_files,
    invoice_files,
    approval_files,
    grn_pdf_content,
):
    """
    Send GRN Notification Email with Merged PDF Attachments
    
    Composes and sends an email notification for GRN submission with all
    supporting documents merged into a single PDF attachment. Handles image
    file conversion and temporary file cleanup.
    
    Args:
        request: HTTP request object for user context
        po_number (str): Purchase Order number for reference
        grn_number (str): Generated GRN number
        chaalan_files (list): List of chalan file objects
        invoice_files (list): List of invoice file objects
        approval_files (list): List of approval file objects
        grn_pdf_content (bytes): Binary content of the main GRN PDF
    
    Process Flow:
        1. Retrieve requisition and vendor information
        2. Prepare email recipients and content
        3. Merge GRN PDF with supporting documents
        4. Send email with merged attachment
        5. Clean up temporary files
    
    Note: Returns silently on any failure to prevent disrupting main GRN flow
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: RETRIEVE REQUISITION AND VENDOR DATA
        # ------------------------------------------------------------
        
        # Find the requisition by PO number
        requisition = PurchaseRequisition.objects.filter(po_number=po_number).first()
        if not requisition:
            return
        
        # Find vendor associated with the requisition's stock item
        vendor = ProductVendor.objects.filter(
            product__name=requisition.stock_item
        ).first()
        if not vendor:
            return
        
        # ------------------------------------------------------------
        # SECTION 2: PREPARE EMAIL RECIPIENTS
        # ------------------------------------------------------------
        
        # Extract vendor email addresses (comma-separated string)
        vendor_emails = vendor.vendor.email.split(",")
        
        # Standard internal email addresses
        purchase_email = "purchase@shwetdharamilk.com"
        finance_email = "finance@shwetdharamilk.com"
        
        # Find product and HOD email for CC list
        product = Product.objects.filter(name=requisition.stock_item).first()
        hod_email = product.hod.email if product and product.hod else None
        
        # Build recipient and CC lists
        recipient_list = [purchase_email, finance_email,] + vendor_emails
        cc_list = [hod_email] if hod_email else []
        
        # ------------------------------------------------------------
        # SECTION 3: RETRIEVE GRN DETAILS FOR EMAIL CONTENT
        # ------------------------------------------------------------
        
        # Find the specific GRN record for quantity details
        grn = DoGRN.objects.filter(
            po_number=po_number, stock_item=requisition.stock_item
        ).first()
        if not grn:
            return
        
        # ------------------------------------------------------------
        # SECTION 4: PREPARE EMAIL CONTENT
        # ------------------------------------------------------------
        
        subject = "GRN Submission for Received Items"
        
        # HTML email template with GRN details table
        message = f"""
        <html>
        <body>
        <p>Dear Sir,</p>
        <p>We have received the items as per the details mentioned below:</p>
        <table border="1" cellpadding="5" cellspacing="0">
            <tr>
                <th>Request No</th>
                <th>Request Date</th>
                <th>Item</th>
                <th>Request Qty</th>
                <th>Received Qty</th>
                <th>Remarks</th>
            </tr>
            <tr>
                <td>{requisition.requisition_number}</td>
                <td>{requisition.date_of_request.strftime("%b %d, %Y")}</td>
                <td>{requisition.stock_item}</td>
                <td>{requisition.quantity}</td>
                <td>{grn.quantity_received}</td>
                <td>{requisition.remark}</td>
            </tr>
        </table>
        <p>The detailed GRN and required supporting documents are attached for your reference.</p>
        <p>Regards,<br>
        {request.user.get_full_name()}<br>
        {request.user.employee_code}<br>
        {request.user.department} & {request.user.location}</p>
        </body>
        </html>
        """
        
        # ------------------------------------------------------------
        # SECTION 5: CREATE EMAIL WITH HTML CONTENT
        # ------------------------------------------------------------
        
        email = EmailMessage(
            subject, 
            message, 
            settings.DEFAULT_FROM_EMAIL, 
            recipient_list, 
            cc=cc_list
        )
        email.content_subtype = "html"
        
        # ------------------------------------------------------------
        # SECTION 6: MERGE GRN PDF WITH SUPPORTING DOCUMENTS
        # ------------------------------------------------------------
        
        merger = PdfMerger()
        temp_files = []

        # Add main GRN PDF to merger
        grn_pdf_io = io.BytesIO(grn_pdf_content)
        merger.append(grn_pdf_io)

        # Combine all supporting files
        all_files = chaalan_files + invoice_files + approval_files

        # Process each supporting file
        for file in all_files:
            if not file:
                continue
                
            # Save file temporarily for processing
            file_path = f"uploaded_files/{file.name}"
            saved_path = default_storage.save(file_path, file)
            full_path = default_storage.path(saved_path)
            temp_files.append(full_path)
            
            # Determine file type and handle accordingly
            file_extension = file.name.split('.')[-1].lower()
            
            if file_extension in ['png', 'jpg', 'jpeg', 'gif', 'bmp', 'tiff', 'webp']:
                # Convert images to PDF before merging
                pdf_path = convert_any_image_to_pdf(full_path)
                if pdf_path:
                    merger.append(pdf_path)
                    temp_files.append(pdf_path)
            elif file_extension == 'pdf':
                # PDF files can be merged directly
                merger.append(full_path)
            else:
                # Unsupported file types are skipped
                continue

        # ------------------------------------------------------------
        # SECTION 7: CREATE MERGED PDF ATTACHMENT
        # ------------------------------------------------------------
        
        # Write merged PDF to in-memory buffer
        merged_pdf_io = io.BytesIO()
        merger.write(merged_pdf_io)
        merger.close()
        merged_pdf_io.seek(0)

        # Attach merged PDF to email
        email.attach(
            f"GRN_and_Attachments_{grn_number}.pdf",
            merged_pdf_io.getvalue(),
            "application/pdf",
        )
        
        # ------------------------------------------------------------
        # SECTION 8: SEND EMAIL
        # ------------------------------------------------------------
        
        email.send()
        
        # ------------------------------------------------------------
        # SECTION 9: CLEAN UP TEMPORARY FILES
        # ------------------------------------------------------------
        
        for temp_file in temp_files:
            if os.path.exists(temp_file):
                try:
                    os.remove(temp_file)
                except Exception:
                    # Silently handle cleanup failures
                    pass
                    
    except Exception:
        # Silent failure to prevent disrupting main GRN submission flow
        # Errors in email sending should not affect GRN creation
        return



# =========== Legacy File Storage with Timestamp ==============

def save_file(file, folder_name, employee_code):
    """
    Legacy File Storage Function (Deprecated)
    
    Original file storage function that adds timestamp prefix to filenames.
    Consider using save_file_with_name() for more control over filenames.
    
    Args:
        file (UploadedFile): File object to save
        folder_name (str): Target folder name
        employee_code (str): Employee identifier for subfolder
    
    Returns:
        str: Path where file was saved in storage system
    
    Note: Creates filename pattern: YYYYMMDDHHMMSS_original_filename.ext
    """
    
    # Generate timestamp in YearMonthDayHourMinuteSecond format
    timestamp = timezone.now().strftime("%Y%m%d%H%M%S")
    
    # Construct filename with timestamp prefix
    file_name = f"{timestamp}_{file.name}"
    
    # Build storage path with folder hierarchy
    file_path = f"{folder_name}/{employee_code}/{file_name}"
    
    # Save file using Django's default storage
    saved_path = default_storage.save(file_path, file)
    
    return saved_path


