# =========== GRN Report PDF Generator ==============

def generate_grn_report(
    request, po_number, grn_number, chaalan_numbers, date_of_receipts
):
    """
    Generate PDF Report for Goods Received Note (GRN)
    
    Creates a formatted PDF report containing GRN details, organizes data by vendor,
    and provides download response. Handles both single and multiple chaalan scenarios.
    
    Args:
        request: HTTP request object with user context
        po_number (str): Purchase Order number for filtering
        grn_number (str): Generated GRN identifier
        chaalan_numbers (list): List of chaalan/delivery note numbers
        date_of_receipts (list): Corresponding receipt dates for chaalans
    
    Returns:
        HttpResponse: PDF file download on success
        HttpResponse: Error page response on failure
    
    Process Flow:
        1. Fetch requisition and GRN data
        2. Organize GRN data by vendor for reporting
        3. Prepare context for PDF template
        4. Generate and save PDF
        5. Return PDF download response
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: FETCH REQUISITION DATA
        # ------------------------------------------------------------
        
        # Retrieve all requisitions for the given PO number
        requisitions = get_list_or_404(PurchaseRequisition, po_number=po_number)
        
        # ------------------------------------------------------------
        # SECTION 2: FETCH AND ORGANIZE GRN DATA
        # ------------------------------------------------------------
        
        # Get all GRN records for this PO
        grn_data = DoGRN.objects.filter(po_number=po_number)
        
        # Extract unique product names from GRN data
        product_names = list(set(grn.stock_item for grn in grn_data))
        products = Product.objects.filter(name__in=product_names)
        
        # ------------------------------------------------------------
        # SECTION 3: ORGANIZE GRN DATA BY VENDOR
        # ------------------------------------------------------------
        
        vendor_grn_data = {}
        for grn in grn_data:
            # Find vendor associated with this product
            product_vendor = ProductVendor.objects.filter(
                product__name=grn.stock_item
            ).first()
            
            if product_vendor:
                vendor = product_vendor.vendor
                
                # Initialize vendor dictionary if not present
                if vendor not in vendor_grn_data:
                    vendor_grn_data[vendor] = {}
                
                # Initialize PO list for this vendor if not present
                if grn.po_number not in vendor_grn_data[vendor]:
                    vendor_grn_data[vendor][grn.po_number] = []
                
                # Add GRN record to vendor's PO list
                vendor_grn_data[vendor][grn.po_number].append(grn)
        
        # ------------------------------------------------------------
        # SECTION 4: PREPARE TEMPLATE CONTEXT
        # ------------------------------------------------------------
        
        context = {
            "requisitions": requisitions,
            "vendor_grn_data": vendor_grn_data,
            "chaalan_numbers": chaalan_numbers,
            "date_of_receipts": date_of_receipts,
            "logo_url": request.build_absolute_uri(static("images/shwetdharalogo.png")),
            "signature_url": request.user.signature.url if request.user.signature else None,
            "mohar_url": request.user.mohar.url if request.user.mohar else None,
            "location": request.user.location,
        }
        
        # ------------------------------------------------------------
        # SECTION 5: GENERATE PDF FROM TEMPLATE
        # ------------------------------------------------------------
        
        # Render HTML template with context
        html_string = render_to_string("grn_report.html", context)
        
        # Convert HTML to PDF using WeasyPrint
        html = HTML(string=html_string, base_url=request.build_absolute_uri("/"))
        pdf = html.write_pdf()
        
        # ------------------------------------------------------------
        # SECTION 6: SAVE PDF TO STORAGE
        # ------------------------------------------------------------
        
        employee_code = request.user.employee_code
        timestamp = now().strftime("%Y%m%d%H%M%S")
        grn_file_path = f"grns/{employee_code}/{timestamp}_GRN_Report_{grn_number}.pdf"
        default_storage.save(grn_file_path, ContentFile(pdf))
        
        # ------------------------------------------------------------
        # SECTION 7: RETURN PDF DOWNLOAD RESPONSE
        # ------------------------------------------------------------
        
        response = HttpResponse(pdf, content_type="application/pdf")
        response["Content-Disposition"] = f'attachment; filename="GRN_Report_{grn_number}_.pdf"'
        return response
        
    except Exception as e:
        # Handle any unexpected errors during report generation
        return render(
            request, 
            "error_page.html", 
            {"error": f"Error generating GRN report: {str(e)}"}
        )



