# =========== Simple Image to PDF Converter ==============

def convert_image_to_pdf(image_path):
    """
    Basic Image to PDF Converter using ReportLab
    
    Converts PNG and JPG images to PDF with exact dimensions.
    Creates PDF with same page size as original image.
    
    Args:
        image_path (str): Full path to source image file
    
    Returns:
        str or None: Path to generated PDF file, None on failure
    
    Limitations:
        - Only handles .png and .jpg extensions
        - Uses simple file extension replacement
        - Fixed to ReportLab canvas implementation
    """
    
    try:
        # Open and read image dimensions
        image = Image.open(image_path)
        
        # Generate PDF path by replacing image extension
        pdf_path = image_path.replace(".png", ".pdf").replace(".jpg", ".pdf")
        
        # Create PDF with ReportLab canvas matching image dimensions
        with open(pdf_path, "wb") as f:
            img_width, img_height = image.size
            
            # Initialize canvas with image dimensions as page size
            pdf_canvas = canvas.Canvas(f, pagesize=(img_width, img_height))
            
            # Draw image at full size, starting from bottom-left corner
            pdf_canvas.drawImage(image_path, 0, 0, width=img_width, height=img_height)
            
            # Complete PDF page and save
            pdf_canvas.showPage()
            pdf_canvas.save()
        
        return pdf_path
        
    except Exception:
        # Return None for any conversion failure
        return None



# =========== Database Backup Export Utility ==============

@staff_member_required
def download_backup(request):
    """
    Database Backup Exporter - Generates SQL Backup ZIP
    
    Creates a ZIP archive containing SQL files for all database tables.
    Each table is exported with both schema (CREATE TABLE) and data (INSERT).
    Requires staff member permissions for security.
    
    Args:
        request: HTTP request object
    
    Returns:
        HttpResponse: ZIP file download on success
        HttpResponse: Error message if no tables found
    
    Security:
        - Requires @staff_member_required decorator
        - Escapes special characters in SQL values
        - Uses parameterized table names
    
    Export Format:
        ZIP Archive containing:
        - table1.sql (CREATE TABLE + INSERT statements)
        - table2.sql (CREATE TABLE + INSERT statements)
        - ... etc
    """
    
    # Create in-memory ZIP buffer
    zip_buffer = BytesIO()
    
    with zipfile.ZipFile(zip_buffer, "w", zipfile.ZIP_DEFLATED) as zip_file:
        
        # ------------------------------------------------------------
        # SECTION 1: RETRIEVE DATABASE TABLE LIST
        # ------------------------------------------------------------
        
        with connection.cursor() as cursor:
            cursor.execute("SHOW TABLES")
            tables = [row[0] for row in cursor.fetchall()]
        
        # Validate that tables exist
        if not tables:
            return HttpResponse(
                "No tables found in the database.", 
                status=404
            )
        
        # ------------------------------------------------------------
        # SECTION 2: EXPORT EACH TABLE TO SQL
        # ------------------------------------------------------------
        
        for table_name in tables:
            
            # Get table schema information
            with connection.cursor() as cursor:
                cursor.execute(f"DESCRIBE `{table_name}`")
                columns_info = cursor.fetchall()
                
                # Retrieve all table data
                cursor.execute(f"SELECT * FROM `{table_name}`")
                rows = cursor.fetchall()
            
            # Create in-memory buffer for SQL statements
            sql_buffer = BytesIO()
            
            # --------------------------------------------------------
            # SUBSECTION: Generate DROP TABLE statement
            # --------------------------------------------------------
            sql_buffer.write(
                f"DROP TABLE IF EXISTS `{table_name}`;\n".encode("utf-8")
            )
            
            # --------------------------------------------------------
            # SUBSECTION: Generate CREATE TABLE statement
            # --------------------------------------------------------
            create_table_sql = f"CREATE TABLE `{table_name}` (\n"
            
            for column in columns_info:
                column_name, column_type, is_nullable, key, default, extra = column
                create_table_sql += f"    `{column_name}` {column_type} {extra},\n"
            
            create_table_sql = create_table_sql.rstrip(",\n") + "\n);\n"
            sql_buffer.write(create_table_sql.encode("utf-8"))
            
            # --------------------------------------------------------
            # SUBSECTION: Generate INSERT statements for each row
            # --------------------------------------------------------
            for row in rows:
                # Process each column value with proper escaping
                values = ", ".join(
                    [
                        (
                            f"'{str(value).replace('\\', '\\\\').replace('\"', '\\\"')}'"
                            if value is not None
                            else "NULL"
                        )
                        for value in row
                    ]
                )
                
                sql_buffer.write(
                    f"INSERT INTO `{table_name}` VALUES ({values});\n".encode("utf-8")
                )
            
            # --------------------------------------------------------
            # SUBSECTION: Add SQL file to ZIP archive
            # --------------------------------------------------------
            zip_file.writestr(f"{table_name}.sql", sql_buffer.getvalue())
    
    # ------------------------------------------------------------
    # SECTION 3: PREPARE ZIP FILE DOWNLOAD RESPONSE
    # ------------------------------------------------------------
    
    zip_buffer.seek(0)
    
    response = HttpResponse(zip_buffer, content_type="application/zip")
    response["Content-Disposition"] = "attachment; filename=database_backup.zip"
    
    return response



# =========== Admin Choice Editor Utility ==============

@staff_member_required
@login_required(login_url='login')
def edit_choices(request):
    """
    Django Choice Configuration Editor
    
    Provides web-based interface for administrators to edit Django choice constants
    defined in choices.py. Allows runtime modification of dropdown options and
    other fixed choice lists without code deployment.
    
    Args:
        request: HTTP request object
    
    Returns:
        HttpResponse: Edit form (GET) or redirect (POST on save)
    
    Security:
        - Requires @staff_member_required decorator
        - Restricted to staff users only
        - File path is hardcoded for safety
    
    File Location:
        {project_root}/choices.py (in same directory as views.py)
    
    Usage:
        GET: Display current choices.py content in editable textarea
        POST: Save modified content and redirect to admin index
    """
    
    # Define path to choices.py file (relative to views.py location)
    choices_file_path = os.path.join(os.path.dirname(__file__), "choices.py")
    
    if request.method == "POST":
        # ------------------------------------------------------------
        # SECTION 1: HANDLE FORM SUBMISSION (SAVE CHANGES)
        # ------------------------------------------------------------
        
        # Extract modified content from POST data
        content = request.POST.get("content")
        
        if content:
            # Write updated content to choices.py file
            with open(choices_file_path, "w") as f:
                f.write(content)
            
            # Redirect to Django admin index after successful save
            return redirect("admin:index")
    
    else:
        # ------------------------------------------------------------
        # SECTION 2: HANDLE PAGE LOAD (DISPLAY CURRENT CONTENT)
        # ------------------------------------------------------------
        
        # Read current content from choices.py file
        with open(choices_file_path, "r") as f:
            content = f.read()
    
    # ------------------------------------------------------------
    # SECTION 3: RENDER EDITING INTERFACE
    # ------------------------------------------------------------
    
    # Render template with current file content for editing
    return render(
        request, 
        "admin/edit_choices.html", 
        {"content": content}
    )


# =========== Indent Creation and HOD Notification View ==============

@login_required(login_url="login")
@restrict_hod_access
def createIndent(request):
    """
    Create Purchase Indent with HOD Notifications
    
    Handles creation of purchase requisitions (indents) with automatic
    HOD email notifications. Supports multiple items in a single indent
    with batch numbering.
    
    Args:
        request: HTTP request object
    
    Returns:
        HttpResponse: Redirect to success page on success
        HttpResponse: Error page with form on failure
    
    Process Flow:
        1. Validate authentication and authorization
        2. Process POST data with multiple items
        3. Generate batch requisition number
        4. Save requisitions in atomic transaction
        5. Send HOD notifications grouped by department
        6. Redirect to success page
    
    Security:
        - @login_required ensures authentication
        - @restrict_hod_access limits access by role
    """
    
    # Validate user authentication
    if not request.user.is_authenticated:
        return redirect("login")
    
    # Load choice constants for form dropdowns
    location_choices = LOCATION_CHOICES
    department_choices = DEPARTMENT_CHOICES
    employee_code_choices = EMPLOYEE_CODE_CHOICES
    uom_choices = UOM_CHOICES
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: HANDLE FORM SUBMISSION (POST REQUEST)
        # ------------------------------------------------------------
        if request.method == "POST":
            
            # --------------------------------------------------------
            # SUBSECTION: Extract Form Data
            # --------------------------------------------------------
            department = request.POST.get("department")
            employee_name = request.POST.get("employee_name")
            employee_code = request.POST.get("employee_code")
            location = request.POST.get("location")
            
            # Extract array data for multiple items
            uoms = request.POST.getlist("uom[]")
            stock_items = request.POST.getlist("stock_item_name[]")
            quantities = request.POST.getlist("quantity[]")
            expected_delivery_dates = request.POST.getlist("date[]")
            remarks = request.POST.getlist("remark[]")
            
            # --------------------------------------------------------
            # SUBSECTION: Validate Required Data
            # --------------------------------------------------------
            if not uoms or not stock_items or not quantities:
                return render(
                    request,
                    "create-an-indent.html",
                    {
                        "location_choices": location_choices,
                        "department_choices": department_choices,
                        "employee_code_choices": employee_code_choices,
                        "uom_choices": uom_choices,
                        "error_message": "Please add at least one product to the indent.",
                    },
                )
            
            # --------------------------------------------------------
            # SUBSECTION: Generate Batch Requisition Number
            # --------------------------------------------------------
            last_requisition = (
                PurchaseRequisition.objects.filter(requisition_number__startswith="REQ")
                .order_by("-id")
                .first()
            )
            last_number = (
                int(last_requisition.requisition_number[3:]) if last_requisition else 0
            )
            batch_requisition_number = f"REQ{last_number + 1:04d}"
            
            # --------------------------------------------------------
            # SUBSECTION: Save Requisitions in Atomic Transaction
            # --------------------------------------------------------
            with transaction.atomic():
                for i in range(len(uoms)):
                    PurchaseRequisition.objects.create(
                        department=department,
                        employee_name=employee_name,
                        employee_code=employee_code,
                        location=location,
                        uom=uoms[i],
                        stock_item=stock_items[i],
                        quantity=int(quantities[i]),
                        expected_delivery_date=expected_delivery_dates[i],
                        remark=remarks[i],
                        requisition_number=batch_requisition_number,
                        created_by=request.user,
                    )
            
            # --------------------------------------------------------
            # SUBSECTION: Organize Items by HOD for Grouped Emails
            # --------------------------------------------------------
            hod_items_map = {}
            
            for i, stock_item_name in enumerate(stock_items):
                product = Product.objects.filter(name=stock_item_name).first()
                
                if product and product.hod:
                    hod_email = product.hod.email
                    
                    # Initialize HOD's item list if first item
                    if hod_email not in hod_items_map:
                        hod_items_map[hod_email] = []
                    
                    # Add item details to HOD's list
                    hod_items_map[hod_email].append(
                        {
                            "item_name": stock_item_name,
                            "quantity": quantities[i],
                            "location": location,
                            "remark": remarks[i],
                            "expected_delivery_date": expected_delivery_dates[i],
                        }
                    )
            
            # --------------------------------------------------------
            # SUBSECTION: Dispatch HOD Notifications (NON-BLOCKING)
            # --------------------------------------------------------
            # The requisitions are already committed in the atomic block above.
            # Hand the email work to Celery — one task per HOD — so this request
            # returns immediately instead of being held open on synchronous
            # SMTP. This is what lets many users raise indents concurrently:
            # no request blocks while emails are delivered in the background.
            from .tasks_sequential import send_indent_hod_email

            if not hod_items_map:
                logger.warning(
                    "Indent %s saved but no HODs mapped to its products; "
                    "no notification emails dispatched.",
                    batch_requisition_number,
                )
            else:
                for hod_email, items in hod_items_map.items():
                    try:
                        send_indent_hod_email.delay(
                            batch_requisition_number,
                            employee_name,
                            hod_email,
                            items,
                        )
                    except Exception as dispatch_error:
                        # Broker unreachable: the indent is already saved, so we
                        # log and continue rather than failing the user's request.
                        logger.error(
                            "Failed to queue indent email for %s (indent %s): %s",
                            hod_email,
                            batch_requisition_number,
                            dispatch_error,
                        )

            # --------------------------------------------------------
            # SUBSECTION: Redirect to Success Page
            # --------------------------------------------------------
            return redirect("request-sent")
    
    except Exception:
        # ------------------------------------------------------------
        # SECTION 2: ERROR HANDLING
        # ------------------------------------------------------------
        return render(
            request,
            "create-an-indent.html",
            {
                "location_choices": location_choices,
                "department_choices": department_choices,
                "employee_code_choices": employee_code_choices,
                "uom_choices": uom_choices,
                "error_message": "An unexpected error occurred. Please try again.",
            },
        )
    
    # ------------------------------------------------------------
    # SECTION 3: HANDLE INITIAL PAGE LOAD (GET REQUEST)
    # ------------------------------------------------------------
    return render(
        request,
        "create-an-indent.html",
        {
            "location_choices": location_choices,
            "department_choices": department_choices,
            "employee_code_choices": employee_code_choices,
            "uom_choices": uom_choices,
        },
    )


# =========== Raise Indent by Excel (Bulk Upload) ==============

@login_required(login_url="login")
def download_indent_template(request):
    """
    Generate a pre-filled Excel template for raising an indent in bulk.

    The sheet lists every active product (one row each) with its UOM already
    filled in ('NONE' when the product has no UOM). The user only enters a
    Quantity (and optional Remark) against the products they want, then
    re-uploads the file via ``import_indent_excel``. Because the product names
    are printed by the template, there is no typing and therefore no
    name-matching ambiguity on upload.
    """

    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Indent"

    headers = ["Product Name", "UOM", "Quantity", "Remark"]
    ws.append(headers)

    # Header styling (matches the app's green/white theme used elsewhere)
    header_fill = PatternFill(start_color="A3B087", end_color="A3B087", fill_type="solid")
    header_font = Font(color="FFFFFF", bold=True)
    thin = Side(style="thin", color="CCCCCC")
    border = Border(left=thin, right=thin, top=thin, bottom=thin)
    for col_idx in range(1, len(headers) + 1):
        cell = ws.cell(row=1, column=col_idx)
        cell.fill = header_fill
        cell.font = header_font
        cell.alignment = Alignment(horizontal="center", vertical="center")
        cell.border = border

    # One row per product, name + UOM pre-filled, quantity/remark blank.
    # report_only -> just the 35 Sale & Stock Report items, printed by their exact report
    # names (e.g. "Cattle Feed Sag (50_Kg)"); otherwise every active product by real name.
    report_only = request.GET.get("report_only", "").strip().lower() in ("1", "true", "yes")
    if report_only:
        from . import stock_report as stock_report_engine
        for product, display in stock_report_engine.report_products():
            ws.append([display, product.uom or "NONE", "", ""])
    else:
        for product in Product.objects.filter(is_active=True).order_by("name"):
            ws.append([product.name, product.uom or "NONE", "", ""])

    # Column widths for readability
    for col, width in {"A": 45, "B": 14, "C": 12, "D": 35}.items():
        ws.column_dimensions[col].width = width

    # Keep the header visible while scrolling the (potentially long) list
    ws.freeze_panes = "A2"

    output = BytesIO()
    wb.save(output)
    output.seek(0)

    kind = "report_items" if report_only else "all_products"
    filename = f"indent_template_{kind}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
    response = HttpResponse(
        output.read(),
        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )
    response["Content-Disposition"] = f'attachment; filename="{filename}"'
    return response


@login_required(login_url="login")
def import_indent_excel(request):
    """
    Parse an uploaded indent Excel (produced by ``download_indent_template``)
    and return the filled line-items as JSON.

    The front-end loads these rows into the existing product table so the user
    can review them and submit through the normal ``createIndent`` POST path —
    no save/email logic is duplicated here.

    Rules:
        * Only rows with a positive Quantity become line-items.
        * Product is matched by exact name against active products.
        * Rows with a quantity but an unknown product / bad quantity are
          reported in ``errors`` and skipped (valid rows still load).
    """
    if request.method != "POST" or not request.FILES.get("file"):
        return JsonResponse({"success": False, "error": "No file uploaded."}, status=400)

    excel_file = request.FILES["file"]
    if not excel_file.name.lower().endswith((".xlsx", ".xls")):
        return JsonResponse(
            {"success": False, "error": "Please upload a valid .xlsx file (use the downloaded template)."},
            status=400,
        )

    try:
        wb = openpyxl.load_workbook(excel_file, data_only=True, read_only=True)
    except Exception:
        return JsonResponse(
            {"success": False, "error": "Could not read the Excel file. Please use the downloaded template."},
            status=400,
        )

    ws = wb.active

    # Cache active products by name for fast, exact matching
    product_map = {p.name.strip(): p for p in Product.objects.filter(is_active=True)}
    # Alias-aware fallback for sheets printed with report names.
    from . import stock_report as stock_report_engine
    _report_norm_cache = stock_report_engine.build_product_norm_cache()

    rows = []
    errors = []
    for row_idx, row in enumerate(ws.iter_rows(min_row=2, values_only=True), start=2):
        if not row:
            continue

        name = str(row[0]).strip() if len(row) > 0 and row[0] is not None else ""
        uom_val = str(row[1]).strip() if len(row) > 1 and row[1] is not None else ""
        qty_raw = row[2] if len(row) > 2 else None
        remark = str(row[3]).strip() if len(row) > 3 and row[3] is not None else ""

        # Skip rows the user left untouched (no quantity)
        if qty_raw is None or str(qty_raw).strip() == "":
            continue
        if not name:
            continue

        # Validate quantity
        try:
            quantity = int(float(str(qty_raw).strip()))
        except (ValueError, TypeError):
            errors.append(f"Row {row_idx}: '{name}' — invalid quantity '{qty_raw}'.")
            continue
        if quantity <= 0:
            continue  # zero / negative => treated as not requested

        # Exact active-product name first; then fall back to the report-name aliases so a
        # sheet printed with report names ("Cattle Feed Sag (50_Kg)") still resolves to the
        # real product ("CF- SAG 50 KG").
        product = product_map.get(name)
        if not product:
            product = stock_report_engine.resolve_product_by_name(name, _report_norm_cache, create=False)
        if not product:
            errors.append(f"Row {row_idx}: product '{name}' not found or inactive.")
            continue

        rows.append({
            "product_id": product.id,
            "name": product.name,
            "display": stock_report_engine.report_display_name(product.name),
            "uom": product.uom or (uom_val or "NONE"),
            "quantity": quantity,
            "remark": remark,
        })

    wb.close()

    if not rows and not errors:
        return JsonResponse(
            {"success": False, "error": "No products with a quantity were found in the file."},
            status=400,
        )

    return JsonResponse({"success": True, "rows": rows, "errors": errors, "count": len(rows)})


# =========== Stock Transfer Note (STN) — Location User ==============

def _render_stn_pdf(stn, request):
    """
    Render a saved StockTransferNote to a PDF (BytesIO) using s.t.n_report.html.

    Shared by create_stn (after save) and download_stn_pdf (re-download). The
    'Prepared By' signature and 'Approved By' stamp come from the creating
    user's own signature / mohar.
    """

    user = stn.created_by
    prepared_by_signature = checked_by_signature = approved_by_stamp = None
    if user:
        if getattr(user, "signature", None):
            prepared_by_signature = request.build_absolute_uri(user.signature.url)
            checked_by_signature = prepared_by_signature
        if getattr(user, "mohar", None):
            approved_by_stamp = request.build_absolute_uri(user.mohar.url)

    context = {
        "items": stn.items.all(),
        "from_location": stn.from_location,
        "from_address": stn.from_address,
        "to_location": stn.to_location,
        "to_address": stn.to_address,
        "company_name": "Shwetdhara Milk Producer Company Limited",
        "logo_url": request.build_absolute_uri(static("images/shwetdharalogo.png")),
        "today_date": stn.created_at.strftime("%d-%m-%Y") if stn.created_at else datetime.now().strftime("%d-%m-%Y"),
        "stn_number": stn.stn_number,
        "prepared_by_signature": prepared_by_signature,
        "checked_by_signature": checked_by_signature,
        "approved_by_stamp": approved_by_stamp,
        "grn_by": user.get_full_name() if user else "",
        "transporter_name": stn.transporter_name,
        "vehicle_number": stn.vehicle_number,
        "driver_name": stn.driver_name,
        "driver_contact": stn.driver_contact,
    }

    html_string = render_to_string("s.t.n_report.html", context)
    pdf_buffer = BytesIO()
    HTML(string=html_string, base_url=request.build_absolute_uri("/")).write_pdf(pdf_buffer)
    pdf_buffer.seek(0)
    return pdf_buffer


@login_required(login_url="login")
def create_stn(request):
    """
    Location user's Stock Transfer Note creator.

    GET  -> renders the create page (destination + transporter + item rows,
            plus the same Excel bulk-upload used for indents).
    POST -> validates, saves a StockTransferNote + items, then streams the
            generated PDF back as a download. The saved record stays available
            for re-download from the 'Recent STNs' list on the page.

    From location/address = the logged-in user's own location/address.
    To address is looked up from a user at the destination location (if any).
    """

    location_choices = LOCATION_CHOICES
    uom_choices = UOM_CHOICES

    if request.method == "POST":
        # The Generate button submits over AJAX (progress modal) — return JSON on error
        # so the modal can show it, instead of re-rendering the whole page.
        is_ajax = request.headers.get("x-requested-with") == "XMLHttpRequest"
        to_location = (request.POST.get("to_location") or "").strip()
        transporter_name = (request.POST.get("transporter_name") or "").strip()
        vehicle_number = (request.POST.get("vehicle_number") or "").strip()
        driver_name = (request.POST.get("driver_name") or "").strip()
        driver_contact = (request.POST.get("driver_contact") or "").strip()

        stock_item_ids = request.POST.getlist("stock_item[]")
        stock_items = request.POST.getlist("stock_item_name[]")
        quantities = request.POST.getlist("quantity[]")
        uoms = request.POST.getlist("uom[]")

        # Build the validated line-item list (skip blank/zero rows).
        # Each line carries the product id so we can deduct from inventory.
        line_items = []
        for i in range(len(stock_items)):
            name = (stock_items[i] or "").strip()
            qty_raw = quantities[i] if i < len(quantities) else ""
            if not name or str(qty_raw).strip() == "":
                continue
            try:
                qty = int(float(str(qty_raw).strip()))
            except (ValueError, TypeError):
                continue
            if qty <= 0:
                continue
            pid = stock_item_ids[i] if i < len(stock_item_ids) else ""
            line_items.append((pid, name, uoms[i] if i < len(uoms) else "", qty))

        error_message = None
        if not to_location:
            error_message = "Please select a destination location."
        elif to_location == request.user.location:
            error_message = "Destination location must be different from your own location."
        elif not line_items:
            error_message = "Please add at least one item with a quantity."

        if error_message:
            if is_ajax:
                return JsonResponse({"success": False, "error": error_message}, status=400)
            return render(request, "create_stn.html", {
                "location_choices": location_choices,
                "uom_choices": uom_choices,
                "error_message": error_message,
            })

        to_user = CustomUser.objects.filter(location=to_location).first()
        to_address = to_user.address if to_user else ""

        # Generating an STN only creates the draft document (and its PDF). No
        # inventory is touched here — the creator commits the dispatch later by
        # clicking "Final Posting" in View Your STN. We still resolve and store
        # the product on each line so posting/receiving can move stock reliably.
        with transaction.atomic():
            stn = StockTransferNote.objects.create(
                created_by=request.user,
                from_location=request.user.location,
                from_address=request.user.address or "",
                to_location=to_location,
                to_address=to_address,
                transporter_name=transporter_name,
                vehicle_number=vehicle_number,
                driver_name=driver_name,
                driver_contact=driver_contact,
            )
            for (pid, name, uom, qty) in line_items:
                product = None
                if pid:
                    product = Product.objects.filter(id=pid).first()
                if product is None:
                    product = Product.objects.filter(name=name).first()
                StockTransferNoteItem.objects.create(
                    stn=stn, product=product, stock_item=name, uom=uom or "", quantity=qty
                )

        # Generate the PDF and stream it back as a download
        pdf_buffer = _render_stn_pdf(stn, request)
        response = HttpResponse(pdf_buffer.read(), content_type="application/pdf")
        response["Content-Disposition"] = f'attachment; filename="{stn.stn_number}.pdf"'
        response["X-STN-Number"] = stn.stn_number   # let the AJAX caller name the toast/file
        return response

    # GET
    return render(request, "create_stn.html", {
        "location_choices": location_choices,
        "uom_choices": uom_choices,
    })


@login_required(login_url="login")
def download_stn_pdf(request, stn_number):
    """Re-generate and download the PDF for a previously saved STN."""

    stn = get_object_or_404(StockTransferNote, stn_number=stn_number)
    pdf_buffer = _render_stn_pdf(stn, request)
    response = HttpResponse(pdf_buffer.read(), content_type="application/pdf")
    response["Content-Disposition"] = f'attachment; filename="{stn.stn_number}.pdf"'
    return response


def _render_stn_grn_pdf(stn, request):
    """
    Render the GRN-against-STN to a PDF (BytesIO) using s.t.n_grn_report.html.

    Lists every product with its received (good) quantity, the expired/rejected
    quantity returned to the sender, and any shortfall. The 'Received By'
    signature / stamp come from the receiving user.
    """

    user = stn.received_by or stn.created_by
    received_by_signature = approved_by_stamp = None
    if user:
        if getattr(user, "signature", None):
            received_by_signature = request.build_absolute_uri(user.signature.url)
        if getattr(user, "mohar", None):
            approved_by_stamp = request.build_absolute_uri(user.mohar.url)

    context = {
        "items": stn.items.all(),
        "from_location": stn.from_location,
        "from_address": stn.from_address,
        "to_location": stn.to_location,
        "to_address": stn.to_address,
        "company_name": "Shwetdhara Milk Producer Company Limited",
        "logo_url": request.build_absolute_uri(static("images/shwetdharalogo.png")),
        "received_date": stn.received_at.strftime("%d-%m-%Y") if stn.received_at else datetime.now().strftime("%d-%m-%Y"),
        "stn_number": stn.stn_number,
        "grn_number": stn.grn_number,
        "received_by_signature": received_by_signature,
        "approved_by_stamp": approved_by_stamp,
        "received_by_name": user.get_full_name() if user else "",
    }

    html_string = render_to_string("s.t.n_grn_report.html", context)
    pdf_buffer = BytesIO()
    HTML(string=html_string, base_url=request.build_absolute_uri("/")).write_pdf(pdf_buffer)
    pdf_buffer.seek(0)
    return pdf_buffer


@login_required(login_url="login")
def download_stn_grn_pdf(request, stn_number):
    """Generate and download the GRN-against-STN PDF for a received STN."""

    stn = get_object_or_404(StockTransferNote, stn_number=stn_number)
    if not stn.is_received:
        messages.error(request, f"{stn.stn_number} has not been received yet — no GRN to download.")
        return redirect("incoming_stns")
    pdf_buffer = _render_stn_grn_pdf(stn, request)
    response = HttpResponse(pdf_buffer.read(), content_type="application/pdf")
    filename = f"{stn.grn_number or stn.stn_number}-GRN.pdf"
    response["Content-Disposition"] = f'attachment; filename="{filename}"'
    return response


@login_required(login_url="login")
def final_post_stn(request, stn_number):
    """
    Final-post a draft STN: this is the explicit commit step that actually
    dispatches the goods. Each item is deducted from the creator's inventory
    (TRANSFER_OUT + audit history) and the STN is marked posted. Atomic — all
    items or none. Only the creator can post, and only once.
    """

    stn = get_object_or_404(
        StockTransferNote, stn_number=stn_number, created_by=request.user
    )

    if stn.is_posted:
        messages.info(request, f"{stn.stn_number} has already been final-posted.")
        return redirect("view_stns")
    if request.method != "POST":
        return redirect("view_stns")

    try:
        with transaction.atomic():
            for item in stn.items.all():
                product = item.product or Product.objects.filter(name=item.stock_item).first()
                if product is None:
                    raise ValueError(
                        f"Could not match product '{item.stock_item}' to your catalog."
                    )
                try:
                    inventory = Inventory.objects.select_for_update().get(
                        mcc_bmc_user=request.user, product=product
                    )
                except Inventory.DoesNotExist:
                    raise ValueError(
                        f"You have no inventory of '{item.stock_item}' at "
                        f"{request.user.location} to transfer."
                    )
                if inventory.quantity < item.quantity:
                    raise ValueError(
                        f"Insufficient stock for '{item.stock_item}': you have "
                        f"{inventory.quantity}, but the STN dispatches {item.quantity}."
                    )
                inventory.deduct_quantity(
                    item.quantity,
                    action="TRANSFER_OUT",
                    reference_number=stn.stn_number,
                    notes=f"Stock transfer to {stn.to_location} (STN {stn.stn_number})",
                    user=request.user,
                )

            stn.is_posted = True
            stn.posted_by = request.user
            stn.posted_at = timezone.now()
            stn.save(update_fields=["is_posted", "posted_by", "posted_at"])
    except (ValueError, ValidationError) as exc:
        messages.error(request, f"Could not post {stn.stn_number}: {exc}")
        return redirect("view_stns")

    messages.success(
        request,
        f"{stn.stn_number} final-posted — {stn.items.count()} item(s) deducted from your inventory.",
    )
    return redirect("view_stns")


@login_required(login_url="login")
def view_stns(request):
    """
    'View Your STN' page — lists the Stock Transfer Notes created by the user,
    with filtering by STN number, date range, month, and destination location.
    Each row links to a freshly-regenerated PDF for download.
    """

    base_qs = StockTransferNote.objects.filter(created_by=request.user)

    search = request.GET.get("search", "").strip()
    date_from = request.GET.get("date_from", "").strip()
    date_to = request.GET.get("date_to", "").strip()
    month = request.GET.get("month", "").strip()          # format: YYYY-MM
    location = request.GET.get("location", "").strip()
    status = request.GET.get("status", "").strip()        # draft | posted | received

    qs = base_qs
    if search:
        qs = qs.filter(stn_number__icontains=search)
    if status == "draft":
        qs = qs.filter(is_posted=False)
    elif status == "posted":
        qs = qs.filter(is_posted=True, is_received=False)
    elif status == "received":
        qs = qs.filter(is_received=True)
    if location:
        qs = qs.filter(to_location=location)
    if month:
        try:
            year_str, month_str = month.split("-")
            qs = qs.filter(created_at__year=int(year_str), created_at__month=int(month_str))
        except (ValueError, TypeError):
            pass
    if date_from:
        try:
            qs = qs.filter(created_at__date__gte=datetime.strptime(date_from, "%Y-%m-%d").date())
        except ValueError:
            pass
    if date_to:
        try:
            qs = qs.filter(created_at__date__lte=datetime.strptime(date_to, "%Y-%m-%d").date())
        except ValueError:
            pass

    qs = qs.order_by("-created_at")

    paginator = Paginator(qs, 25)
    page_obj = paginator.get_page(request.GET.get("page"))

    # Distinct destination locations this user has shipped to (for the dropdown)
    locations = list(
        base_qs.values_list("to_location", flat=True).distinct().order_by("to_location")
    )

    return render(request, "view_stns.html", {
        "stns": page_obj,
        "page_obj": page_obj,
        "search": search,
        "date_from": date_from,
        "date_to": date_to,
        "month": month,
        "location_filter": location,
        "status_filter": status,
        "locations": locations,
        "total_count": qs.count(),
        "draft_count": base_qs.filter(is_posted=False).count(),
    })


@login_required(login_url="login")
@require_GET
def stn_items_json(request, stn_number):
    """Item detail for one STN, for the 'Show Items' modal on View Your STNs.

    Returns the header (route, transporter, status) and every line item with its
    dispatched / received / rejected quantities. Visible to the STN's creator, the
    destination location, or a superuser.
    """
    stn = get_object_or_404(
        StockTransferNote.objects.prefetch_related("items"), stn_number=stn_number
    )
    allowed = (
        request.user.is_superuser
        or stn.created_by_id == request.user.id
        or (stn.to_location or "").strip().lower() == (request.user.location or "").strip().lower()
    )
    if not allowed:
        return JsonResponse({"success": False, "error": "You don't have access to this STN."}, status=403)

    if stn.is_received:
        status = "received"
    elif stn.is_posted:
        status = "posted"
    else:
        status = "draft"

    items = []
    for i, it in enumerate(stn.items.all(), start=1):
        items.append({
            "sr": i,
            "stock_item": it.stock_item,
            "uom": it.uom or "—",
            "quantity": it.quantity,
            "received_quantity": it.received_quantity,   # None until received
            "rejected_quantity": it.rejected_quantity or 0,
            "shortfall": it.shortfall,                   # None until received
        })

    return JsonResponse({
        "success": True,
        "stn_number": stn.stn_number,
        "from_location": stn.from_location,
        "to_location": stn.to_location,
        "transporter_name": stn.transporter_name or "—",
        "vehicle_number": stn.vehicle_number or "—",
        "driver_name": stn.driver_name or "—",
        "driver_contact": stn.driver_contact or "—",
        "grn_number": stn.grn_number or "",
        "created_at": stn.created_at.strftime("%d %b %Y, %I:%M %p") if stn.created_at else "",
        "status": status,
        "item_count": len(items),
        "total_quantity": sum(it["quantity"] for it in items),
        "items": items,
    })


@login_required(login_url="login")
def incoming_stns(request):
    """
    'Incoming STNs' — Stock Transfer Notes addressed to the current user's
    location. Pending ones can be received (which adds the items to the user's
    inventory); received ones are shown for reference with PDF download.
    """

    # Only posted (dispatched) STNs can be received — drafts that haven't been
    # final-posted aren't shown to the destination yet.
    base_qs = StockTransferNote.objects.filter(
        to_location=request.user.location, is_posted=True
    )

    show = request.GET.get("show", "pending").strip()  # pending | received | all
    search = request.GET.get("search", "").strip()

    qs = base_qs
    if show == "pending":
        qs = qs.filter(is_received=False)
    elif show == "received":
        qs = qs.filter(is_received=True)
    if search:
        qs = qs.filter(stn_number__icontains=search)
    qs = qs.order_by("is_received", "-created_at")

    paginator = Paginator(qs, 25)
    page_obj = paginator.get_page(request.GET.get("page"))

    return render(request, "incoming_stns.html", {
        "stns": page_obj,
        "page_obj": page_obj,
        "show": show,
        "search": search,
        "pending_count": base_qs.filter(is_received=False).count(),
    })


def _stn_receivable_or_redirect(request, stn_number):
    """Fetch an STN and validate the current user may receive it.
    Returns (stn, None) if OK, or (None, redirect_response) if not."""

    stn = get_object_or_404(StockTransferNote, stn_number=stn_number)
    # Normalise case + whitespace: the incoming list matches in MySQL
    # (case-insensitive collation), so the guard must do the same — otherwise
    # "PRATAPGARH" vs "Pratapgarh" passes the list but fails a plain `!=`.
    if (stn.to_location or "").strip().casefold() != (request.user.location or "").strip().casefold():
        messages.error(request, "This STN is not addressed to your location.")
        return None, redirect("incoming_stns")
    if not stn.is_posted:
        messages.error(request, f"{stn.stn_number} has not been final-posted (dispatched) yet.")
        return None, redirect("incoming_stns")
    if stn.is_received:
        messages.info(request, f"{stn.stn_number} has already been received (GRN {stn.grn_number}).")
        return None, redirect("incoming_stns")
    return stn, None


@login_required(login_url="login")
def download_incoming_stn_excel(request, stn_number):
    """
    Excel for the receiver: lists what was transferred (locked) plus an editable
    'Received Quantity' column. Sheet protection keeps everything read-only
    except the Received Quantity cells, which the receiver fills in.
    """

    stn = get_object_or_404(StockTransferNote, stn_number=stn_number)

    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "GRN against STN"

    headers = [
        "S.No", "Stock Item", "UOM", "Transferred Quantity",
        "Received Quantity", "Expired/Rejected Quantity",
    ]
    ws.append(headers)
    header_fill = PatternFill(start_color="313647", end_color="313647", fill_type="solid")
    header_font = Font(color="FFFFFF", bold=True)
    locked = Protection(locked=True)
    editable = Protection(locked=False)
    for col_idx in range(1, len(headers) + 1):
        cell = ws.cell(row=1, column=col_idx)
        cell.fill = header_fill
        cell.font = header_font
        cell.alignment = Alignment(horizontal="center", vertical="center")
        cell.protection = locked

    for idx, item in enumerate(stn.items.all(), start=1):
        ws.append([idx, item.stock_item, item.uom or "", item.quantity, "", ""])
        row = idx + 1
        # Lock every cell except Received (E) and Expired/Rejected (F)
        for col in range(1, 5):
            ws.cell(row=row, column=col).protection = locked
        recv_cell = ws.cell(row=row, column=5)
        recv_cell.protection = editable
        recv_cell.value = item.quantity  # default = full receipt; receiver edits if less
        rej_cell = ws.cell(row=row, column=6)
        rej_cell.protection = editable
        rej_cell.value = 0  # default = nothing expired/rejected

    for col, width in {"A": 8, "B": 42, "C": 10, "D": 20, "E": 20, "F": 24}.items():
        ws.column_dimensions[col].width = width
    ws.freeze_panes = "A2"

    # Protect the sheet so only the unlocked Received Quantity cells are editable
    ws.protection.sheet = True
    ws.protection.enable()

    output = BytesIO()
    wb.save(output)
    output.seek(0)
    response = HttpResponse(
        output.read(),
        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )
    response["Content-Disposition"] = f'attachment; filename="GRN_{stn.stn_number}.xlsx"'
    return response


@login_required(login_url="login")
def receive_stn(request, stn_number):
    """
    Receive an STN and create the GRN-against-STN.

    GET  -> shows the receive page (items with transferred qty, editable received
            qty, proof upload, and a link to download the locked Excel).
    POST -> reads received quantities (from the uploaded filled Excel if present,
            else the on-page inputs), adds the RECEIVED quantity to the receiver's
            inventory (TRANSFER_IN), stores the proof, assigns a GRN number, and
            marks the STN received. Atomic.
    """

    stn, redirect_response = _stn_receivable_or_redirect(request, stn_number)
    if redirect_response is not None:
        return redirect_response

    items = list(stn.items.all())

    if request.method != "POST":
        return render(request, "receive_stn.html", {"stn": stn, "items": items})

    # The receive page submits via fetch so it can show a progress bar, download
    # the GRN sheet, then redirect. For that flow we return JSON on error instead
    # of a redirect (a non-PDF response is how the page detects a failure).
    is_ajax = request.headers.get("x-requested-with") == "XMLHttpRequest"

    def _fail(message):
        if is_ajax:
            return JsonResponse({"error": message}, status=400)
        messages.error(request, message)
        return redirect("receive_stn", stn_number=stn.stn_number)

    # ---- Resolve received / expired quantity per item -------------------
    # Priority: a filled Excel upload (column 5 = Received Quantity, column 6 =
    # Expired/Rejected Quantity), else the on-page number inputs. Default
    # received = transferred, expired = 0.
    received_map = {}
    rejected_map = {}
    excel_file = request.FILES.get("received_excel")
    if excel_file:
        try:
            wb = openpyxl.load_workbook(excel_file, data_only=True, read_only=True)
            ws = wb.active
            rows = [r for r in ws.iter_rows(min_row=2, values_only=True)]
            wb.close()
            # Rows align with item order (the template is generated in that order)
            for item, row in zip(items, rows):
                if row and len(row) >= 5 and row[4] is not None and str(row[4]).strip() != "":
                    received_map[item.id] = row[4]
                if row and len(row) >= 6 and row[5] is not None and str(row[5]).strip() != "":
                    rejected_map[item.id] = row[5]
        except Exception:
            return _fail("Could not read the uploaded Excel. Use the downloaded template.")

    # Proof is mandatory whenever any item is received short (received < transferred).
    # Receipt is the always-uploaded acknowledgement document.
    receipt_file = request.FILES.get("receipt")
    proof_file = request.FILES.get("proof")
    has_shortfall = False

    try:
        with transaction.atomic():
            for item in items:
                raw = received_map.get(item.id, request.POST.get(f"received_qty_{item.id}", ""))
                if raw is None or str(raw).strip() == "":
                    received = item.quantity  # default to full receipt
                else:
                    try:
                        received = int(float(str(raw).strip()))
                    except (ValueError, TypeError):
                        raise ValueError(f"Invalid received quantity for '{item.stock_item}'.")

                # Expired / rejected units (returned to the sender). From the
                # uploaded Excel (column F) if present, else the on-page input.
                rej_raw = rejected_map.get(item.id, request.POST.get(f"rejected_qty_{item.id}", ""))
                if rej_raw is None or str(rej_raw).strip() == "":
                    rejected = 0
                else:
                    try:
                        rejected = int(float(str(rej_raw).strip()))
                    except (ValueError, TypeError):
                        raise ValueError(f"Invalid expired/rejected quantity for '{item.stock_item}'.")

                if received < 0:
                    raise ValueError(f"Received quantity for '{item.stock_item}' cannot be negative.")
                if rejected < 0:
                    raise ValueError(f"Expired/rejected quantity for '{item.stock_item}' cannot be negative.")
                if received > item.quantity:
                    raise ValueError(
                        f"Received quantity for '{item.stock_item}' ({received}) cannot exceed "
                        f"the transferred quantity ({item.quantity})."
                    )
                if received + rejected > item.quantity:
                    raise ValueError(
                        f"For '{item.stock_item}', received ({received}) + expired/rejected ({rejected}) "
                        f"cannot exceed the transferred quantity ({item.quantity})."
                    )
                if received < item.quantity:
                    has_shortfall = True

                item.received_quantity = received
                item.rejected_quantity = rejected
                item.save(update_fields=["received_quantity", "rejected_quantity"])

                product = item.product or Product.objects.filter(name=item.stock_item).first()

                # Good units → receiver's inventory (the GRN of good products).
                if received > 0:
                    if product is None:
                        raise ValueError(
                            f"Could not match product '{item.stock_item}' to your catalog."
                        )
                    inventory, _ = Inventory.objects.select_for_update().get_or_create(
                        mcc_bmc_user=request.user, product=product, defaults={"quantity": 0}
                    )
                    inventory.add_quantity(
                        received,
                        action="TRANSFER_IN",
                        reference_number=stn.stn_number,
                        notes=f"Received from {stn.from_location} (STN {stn.stn_number})",
                        user=request.user,
                    )

                # Expired/rejected units → returned (redispatched) to the sender's
                # inventory so they can be sent out again.
                if rejected > 0:
                    if stn.created_by is None:
                        raise ValueError(
                            f"Cannot return the expired/rejected units of '{item.stock_item}' — the "
                            f"original sender of this STN no longer exists. Record them as a shortfall instead."
                        )
                    if product is None:
                        raise ValueError(
                            f"Could not match product '{item.stock_item}' to your catalog."
                        )
                    sender_inv, _ = Inventory.objects.select_for_update().get_or_create(
                        mcc_bmc_user=stn.created_by, product=product, defaults={"quantity": 0}
                    )
                    sender_inv.add_quantity(
                        rejected,
                        action="RETURN",
                        reference_number=stn.stn_number,
                        notes=f"Expired/rejected on receipt at {stn.to_location} — returned (STN {stn.stn_number})",
                        user=request.user,
                    )

            # Proof of receipt is required when anything is received short.
            if has_shortfall and not proof_file and not stn.proof:
                raise ValueError(
                    "Proof of receipt is required because the received quantity is less "
                    "than the transferred quantity for one or more items."
                )

            # Assign a sequential GRN-against-STN number
            last = (
                StockTransferNote.objects.filter(grn_number__startswith="GRNSTN-")
                .order_by("-id")
                .first()
            )
            last_num = int(last.grn_number.split("-")[-1]) if last and last.grn_number else 0
            stn.grn_number = f"GRNSTN-{last_num + 1:06d}"

            if receipt_file:
                stn.receipt = receipt_file
            if proof_file:
                stn.proof = proof_file

            stn.is_received = True
            stn.received_by = request.user
            stn.received_at = timezone.now()
            stn.save(update_fields=["grn_number", "receipt", "proof", "is_received", "received_by", "received_at"])
    except (ValueError, ValidationError) as exc:
        return _fail(f"Could not receive {stn.stn_number}: {exc}")

    # GRN done — stream the GRN-against-STN PDF straight back as a download.
    pdf_buffer = _render_stn_grn_pdf(stn, request)
    response = HttpResponse(pdf_buffer.read(), content_type="application/pdf")
    filename = f"{stn.grn_number or stn.stn_number}-GRN.pdf"
    response["Content-Disposition"] = f'attachment; filename="{filename}"'
    return response


@login_required(login_url="login")
def stn_grn_detail(request, stn_number):
    """
    View a created GRN-against-STN: every product with its received (good)
    quantity, the expired/rejected quantity returned to the sender, and any
    remaining shortfall.
    """

    stn = get_object_or_404(StockTransferNote, stn_number=stn_number)
    items = list(stn.items.all())
    return render(request, "stn_grn_detail.html", {
        "stn": stn,
        "items": items,
        "total_items": len(items),
    })


# =========== Requisition Export to Excel ==============

@login_required(login_url="login")
@restrict_hod_access
def exportAExcelSheet(request):
    """
    Export User's Requisitions to Excel Report
    
    Generates an Excel spreadsheet containing all requisitions created by the
    current user. Includes related HOD approvals, purchase department data,
    and GRN information in a comprehensive report format.
    
    Args:
        request: HTTP request object
    
    Returns:
        HttpResponse: Excel file download response
    
    Report Includes:
        - Basic requisition details
        - HOD approval information
        - Purchase department data
        - GRN completion status
        - Simplified PO numbers (removes additional metadata)
    
    Security:
        - @login_required ensures authentication
        - @restrict_hod_access limits access by role
        - Only exports requisitions created by current user
    """
    
    # ------------------------------------------------------------
    # SECTION 1: INITIALIZE EXCEL WORKBOOK
    # ------------------------------------------------------------
    
    # Create new Excel workbook and worksheet
    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Requisitions"
    
    # Define report headers (without "Time of Request")
    headers = [
        "Indent Raised By",
        "Requisition Number",
        "Date of Request",
        "Employee Name",
        "Department",
        "Employee Code",
        "Location",
        "UOM",
        "Stock Item",
        "Quantity",
        "Remark",
        "Status",
        "Approved By",
        "Approval Date",
        "PO Number",
        "PO Generated By",
        "PO Generation Date",
        "Party Name",
        "GRN Number",
        "GRN Date",
        "GRN Done By",
    ]
    
    # Add headers to first row
    ws.append(headers)
    
    # ------------------------------------------------------------
    # SECTION 2: RETRIEVE USER'S REQUISITIONS
    # ------------------------------------------------------------
    
    # Fetch all requisitions created by the current user
    requisitions = PurchaseRequisition.objects.filter(created_by=request.user)
    
    # ------------------------------------------------------------
    # SECTION 3: POPULATE EXCEL WITH REQUISITION DATA
    # ------------------------------------------------------------
    
    for requisition in requisitions:
        
        # Retrieve related records for this requisition
        hod_approval = HODApproval.objects.filter(requisition=requisition).first()
        purchase_dept = PurchaseDepartment.objects.filter(requisition=requisition).first()
        grn_entry = DoGRN.objects.filter(
            requisition_number=requisition.requisition_number
        ).first()
        
        # --------------------------------------------------------
        # SUBSECTION: Process PO Number
        # --------------------------------------------------------
        po_number = "N/A"
        if purchase_dept and purchase_dept.po_number:
            # Extract only the base PO number (before colon)
            po_number = purchase_dept.po_number.split(':')[0]
        
        # --------------------------------------------------------
        # SUBSECTION: Add Requisition Row to Excel
        # --------------------------------------------------------
        ws.append([
            # User Information
            f"{request.user.first_name} {request.user.last_name}",
            
            # Requisition Details
            requisition.requisition_number,
            requisition.date_of_request.strftime("%d-%m-%Y"),  # Date only
            requisition.employee_name,
            requisition.department,
            requisition.employee_code,
            requisition.location,
            requisition.uom,
            requisition.stock_item,
            requisition.quantity,
            requisition.remark or "",
            requisition.status,
            
            # HOD Approval Information
            hod_approval.approved_by.get_full_name() if hod_approval and hod_approval.approved_by else "",
            hod_approval.approval_date.strftime("%d-%m-%Y") if hod_approval and hod_approval.approval_date else "",
            
            # Purchase Department Information
            po_number,  # Simplified PO number
            purchase_dept.po_generated_by.get_full_name() if purchase_dept and purchase_dept.po_generated_by else "",
            purchase_dept.po_generation_date.strftime("%d-%m-%Y") if purchase_dept and purchase_dept.po_generation_date else "",
            purchase_dept.party_name if purchase_dept else "",
            
            # GRN Information
            grn_entry.grn_number if grn_entry else "N/A",
            grn_entry.date_of_receipt.strftime("%d-%m-%Y") if grn_entry else "N/A",
            grn_entry.employee_name if grn_entry else "N/A",
        ])
    
    # ------------------------------------------------------------
    # SECTION 4: FORMAT EXCEL COLUMNS
    # ------------------------------------------------------------
    
    # Set uniform column width for better readability
    for col_num, header in enumerate(headers, start=1):
        ws.column_dimensions[get_column_letter(col_num)].width = 20
    
    # ------------------------------------------------------------
    # SECTION 5: PREPARE DOWNLOAD RESPONSE
    # ------------------------------------------------------------
    
    # Create HTTP response with Excel MIME type
    response = HttpResponse(
        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )
    
    # Set filename with user's name for personalization
    response["Content-Disposition"] = (
        f'attachment; filename="{request.user.get_full_name()}_indent_details.xlsx"'
    )
    
    # Save workbook to response
    wb.save(response)
    
    return response


# =========== HOD Requisition Export to Excel ==============

@login_required(login_url='login')
def export_as_excel_hod(request):
    """
    Export HOD's Department Requisitions to Excel Report
    
    Generates an Excel spreadsheet containing all requisitions for products
    managed by the current HOD. Includes approval status, PO information,
    and proper timezone handling for Indian Standard Time (IST).
    
    Args:
        request: HTTP request object
    
    Returns:
        HttpResponse: Excel file download response
        HttpResponse: 403 error page if user is not HOD
    
    Report Filters:
        - Only requisitions for products assigned to current HOD
        - Status: APPROVED, REJECTED, or PO GENERATED
        - Sorted by most recent request date
    
    Timezone Handling:
        - Converts all dates to Indian Standard Time (IST)
        - Handles both naive and aware datetime objects
    
    Security:
        - Validates user has HOD role before processing
        - Only exports data for products under HOD's supervision
    """
    
    # ------------------------------------------------------------
    # SECTION 1: AUTHORIZATION CHECK
    # ------------------------------------------------------------
    
    # Verify user has HOD role permissions
    if not request.user.is_hod:
        return render(request, "403.html", status=403)
    
    # ------------------------------------------------------------
    # SECTION 2: FETCH HOD'S ASSIGNED PRODUCTS
    # ------------------------------------------------------------
    
    # Get list of stock items managed by this HOD
    hod_stock_items = Product.objects.filter(hod=request.user).values_list(
        "name", flat=True
    )
    
    # ------------------------------------------------------------
    # SECTION 3: RETRIEVE FILTERED REQUISITIONS
    # ------------------------------------------------------------
    
    # Fetch requisitions with status filter and related data
    requisitions = (
        PurchaseRequisition.objects.filter(
            stock_item__in=hod_stock_items,
            status__in=["APPROVED", "REJECTED", "PO GENERATED"],
        )
        .prefetch_related("purchasedepartment_set", "hodapproval_set")
        .order_by("-date_of_request", "-time_of_request")
    )
    
    # ------------------------------------------------------------
    # SECTION 4: INITIALIZE EXCEL WORKBOOK
    # ------------------------------------------------------------
    
    # Create new Excel workbook and worksheet
    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Requisitions"
    
    # Define report headers (simplified without time columns)
    headers = [
        "Requisition Number",
        "Date of Request",
        "Requested By",
        "Department",
        "Location",
        "Stock Item",
        "Quantity",
        "Expected Delivery Date",
        "Remark",
        "Status",
        "Approval Status",
        "Approval/Rejected Date",
        "PO Number",
        "PO Generation Date",
    ]
    
    # Add headers to first row
    ws.append(headers)
    
    # ------------------------------------------------------------
    # SECTION 5: TIMEZONE SETUP
    # ------------------------------------------------------------
    
    # Define Indian Standard Time zone for date conversions
    IST = pytz.timezone("Asia/Kolkata")
    
    # ------------------------------------------------------------
    # SECTION 6: POPULATE EXCEL WITH REQUISITION DATA
    # ------------------------------------------------------------
    
    for requisition in requisitions:
        
        # --------------------------------------------------------
        # SUBSECTION: Process Approval Data
        # --------------------------------------------------------
        approval = requisition.hodapproval_set.first()
        approval_status = approval.status if approval else "PENDING"
        
        # Process approval date with timezone conversion
        approval_date = "N/A"
        if approval and approval.approval_date:
            # Handle naive datetime objects
            if approval.approval_date.tzinfo is None:
                approval_date_aware = make_aware(approval.approval_date, timezone=IST)
            else:
                approval_date_aware = approval.approval_date
            
            # Convert to IST and format
            approval_date = approval_date_aware.astimezone(IST).strftime("%d-%m-%Y")
        
        # --------------------------------------------------------
        # SUBSECTION: Process Purchase Department Data
        # --------------------------------------------------------
        po_number = "N/A"
        po_generation_date = "N/A"
        
        purchase_department = requisition.purchasedepartment_set.first()
        if purchase_department:
            # Extract base PO number (before colon)
            if purchase_department.po_number:
                po_number = purchase_department.po_number.split(':')[0]
            
            # Process PO generation date with timezone
            if purchase_department.po_generation_date:
                if purchase_department.po_generation_date.tzinfo is None:
                    po_date_aware = make_aware(
                        purchase_department.po_generation_date, 
                        timezone=IST
                    )
                else:
                    po_date_aware = purchase_department.po_generation_date
                
                # Convert to IST and format
                po_generation_date = po_date_aware.astimezone(IST).strftime("%d-%m-%Y")
        
        # --------------------------------------------------------
        # SUBSECTION: Add Requisition Row to Excel
        # --------------------------------------------------------
        row = [
            # Requisition Details
            requisition.requisition_number,
            requisition.date_of_request.strftime("%d-%m-%Y"),
            requisition.employee_name,
            requisition.department,
            requisition.location,
            requisition.stock_item,
            requisition.quantity,
            
            # Delivery Information
            requisition.expected_delivery_date.strftime("%d-%m-%Y") 
            if requisition.expected_delivery_date else "N/A",
            
            # Remarks and Status
            requisition.remark or "",
            requisition.status,
            approval_status,
            
            # Approval Information
            approval_date,
            
            # Purchase Order Information
            po_number,
            po_generation_date,
        ]
        
        ws.append(row)
    
    # ------------------------------------------------------------
    # SECTION 7: FORMAT EXCEL COLUMNS
    # ------------------------------------------------------------
    
    # Set uniform column width for better readability
    for col_num, header in enumerate(headers, start=1):
        ws.column_dimensions[get_column_letter(col_num)].width = 18
    
    # ------------------------------------------------------------
    # SECTION 8: PREPARE DOWNLOAD RESPONSE
    # ------------------------------------------------------------
    
    # Create HTTP response with Excel MIME type
    filename = f"{request.user.first_name}_{request.user.last_name}_approval_report.xlsx"
    response = HttpResponse(
        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )
    response["Content-Disposition"] = f'attachment; filename="{filename}"'
    
    # Save workbook to response
    wb.save(response)
    
    return response



