# =========== Vendor Product Catalog Endpoint ==============
@login_required(login_url="login")
@restrict_hod_access
def get_vendor_products(request, vendor_id):
    """
    Retrieve Product Catalog for Specific Vendor
    
    Fetches all products associated with a given vendor, including
    product names and sizes for use in dropdowns and forms.
    
    Args:
        request: HTTP request object with user authentication
        vendor_id (int): Primary key identifier for the vendor
    
    Returns:
        JsonResponse: JSON array of product objects
    
    Product Object Structure:
        [
            {
                "name": str,        // Product name
                "size": str         // Product size/unit information
            },
            ...
        ]
    
    Security:
        - @login_required ensures user authentication
        - @restrict_hod_access enforces role-based permissions
        - Vendor ID validated through database query
    
    Usage:
        Typically called via AJAX to populate product dropdowns
        when a vendor is selected in purchase-related forms.
    """
    
    # ------------------------------------------------------------
    # SECTION 1: FETCH VENDOR PRODUCT MAPPINGS
    # ------------------------------------------------------------
    
    # Query ProductVendor relationships for the specified vendor
    products = ProductVendor.objects.filter(vendor_id=vendor_id)
    
    # ------------------------------------------------------------
    # SECTION 2: EXTRACT PRODUCT DATA
    # ------------------------------------------------------------
    
    # Transform to simplified product information format
    product_data = [
        {
            "name": product.product.name,
            "size": product.product.size
        }
        for product in products
    ]
    
    # ------------------------------------------------------------
    # SECTION 3: RETURN JSON RESPONSE
    # ------------------------------------------------------------
    
    # Return JSON array (safe=False allows non-dict serialization)
    return JsonResponse(product_data, safe=False)


