# =========== User Authentication and Login View ==============

@csrf_exempt
def loginView(request):
    """
    User Authentication Endpoint with Single-Session Enforcement
    
    Handles user login via AJAX with email/password authentication.
    Enforces single-session policy by terminating existing sessions
    and implements 1-hour session timeout for security.
    
    Args:
        request: HTTP request object
    
    Returns:
        JsonResponse: AJAX response with success/error and redirect URL
        HttpResponse: Redirect for authenticated users or form render
    
    Security Features:
        - CSRF exemption for AJAX compatibility
        - Single-session enforcement (prevents multiple logins)
        - 1-hour session expiration
        - User account active status validation
        - AJAX-only POST processing
    
    Redirect Logic:
        - Superusers: /admin_dashboard/
        - Finance role: /finance_dashboard/
        - Logistic role: /logistic_dashboard/
        - Default: /viewInventory/
    
    AJAX Response Structure:
        Success: {"success": True, "redirect_url": "/dashboard/"}
        Error: {"success": False, "error": "Error message"}
    """
    
    # ------------------------------------------------------------
    # SECTION 1: SESSION CONFIGURATION
    # ------------------------------------------------------------
    
    # Set session timeout to 1 hour (3600 seconds) for security
    request.session.set_expiry(3600)
    
    # ------------------------------------------------------------
    # SECTION 2: CHECK EXISTING AUTHENTICATION
    # ------------------------------------------------------------
    
    # If user is already authenticated, redirect based on role
    if request.user.is_authenticated:
        # AJAX request handling for authenticated users
        if request.headers.get("X-Requested-With") == "XMLHttpRequest":
            return JsonResponse(
                {
                    "success": True, 
                    "redirect_url": get_redirect_url(request.user)
                }
            )
        # Standard request handling for authenticated users
        return redirect(get_redirect_url(request.user))
    
    # ------------------------------------------------------------
    # SECTION 3: HANDLE AJAX LOGIN REQUESTS (POST)
    # ------------------------------------------------------------
    
    if request.method == "POST":
        # Validate AJAX request header
        if request.headers.get("X-Requested-With") == "XMLHttpRequest":
            
            # ----------------------------------------------------
            # SUBSECTION: Extract Credentials
            # ----------------------------------------------------
            email = request.POST.get("email")
            password = request.POST.get("password")
            
            # ----------------------------------------------------
            # SUBSECTION: Validate User Existence
            # ----------------------------------------------------
            try:
                user_obj = CustomUser.objects.get(email=email)
            except ObjectDoesNotExist:
                # Generic error message for security (don't reveal user existence)
                return JsonResponse(
                    {
                        "success": False, 
                        "error": "Invalid email or password."
                    }
                )
            
            # ----------------------------------------------------
            # SUBSECTION: Enforce Single-Session Policy
            # ----------------------------------------------------
            active_sessions = Session.objects.filter(expire_date__gte=now())
            for session in active_sessions:
                data = session.get_decoded()
                if data.get("_auth_user_id") == str(user_obj.id):
                    # Terminate existing session
                    session.delete()
                    return JsonResponse(
                        {
                            "success": False,
                            "error": "You were logged out from another device. Please try logging in again.",
                        }
                    )
            
            # ----------------------------------------------------
            # SUBSECTION: Authenticate User Credentials
            # ----------------------------------------------------
            user = authenticate(request, email=email, password=password)
            
            if user:
                # Validate user account status
                if not user.is_active:
                    return JsonResponse(
                        {
                            "success": False, 
                            "error": "Your account is inactive."
                        }
                    )
                
                # Perform login and establish session
                login(request, user)
                
                return JsonResponse(
                    {
                        "success": True, 
                        "redirect_url": get_redirect_url(user)
                    }
                )
            else:
                # Authentication failed - invalid credentials
                return JsonResponse(
                    {
                        "success": False, 
                        "error": "Invalid email or password."
                    }
                )
        
        # Non-AJAX POST requests redirected to login page
        return redirect("login")
    
    # ------------------------------------------------------------
    # SECTION 4: HANDLE INITIAL PAGE LOAD (GET)
    # ------------------------------------------------------------
    
    # Render login form template
    return render(request, "login.html")



# =========== User Role-Based Redirect Utility ==============

def get_redirect_url(user):
    """
    Determine Dashboard Redirect URL Based on User Role
    
    Maps user roles to appropriate dashboard URLs following the principle
    of least privilege. Each role type receives access to relevant
    functionality areas.
    
    Args:
        user (CustomUser): Authenticated user object with role flags
    
    Returns:
        str: URL pattern name for redirection
    
    Role Hierarchy:
        1. Superuser: Full administrative access
        2. HOD: Department approval dashboard
        3. Purchase: Purchase requisition management
        4. Finance: Financial dashboard and reports
        5. Logistic: Logistics and dispatch management
        6. Default: Indent creation interface
    
    Error Handling:
        Returns 'login' URL if reverse match fails (URL configuration issue)
    
    Note:
        Order of checks matters - superuser check should be first
        to prevent privilege escalation through multiple role flags
    """
    
    try:
        # ------------------------------------------------------------
        # ROLE 1: SUPERUSER / ADMINISTRATOR
        # ------------------------------------------------------------
        if user.is_superuser:
            return "admin_dashboard"
        
        # ------------------------------------------------------------
        # ROLE 2: HEAD OF DEPARTMENT (HOD)
        # ------------------------------------------------------------
        if user.is_hod:
            return "hod_requisitions"
        
        # ------------------------------------------------------------
        # ROLE 3: PURCHASE DEPARTMENT
        # ------------------------------------------------------------
        if user.is_purchase:
            return "view_purchase_requisitions"
        
        # ------------------------------------------------------------
        # ROLE 4: FINANCE DEPARTMENT
        # ------------------------------------------------------------
        if user.is_finance:
            return "finance_dashboard"
        
        # ------------------------------------------------------------
        # ROLE 5: LOGISTICS DEPARTMENT
        # ------------------------------------------------------------
        if user.is_logistic:
            return "logistic_dashboard"
        
        # ------------------------------------------------------------
        # DEFAULT: REGULAR USER (INDENT CREATION)
        # ------------------------------------------------------------
        return "create-an-indent"
        
    except NoReverseMatch:
        # ------------------------------------------------------------
        # ERROR HANDLING: URL CONFIGURATION ISSUE
        # ------------------------------------------------------------
        # Fallback to login if URL pattern doesn't exist
        # This prevents crashes due to misconfigured URLs
        return "login"

# =========== Finance Dashboard View ==============

@login_required(login_url="login")
@restrict_user_access
def finance_dashboard(request):
    """
    Finance Department Dashboard Controller
    
    Renders the main finance dashboard with location filtering and
    date selection capabilities. Provides dropdowns for filtering
    financial data by location, month, and year.
    
    Args:
        request: HTTP request object with user authentication
    
    Returns:
        HttpResponse: Rendered finance dashboard template with context
    
    Context Variables:
        - locations: Distinct location list for filtering
        - months: Full month names for selection
        - years: Current and next two years for planning
        - current_month: Default month for filters
        - current_year: Default year for filters
    
    Features:
        - Location-based data filtering
        - Month and year selection for period reports
        - Defaults to current month/year for immediate relevance
    
    Security:
        - @login_required ensures authentication
        - @restrict_user_access limits to finance role
    """
    
    # ------------------------------------------------------------
    # SECTION 1: GATHER LOCATION DATA
    # ------------------------------------------------------------
    
    # Extract distinct locations from user profiles for filtering
    locations = CustomUser.objects.values_list("location", flat=True).distinct()
    
    # ------------------------------------------------------------
    # SECTION 2: PREPARE DATE FILTER OPTIONS
    # ------------------------------------------------------------
    
    # Get current date for default values
    current_date = timezone.now().date()
    current_month = current_date.strftime('%B')  # Full month name (e.g., "December")
    current_year = current_date.year
    
    # Generate list of all months for dropdown
    months = list(calendar.month_name)[1:]  # Remove empty first element
    
    # Generate years list (current year + next two years for planning)
    years = [current_year, current_year + 1, current_year + 2]
    
    # ------------------------------------------------------------
    # SECTION 3: RENDER DASHBOARD TEMPLATE
    # ------------------------------------------------------------
    
    return render(
        request,
        "finance_dashboard.html",
        {
            "locations": locations,
            "months": months,
            "years": years,
            "current_month": current_month,
            "current_year": current_year,
        },
    )

# =========== Logistics Dashboard and Dispatch Management ==============

@login_required(login_url="login")
@restrict_user_access
def logistic_dashboard(request):
    """
    Logistics Department Dashboard and Dispatch Manager
    
    Handles stock transfer management with STN generation, email notifications,
    and dispatch tracking. Provides interface for selecting items, entering
    transporter details, and sending dispatch notifications.
    
    Args:
        request: HTTP request object with user authentication
    
    Returns:
        JsonResponse: Success/error response for AJAX operations
        HttpResponse: Rendered dashboard for GET requests
    
    Key Processes:
        - STN (Stock Transfer Note) generation with sequential numbering
        - PDF report generation with transporter details
        - Multi-recipient email notifications with attachments
        - E-way bill merging with STN documents
        - Dispatch notification tracking
    
    Security:
        - @login_required ensures authentication
        - @restrict_user_access limits to logistics role
    """

    # ------------------------------------------------------------
    # SECTION 0: RETIRED — REDIRECT TO THE NEW STN FLOW
    # ------------------------------------------------------------
    # Stock transfers are now created directly by location users as Stock
    # Transfer Notes (create_stn deducts inventory on dispatch; destinations
    # accept them via Incoming STNs). The old logistics dispatch dashboard is
    # retired: this redirect stops new LogisticDepartment/DispatchNotification
    # records from being created. Soft retire only — the code, models, data,
    # and the GRN-against-STN receive remain intact; delete this block to
    # restore the old dashboard.
    messages.info(
        request,
        "The logistics dispatch dashboard has been retired. Stock transfers are "
        "now created directly as Stock Transfer Notes.",
    )
    return redirect("create_stn")

    # ------------------------------------------------------------
    # SECTION 1: HANDLE DISPATCH FORM SUBMISSION (POST)
    # ------------------------------------------------------------
    if request.method == "POST":
        
        # --------------------------------------------------------
        # SUBSECTION: Extract Form Data
        # --------------------------------------------------------
        selected_items = request.POST.getlist("selected_items[]")
        email_recipients = request.POST.get("email", "").split(",")
        email_recipients = [
            email.strip() for email in email_recipients if email.strip()
        ]
        
        # Extract transporter details
        transporter_name = request.POST.get("transporter_name")
        vehicle_number = request.POST.get("vehicle_number")
        driver_name = request.POST.get("driver_name")
        driver_contact = request.POST.get("driver_contact")
        
        # Extract e-way bill file
        eway_bill_file = request.FILES.get("eway_bill")
        
        # --------------------------------------------------------
        # SUBSECTION: Validate Required Data
        # --------------------------------------------------------
        if not selected_items or not email_recipients:
            return JsonResponse(
                {
                    "success": False,
                    "message": "No items selected or no email recipients provided.",
                }
            )
        
        # --------------------------------------------------------
        # SUBSECTION: Fetch Selected Items for Processing
        # --------------------------------------------------------
        queryset = LogisticDepartment.objects.filter(
            id__in=selected_items, mail_sent=False
        )
        items_list = list(queryset)
        
        if not items_list:
            return JsonResponse(
                {
                    "success": False,
                    "message": "Selected items have already been processed.",
                }
            )
        
        # --------------------------------------------------------
        # SUBSECTION: Extract Location Information
        # --------------------------------------------------------
        from_location = items_list[0].from_location
        to_location = items_list[0].to_location
        
        # Fetch complete addresses for locations
        from_user = CustomUser.objects.filter(location=from_location).first()
        to_user = CustomUser.objects.filter(location=to_location).first()
        from_address = from_user.address if from_user else "Address not found"
        to_address = to_user.address if to_user else "Address not found"
        
        # --------------------------------------------------------
        # SUBSECTION: Generate Sequential STN Number
        # --------------------------------------------------------
        last_stn = (
            LogisticDepartment.objects.filter(stn_number__isnull=False)
            .order_by("-stn_number")
            .first()
        )
        
        if last_stn and last_stn.stn_number:
            last_stn_number = int(last_stn.stn_number.split("-")[-1])
            next_stn_number = last_stn_number + 1
        else:
            next_stn_number = 1
        
        stn_number = f"STN-{next_stn_number:06d}"
        
        # --------------------------------------------------------
        # SUBSECTION: Organize Items by Email Recipient
        # --------------------------------------------------------
        items_by_email = defaultdict(list)
        for item in items_list:
            for email in email_recipients:
                items_by_email[email].append(item)
        
        # --------------------------------------------------------
        # SUBSECTION: Process Each Recipient's Email
        # --------------------------------------------------------
        email_sent_successfully = True
        
        for email, items in items_by_email.items():
            
            # ----------------------------------------------------
            # Build HTML Table for Email Content
            # ----------------------------------------------------
            item_table = """
            <table border="1" cellpadding="5" cellspacing="0" style="border-collapse: collapse; width: 100%;">
                <thead>
                    <tr>
                        <th>S.No</th>
                        <th>Stock Item</th>
                        <th>Quantity</th>
                    </tr>
                </thead>
                <tbody>
            """
            
            for index, item in enumerate(items, start=1):
                item_table += f"""
                    <tr>
                        <td>{index}</td>
                        <td>{item.stock_item}</td>
                        <td>{item.quantity}</td>
                    </tr>
                """
            
            item_table += "</tbody></table>"
            
            # ----------------------------------------------------
            # Fetch Signatures and Stamps for PDF
            # ----------------------------------------------------
            user = CustomUser.objects.filter(email=email).first()
            prepared_by_signature = checked_by_signature = approved_by_stamp = None
            
            if user:
                if user.signature:
                    prepared_by_signature = request.build_absolute_uri(
                        user.signature.url
                    )
                    checked_by_signature = prepared_by_signature
                if user.mohar:
                    approved_by_stamp = request.build_absolute_uri(user.mohar.url)
            
            # ----------------------------------------------------
            # Generate Stock Transfer Note PDF
            # ----------------------------------------------------
            pdf_buffer = BytesIO()
            
            context = {
                "items": items,
                "from_location": from_location,
                "from_address": from_address,
                "to_location": to_location,
                "to_address": to_address,
                "company_name": "Shwetdhara Milk Producer Company Limited",
                "logo_url": request.build_absolute_uri(
                    static("images/shwetdharalogo.png")
                ),
                "today_date": datetime.now().strftime("%d-%m-%Y"),
                "stn_number": stn_number,
                "prepared_by_signature": prepared_by_signature,
                "checked_by_signature": checked_by_signature,
                "approved_by_stamp": approved_by_stamp,
                "transporter_name": transporter_name,
                "vehicle_number": vehicle_number,
                "driver_name": driver_name,
                "driver_contact": driver_contact,
            }
            
            # Render HTML template to PDF
            html_string = render_to_string("s.t.n_report.html", context)
            HTML(string=html_string).write_pdf(pdf_buffer)
            pdf_buffer.seek(0)
            
            # ----------------------------------------------------
            # Merge STN PDF with E-way Bill (if provided)
            # ----------------------------------------------------
            merged_pdf_buffer = BytesIO()
            merger = PdfMerger()
            merger.append(pdf_buffer)
            
            if eway_bill_file:
                try:
                    eway_bill_buffer = BytesIO(eway_bill_file.read())
                    eway_bill_file.seek(0)
                    
                    # Validate PDF format
                    try:
                        PdfReader(eway_bill_buffer)
                        eway_bill_buffer.seek(0)
                        merger.append(eway_bill_buffer)
                    except Exception:
                        # Convert image to PDF if not already PDF
                        eway_bill_path = f"/tmp/{eway_bill_file.name}"
                        with open(eway_bill_path, "wb") as temp_file:
                            temp_file.write(eway_bill_file.read())
                        pdf_path = convert_image_to_pdf(eway_bill_path)
                        if pdf_path:
                            merger.append(pdf_path)
                            
                except Exception:
                    return JsonResponse(
                        {
                            "success": False,
                            "message": "Failed to process Eway Bill file.",
                        }
                    )
            
            merger.write(merged_pdf_buffer)
            merger.close()
            merged_pdf_buffer.seek(0)
            
            # ----------------------------------------------------
            # Send Email with Attachments
            # ----------------------------------------------------
            subject = f"Material Dispatch Notification - {stn_number}"
            message = f"""
            <html>
               <body>
                   <p>Dear {from_location} Store,</p>
                   <p>You are requested to dispatch the following items to <strong>{to_location}</strong>.</p>
                   <p>Please find the attached PDF and see below table:</p>
                   {item_table}
                   <p>Thanks and Regards,</p>
                   <p><strong>Logistic Department</strong></p>
               </body>
            </html>
            """
            
            from_email = settings.DEFAULT_FROM_EMAIL
            cc_emails = [""]
            
            email_message = EmailMessage(
                subject, message, from_email, [email], cc=cc_emails
            )
            email_message.content_subtype = "html"
            email_message.attach(
                "Stock_Transfer_Note_and_Eway_Bill.pdf",
                merged_pdf_buffer.getvalue(),
                "application/pdf",
            )
            
            try:
                email_message.send()
            except Exception:
                email_sent_successfully = False
                break
        
        # --------------------------------------------------------
        # SUBSECTION: Process Successful Email Dispatch
        # --------------------------------------------------------
        if email_sent_successfully:
            
            # Update items with STN number and mail status
            for item in items_list:
                item.stn_number = stn_number
                item.mail_sent = True
                item.save()
            
            # Attach requisition references to logistics items
            for item in items_list:
                requisition = (
                    PurchaseRequisition.objects.filter(
                        stock_item=item.stock_item,
                        location=item.to_location,
                        status="APPROVED FOR TRANSFER",
                    )
                    .order_by("-id")
                    .first()
                )
                
                if requisition:
                    item.requisition = requisition
                    item.save()
            
            # Create dispatch notifications for tracking
            for item in items_list:
                for email in email_recipients:
                    to_user = CustomUser.objects.filter(email=email).first()
                    if from_user and to_user:
                        notification = DispatchNotification(
                            logistic_department=item,
                            from_user=from_user,
                            to_user=to_user,
                            is_dispatched=False,
                        )
                        notification.save()
            
            return JsonResponse(
                {
                    "success": True, 
                    "message": "Mail sent successfully!"
                }
            )
        
        else:
            return JsonResponse(
                {
                    "success": False,
                    "message": "Failed to send email to one or more recipients.",
                }
            )
    
    # ------------------------------------------------------------
    # SECTION 2: HANDLE DASHBOARD DISPLAY (GET REQUEST)
    # ------------------------------------------------------------
    
    # Fetch pending logistics items (not yet dispatched)
    logistics_data = LogisticDepartment.objects.filter(mail_sent=False)
    
    # Group items by source and destination locations
    grouped_data = defaultdict(list)
    for item in logistics_data:
        key = (item.from_location, item.to_location)
        grouped_data[key].append(item)
    
    # Build notification email list for each location
    notification_emails = {
        key[0]: [
            {
                "email": user.email,
                "name": user.get_full_name(),
            }
            for user in CustomUser.objects.filter(
                department__in=["IT & MIS", "AYODHYA H.O STORE"], 
                location=key[0]
            )
        ]
        for key in grouped_data.keys()
    }
    
    # ------------------------------------------------------------
    # SECTION 3: RENDER LOGISTICS DASHBOARD
    # ------------------------------------------------------------
    
    return render(
        request,
        "logistic_dashboard.html",
        {
            "grouped_data": dict(grouped_data),
            "notification_emails": notification_emails,
        },
    )

# =========== STN Data Retrieval Endpoint ==============

@login_required(login_url="login")
def get_stn_data(request):
    """
    Retrieve Stock Transfer Note (STN) Data for GRN Processing
    
    Fetches detailed information for a specific STN number to support
    Goods Received Note (GRN) creation. Returns user context along with
    itemized transfer details.
    
    Args:
        request: HTTP request object with user authentication
        stn_number (query param): STN identifier from URL parameters
    
    Returns:
        JsonResponse: Structured data containing STN details and user context
    
    Response Structure:
        {
            "employee_name": str,
            "employee_code": str,
            "employee_location": str,
            "department": str,
            "stn_number": str,
            "items": [
                {
                    "stock_item": str,
                    "quantity_ordered": int/float
                },
                ...
            ]
        }
    
    Usage:
        Called during GRN creation to pre-populate form fields with
        STN information, reducing manual data entry.
    
    Security:
        - @login_required ensures user authentication
        - Returns data only for authenticated users
    """
    
    # ------------------------------------------------------------
    # SECTION 1: EXTRACT STN NUMBER FROM REQUEST
    # ------------------------------------------------------------
    
    # Retrieve STN number from query parameters
    stn_number = request.GET.get("stn_number")
    
    # ------------------------------------------------------------
    # SECTION 2: FETCH STN-RELATED DATA
    # ------------------------------------------------------------
    
    # Query database for all items associated with this STN
    stn_data = LogisticDepartment.objects.filter(stn_number=stn_number)
    
    # ------------------------------------------------------------
    # SECTION 3: BUILD RESPONSE DATA STRUCTURE
    # ------------------------------------------------------------
    
    data = {
        # User Context Information
        "employee_name": f"{request.user.first_name} {request.user.last_name}",
        "employee_code": request.user.employee_code,
        "employee_location": request.user.location,
        "department": request.user.department,
        
        # STN Identification
        "stn_number": stn_number,
        
        # Itemized Transfer Details
        "items": [
            {
                "stock_item": stn.stock_item,
                "quantity_ordered": stn.quantity,
            }
            for stn in stn_data
        ],
    }
    
    # ------------------------------------------------------------
    # SECTION 4: RETURN JSON RESPONSE
    # ------------------------------------------------------------
    
    return JsonResponse(data)





# =========== Dispatch Notifications Management ==============

@login_required(login_url='login')
def dispatch_notification_list(request):
    """
    Display Pending Dispatch Notifications Grouped by Location
    
    Renders a consolidated view of all pending stock transfer notifications
    for the current user. Groups notifications by source/destination
    locations for organized display.
    
    Args:
        request: HTTP request object with user authentication
    
    Returns:
        HttpResponse: Rendered template with grouped notification data
    
    Data Structure:
        grouped_notifications: {
            (from_location, to_location): [notification_objects]
        }
        notification_emails: {
            to_location: [{"email": str, "name": str}]
        }
    
    Purpose:
        - Provides overview of incoming stock transfers
        - Groups related items for batch processing
        - Supplies contact information for coordination
    """
    
    # ------------------------------------------------------------
    # SECTION 1: FETCH USER'S PENDING NOTIFICATIONS
    # ------------------------------------------------------------
    
    # Retrieve all pending notifications for the current user
    notifications = DispatchNotification.objects.filter(
        to_user=request.user, is_dispatched=False
    )
    
    # ------------------------------------------------------------
    # SECTION 2: GROUP NOTIFICATIONS BY LOCATION PAIR
    # ------------------------------------------------------------
    
    grouped_notifications = defaultdict(list)
    for notification in notifications:
        # Create grouping key based on transfer route
        key = (
            notification.logistic_department.from_location,
            notification.logistic_department.to_location,
        )
        grouped_notifications[key].append(notification)
    
    # ------------------------------------------------------------
    # SECTION 3: GATHER CONTACT INFORMATION FOR DESTINATIONS
    # ------------------------------------------------------------
    
    # Build email contact list for each destination location
    notification_emails = {
        key[1]: [
            {
                "email": user.email,
                "name": user.get_full_name(),
            }
            for user in CustomUser.objects.filter(location=key[1])
        ]
        for key in grouped_notifications.keys()
    }
    
    # ------------------------------------------------------------
    # SECTION 4: RENDER NOTIFICATION DASHBOARD
    # ------------------------------------------------------------
    
    return render(
        request,
        "dispatch_notifications.html",
        {
            "grouped_notifications": dict(grouped_notifications),
            "notification_emails": notification_emails,
        },
    )


@login_required(login_url="login")
def download_dispatch_excel(request):
    """
    Export the items being dispatched for one route (from -> to) as an Excel
    file, with the STN number on each line. Lets the dispatcher download the
    full list as a file instead of scrolling the whole on-screen table.
    """

    from_location = (request.GET.get("from_location") or "").strip()
    to_location = (request.GET.get("to_location") or "").strip()

    # Same set of rows the dispatch page shows for this route (pending only)
    notifications = (
        DispatchNotification.objects.filter(
            to_user=request.user,
            is_dispatched=False,
            from_user__location=request.user.location,
            logistic_department__from_location=from_location,
            logistic_department__to_location=to_location,
        )
        .select_related("logistic_department")
        .order_by("logistic_department__stn_number")
    )

    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Dispatch Items"

    headers = ["S.No", "STN Number", "Stock Item", "Quantity", "From Location", "To Location"]
    ws.append(headers)
    header_fill = PatternFill(start_color="313647", end_color="313647", fill_type="solid")
    header_font = Font(color="FFFFFF", bold=True)
    for col_idx in range(1, len(headers) + 1):
        cell = ws.cell(row=1, column=col_idx)
        cell.fill = header_fill
        cell.font = header_font
        cell.alignment = Alignment(horizontal="center", vertical="center")

    stn_numbers = []
    for idx, notification in enumerate(notifications, start=1):
        ld = notification.logistic_department
        if ld.stn_number and ld.stn_number not in stn_numbers:
            stn_numbers.append(ld.stn_number)
        ws.append([
            idx,
            ld.stn_number or "",
            ld.stock_item,
            ld.quantity,
            ld.from_location,
            ld.to_location,
        ])

    for col, width in {"A": 8, "B": 18, "C": 42, "D": 12, "E": 22, "F": 22}.items():
        ws.column_dimensions[col].width = width
    ws.freeze_panes = "A2"

    # Name the file by the STN number when there's a single one, else by route
    if len(stn_numbers) == 1:
        filename = f"Dispatch_{stn_numbers[0]}.xlsx"
    else:
        safe_from = (from_location or "FROM").replace(" ", "_")
        safe_to = (to_location or "TO").replace(" ", "_")
        filename = f"Dispatch_{safe_from}_to_{safe_to}.xlsx"

    output = BytesIO()
    wb.save(output)
    output.seek(0)
    response = HttpResponse(
        output.read(),
        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )
    response["Content-Disposition"] = f'attachment; filename="{filename}"'
    return response


# =========== Dispatch Items Management ==============

@login_required(login_url='login')
def dispatch_item(request, notification_id):
    """
    Process Individual Stock Dispatch with Inventory Updates
    
    Handles single-item dispatch processing with comprehensive inventory
    tracking. Updates inventory levels, creates audit history, and marks
    notifications as completed.
    
    Args:
        request: HTTP request object with user authentication
        notification_id (int): ID of specific dispatch notification
    
    Returns:
        JsonResponse: Success/error response for AJAX operations
        HttpResponse: Dispatch form for GET requests
    
    Process Flow:
        1. Validate notification ownership and existence
        2. Check inventory availability
        3. Update inventory with atomic transaction
        4. Create inventory history audit record
        5. Log dispatch completion
        6. Mark notification as dispatched
    
    Security:
        - Ensures user can only dispatch items sent to them
        - Uses atomic transactions for data consistency
        - Validates all quantity constraints
    """
    
    # ------------------------------------------------------------
    # SECTION 1: RETRIEVE AND VALIDATE NOTIFICATION
    # ------------------------------------------------------------
    
    # Fetch notification with ownership validation
    notification = get_object_or_404(
        DispatchNotification, id=notification_id, to_user=request.user
    )
    logistic_department = notification.logistic_department
    
    # ------------------------------------------------------------
    # SECTION 2: HANDLE DISPATCH FORM SUBMISSION (POST)
    # ------------------------------------------------------------
    if request.method == "POST":
        
        # Extract requested dispatch quantity
        quantity = int(request.POST.get("quantity"))
        
        # --------------------------------------------------------
        # SUBSECTION: Validate Dispatch Quantity
        # --------------------------------------------------------
        if quantity > logistic_department.quantity:
            return JsonResponse(
                {
                    "success": False, 
                    "message": "Quantity exceeds available stock."
                }
            )
        
        # --------------------------------------------------------
        # SUBSECTION: Process Dispatch with Atomic Transaction
        # --------------------------------------------------------
        try:
            with transaction.atomic():
                
                # ----------------------------------------------------
                # Retrieve and Lock Inventory Record
                # ----------------------------------------------------
                inventory = Inventory.objects.select_for_update().get(
                    mcc_bmc_user=request.user, 
                    product=logistic_department.product
                )
                
                # Validate inventory availability
                if inventory.quantity < quantity:
                    return JsonResponse(
                        {
                            "success": False, 
                            "message": "Insufficient inventory."
                        }
                    )
                
                # ----------------------------------------------------
                # Record Current Quantity for Audit Trail
                # ----------------------------------------------------
                previous_quantity = inventory.quantity
                
                # ----------------------------------------------------
                # Update Inventory Quantity
                # ----------------------------------------------------
                inventory.quantity -= quantity
                inventory.save()
                
                # ----------------------------------------------------
                # Create Inventory History Audit Record
                # ----------------------------------------------------
                InventoryHistory.objects.create(
                    inventory=inventory,
                    action='TRANSFER_OUT',
                    quantity_change=-quantity,
                    previous_quantity=previous_quantity,
                    new_quantity=inventory.quantity,
                    reference_number=logistic_department.stn_number,
                    notes=(
                        f"Stock transfer to {logistic_department.to_location}. "
                        f"STN: {logistic_department.stn_number}"
                    ),
                    performed_by=request.user
                )
                
                # ----------------------------------------------------
                # Log Dispatch Activity
                # ----------------------------------------------------
                DispatchLog.objects.create(
                    logistic_department=logistic_department,
                    dispatched_by=request.user,
                    quantity=quantity,
                )
                
                # ----------------------------------------------------
                # Mark Notification as Completed
                # ----------------------------------------------------
                notification.is_dispatched = True
                notification.save()
                
        except Inventory.DoesNotExist:
            return JsonResponse(
                {
                    "success": False,
                    "message": "Inventory matching query does not exist.",
                }
            )
        except Exception:
            return JsonResponse(
                {
                    "success": False, 
                    "message": "An unexpected error occurred."
                }
            )
        
        # --------------------------------------------------------
        # SUBSECTION: Return Success Response
        # --------------------------------------------------------
        return JsonResponse(
            {
                "success": True, 
                "message": "Item dispatched successfully."
            }
        )
    
    # ------------------------------------------------------------
    # SECTION 3: HANDLE DISPATCH FORM DISPLAY (GET)
    # ------------------------------------------------------------
    
    return render(
        request, 
        "dispatch_item.html", 
        {"notification": notification}
    )
# =========== Bulk Dispatch Processing with Inventory Transfer ==============

@login_required(login_url='login')
def dispatch_selected_items(request):
    """
    Bulk Dispatch Processing with Source Inventory Deduction
    
    Handles multiple dispatch notifications in a single transaction with
    comprehensive inventory management. Deducts stock from source location,
    creates audit trails, and sends consolidated notification emails.
    
    Args:
        request: HTTP request object with user authentication
    
    Returns:
        JsonResponse: Success/error response for bulk dispatch operation
    
    Key Features:
        - Processes multiple notifications in atomic transaction
        - Deducts inventory from source location users
        - Creates TRANSFER_OUT audit records
        - Sends consolidated email notifications
        - Maintains GRN requirement flag for destination
    
    Inventory Flow:
        1. Deduct from source location inventory immediately
        2. Create TRANSFER_OUT history for audit trail
        3. Destination receives notification to create GRN
        4. GRN at destination adds inventory to their location
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATE REQUEST METHOD
    # ------------------------------------------------------------
    if request.method != "POST":
        return JsonResponse(
            {
                "success": False, 
                "message": "Invalid request method."
            }
        )
    
    # ------------------------------------------------------------
    # SECTION 2: EXTRACT SELECTED NOTIFICATIONS
    # ------------------------------------------------------------
    selected_notifications = request.POST.getlist("selected_notifications[]")
    
    # ------------------------------------------------------------
    # SECTION 3: PROCESS BULK DISPATCH IN TRANSACTION
    # ------------------------------------------------------------
    try:
        with transaction.atomic():
            
            # Initialize email data structure for consolidated notification
            email_data = {
                "from_user_email": None,
                "to_user_email": None,
                "items": [],
                "from_location": None,
                "to_location": None,
            }
            
            # --------------------------------------------------------
            # SUBSECTION: Process Each Selected Notification
            # --------------------------------------------------------
            for notification_id in selected_notifications:
                
                # Retrieve and validate notification
                notification = get_object_or_404(
                    DispatchNotification, 
                    id=notification_id, 
                    to_user=request.user
                )
                
                logistic_department = notification.logistic_department
                
                # ----------------------------------------------------
                # Locate Product Instance
                # ----------------------------------------------------
                product = get_object_or_404(
                    Product, 
                    name=logistic_department.stock_item
                )
                
                # ----------------------------------------------------
                # Find Source Location Users
                # ----------------------------------------------------
                from_location_users = CustomUser.objects.filter(
                    location=logistic_department.from_location
                )
                
                if not from_location_users.exists():
                    return JsonResponse(
                        {
                            "success": False,
                            "message": f"No users found at source location: {logistic_department.from_location}",
                        }
                    )
                
                # Use first available user at source location
                from_location_user = from_location_users.first()
                
                # ----------------------------------------------------
                # Retrieve and Update Source Inventory
                # ----------------------------------------------------
                try:
                    inventory = Inventory.objects.select_for_update().get(
                        mcc_bmc_user=from_location_user, 
                        product=product
                    )
                except Inventory.DoesNotExist:
                    return JsonResponse(
                        {
                            "success": False,
                            "message": f"Inventory not found for {logistic_department.stock_item} at {logistic_department.from_location}",
                        }
                    )
                
                # Validate inventory availability
                if inventory.quantity < logistic_department.quantity:
                    return JsonResponse(
                        {
                            "success": False,
                            "message": f"Insufficient inventory for {logistic_department.stock_item} at {logistic_department.from_location}",
                        }
                    )
                
                # ----------------------------------------------------
                # Deduct Inventory from Source Location
                # ----------------------------------------------------
                previous_quantity = inventory.quantity
                quantity_to_deduct = logistic_department.quantity
                
                inventory.quantity -= quantity_to_deduct
                inventory.save()
                
                # ----------------------------------------------------
                # Create TRANSFER_OUT Audit History Record
                # ----------------------------------------------------
                InventoryHistory.objects.create(
                    inventory=inventory,
                    action='TRANSFER_OUT',
                    quantity_change=-quantity_to_deduct,
                    previous_quantity=previous_quantity,
                    new_quantity=inventory.quantity,
                    reference_number=logistic_department.stn_number,
                    notes=(
                        f"Stock transfer to {logistic_department.to_location}. "
                        f"STN: {logistic_department.stn_number}, "
                        f"From: {logistic_department.from_location}, "
                        f"To: {logistic_department.to_location}. "
                        f"Inventory will be added at destination after GRN."
                    ),
                    performed_by=request.user
                )
                
                # ----------------------------------------------------
                # Create Dispatch Log Record
                # ----------------------------------------------------
                DispatchLog.objects.create(
                    logistic_department=logistic_department,
                    dispatched_by=request.user,
                    quantity=logistic_department.quantity,
                )
                
                # ----------------------------------------------------
                # Mark Related Notifications as Dispatched
                # ----------------------------------------------------
                DispatchNotification.objects.filter(
                    logistic_department=logistic_department,
                    to_user__location=notification.to_user.location,
                    is_dispatched=False,
                ).update(is_dispatched=True)
                
                # ----------------------------------------------------
                # Collect Destination User for Email
                # ----------------------------------------------------
                to_location_users = CustomUser.objects.filter(
                    location=logistic_department.to_location
                )
                to_location_user = to_location_users.first() if to_location_users.exists() else None
                
                # ----------------------------------------------------
                # Populate Email Data Structure
                # ----------------------------------------------------
                if not email_data["from_user_email"]:
                    email_data["from_user_email"] = from_location_user.email
                    email_data["from_location"] = logistic_department.from_location
                
                if not email_data["to_user_email"] and to_location_user:
                    email_data["to_user_email"] = to_location_user.email
                    email_data["to_location"] = logistic_department.to_location
                
                email_data["items"].append(
                    {
                        "stock_item": logistic_department.stock_item,
                        "quantity": logistic_department.quantity,
                        "from_location": logistic_department.from_location,
                        "to_location": logistic_department.to_location,
                        "stn_number": logistic_department.stn_number,
                    }
                )
            
            # --------------------------------------------------------
            # SUBSECTION: Send Consolidated Email Notification
            # --------------------------------------------------------
            if email_data["items"] and email_data["to_user_email"]:
                
                subject = f"Dispatch Notification for Items from {email_data['from_location']} to {email_data['to_location']}"
                
                # Build HTML email content
                message = f"""
                <html>
                    <body>
                        <p>Dear Recipient,</p>
                        <p>The following items have been dispatched from {email_data['from_location']} to your location:</p>
                        <table border="1" cellpadding="5" cellspacing="0" style="border-collapse: collapse; width: 100%;">
                            <thead>
                                <tr>
                                    <th>Stock Item</th>
                                    <th>Quantity</th>
                                    <th>From Location</th>
                                    <th>To Location</th>
                                    <th>STN Number</th>
                                </tr>
                            </thead>
                            <tbody>
                """
                
                for item in email_data["items"]:
                    message += f"""
                        <tr>
                            <td>{item['stock_item']}</td>
                            <td>{item['quantity']}</td>
                            <td>{item['from_location']}</td>
                            <td>{item['to_location']}</td>
                            <td>{item['stn_number']}</td>
                        </tr>
                    """
                
                message += f"""
                            </tbody>
                        </table>
                        <p><strong>Note:</strong> Please process GRN against this STN to add these items to your inventory.</p>
                        <p>Thanks and Regards,</p>
                        <p><strong>{email_data['from_user_email']}</strong><br>{email_data['from_location']}</p>
                    </body>
                </html>
                """
                
                # Create and send email
                email = EmailMessage(
                    subject,
                    message,
                    email_data["from_user_email"],
                    [email_data["to_user_email"]],
                )
                email.content_subtype = "html"
                
                # Attach STN PDF files if provided
                for notification_id in selected_notifications:
                    stn_pdf = request.FILES.get(f"stn_pdf_{notification_id}")
                    if stn_pdf:
                        email.attach(
                            stn_pdf.name, 
                            stn_pdf.read(), 
                            stn_pdf.content_type
                        )
                
                # Send email (continue even if email fails)
                try:
                    email.send()
                except Exception:
                    # Email failure doesn't invalidate dispatch
                    pass
    
    except Exception:
        # ------------------------------------------------------------
        # SECTION 4: ERROR HANDLING
        # ------------------------------------------------------------
        return JsonResponse(
            {
                "success": False, 
                "message": "An unexpected error occurred during dispatch."
            }
        )
    
    # ------------------------------------------------------------
    # SECTION 5: SUCCESS RESPONSE
    # ------------------------------------------------------------
    return JsonResponse(
        {
            "success": True, 
            "message": "Selected items dispatched successfully. Inventory deducted from source location. GRN required at destination to add inventory."
        }
    )
# =========== Dispatch Log Book with Search Functionality ==============

@login_required(login_url="login")
def dispatch_log_book(request):
    """
    Dispatch History and Audit Log with Advanced Search
    
    Displays a searchable log of all dispatches performed by the current user.
    Provides comprehensive filtering across multiple dispatch attributes
    for easy tracking and audit purposes.
    
    Args:
        request: HTTP request object with user authentication
        search (query param): Optional search term for filtering logs
    
    Returns:
        HttpResponse: Rendered template with filtered dispatch logs
    
    Searchable Fields:
        - Stock Item (partial match, case-insensitive)
        - From Location (partial match, case-insensitive)
        - To Location (partial match, case-insensitive)
        - Dispatcher Name (first/last name, partial match)
        - Dispatch Date/Time (partial match)
    
    Display Order:
        - Most recent dispatches appear first
        - Chronological descending by dispatch timestamp
    
    Security:
        - Only displays logs for the authenticated user
        - User cannot access other users' dispatch history
    """
    
    # ------------------------------------------------------------
    # SECTION 1: EXTRACT SEARCH QUERY PARAMETER
    # ------------------------------------------------------------
    
    # Retrieve and clean search term from query parameters
    search_query = request.GET.get("search", "").strip()
    
    # ------------------------------------------------------------
    # SECTION 2: RETRIEVE USER'S DISPATCH LOGS
    # ------------------------------------------------------------
    
    # Fetch all dispatch logs for the authenticated user
    dispatch_logs = DispatchLog.objects.filter(dispatched_by=request.user)
    
    # ------------------------------------------------------------
    # SECTION 3: APPLY SEARCH FILTERS IF PROVIDED
    # ------------------------------------------------------------
    if search_query:
        dispatch_logs = dispatch_logs.filter(
            # Search by Stock Item Name
            Q(logistic_department__stock_item__icontains=search_query)
            
            # Search by Source Location
            | Q(logistic_department__from_location__icontains=search_query)
            
            # Search by Destination Location
            | Q(logistic_department__to_location__icontains=search_query)
            
            # Search by Dispatcher's First Name
            | Q(dispatched_by__first_name__icontains=search_query)
            
            # Search by Dispatcher's Last Name
            | Q(dispatched_by__last_name__icontains=search_query)
            
            # Search by Dispatch Timestamp (partial date/time match)
            | Q(dispatched_at__icontains=search_query)
        )
    
    # ------------------------------------------------------------
    # SECTION 4: ORDER RESULTS BY DISPATCH TIME
    # ------------------------------------------------------------
    
    # Sort with most recent dispatches first
    dispatch_logs = dispatch_logs.order_by("-dispatched_at")
    
    # ------------------------------------------------------------
    # SECTION 5: RENDER DISPATCH LOG TEMPLATE
    # ------------------------------------------------------------
    
    return render(
        request,
        "dispatch_log.html",
        {
            "dispatch_logs": dispatch_logs,
            "search_query": search_query,  # Return search term for form persistence
        },
    )
    
# =========== Financial Document Data Retrieval API ==============

@login_required(login_url='login')
def fetch_finance_data(request):
    """
    Comprehensive Financial Document Aggregator with Date Filtering
    
    Retrieves and organizes GRN files, STN documents, and chalan records
    based on location and date range. Supports both file system and
    database sources for complete document coverage.
    
    Args:
        request: HTTP request object with query parameters:
            - location: Filter documents by location
            - fromDate: Start date for date range filter (YYYY-MM-DD)
            - toDate: End date for date range filter (YYYY-MM-DD)
    
    Returns:
        JsonResponse: Structured document data organized by type
    
    Response Structure:
        {
            "grn_files": [
                {
                    "employee_code": str,
                    "grn_file": str,
                    "chalan_file": str or None,
                    "file_type": "grn",
                    "timestamp": str or None
                }
            ],
            "grn_against_stn_files": [
                {
                    "employee_code": str,
                    "stn_file": str,
                    "file_type": "stn",
                    "timestamp": str or None,
                    "stn_number": str or None,
                    "grn_number": str or None,
                    "source": "database" or "file_system"
                }
            ],
            "chalan_files": [
                {
                    "employee_code": str,
                    "chalan_file": str,
                    "file_type": "chalan",
                    "timestamp": str or None
                }
            ],
            "media_url": str
        }
    
    Search Sources:
        1. File System: Direct file scanning in media folders
        2. Database: Official records with metadata (STN, GRN numbers)
    
    Note: Prioritizes database records over file system for accuracy
    """
    
    # ------------------------------------------------------------
    # SECTION 1: EXTRACT FILTER PARAMETERS
    # ------------------------------------------------------------
    selected_location = request.GET.get("location", "")
    from_date = request.GET.get("fromDate", "")
    to_date = request.GET.get("toDate", "")
    
    # ------------------------------------------------------------
    # SECTION 2: INITIALIZE DATA STRUCTURES
    # ------------------------------------------------------------
    grn_files_with_chalan = []      # GRN files with linked chalans
    grn_against_stn_files = []      # STN files (from both sources)
    standalone_chalan_files = []    # Chalan files without GRN links
    
    # ------------------------------------------------------------
    # SECTION 3: VALIDATE LOCATION SELECTION
    # ------------------------------------------------------------
    if not selected_location:
        return JsonResponse(
            {
                "grn_files": [],
                "grn_against_stn_files": [],
                "chalan_files": [],
                "media_url": settings.MEDIA_URL,
            }
        )
    
    # ------------------------------------------------------------
    # SECTION 4: RETRIEVE EMPLOYEES FOR SELECTED LOCATION
    # ------------------------------------------------------------
    employee_codes = CustomUser.objects.filter(
        location=selected_location
    ).values_list("employee_code", flat=True)
    
    # Define base media directory for file scanning
    base_media_dir = settings.MEDIA_ROOT
    
    # ------------------------------------------------------------
    # SECTION 5: PROCESS EACH EMPLOYEE'S DOCUMENTS
    # ------------------------------------------------------------
    for employee_code in employee_codes:
        
        # --------------------------------------------------------
        # SUBSECTION: Define File Paths
        # --------------------------------------------------------
        grn_folder_path = os.path.join(base_media_dir, "grns", employee_code)
        chalan_folder_path = os.path.join(base_media_dir, "chalan_files", employee_code)
        grn_against_stn_folder_path = os.path.join(base_media_dir, "grn_against_stn", employee_code)
        
        # --------------------------------------------------------
        # SUBSECTION: Process GRN Files with Chalan Linking
        # --------------------------------------------------------
        if os.path.exists(grn_folder_path) and os.path.isdir(grn_folder_path):
            
            # List all GRN files in employee's directory
            grn_files = [
                f for f in os.listdir(grn_folder_path)
                if os.path.isfile(os.path.join(grn_folder_path, f))
            ]
            
            for grn_file in grn_files:
                
                # Extract timestamp from GRN filename
                grn_timestamp = extract_timestamp_from_filename(grn_file)
                
                # Apply date filter if provided
                if from_date and to_date:
                    if not grn_timestamp:
                        # Skip files without timestamps when filtering
                        continue
                    
                    grn_date_str = grn_timestamp.strftime("%Y-%m-%d")
                    if not (from_date <= grn_date_str <= to_date):
                        # Skip files outside date range
                        continue
                
                # Find corresponding chalan file
                corresponding_chalan = find_chalan_by_timestamp(
                    chalan_folder_path, grn_timestamp
                )
                
                # Add to GRN files list
                grn_files_with_chalan.append({
                    'employee_code': employee_code,
                    'grn_file': grn_file,
                    'chalan_file': corresponding_chalan,
                    'file_type': 'grn',
                    'timestamp': grn_timestamp.strftime("%Y%m%d%H%M%S") if grn_timestamp else None
                })
        
        # --------------------------------------------------------
        # SUBSECTION: Process GRN Against STN Files (File System)
        # --------------------------------------------------------
        if os.path.exists(grn_against_stn_folder_path) and os.path.isdir(grn_against_stn_folder_path):
            
            # List all STN files in directory
            stn_files = [
                f for f in os.listdir(grn_against_stn_folder_path)
                if os.path.isfile(os.path.join(grn_against_stn_folder_path, f))
            ]
            
            for stn_file in stn_files:
                
                # Extract timestamp from STN filename
                stn_timestamp = extract_timestamp_from_filename(stn_file)
                
                # Apply date filter if provided
                if from_date and to_date:
                    if not stn_timestamp:
                        continue
                    
                    stn_date_str = stn_timestamp.strftime("%Y-%m-%d")
                    if not (from_date <= stn_date_str <= to_date):
                        continue
                
                # Add file system STN record
                grn_against_stn_files.append({
                    'employee_code': employee_code,
                    'stn_file': stn_file,
                    'file_type': 'stn',
                    'timestamp': stn_timestamp.strftime("%Y%m%d%H%M%S") if stn_timestamp else None,
                    'source': 'file_system'
                })
        
        # --------------------------------------------------------
        # SUBSECTION: Process GRN Against STN Files (Database)
        # --------------------------------------------------------
        # Query official STN records from database
        stn_records = DoGRNAgainstSTN.objects.filter(
            employee_code=employee_code,
            location=selected_location
        )
        
        for stn_record in stn_records:
            
            # Validate STN file exists in database record
            if not stn_record.stn_file:
                continue
            
            # Extract filename from FileField
            stn_filename = os.path.basename(str(stn_record.stn_file))
            
            # Verify file exists in storage
            stn_file_path = os.path.join(settings.MEDIA_ROOT, str(stn_record.stn_file))
            if not os.path.exists(stn_file_path):
                continue
            
            # Extract date for filtering
            stn_date = stn_record.stn_date
            
            # Apply date filter if provided
            if from_date and to_date and stn_date:
                stn_date_str = stn_date.strftime("%Y-%m-%d")
                if not (from_date <= stn_date_str <= to_date):
                    continue
            
            # Check for duplicate entries (file system vs database)
            already_added = any(
                item.get('stn_file') == stn_filename 
                for item in grn_against_stn_files
            )
            
            if not already_added:
                grn_against_stn_files.append({
                    'employee_code': employee_code,
                    'stn_file': stn_filename,
                    'file_type': 'stn',
                    'timestamp': stn_date.strftime("%Y%m%d") if stn_date else None,
                    'stn_number': stn_record.stn_number,
                    'grn_number': stn_record.grn_number,
                    'source': 'database'
                })
        
        # --------------------------------------------------------
        # SUBSECTION: Process Standalone Chalan Files
        # --------------------------------------------------------
        if os.path.exists(chalan_folder_path) and os.path.isdir(chalan_folder_path):
            
            # List all chalan files
            chalan_files = [
                f for f in os.listdir(chalan_folder_path)
                if os.path.isfile(os.path.join(chalan_folder_path, f))
            ]
            
            for chalan_file in chalan_files:
                
                # Check if chalan is already linked to a GRN
                is_linked = any(
                    item.get('chalan_file') == chalan_file
                    for item in grn_files_with_chalan
                )
                
                if not is_linked:
                    
                    # Extract timestamp for filtering
                    chalan_timestamp = extract_timestamp_from_filename(chalan_file)
                    
                    # Apply date filter if provided
                    if from_date and to_date:
                        if not chalan_timestamp:
                            continue
                        
                        chalan_date_str = chalan_timestamp.strftime("%Y-%m-%d")
                        if not (from_date <= chalan_date_str <= to_date):
                            continue
                    
                    # Add as standalone chalan
                    standalone_chalan_files.append({
                        'employee_code': employee_code,
                        'chalan_file': chalan_file,
                        'file_type': 'chalan',
                        'timestamp': chalan_timestamp.strftime("%Y%m%d%H%M%S") if chalan_timestamp else None
                    })
    
    # ------------------------------------------------------------
    # SECTION 6: PREPARE FINAL RESPONSE
    # ------------------------------------------------------------
    response_data = {
        "grn_files": grn_files_with_chalan,
        "grn_against_stn_files": grn_against_stn_files,
        "chalan_files": standalone_chalan_files,
        "media_url": settings.MEDIA_URL,
    }
    
    return JsonResponse(response_data)

# =========== HELPER FUNCTIONS ==============

def extract_timestamp_from_filename(filename):
    """
    Extract timestamp from filename by searching for timestamp patterns.
    
    This function analyzes filenames to find embedded timestamp information.
    It supports two patterns:
    1. 14-digit timestamps (YYYYMMDDHHMMSS) - Complete datetime
    2. 8-digit dates (YYYYMMDD) - Date only
    
    Args:
        filename (str): The filename to analyze
        
    Returns:
        datetime: Parsed datetime object if timestamp found, else None
        
    Example:
        >>> extract_timestamp_from_filename("document_20231225143045.pdf")
        datetime(2023, 12, 25, 14, 30, 45)
        >>> extract_timestamp_from_filename("report_20231225.xlsx") 
        datetime(2023, 12, 25, 0, 0, 0)
    """
    try:
        # Remove file extension to focus on filename
        name_without_ext = os.path.splitext(filename)[0]
        
        # --------------------------------------------------------
        # PATTERN 1: 14-digit timestamp (YYYYMMDDHHMMSS)
        # --------------------------------------------------------
        import re
        timestamp_match = re.search(r'(\d{14})', name_without_ext)
        if timestamp_match:
            timestamp_str = timestamp_match.group(1)
            return datetime.strptime(timestamp_str, '%Y%m%d%H%M%S')
        
        # --------------------------------------------------------
        # PATTERN 2: 8-digit date (YYYYMMDD)
        # --------------------------------------------------------
        date_match = re.search(r'(\d{8})', name_without_ext)
        if date_match:
            date_str = date_match.group(1)
            return datetime.strptime(date_str, '%Y%m%d')
        
        # --------------------------------------------------------
        # NO PATTERN FOUND
        # --------------------------------------------------------
        return None
        
    except Exception:
        # Return None for any parsing errors
        return None
    
# ==========A function for finding the chalan by timestamp==========
def find_chalan_by_timestamp(chalan_folder_path, grn_timestamp):
    """
    Find corresponding chalan file for a given GRN timestamp.
    
    This function searches through chalan files in the specified folder
    to find a file with a timestamp matching the given GRN timestamp.
    
    Args:
        chalan_folder_path (str): Path to the chalan files directory
        grn_timestamp (datetime): Timestamp of the GRN file to match
        
    Returns:
        str: Matching chalan filename if found, otherwise None
        
    Matching Logic:
        1. Exact 14-digit timestamp match (YYYYMMDDHHMMSS)
        2. Same day match using 8-digit date (YYYYMMDD)
    
    Example:
        >>> find_chalan_by_timestamp("/media/chalan_files/EMP001", 
        >>>                          datetime(2023, 12, 25, 14, 30, 45))
        "chalan_20231225143046.pdf"
    """
    # Validate inputs
    if not os.path.exists(chalan_folder_path) or not grn_timestamp:
        return None
    
    try:
        # Convert GRN timestamp to string formats for matching
        grn_timestamp_14 = grn_timestamp.strftime('%Y%m%d%H%M%S')
        grn_timestamp_8 = grn_timestamp.strftime('%Y%m%d')
        
        # Get list of chalan files in the directory
        chalan_files = [
            f for f in os.listdir(chalan_folder_path)
            if os.path.isfile(os.path.join(chalan_folder_path, f))
        ]
        
        # Search for matching chalan file
        for chalan_file in chalan_files:
            chalan_timestamp = extract_timestamp_from_filename(chalan_file)
            
            if chalan_timestamp:
                # Convert chalan timestamp to string formats
                chalan_timestamp_14 = chalan_timestamp.strftime('%Y%m%d%H%M%S')
                chalan_timestamp_8 = chalan_timestamp.strftime('%Y%m%d')
                
                # Check for exact timestamp match (14-digit) ONLY
                if chalan_timestamp_14 == grn_timestamp_14:
                    return chalan_file
                
                # NOTE: Same-day match removed — too loose, causes
                # multiple GRNs to get the same chalan file
        
        # No matching chalan found
        return None
        
    except Exception:
        # Return None for any errors during the search
        return None


# =========== FINANCE DEPARTMENT GRN & INDENT EXCEL EXPORT ==============
# Export comprehensive requisition data with GRN details for Finance Department
# Includes purchase requisitions, approvals, PO details, and GRN information
# in Excel format for financial tracking and auditing purposes.

@login_required(login_url="login")
def export_excel_finance_data_of_grn_chaalan(request):
    """
    Export Finance Department GRN and Indent Report to Excel
    
    Generates a comprehensive Excel report containing purchase requisitions,
    approvals, purchase orders, and GRN (Goods Receipt Note) details.
    This report is specifically for Finance Department use to track
    procurement-to-receipt lifecycle.
    
    Report Includes:
    - Requisition details and status
    - HOD approval workflow
    - Purchase order information
    - GRN details (both DoGRN and DoGRNAgainstSTN)
    - Delivery quantities comparison
    
    Permission: Only accessible by finance department users
    
    Returns:
        HttpResponse: Excel file download
    
    File Format: .xlsx
    File Name: Indent_and_GRN_report_for_finance_department.xlsx
    """
    
    # ------------------------------------------------------------
    # SECTION 1: AUTHORIZATION CHECK
    # ------------------------------------------------------------
    if not request.user.is_finance:
        return render(request, "403.html", status=403)
    
    # ------------------------------------------------------------
    # SECTION 2: FETCH REQUISITION DATA
    # ------------------------------------------------------------
    # Retrieve all purchase requisitions with related data
    # Ordered by requisition number and date for chronological reporting
    requisitions = (
        PurchaseRequisition.objects.all()
        .prefetch_related("purchasedepartment_set", "hodapproval_set")
        .order_by("-requisition_number", "-date_of_request")
    )
    
    # ------------------------------------------------------------
    # SECTION 3: INITIALIZE EXCEL WORKBOOK
    # ------------------------------------------------------------
    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Requisitions"
    
    # Define report headers - comprehensive procurement lifecycle tracking
    headers = [
        "Requisition Number",        # PR-001 format identifier
        "Date of Request",           # Request initiation date
        "Requested By",              # Employee who requested
        "Department",                # Requesting department
        "Location",                  # Office/branch location
        "Product Name",              # Stock item description
        "Quantity Ordered",          # Original requested quantity
        "Quantity Delivered",        # Actual received quantity
        "Expected Delivery Date",    # Original delivery estimate
        "Remark",                    # Additional comments
        "Status",                    # Overall requisition status
        "Approval Status",           # HOD approval status
        "Approval/Rejected Date",    # When approval/rejection occurred
        "Approved By",               # HOD who approved/rejected
        "PO Number",                 # Purchase Order identifier
        "PO Generation Date",        # When PO was created
        "GRN Number",                # Goods Receipt Note identifier
        "GRN Date",                  # When goods were received
        "GRN Done By",               # Employee who performed GRN
    ]
    
    # Write headers to first row
    ws.append(headers)
    
    # ------------------------------------------------------------
    # SECTION 4: TIMEZONE SETUP
    # ------------------------------------------------------------
    # Use Indian Standard Time for all date conversions
    IST = pytz.timezone("Asia/Kolkata")
    
    # ------------------------------------------------------------
    # SECTION 5: POPULATE DATA ROWS
    # ------------------------------------------------------------
    for requisition in requisitions:
        
        # --------------------------------------------------------
        # SUBSECTION: Extract HOD Approval Details
        # --------------------------------------------------------
        approval = requisition.hodapproval_set.first()
        approval_status = approval.status if approval else "PENDING"
        
        # Process approval dates and approver information
        if approval and approval.status in ["APPROVED", "REJECTED", "APPROVED FOR TRANSFER"]:
            approval_date = approval.approval_date
            if approval_date:
                if is_naive(approval_date):
                    approval_date = make_aware(approval_date, IST)
                approval_date = localtime(approval_date).strftime("%d-%m-%Y")
            else:
                approval_date = "N/A"
            approved_by = approval.approved_by.get_full_name() if approval.approved_by else "N/A"
        else:
            approval_date = "N/A"
            approved_by = "N/A"
        
        # --------------------------------------------------------
        # SUBSECTION: Extract Purchase Order Details
        # --------------------------------------------------------
        purchase_department = requisition.purchasedepartment_set.first()
        if purchase_department:
            po_number = (
                purchase_department.po_number.split(":")[0]
                if purchase_department.po_number
                else "N/A"
            )
            po_generation_date = purchase_department.po_generation_date
            if po_generation_date:
                if is_naive(po_generation_date):
                    po_generation_date = make_aware(po_generation_date, IST)
                po_generation_date = localtime(po_generation_date).strftime("%d-%m-%Y")
            else:
                po_generation_date = "N/A"
        else:
            po_number = "N/A"
            po_generation_date = "N/A"
        
        # --------------------------------------------------------
        # SUBSECTION: Extract GRN Details
        # --------------------------------------------------------
        quantity_ordered = requisition.quantity  # Original requested quantity
        quantity_delivered = 0  # Default value, updated if GRN exists
        grn_number = "N/A"
        grn_date = "N/A"
        grn_done_by = "N/A"
        
        # Handle different requisition statuses for GRN lookup
        if requisition.status == "APPROVED FOR TRANSFER":
            # STN-based GRN (Stock Transfer Note)
            grn = DoGRNAgainstSTN.objects.filter(
                stn_number=requisition.requisition_number
            ).first()
            if grn:
                grn_number = grn.grn_number
                grn_date = grn.created_at.strftime("%d-%m-%Y") if grn.created_at else "N/A"
                grn_done_by = grn.employee_name
                quantity_delivered = grn.quantity_received  # Actual received quantity
        
        elif requisition.status == "PO GENERATED":
            # Standard Purchase Order GRN
            grn = DoGRN.objects.filter(
                requisition_number=requisition.requisition_number
            ).first()
            if grn:
                grn_number = grn.grn_number
                grn_date = grn.created_at.strftime("%d-%m-%Y") if grn.created_at else "N/A"
                grn_done_by = grn.employee_name
                quantity_delivered = grn.quantity_received  # Actual received quantity
        
        # --------------------------------------------------------
        # SUBSECTION: Construct Excel Row
        # --------------------------------------------------------
        row = [
            requisition.requisition_number,
            requisition.date_of_request.strftime("%d-%m-%Y"),
            requisition.employee_name,
            requisition.department,
            requisition.location,
            requisition.stock_item,
            quantity_ordered,
            quantity_delivered,
            (
                requisition.expected_delivery_date.strftime("%d-%m-%Y")
                if requisition.expected_delivery_date else "N/A"
            ),
            requisition.remark or "",
            requisition.status,
            approval_status,
            approval_date,
            approved_by,
            po_number,
            po_generation_date,
            grn_number,
            grn_date,
            grn_done_by,
        ]
        
        # Add row to Excel sheet
        ws.append(row)
    
    # ------------------------------------------------------------
    # SECTION 6: FORMAT EXCEL SHEET
    # ------------------------------------------------------------
    # Set consistent column widths for better readability
    for col_num, header in enumerate(headers, start=1):
        ws.column_dimensions[get_column_letter(col_num)].width = 18
    
    # ------------------------------------------------------------
    # SECTION 7: PREPARE DOWNLOAD RESPONSE
    # ------------------------------------------------------------
    filename = f"Indent_and_GRN_report_for_finance_department.xlsx"
    response = HttpResponse(
        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )
    response["Content-Disposition"] = f'attachment; filename="{filename}"'
    
    # Save workbook to HTTP response
    wb.save(response)
    
    return response


# =========== USER LOGOUT FUNCTION ==============
# Simple, secure logout function that terminates user sessions
# Redirects to login page after clearing authentication credentials

def logoutView(request):
    """
    User Session Termination Handler
    
    Safely terminates the current user's session by:
    1. Clearing server-side session data via Django's logout()
    2. Removing authentication cookies from the browser
    3. Redirecting to the login page for re-authentication
    
    Security Features:
    - Prevents session fixation attacks
    - Clears all session data (not just authentication)
    - Ensures complete session termination
    
    Returns:
        HttpResponseRedirect: Redirect to login page
    
    Flow:
        User Session → Logout Process → Login Page Redirect
    """
    
    # ------------------------------------------------------------
    # SECTION 1: TERMINATE SESSION
    # ------------------------------------------------------------
    # Django's logout() function:
    # - Clears the current session from the database
    # - Removes authenticated user from request
    # - Deletes session cookie from browser
    # - Prevents session reuse
    logout(request)
    
    # ------------------------------------------------------------
    # SECTION 2: REDIRECT TO LOGIN
    # ------------------------------------------------------------
    # Redirect to login page with clean state
    # This ensures users must re-authenticate for further access
    return redirect("login")


# =========== USER AUTHENTICATION STATUS CHECK ==============
# Authentication state verification endpoint for frontend validation
# Provides real-time authentication status via JSON response for AJAX requests

def is_authenticated_view(request):
    """
    Authentication Status Verification Endpoint
    
    Returns the current user's authentication state as a JSON response.
    Primarily used by frontend applications to determine if the user
    is logged in and can access protected resources or features.
    
    Response Format:
        {
            "is_authenticated": boolean
        }
    
    Use Cases:
        - Conditional UI rendering (show/hide login buttons)
        - API access validation before AJAX calls
        - Session timeout detection
        - Protected route access verification
    
    Security Note:
        - Does not perform any authentication itself
        - Simply reports the current authentication state
        - Safe for public access (no sensitive data exposed)
    
    Returns:
        JsonResponse: JSON object with authentication boolean
    
    Example Response:
        {"is_authenticated": true}  → User is logged in
        {"is_authenticated": false} → User is not logged in
    """
    
    # ------------------------------------------------------------
    # SECTION 1: CHECK AUTHENTICATION STATUS
    # ------------------------------------------------------------
    # Django's User model provides is_authenticated attribute
    # - Returns True if user has valid authentication credentials
    # - Returns False for anonymous/unauthenticated users
    # - This is a property, not a method call
    authentication_status = request.user.is_authenticated
    
    # ------------------------------------------------------------
    # SECTION 2: RETURN JSON RESPONSE
    # ------------------------------------------------------------
    # Return simple, consistent JSON response
    # Minimal payload for fast frontend processing
    return JsonResponse({
        "is_authenticated": authentication_status
    })


# =========== TRANSFER REQUEST PROCESSING API ==============
# Inventory transfer approval/rejection system for HOD-level users
# Handles inventory quantity transfers between users with database consistency

@login_required(login_url='login')
@restrict_hod_access
def processTransferRequest(request, transfer_id, action):
    """
    Process Inventory Transfer Request (Accept/Reject)
    
    HOD-level endpoint for managing inventory transfer requests between users.
    Handles the complete transfer workflow including inventory updates,
    quantity adjustments, and transfer status management.
    
    Args:
        request: HTTP request object
        transfer_id (int): ID of the transfer request to process
        action (str): Action to perform - "ACCEPT" or "REJECT"
    
    Returns:
        JsonResponse: Success/error response with relevant data
    
    Workflow for ACCEPT:
        1. Verify transfer request exists
        2. Get associated product details
        3. Add product to receiver's inventory (or update existing)
        4. Deduct quantity from sender's inventory
        5. Update transfer request status to ACCEPT
        6. Return success response with inventory details
    
    Workflow for REJECT:
        1. Verify transfer request exists
        2. Update transfer request status to REJECT
        3. Return rejection confirmation
    
    Permissions:
        - Requires user authentication (@login_required)
        - Restricted to HOD users only (@restrict_hod_access)
    
    Error Handling:
        - Invalid request method (405)
        - Invalid action parameter (400)
        - Transfer request not found (404)
        - Inventory records not found (404)
        - General server errors (500)
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATE REQUEST METHOD
    # ------------------------------------------------------------
    if request.method != "POST":
        return JsonResponse({"error": "Invalid request method"}, status=405)
    
    # ------------------------------------------------------------
    # SECTION 2: PROCESS TRANSFER REQUEST
    # ------------------------------------------------------------
    try:
        # Retrieve the specific transfer request
        transfer_request = Transfer.objects.get(id=transfer_id)
        
        # --------------------------------------------------------
        # SUBSECTION: Handle ACCEPT Action
        # --------------------------------------------------------
        if action == "ACCEPT":
            # Extract product from transfer request
            product = transfer_request.product
            
            # ----------------------------------------------------
            # Step 1: Update Receiver's Inventory
            # ----------------------------------------------------
            # Get or create inventory record for receiver
            receiver_inventory, created = Inventory.objects.get_or_create(
                mcc_bmc_user=transfer_request.to_user.user,
                product=product
            )
            
            # Increase receiver's inventory quantity
            receiver_inventory.quantity = F("quantity") + transfer_request.quantity
            receiver_inventory.save()
            receiver_inventory.refresh_from_db()  # Get updated value
            
            # ----------------------------------------------------
            # Step 2: Update Sender's Inventory
            # ----------------------------------------------------
            # Retrieve sender's inventory (must exist for transfer)
            sender_inventory = Inventory.objects.get(
                mcc_bmc_user=transfer_request.from_user.user,
                product=product
            )
            
            # Decrease sender's inventory quantity
            sender_inventory.quantity = F("quantity") - transfer_request.quantity
            sender_inventory.save()
            sender_inventory.refresh_from_db()  # Get updated value
            
            # ----------------------------------------------------
            # Step 3: Update Transfer Status
            # ----------------------------------------------------
            transfer_request.status = "ACCEPT"
            transfer_request.save()
            
            # ----------------------------------------------------
            # Step 4: Return Success Response
            # ----------------------------------------------------
            return JsonResponse({
                "message": "Transfer request accepted successfully!",
                "transfer_id": transfer_id,
                "product": {
                    "id": product.id,
                    "name": product.name,
                    "quantity": receiver_inventory.quantity,
                },
                "receiver": {
                    "id": transfer_request.to_user.id,
                    "name": transfer_request.to_user.user.username,
                },
                "sender": {
                    "id": transfer_request.from_user.id,
                    "name": transfer_request.from_user.user.username,
                },
            })
        
        # --------------------------------------------------------
        # SUBSECTION: Handle REJECT Action
        # --------------------------------------------------------
        elif action == "REJECT":
            # Update transfer status to REJECT
            transfer_request.status = "REJECT"
            transfer_request.save()
            
            return JsonResponse({
                "message": "Transfer request rejected."
            })
        
        # --------------------------------------------------------
        # SUBSECTION: Handle Invalid Action
        # --------------------------------------------------------
        else:
            return JsonResponse({"error": "Invalid action"}, status=400)
    
    # ------------------------------------------------------------
    # SECTION 3: ERROR HANDLING
    # ------------------------------------------------------------
    except Transfer.DoesNotExist:
        return JsonResponse(
            {"error": "Transfer request does not exist"},
            status=404
        )
    
    except Inventory.DoesNotExist:
        return JsonResponse(
            {"error": "Inventory record not found"},
            status=404
        )
    
    except Exception as e:
        # Log the error for server-side debugging
        # Consider adding proper logging here in production
        return JsonResponse(
            {"error": "An internal server error occurred"},
            status=500
        )


