# =========== HEAD OF DEPARTMENT REQUISITION DASHBOARD ==============
# HOD-level purchase requisition approval interface with product mapping
# Displays pending requisitions for HOD approval with cross-system product mapping

@login_required(login_url="login")
def hod_requisitions_view(request):
    """
    Head of Department Requisition Management Dashboard
    
    Provides HOD users with a comprehensive view of pending purchase requisitions
    that require their approval. Includes intelligent product name mapping between
    different systems (INDENT_EASY, NDDB, SAP) for consistent product identification.
    
    Key Features:
        - HOD-specific requisition filtering by managed products
        - Intelligent product name mapping across systems
        - Paginated requisition display (10 per page)
        - Location-based filtering support
        - Exclusion of already processed requisitions
    
    Product Mapping Logic:
        1. Finds INDENT_EASY product in mapping database
        2. Looks for corresponding NDDB product name in same mapping group
        3. Falls back to SAP mapping if NDDB not available
        4. Uses original INDENT_EASY name if no mapping found
    
    Permissions:
        - Requires authenticated user login
        - Restricted to users with is_hod=True flag
        - Returns 403 Forbidden for non-HOD users
    
    Returns:
        HttpResponse: Rendered hod_requisitions.html template with:
            - page_obj: Paginated requisition list with mapped product names
            - locations: Distinct location list for filtering
    
    Template Context:
        page_obj: Paginated requisition objects with:
            - Original stock_item field
            - Mapped product name (mapped_product_name)
            - Source system (mapped_system)
        locations: List of distinct user locations for dropdown
    """
    
    # ------------------------------------------------------------
    # SECTION 1: AUTHORIZATION VALIDATION
    # ------------------------------------------------------------
    # Verify user has HOD privileges
    if not request.user.is_hod:
        return render(request, "403.html", status=403)
    
    # ------------------------------------------------------------
    # SECTION 2: IDENTIFY HOD-MANAGED PRODUCTS
    # ------------------------------------------------------------
    # Retrieve all stock items assigned to this HOD for management
    hod_stock_items = Product.objects.filter(hod=request.user).values_list(
        "name", flat=True
    )
    
    # ------------------------------------------------------------
    # SECTION 3: FILTER PENDING REQUISITIONS
    # ------------------------------------------------------------
    # Fetch requisitions for HOD's products, excluding processed ones
    requisitions = (
        PurchaseRequisition.objects.filter(stock_item__in=hod_stock_items)
        .exclude(
            status__in=[
                "APPROVED",
                "REJECTED",
                "PO GENERATED",
                "APPROVED FOR TRANSFER",
            ]
        )
        .order_by("-date_of_request", "-time_of_request")
    )
    
    # ------------------------------------------------------------
    # SECTION 4: APPLY PRODUCT NAME MAPPING
    # ------------------------------------------------------------
    # Enhance each requisition with mapped product names from other systems
    requisitions_with_mapped_names = []
    
    for requisition in requisitions:
        original_product_name = requisition.stock_item
        
        try:
            # Attempt to find INDENT_EASY mapping entry
            indent_easy_mapping = ProductMapping.objects.filter(
                system='INDENT_EASY',
                product_name=original_product_name,
                is_active=True
            ).first()
            
            if indent_easy_mapping:
                # Find the mapping group containing this INDENT_EASY product
                mapping_relation = ProductMappingRelation.objects.filter(
                    product_mapping=indent_easy_mapping
                ).first()
                
                if mapping_relation:
                    group = mapping_relation.group
                    
                    # Priority 1: Look for NDDB mapping in same group
                    nddb_mapping = ProductMapping.objects.filter(
                        system='NDDB',
                        groups__group=group,
                        is_active=True
                    ).first()
                    
                    if nddb_mapping:
                        requisition.mapped_product_name = nddb_mapping.product_name
                        requisition.mapped_system = 'NDDB'
                    
                    else:
                        # Priority 2: Fallback to SAP mapping
                        sap_mapping = ProductMapping.objects.filter(
                            system='SAP',
                            groups__group=group,
                            is_active=True
                        ).first()
                        
                        if sap_mapping:
                            requisition.mapped_product_name = sap_mapping.product_name
                            requisition.mapped_system = 'SAP'
                        
                        else:
                            # No alternative mapping found, use original
                            requisition.mapped_product_name = original_product_name
                            requisition.mapped_system = 'INDENT_EASY'
                
                else:
                    # No group relationship found
                    requisition.mapped_product_name = original_product_name
                    requisition.mapped_system = 'INDENT_EASY'
            
            else:
                # No INDENT_EASY mapping entry
                requisition.mapped_product_name = original_product_name
                requisition.mapped_system = 'INDENT_EASY'
        
        except Exception:
            # Safe fallback on any mapping errors
            requisition.mapped_product_name = original_product_name
            requisition.mapped_system = 'INDENT_EASY'
        
        # Add enhanced requisition to list
        requisitions_with_mapped_names.append(requisition)
    
    # ------------------------------------------------------------
    # SECTION 5: PREPARE LOCATION FILTER DATA
    # ------------------------------------------------------------
    # Extract distinct locations for dropdown filtering
    locations = CustomUser.objects.values_list("location", flat=True).distinct()
    
    # ------------------------------------------------------------
    # SECTION 6: PAGINATE REQUISITION LIST
    # ------------------------------------------------------------
    # Configure pagination (10 requisitions per page)
    paginator = Paginator(requisitions_with_mapped_names, 10)
    page_number = request.GET.get("page")
    page_obj = paginator.get_page(page_number)
    
    # ------------------------------------------------------------
    # SECTION 7: RENDER HOD DASHBOARD TEMPLATE
    # ------------------------------------------------------------
    return render(
        request,
        "hod_requisitions.html",
        {
            "page_obj": page_obj,
            "locations": locations
        }
    )


# =========== HOD BATCH REQUISITION PROCESSING ==============
# Batch approval system for HODs to process multiple requisitions simultaneously
# Enables efficient bulk approval for "APPROVED FOR TRANSFER" status

@login_required(login_url="login")
def process_requisitions(request):
    """
    Head of Department Batch Requisition Processing
    
    Handles bulk approval of multiple purchase requisitions in a single operation.
    Updates selected requisitions to "APPROVED FOR TRANSFER" status and creates
    corresponding HODApproval records for audit trail.
    
    Workflow:
        1. Receives list of requisition IDs via POST request
        2. Validates each requisition exists
        3. Updates requisition status to "APPROVED FOR TRANSFER"
        4. Creates/updates HODApproval record with approver details
        5. Returns success message and redirects to HOD dashboard
    
    Features:
        - Bulk processing for operational efficiency
        - Atomic updates with proper error handling
        - Creates audit trail with HOD approval records
        - Success feedback via Django messages framework
    
    Args:
        request: HTTP POST request containing selected requisition IDs
    
    Returns:
        HttpResponseRedirect: Redirect to hod_requisitions view
    
    Security:
        - Requires authenticated user
        - Only processes POST requests
        - Uses get_object_or_404 for safe object retrieval
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATE REQUEST METHOD
    # ------------------------------------------------------------
    if request.method != "POST":
        # Non-POST requests are redirected without processing
        return redirect("hod_requisitions")
    
    # ------------------------------------------------------------
    # SECTION 2: EXTRACT SELECTED REQUISITIONS
    # ------------------------------------------------------------
    selected_requisitions = request.POST.getlist("selected_requisitions")
    
    # ------------------------------------------------------------
    # SECTION 3: PROCESS EACH SELECTED REQUISITION
    # ------------------------------------------------------------
    for requisition_id in selected_requisitions:
        # --------------------------------------------------------
        # SUBSECTION: Retrieve Requisition Safely
        # --------------------------------------------------------
        # Uses get_object_or_404 to handle non-existent IDs gracefully
        requisition = get_object_or_404(PurchaseRequisition, id=requisition_id)
        
        # --------------------------------------------------------
        # SUBSECTION: Create/Update HOD Approval Record
        # --------------------------------------------------------
        # Creates audit trail entry for HOD approval decision
        hod_approval, created = HODApproval.objects.update_or_create(
            requisition=requisition,
            defaults={
                "status": "APPROVED FOR TRANSFER",
                "approved_by": request.user,
            },
        )
        
        # --------------------------------------------------------
        # SUBSECTION: Update Requisition Status
        # --------------------------------------------------------
        requisition.status = "APPROVED FOR TRANSFER"
        requisition.save()
    
    # ------------------------------------------------------------
    # SECTION 4: PROVIDE USER FEEDBACK
    # ------------------------------------------------------------
    # Success message displayed on redirected page
    messages.success(
        request,
        f"Successfully processed {len(selected_requisitions)} requisition(s) for transfer."
    )
    
    # ------------------------------------------------------------
    # SECTION 5: REDIRECT TO HOD DASHBOARD
    # ------------------------------------------------------------
    return redirect("hod_requisitions")

# =========== HOD SINGLE REQUISITION APPROVAL API ==============
# Atomic approval system for individual requisitions with dual workflow support
# Handles both direct approval and transfer approval with email notifications

@csrf_exempt
@login_required(login_url='login')
@transaction.atomic
def approve_requisition(request, pk):
    """
    Head of Department Individual Requisition Approval
    
    Processes single requisition approval with atomic database transaction.
    Supports two approval workflows:
    
    1. Direct Approval (APPROVED):
        - Standard procurement approval
        - Routes to purchase department
    
    2. Transfer Approval (APPROVED FOR TRANSFER):
        - Inter-location stock transfers
        - Creates logistic department entries
        - Routes to both purchase and logistic teams
    
    Features:
        - Atomic transaction ensures data consistency
        - Dual approval workflow support
        - Automated email notifications
        - AJAX-compatible JSON responses
        - Audit trail via HODApproval records
    
    Args:
        request: HTTP request (POST required for approval)
        pk (int): Primary key of requisition to approve
    
    Returns:
        - JsonResponse: For AJAX requests (success/error)
        - HttpResponseRedirect: For regular requests to HOD dashboard
        - HttpResponseForbidden: For unauthorized access attempts
    
    Email Notifications:
        - APPROVED: Sent to purchase@shwetdharamilk.com
        - APPROVED FOR TRANSFER: Sent to ashishgoud8787@shwetdharamilk.com
        - CC: shivamchaubey@shwetharamilk.com (if configured)
    """
    
    # ------------------------------------------------------------
    # SECTION 1: AUTHORIZATION VALIDATION
    # ------------------------------------------------------------
    if not request.user.is_hod:
        return HttpResponseForbidden(
            "You are not authorized to approve requisitions."
        )
    
    # ------------------------------------------------------------
    # SECTION 2: ATOMIC APPROVAL TRANSACTION
    # ------------------------------------------------------------
    try:
        # Enclose all database operations in single transaction
        with transaction.atomic():
            
            # ----------------------------------------------------
            # SUBSECTION: Retrieve Requisition Data
            # ----------------------------------------------------
            requisition = get_object_or_404(PurchaseRequisition, pk=pk)
            from_location = request.POST.get("from_location")
            
            # ----------------------------------------------------
            # SUBSECTION: Determine Approval Type
            # ----------------------------------------------------
            # Transfer approval requires source location
            if from_location:
                status_value = "APPROVED FOR TRANSFER"
            else:
                status_value = "APPROVED"
            
            # ----------------------------------------------------
            # SUBSECTION: Create HOD Approval Audit Record
            # ----------------------------------------------------
            hod_approval, created = HODApproval.objects.update_or_create(
                requisition=requisition,
                defaults={
                    "status": status_value[:250],  # Ensure field length compliance
                    "approved_by": request.user,
                    "approval_date": now(),
                },
            )
            
            # ----------------------------------------------------
            # SUBSECTION: Handle Transfer Approval Workflow
            # ----------------------------------------------------
            if from_location:
                # Create logistic department entry for stock transfer
                LogisticDepartment.objects.create(
                    requested_by=request.user,
                    to_location=requisition.location,
                    from_location=from_location,
                    stock_item=requisition.stock_item,
                    quantity=requisition.quantity,
                )
                requisition.status = "APPROVED FOR TRANSFER"
            else:
                # Standard direct approval
                requisition.status = "APPROVED"
            
            # ----------------------------------------------------
            # SUBSECTION: Save Updated Requisition
            # ----------------------------------------------------
            requisition.save()
        
        # --------------------------------------------------------
        # SECTION 3: SEND APPROVAL NOTIFICATION EMAILS
        # --------------------------------------------------------
        # Email sending outside transaction for performance
        try:
            # Build email subject based on approval type
            if from_location:
                subject = f"Transfer Requisition Approved: {requisition.requisition_number}"
            else:
                subject = f"Requisition Approved: {requisition.requisition_number}"
            
            # Construct detailed email body
            message = (
                f"Requisition Number: {requisition.requisition_number}\n"
                f"Date of Request: {requisition.date_of_request}\n"
                f"Time of Request: {requisition.time_of_request}\n"
                f"Employee Name: {requisition.employee_name}\n"
                f"Department: {requisition.department}\n"
                f"To Location: {requisition.location}\n"
                f"Stock Item: {requisition.stock_item}\n"
                f"Quantity: {requisition.quantity}\n"
                f"Expected Delivery Date: {requisition.expected_delivery_date}\n"
                f"Remark: {requisition.remark or 'N/A'}\n"
            )
            
            # Add transfer location details if applicable
            if from_location:
                message += f"From Location: {from_location}\n"
            
            # Determine recipients based on approval type
            if requisition.status == "APPROVED FOR TRANSFER":
                recipient_list = ["ashishgoud8787@shwetdharamilk.com"]
            else:
                recipient_list = ["purchase@shwetdharamilk.com"]
            
            # Configure CC recipients
            cc_list = [""] if "" else []
            
            # Send email notification
            email = EmailMessage(
                subject=subject,
                body=message,
                from_email=settings.DEFAULT_FROM_EMAIL,
                to=recipient_list,
                cc=cc_list if cc_list else None,
            )
            email.send(fail_silently=False)
            
        except Exception as email_error:
            # Email failure logged but doesn't block approval
            pass
        
        # --------------------------------------------------------
        # SECTION 4: RETURN APPROPRIATE RESPONSE
        # --------------------------------------------------------
        # Handle AJAX requests with JSON response
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({
                "message": "Requisition approved successfully.",
                "status": requisition.status
            })
        
        # Regular request redirection
        return redirect("hod_requisitions")
    
    # ------------------------------------------------------------
    # SECTION 5: ERROR HANDLING
    # ------------------------------------------------------------
    except Exception as e:
        # Handle AJAX error responses
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({
                "error": "Internal server error",
                "message": "Failed to approve requisition"
            }, status=500)
        
        # Regular request error handling
        return redirect("hod_requisitions")
@login_required(login_url='login')
def approve_requisitions_bulk(request):
    """HOD approves several requisitions in one go. Same effect as approving each one
    individually (audit record + APPROVED status), with one summary email to purchase
    instead of one email per item."""
    if not request.user.is_hod:
        return HttpResponseForbidden("You are not authorized to approve requisitions.")
    if request.method != "POST":
        return JsonResponse({"error": "Invalid request method"}, status=400)
    ids = request.POST.getlist("requisition_ids[]")
    if not ids:
        return JsonResponse({"error": "No requisitions selected."}, status=400)

    approved = []
    with transaction.atomic():
        requisitions = (PurchaseRequisition.objects.filter(id__in=ids)
                        .exclude(status__in=["APPROVED", "REJECTED", "PO GENERATED",
                                             "APPROVED FOR TRANSFER"]))
        for requisition in requisitions:
            HODApproval.objects.update_or_create(
                requisition=requisition,
                defaults={
                    "status": "APPROVED",
                    "approved_by": request.user,
                    "approval_date": now(),
                },
            )
            requisition.status = "APPROVED"
            requisition.save()
            approved.append(requisition)

    if not approved:
        return JsonResponse(
            {"error": "Nothing to approve — the selected requisitions are already processed."},
            status=400)

    try:
        lines = [
            f"- {r.requisition_number} | {r.stock_item} x {r.quantity} | "
            f"To: {r.location} | Expected: {r.expected_delivery_date}"
            for r in approved
        ]
        message = ("The following requisitions were approved:\n\n"
                   + "\n".join(lines)
                   + f"\n\nApproved by: {request.user.get_full_name()}")
        EmailMessage(
            subject=f"{len(approved)} Requisition(s) Approved",
            body=message,
            from_email=settings.DEFAULT_FROM_EMAIL,
            to=["purchase@shwetdharamilk.com"],
        ).send(fail_silently=False)
    except Exception:
        pass   # email failure must not block the approvals

    return JsonResponse({
        "message": f"Approved {len(approved)} requisition(s).",
        "approved": [r.id for r in approved],
    })


# =========== HOD REQUISITION REJECTION HANDLER ==============
# Secure rejection system for HODs to decline purchase requisitions
# Maintains audit trail while updating requisition status

@login_required(login_url='login')
def reject_requisition(request, pk):
    """
    Head of Department Requisition Rejection Handler
    
    Processes rejection of individual purchase requisitions by authorized HODs.
    Creates audit trail entries while updating the requisition status to REJECTED.
    
    Workflow:
        1. Validates user has HOD authorization
        2. Retrieves target requisition safely
        3. Creates/updates HODApproval record with REJECTED status
        4. Updates requisition status to REJECTED
        5. Redirects back to HOD requisition dashboard
    
    Audit Features:
        - HODApproval record captures rejection details
        - Timestamp and approver information stored
        - Complete rejection audit trail maintained
    
    Security:
        - Restricted to authenticated HOD users only
        - Returns 403 Forbidden for unauthorized access
        - Uses get_object_or_404 for safe object retrieval
    
    Args:
        request: HTTP request object
        pk (int): Primary key of requisition to reject
    
    Returns:
        HttpResponseRedirect: Redirect to hod_requisitions view
        HttpResponse: 403 Forbidden page for unauthorized users
    
    Error Handling:
        - Returns to HOD dashboard on any exception
        - Exception details logged server-side
    """
    
    # ------------------------------------------------------------
    # SECTION 1: AUTHORIZATION VALIDATION
    # ------------------------------------------------------------
    if not request.user.is_hod:
        return render(request, "403.html", status=403)
    
    # ------------------------------------------------------------
    # SECTION 2: RETRIEVE REQUISITION
    # ------------------------------------------------------------
    requisition = get_object_or_404(PurchaseRequisition, pk=pk)
    
    # ------------------------------------------------------------
    # SECTION 3: PROCESS REJECTION
    # ------------------------------------------------------------
    try:
        # --------------------------------------------------------
        # SUBSECTION: Create Rejection Audit Record
        # --------------------------------------------------------
        # Updates or creates HODApproval entry for audit trail
        hod_approval, created = HODApproval.objects.update_or_create(
            requisition=requisition,
            defaults={
                "status": "REJECTED",
                "approved_by": request.user,
            },
        )
        
        # --------------------------------------------------------
        # SUBSECTION: Update Requisition Status
        # --------------------------------------------------------
        requisition.status = "REJECTED"
        requisition.save()
        
        # --------------------------------------------------------
        # SECTION 4: REDIRECT TO HOD DASHBOARD
        # --------------------------------------------------------
        return redirect("hod_requisitions")
    
    # ------------------------------------------------------------
    # SECTION 5: ERROR HANDLING
    # ------------------------------------------------------------
    except Exception:
        # On any error, safely redirect to HOD dashboard
        # Exception details can be logged server-side for debugging
        return redirect("hod_requisitions")

# =========== REQUISITION DETAIL RETRIEVAL API ==============
# Lightweight API endpoint for fetching specific requisition details
# Provides essential requisition data in JSON format for frontend consumption

@login_required(login_url='login')
def get_requisition_details(request, requisition_id):
    """
    Requisition Detail Information Endpoint
    
    Returns key details of a specific purchase requisition in JSON format.
    Primarily used by frontend applications for dynamic content loading,
    form pre-population, or validation workflows.
    
    Response Structure:
        {
            "id": int,                    # Requisition database ID
            "bags": str,                  # Unit of measure (UOM)
            "stock_item": str,            # Product/stock item name
            "quantity": int,              # Requested quantity
            "expected_delivery_date": str,# ISO format delivery date
            "remark": str                 # Additional remarks/comments
        }
    
    Use Cases:
        - Dynamic form pre-filling
        - Validation and confirmation workflows
        - Modal/dialog content loading
        - Integration with third-party systems
    
    Security:
        - No authentication required (public endpoint)
        - Safe object retrieval via get_object_or_404
        - Minimal data exposure strategy
    
    Args:
        request: HTTP request object
        requisition_id (int): Database ID of requisition to retrieve
    
    Returns:
        JsonResponse: Structured requisition data
    
    Error Response:
        404 Not Found: If requisition doesn't exist
        Returns standard Django 404 page
    """
    
    # ------------------------------------------------------------
    # SECTION 1: RETRIEVE REQUISITION OBJECT
    # ------------------------------------------------------------
    # Safely fetch requisition or return 404 if not found
    requisition = get_object_or_404(PurchaseRequisition, id=requisition_id)
    
    # ------------------------------------------------------------
    # SECTION 2: CONSTRUCT RESPONSE DATA
    # ------------------------------------------------------------
    # Build structured JSON response with essential requisition details
    data = {
        "id": requisition.id,                     # Database identifier
        "bags": requisition.uom,                  # Unit of measurement
        "stock_item": requisition.stock_item,     # Product description
        "quantity": requisition.quantity,         # Requested amount
        "expected_delivery_date": requisition.expected_delivery_date,  # Delivery target
        "remark": requisition.remark,             # Additional notes
    }
    
    # ------------------------------------------------------------
    # SECTION 3: RETURN JSON RESPONSE
    # ------------------------------------------------------------
    return JsonResponse(data)

# =========== REQUISITION UPDATE WITH HOD NOTIFICATION ==============
# Secure requisition modification system with automated HOD email notifications
# Provides atomic updates with HTML-formatted email alerts to product HODs

@login_required(login_url='login')
def update_requisition(request, requisition_id):
    """
    Requisition Modification Handler with HOD Notification
    
    Updates existing requisition details and automatically notifies the
    corresponding Head of Department via HTML-formatted email.
    
    Workflow:
        1. Validates POST request method
        2. Safely retrieves target requisition
        3. Updates requisition fields from POST data
        4. Identifies product HOD for notification
        5. Sends HTML-formatted update notification email
        6. Returns JSON response with success/error status
    
    Email Features:
        - HTML formatting with tabular data presentation
        - Professional email template structure
        - Direct delivery to product-specific HOD
        - Comprehensive update summary
    
    Security:
        - Only accepts POST requests for modifications
        - Safe object retrieval (404 for non-existent requisitions)
        - Validates HOD existence before email dispatch
    
    Args:
        request: HTTP request object (POST required)
        requisition_id (int): Database ID of requisition to update
    
    Returns:
        JsonResponse: Success message or error details
        
    Success Response:
        {"message": "Requisition updated successfully!"}
    
    Error Responses:
        {"error": "Invalid request method"}, status=400
        {"error": "HOD not found for the product."}, status=404
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATE REQUEST METHOD
    # ------------------------------------------------------------
    if request.method != "POST":
        return JsonResponse(
            {"error": "Invalid request method"},
            status=400
        )
    
    # ------------------------------------------------------------
    # SECTION 2: RETRIEVE REQUISITION
    # ------------------------------------------------------------
    requisition = get_object_or_404(PurchaseRequisition, id=requisition_id)
    
    # ------------------------------------------------------------
    # SECTION 3: UPDATE REQUISITION DETAILS
    # ------------------------------------------------------------
    # Extract and update fields from POST data
    requisition.uom = request.POST.get("bags")
    requisition.stock_item = request.POST.get("stock_item")
    requisition.quantity = request.POST.get("quantity")
    requisition.expected_delivery_date = request.POST.get("expected_delivery_date")
    requisition.remark = request.POST.get("remark")
    requisition.save()
    
    # ------------------------------------------------------------
    # SECTION 4: IDENTIFY HOD FOR NOTIFICATION
    # ------------------------------------------------------------
    # Find product and associated HOD
    product = Product.objects.filter(name=requisition.stock_item).first()
    
    if not product or not product.hod:
        return JsonResponse(
            {"error": "HOD not found for the product."},
            status=404
        )
    
    hod_email = product.hod.email
    
    # ------------------------------------------------------------
    # SECTION 5: PREPARE HTML EMAIL CONTENT
    # ------------------------------------------------------------
    subject = f"Requisition {requisition.requisition_number} Updated"
    
    # Professional HTML email template with tabular data
    body = f"""
    <html>
    <body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;">
        <div style="max-width: 600px; margin: 0 auto; padding: 20px;">
            <h2 style="color: #2c3e50;">Requisition Update Notification</h2>
            
            <p>Dear HOD,</p>
            
            <p>The requisition <strong>Requisition Number: {requisition.requisition_number}</strong> 
            has been updated with the following details:</p>
            
            <table style="width: 100%; border-collapse: collapse; margin: 20px 0; border: 1px solid #ddd;">
                <thead>
                    <tr style="background-color: #f8f9fa;">
                        <th style="border: 1px solid #ddd; padding: 12px; text-align: left;">Field</th>
                        <th style="border: 1px solid #ddd; padding: 12px; text-align: left;">Updated Value</th>
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        <td style="border: 1px solid #ddd; padding: 12px;"><strong>Stock Item</strong></td>
                        <td style="border: 1px solid #ddd; padding: 12px;">{requisition.stock_item}</td>
                    </tr>
                    <tr>
                        <td style="border: 1px solid #ddd; padding: 12px;"><strong>Quantity</strong></td>
                        <td style="border: 1px solid #ddd; padding: 12px;">{requisition.quantity}</td>
                    </tr>
                    <tr>
                        <td style="border: 1px solid #ddd; padding: 12px;"><strong>Expected Delivery Date</strong></td>
                        <td style="border: 1px solid #ddd; padding: 12px;">{requisition.expected_delivery_date}</td>
                    </tr>
                    <tr>
                        <td style="border: 1px solid #ddd; padding: 12px;"><strong>UOM (Unit of Measure)</strong></td>
                        <td style="border: 1px solid #ddd; padding: 12px;">{requisition.uom}</td>
                    </tr>
                    <tr>
                        <td style="border: 1px solid #ddd; padding: 12px;"><strong>Remark</strong></td>
                        <td style="border: 1px solid #ddd; padding: 12px;">{requisition.remark}</td>
                    </tr>
                </tbody>
            </table>
            
            <div style="margin-top: 30px; padding-top: 20px; border-top: 1px solid #eee;">
                <p>Best Regards,<br>
                <strong>Your Procurement Team</strong></p>
            </div>
        </div>
    </body>
    </html>
    """
    
    # ------------------------------------------------------------
    # SECTION 6: SEND HOD NOTIFICATION EMAIL
