# =========== LOCATION-BASED INVENTORY DASHBOARD ==============
# Comprehensive inventory visualization with SAP mapping and analytics
# Provides multi-format responses (HTML/JSON) with charts and statistics

@login_required(login_url="login")
def viewInventory(request):
    """
    Location-Based Inventory Management Dashboard
    
    Displays aggregated inventory data for all users in the current user's location.
    Features include SAP product mapping, analytics dashboard, and multi-format 
    response support (HTML for full dashboard, JSON for API consumption).
    
    Core Features:
        - Location-based inventory aggregation
        - SAP product mapping integration
        - Real-time analytics and statistics
        - Stock level categorization
        - Multi-format response support (HTML/JSON)
        - Chart-ready data preparation
    
    Data Processing:
        1. Aggregates inventory quantities by product
        2. Maps products to SAP equivalents
        3. Calculates total inventory value
        4. Categorizes stock levels (High/Medium/Low)
        5. Prepares data for visualization charts
    
    Response Formats:
        HTML: Complete dashboard with charts and statistics
        JSON: Structured inventory data for API consumption
    
    Args:
        request: HTTP request with optional format parameter
    
    Returns:
        HttpResponse: Rendered inventory dashboard (HTML)
        JsonResponse: Structured inventory data (JSON/AJAX)
    """
    
    # ------------------------------------------------------------
    # SECTION 1: IDENTIFY USER LOCATION CONTEXT
    # ------------------------------------------------------------
    user_location = request.user.location
    
    # ------------------------------------------------------------
    # SECTION 2: GATHER LOCATION-SPECIFIC DATA
    # ------------------------------------------------------------
    # Retrieve all users in the same location
    users_in_same_location = CustomUser.objects.filter(location=user_location)
    
    # Identify BMC/MCC entity for the location
    try:
        user_bmc_or_mcc = BMCOrMCC.objects.get(name=user_location)
    except BMCOrMCC.DoesNotExist:
        user_bmc_or_mcc = None
    
    # ------------------------------------------------------------
    # SECTION 3: AGGREGATE INVENTORY DATA
    # ------------------------------------------------------------
    # Aggregate inventory quantities with product details
    inventory_queryset = (
        Inventory.objects.filter(mcc_bmc_user__in=users_in_same_location)
        .values(
            "product__id",
            "product__name",
            "product__size",
            "product__product_code",
            "product__price",
            "product__uom",
            "product__material_type"
        )
        .annotate(total_quantity=Sum("quantity"))
        .annotate(expired_qty=Sum("expired_quantity"))
        .annotate(damaged_qty=Sum("damaged_quantity"))
        .annotate(scrapped_qty=Sum("scrap_quantity"))
        .annotate(value=Sum(F('quantity') * F('product__price')))
        .order_by("product__name")
    )
    
    # ------------------------------------------------------------
    # SECTION 4: ENRICH WITH SAP PRODUCT MAPPING
    # ------------------------------------------------------------
    inventory_list = []
    for item in inventory_queryset:
        # Retrieve SAP mapping information
        sap_mapping_info = get_sap_mapped_product_info(item['product__name'])

        # Create enhanced inventory item
        inventory_item = dict(item)
        inventory_item['sap_mapped_product'] = sap_mapping_info['mapped_product_name']
        inventory_item['sap_mapped_system'] = sap_mapping_info['mapped_system']
        inventory_item['trend'] = 5  # Placeholder trend value
        # Normalise condition counts (Sum can return None when empty)
        inventory_item['expired_qty'] = item.get('expired_qty') or 0
        inventory_item['damaged_qty'] = item.get('damaged_qty') or 0
        inventory_item['scrapped_qty'] = item.get('scrapped_qty') or 0

        inventory_list.append(inventory_item)

    # Flagged stock — products that currently hold expired or damaged units.
    flagged_items = [
        it for it in inventory_list
        if it['expired_qty'] > 0 or it['damaged_qty'] > 0
    ]
    flagged_items.sort(key=lambda x: (x['expired_qty'] + x['damaged_qty']), reverse=True)

    # Location-wide condition totals
    total_good = sum(it['total_quantity'] for it in inventory_list)
    total_expired = sum(it['expired_qty'] for it in inventory_list)
    total_damaged = sum(it['damaged_qty'] for it in inventory_list)
    total_scrapped = sum(it['scrapped_qty'] for it in inventory_list)
    
    # ------------------------------------------------------------
    # SECTION 5: HANDLE JSON/AJAX REQUESTS
    # ------------------------------------------------------------
    # Support both AJAX headers and explicit format parameter
    if (request.headers.get('X-Requested-With') == 'XMLHttpRequest' or 
        request.GET.get('format') == 'json'):
        
        return JsonResponse({
            'inventory': inventory_list,
            'user_bmc_or_mcc': user_bmc_or_mcc.name if user_bmc_or_mcc else None
        })
    
    # ------------------------------------------------------------
    # SECTION 6: PREPARE DASHBOARD ANALYTICS
    # ------------------------------------------------------------
    # Extract distinct UOM (Unit of Measure) options
    uom_choices = list(set(
        item['product__size'] for item in inventory_list 
        if item['product__size']
    ))
    
    # Organize products by size for filtering
    products_by_size = {}
    for item in inventory_list:
        size = item['product__size'] or 'N/A'
        if size not in products_by_size:
            products_by_size[size] = []
        products_by_size[size].append(item['product__name'])
    
    # ------------------------------------------------------------
    # SECTION 7: CALCULATE KEY METRICS
    # ------------------------------------------------------------
    # Total quantity across all inventory items
    total_quantity = sum(item['total_quantity'] for item in inventory_list)
    
    # Stock level categorization
    high_stock_count = sum(1 for item in inventory_list if item['total_quantity'] > 100)
    medium_stock_count = sum(1 for item in inventory_list if 20 < item['total_quantity'] <= 100)
    low_stock_count = sum(1 for item in inventory_list if item['total_quantity'] <= 20)
    
    # Identify top products for visualization
    top_products = sorted(inventory_list, key=lambda x: x['total_quantity'], reverse=True)[:10]
    product_names = [item['product__name'] for item in top_products]
    product_quantities = [item['total_quantity'] for item in top_products]
    
    # Calculate total inventory value
    total_value = sum(item['value'] or 0 for item in inventory_list)
    
    # Average trend (placeholder for actual trend calculation)
    avg_trend = 5
    
    # ------------------------------------------------------------
    # SECTION 7b: CURRENT USER'S OWN STOCK (for condition adjustments)
    # ------------------------------------------------------------
    # The table shows location-aggregated stock, but a user may only adjust the
    # stock held on THEIR own account. Expose their own good/expired/damaged
    # per product so the Adjust modal can cap quantities correctly.
    own_inventory = {}
    for inv in Inventory.objects.filter(mcc_bmc_user=request.user).select_related("product"):
        if not inv.product:
            continue
        own_inventory[inv.product_id] = {
            "good": inv.quantity,
            "expired": inv.expired_quantity,
            "damaged": inv.damaged_quantity,
        }

    # ------------------------------------------------------------
    # SECTION 8: PREPARE TEMPLATE CONTEXT
    # ------------------------------------------------------------
    context = {
        # Core inventory data
        "inventory": inventory_list,
        "own_inventory_json": json.dumps(own_inventory),

        # Stock condition overview
        "flagged_items": flagged_items,
        "flagged_count": len(flagged_items),
        "total_good": total_good,
        "total_expired": total_expired,
        "total_damaged": total_damaged,
        "total_scrapped": total_scrapped,
        
        # Filtering and organization
        "uom_choices": sorted(uom_choices),
        "products_by_size_json": json.dumps(products_by_size),
        
        # Location context
        "user_bmc_or_mcc": user_bmc_or_mcc,
        
        # Analytics and metrics
        "total_quantity": total_quantity,
        "high_stock_count": high_stock_count,
        "medium_stock_count": medium_stock_count,
        "low_stock_count": low_stock_count,
        "total_value": total_value,
        "avg_trend": avg_trend,
        
        # Chart data
        "product_names": json.dumps(product_names),
        "product_quantities": json.dumps(product_quantities),
    }
    
    # ------------------------------------------------------------
    # SECTION 9: RENDER INVENTORY DASHBOARD
    # ------------------------------------------------------------
    return render(request, "inventory.html", context)


@login_required(login_url="login")
def adjust_inventory(request):
    """
    Adjust the current user's OWN stock condition (one-way Good -> bad, or
    dispose/scrap with mandatory proof). AJAX/JSON endpoint used by the inventory
    page's Adjust modal.

    POST params:
      product_id : Product to adjust (must be in the user's own inventory)
      action     : MARK_EXPIRED | MARK_DAMAGED | DISPOSE
      quantity   : positive integer
      source     : (DISPOSE only) GOOD | EXPIRED | DAMAGED — bucket to scrap from
      notes      : optional reason
      proof      : (DISPOSE only) image file — required
    """

    if request.method != "POST":
        return JsonResponse({"success": False, "error": "Invalid request method."}, status=405)

    action = (request.POST.get("action") or "").strip().upper()
    if action not in {"MARK_EXPIRED", "MARK_DAMAGED", "DISPOSE"}:
        return JsonResponse({"success": False, "error": "Unknown action."}, status=400)

    try:
        quantity = int(float(request.POST.get("quantity", "")))
    except (ValueError, TypeError):
        return JsonResponse({"success": False, "error": "Enter a valid quantity."}, status=400)
    if quantity <= 0:
        return JsonResponse({"success": False, "error": "Quantity must be greater than zero."}, status=400)

    product = Product.objects.filter(id=request.POST.get("product_id")).first()
    if product is None:
        return JsonResponse({"success": False, "error": "Product not found."}, status=404)

    # Only the user's OWN inventory row may be adjusted.
    inv = Inventory.objects.filter(mcc_bmc_user=request.user, product=product).first()
    if inv is None:
        return JsonResponse(
            {"success": False, "error": f"You hold no stock of '{product.name}' to adjust."},
            status=400,
        )

    proof_file = request.FILES.get("proof")
    notes = (request.POST.get("notes") or "").strip()

    try:
        with transaction.atomic():
            inv = Inventory.objects.select_for_update().get(pk=inv.pk)

            if action in {"MARK_EXPIRED", "MARK_DAMAGED"}:
                # One-way: move usable (Good) stock into the condition bucket.
                if quantity > inv.quantity:
                    raise ValueError(
                        f"You have only {inv.quantity} usable unit(s) of '{product.name}'."
                    )
                good_before = inv.quantity
                inv.quantity -= quantity
                if action == "MARK_EXPIRED":
                    inv.expired_quantity += quantity
                    bucket_label = "Expired"
                    hist_action = "EXPIRED"
                else:
                    inv.damaged_quantity += quantity
                    bucket_label = "Damaged"
                    hist_action = "DAMAGED"
                inv.save(update_fields=["quantity", "expired_quantity", "damaged_quantity"])

                InventoryHistory.objects.create(
                    inventory=inv, action=hist_action,
                    quantity_change=-quantity, previous_quantity=good_before,
                    new_quantity=inv.quantity, reference_number="",
                    notes=f"Marked {quantity} as {bucket_label}. {notes}".strip(),
                    performed_by=request.user,
                )
                InventoryAdjustment.objects.create(
                    inventory=inv, product=product, performed_by=request.user,
                    location=request.user.location or "", action=action,
                    source_condition="GOOD", quantity=quantity, notes=notes,
                )
                msg = f"Marked {quantity} unit(s) of '{product.name}' as {bucket_label}."

            else:  # DISPOSE / Scrap — removes from inventory, proof required
                source = (request.POST.get("source") or "GOOD").strip().upper()
                if source not in Inventory.CONDITION_FIELDS:
                    raise ValueError("Invalid source bucket to dispose from.")
                if proof_file is None:
                    raise ValueError("A proof photo is required to dispose/scrap stock.")

                field = Inventory.CONDITION_FIELDS[source]
                available = getattr(inv, field)
                if quantity > available:
                    raise ValueError(
                        f"You have only {available} {source.title()} unit(s) of '{product.name}' to dispose."
                    )
                setattr(inv, field, available - quantity)
                inv.scrap_quantity += quantity
                inv.save(update_fields=[field, "scrap_quantity"])

                adj = InventoryAdjustment.objects.create(
                    inventory=inv, product=product, performed_by=request.user,
                    location=request.user.location or "", action="DISPOSE",
                    source_condition=source, quantity=quantity, proof=proof_file, notes=notes,
                )
                # History reflects the disposed (burned/dumped) units leaving the
                # source bucket — shown as a DISPOSED action.
                InventoryHistory.objects.create(
                    inventory=inv, action="DISPOSED",
                    quantity_change=-quantity,
                    previous_quantity=available, new_quantity=available - quantity,
                    reference_number=f"DISPOSAL-{adj.id}",
                    notes=f"Disposed/scrapped {quantity} from {source.title()} (proof attached). {notes}".strip(),
                    performed_by=request.user,
                )
                msg = f"Disposed {quantity} {source.title()} unit(s) of '{product.name}'."
    except (ValueError, ValidationError) as exc:
        return JsonResponse({"success": False, "error": str(exc)}, status=400)

    return JsonResponse({
        "success": True,
        "message": msg,
        "own": {
            "good": inv.quantity,
            "expired": inv.expired_quantity,
            "damaged": inv.damaged_quantity,
        },
    })
# =========== PRODUCT DETAIL RETRIEVAL API ==============
# Comprehensive product information endpoint with inventory analytics
# Provides detailed product data including inventory levels, history, and stock status

@login_required(login_url='login')
def get_product_details(request, product_id):
    """
    Product Detail Information and Analytics API
    
    Retrieves comprehensive product information including:
    - Basic product attributes and specifications
    - Location-based inventory aggregation
    - Stock status classification
    - Recent transaction history
    - Value calculations
    
    Data Sources:
        1. Product master data (Product model)
        2. Location-specific inventory aggregation
        3. Recent inventory transaction history
        4. Stock status classification based on quantity thresholds
    
    Stock Classification:
        - High Stock: > 100 units
        - Medium Stock: 21-100 units
        - Low Stock: ≤ 20 units
    
    Response Formats:
        JSON: Structured product details with success/error status
    
    Args:
        request: HTTP GET request
        product_id (int): Database ID of the product to retrieve
    
    Returns:
        JsonResponse: Comprehensive product data with appropriate HTTP status codes
    
    Success Response (200):
        {
            "success": true,
            "product": {...},
            "inventory": {...},
            "recent_history": [...],
            "last_updated": "2024-01-15 14:30"
        }
    
    Error Responses:
        404: Product not found
        405: Invalid request method
        500: Internal server error
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATE REQUEST METHOD
    # ------------------------------------------------------------
    if request.method != 'GET':
        return JsonResponse({
            'success': False,
            'error': 'Invalid request method'
        }, status=405)
    
    # ------------------------------------------------------------
    # SECTION 2: RETRIEVE AND PROCESS PRODUCT DATA
    # ------------------------------------------------------------
    try:
        # --------------------------------------------------------
        # SUBSECTION: Retrieve Product Master Data
        # --------------------------------------------------------
        product = Product.objects.get(id=product_id)
        
        # --------------------------------------------------------
        # SUBSECTION: Calculate Location-Based Inventory
        # --------------------------------------------------------
        # Identify users in the same location as requester
        user_location = request.user.location
        users_in_same_location = CustomUser.objects.filter(location=user_location)
        
        # Aggregate inventory data for the product across location
        inventory_data = Inventory.objects.filter(
            product=product,
            mcc_bmc_user__in=users_in_same_location
        ).aggregate(
            total_quantity=Sum('quantity'),
            total_value=Sum(F('quantity') * F('product__price'))
        )
        
        # --------------------------------------------------------
        # SUBSECTION: Retrieve Recent Transaction History
        # --------------------------------------------------------
        recent_history = InventoryHistory.objects.filter(
            inventory__product=product,
            inventory__mcc_bmc_user__in=users_in_same_location
        ).select_related('performed_by').order_by('-created_at')[:10]
        
        # Format history data for frontend consumption
        history_data = []
        for history in recent_history:
            history_data.append({
                'date': history.created_at.strftime('%Y-%m-%d %H:%M'),
                'action': history.action,
                'quantity_change': f"{history.quantity_change:+d}",
                'previous_quantity': history.previous_quantity,
                'new_quantity': history.new_quantity,
                'reference_number': history.reference_number or 'N/A',
                'performed_by': f"{history.performed_by.first_name} {history.performed_by.last_name}",
                'notes': history.notes or ''
            })
        
        # --------------------------------------------------------
        # SUBSECTION: Determine Stock Status
        # --------------------------------------------------------
        total_quantity = inventory_data['total_quantity'] or 0
        
        if total_quantity > 100:
            stock_status = 'High Stock'
            status_class = 'high'
        elif total_quantity > 20:
            stock_status = 'Medium Stock'
            status_class = 'medium'
        else:
            stock_status = 'Low Stock'
            status_class = 'low'
        
        # --------------------------------------------------------
        # SECTION 3: CONSTRUCT COMPREHENSIVE RESPONSE
        # --------------------------------------------------------
        return JsonResponse({
            'success': True,
            'product': {
                'id': product.id,
                'name': product.name,
                'product_code': product.product_code or 'N/A',
                'size': product.size or 'N/A',
                'material_type': product.material_type or 'N/A',
                'uom': product.uom or 'N/A',
                'price': float(product.price) if product.price else 0.0,
                'is_active': product.is_active
            },
            'inventory': {
                'total_quantity': total_quantity,
                'total_value': float(inventory_data['total_value']) if inventory_data['total_value'] else 0.0,
                'stock_status': stock_status,
                'status_class': status_class
            },
            'recent_history': history_data,
            'last_updated': recent_history[0].created_at.strftime('%Y-%m-%d %H:%M') if recent_history else 'Never'
        })
    
    # ------------------------------------------------------------
    # SECTION 4: ERROR HANDLING
    # ------------------------------------------------------------
    except Product.DoesNotExist:
        return JsonResponse({
            'success': False,
            'error': 'Product not found'
        }, status=404)
    
    except Exception:
        return JsonResponse({
            'success': False,
            'error': 'Error fetching product details'
        }, status=500)

# =========== PRODUCT HISTORY ANALYTICS API ==============
# Time-series product inventory tracking with chart-ready data
# Provides historical inventory trends with configurable time periods

@login_required(login_url='login')
def get_product_history(request, product_id):
    """
    Product Inventory History and Trend Analysis API
    
    Retrieves historical inventory data for a specific product with:
    - Configurable time periods (default: 30 days)
    - Chart-ready time-series data for visualization
    - Detailed transaction history with audit trail
    - Location-based inventory aggregation
    
    Features:
        1. Time-period configuration via query parameter
        2. Daily aggregation for trend visualization
        3. Detailed transaction audit trail
        4. Fallback to current inventory when no history exists
        5. Comprehensive error handling
    
    Data Processing:
        - Groups inventory changes by day for chart data
        - Provides detailed transaction-level information
        - Calculates quantity deltas and trends
        - Formats data for frontend chart libraries
    
    Args:
        request: HTTP GET request with optional 'period' parameter
        product_id (int): Database ID of the product
    
    Query Parameters:
        period: Number of days to retrieve history for (default: 30)
    
    Returns:
        JsonResponse: Historical data with chart and detailed information
    
    Success Response (200):
        {
            "success": true,
            "product_name": "Product Name",
            "chart_data": {
                "labels": ["2024-01-01", ...],
                "quantities": [150, ...]
            },
            "detailed_history": [...],
            "period": 30,
            "total_records": 25
        }
    
    Error Responses:
        404: Product not found
        405: Invalid request method
        500: Internal server error
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATE REQUEST METHOD
    # ------------------------------------------------------------
    if request.method != 'GET':
        return JsonResponse({
            'success': False,
            'error': 'Invalid request method'
        }, status=405)
    
    # ------------------------------------------------------------
    # SECTION 2: PARSE TIME PERIOD PARAMETER
    # ------------------------------------------------------------
    period = request.GET.get('period', '30')  # Default to 30 days
    
    try:
        period_days = int(period)
    except ValueError:
        period_days = 30  # Fallback to default on invalid input
    
    # ------------------------------------------------------------
    # SECTION 3: RETRIEVE HISTORICAL DATA
    # ------------------------------------------------------------
    try:
        # --------------------------------------------------------
        # SUBSECTION: Retrieve Product Master Record
        # --------------------------------------------------------
        product = Product.objects.get(id=product_id)
        
        # --------------------------------------------------------
        # SUBSECTION: Calculate Date Range
        # --------------------------------------------------------
        end_date = timezone.now()
        start_date = end_date - timezone.timedelta(days=period_days)
        
        # --------------------------------------------------------
        # SUBSECTION: Gather Location Context
        # --------------------------------------------------------
        user_location = request.user.location
        users_in_same_location = CustomUser.objects.filter(location=user_location)
        
        # --------------------------------------------------------
        # SUBSECTION: Retrieve Historical Records
        # --------------------------------------------------------
        history_data = InventoryHistory.objects.filter(
            inventory__product=product,
            inventory__mcc_bmc_user__in=users_in_same_location,
            created_at__range=[start_date, end_date]
        ).select_related('performed_by').order_by('created_at')
        
        # --------------------------------------------------------
        # SUBSECTION: Prepare Chart Data (Daily Aggregation)
        # --------------------------------------------------------
        chart_data = []
        chart_labels = []
        
        # Group historical data by day for trend visualization
        daily_data = {}
        for history in history_data:
            date_str = history.created_at.strftime('%Y-%m-%d')
            # Track the latest quantity for each day
            daily_data[date_str] = history.new_quantity
        
        # Convert grouped data to sorted lists for charting
        for date_str, quantity in sorted(daily_data.items()):
            chart_labels.append(date_str)
            chart_data.append(quantity)
        
        # --------------------------------------------------------
        # SUBSECTION: Handle No History Scenario
        # --------------------------------------------------------
        # Fallback to current inventory if no historical data exists
        if not chart_data:
            current_inventory = Inventory.objects.filter(
                product=product,
                mcc_bmc_user__in=users_in_same_location
            ).aggregate(total_quantity=Sum('quantity'))
            
            if current_inventory['total_quantity']:
                chart_data = [current_inventory['total_quantity']]
                chart_labels = [end_date.strftime('%Y-%m-%d')]
        
        # --------------------------------------------------------
        # SUBSECTION: Prepare Detailed Transaction History
        # --------------------------------------------------------
        detailed_history = []
        for history in history_data.order_by('-created_at'):
            detailed_history.append({
                'date': history.created_at.strftime('%Y-%m-%d %H:%M'),
                'action': history.get_action_display(),
                'quantity_change': history.quantity_change,
                'previous_quantity': history.previous_quantity,
                'new_quantity': history.new_quantity,
                'reference_number': history.reference_number or 'N/A',
                'performed_by': f"{history.performed_by.first_name} {history.performed_by.last_name}",
                'notes': history.notes or ''
            })
        
        # --------------------------------------------------------
        # SECTION 4: CONSTRUCT COMPREHENSIVE RESPONSE
        # --------------------------------------------------------
        return JsonResponse({
            'success': True,
            'product_name': product.name,
            'chart_data': {
                'labels': chart_labels,
                'quantities': chart_data
            },
            'detailed_history': detailed_history,
            'period': period_days,
            'total_records': len(detailed_history)
        })
    
    # ------------------------------------------------------------
    # SECTION 5: ERROR HANDLING
    # ------------------------------------------------------------
    except Product.DoesNotExist:
        return JsonResponse({
            'success': False,
            'error': 'Product not found'
        }, status=404)
    
    except Exception:
        return JsonResponse({
            'success': False,
            'error': 'Error fetching product history'
        }, status=500)
# =========== LOCATION-SPECIFIC INVENTORY API ==============
# Location-based inventory analytics and summary endpoint
# Provides aggregated inventory data with statistical analysis for specified locations

@login_required(login_url='login')
def get_inventory_by_location(request):
    """
    Location-Based Inventory Aggregation and Analytics API
    
    Retrieves and analyzes inventory data for a specific location with:
    - Comprehensive product-level inventory details
    - Statistical summaries and metrics
    - Stock level categorization
    - Value calculations
    
    Features:
        1. Location-specific inventory filtering
        2. Product aggregation across users in location
        3. Value calculation using product pricing
        4. Stock level classification (High/Medium/Low)
        5. Comprehensive summary statistics
    
    Stock Classification Criteria:
        - High Stock: > 100 units
        - Medium Stock: 21-100 units
        - Low Stock: ≤ 20 units
    
    Query Parameters:
        location (required): Name of the location to retrieve inventory for
    
    Args:
        request: HTTP GET request with 'location' parameter
    
    Returns:
        JsonResponse: Structured inventory data with summary statistics
    
    Success Response (200):
        {
            "inventory": [...],
            "summary": {
                "total_products": 25,
                "total_items": 1500,
                "total_value": 75000.00,
                "high_stock_count": 10,
                "medium_stock_count": 10,
                "low_stock_count": 5
            },
            "location": "Mumbai"
        }
    
    Error Responses:
        400: Missing location parameter
        405: Invalid request method
        500: Internal server error
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATE REQUEST METHOD
    # ------------------------------------------------------------
    if request.method != 'GET':
        return JsonResponse({
            'error': 'Invalid request method'
        }, status=405)
    
    # ------------------------------------------------------------
    # SECTION 2: EXTRACT AND VALIDATE LOCATION PARAMETER
    # ------------------------------------------------------------
    location = request.GET.get('location', '').strip()
    
    if not location:
        return JsonResponse({
            'error': 'Location parameter is required'
        }, status=400)
    
    # ------------------------------------------------------------
    # SECTION 3: RETRIEVE LOCATION-SPECIFIC INVENTORY
    # ------------------------------------------------------------
    try:
        # --------------------------------------------------------
        # SUBSECTION: Aggregate Inventory Data
        # --------------------------------------------------------
        # Retrieve and aggregate inventory for the specified location
        inventory_data = Inventory.objects.filter(
             mcc_bmc_user__location=location
        ).values(
            'product__name',
            'product__material_type',
            'product__price',
            'product__size',
            'product__product_code'
        ).annotate(
            total_quantity=Sum('quantity'),
            value=Sum(F('quantity') * F('product__price'))
        ).order_by('product__name')
        
        # --------------------------------------------------------
        # SUBSECTION: Convert QuerySet to Serializable List
        # --------------------------------------------------------
        inventory_list = list(inventory_data)
        
        # --------------------------------------------------------
        # SUBSECTION: Calculate Summary Statistics
        # --------------------------------------------------------
        # Total quantity of all items
        total_items = sum(item['total_quantity'] for item in inventory_list)
        
        # Total monetary value of inventory
        total_value = sum(item['value'] for item in inventory_list if item['value'])
        
        # --------------------------------------------------------
        # SUBSECTION: Categorize Stock Levels
        # --------------------------------------------------------
        high_stock = 0
        medium_stock = 0
        low_stock = 0
        
        for item in inventory_list:
            quantity = item['total_quantity']
            
            if quantity > 100:
                high_stock += 1
            elif quantity > 20:
                medium_stock += 1
            else:
                low_stock += 1
        
        # --------------------------------------------------------
        # SECTION 4: CONSTRUCT COMPREHENSIVE RESPONSE
        # --------------------------------------------------------
        return JsonResponse({
            'inventory': inventory_list,
            'summary': {
                'total_products': len(inventory_list),
                'total_items': total_items,
                'total_value': total_value,
                'high_stock_count': high_stock,
                'medium_stock_count': medium_stock,
                'low_stock_count': low_stock
            },
            'location': location
        })
    
    # ------------------------------------------------------------
    # SECTION 5: ERROR HANDLING
    # ------------------------------------------------------------
    except Exception:
        return JsonResponse({
            'error': 'Error fetching inventory data'
        }, status=500)
