# =========== PURCHASE DEPARTMENT REQUISITION MANAGEMENT VIEW ==============
# Purchase department interface for managing HOD-approved requisitions with PO generation
# Handles purchase order creation, vendor selection, and product mapping integration

# =========== UPDATED PURCHASE REQUISITION VIEW ==============

@login_required(login_url="login")
def view_purchase_requisitions(request):
    """
    Updated view with SAP PO dropdown integration
    SAP PO can be reused across multiple requisitions
    """
    if not request.user.is_authenticated:
        return redirect("login")

    if not hasattr(request.user, "is_purchase") or not request.user.is_purchase:
        return render(request, "403.html", status=403)

    # ================= AJAX HANDLING =================
    if request.headers.get('x-requested-with') == 'XMLHttpRequest':
        if request.method == 'POST' and 'file' in request.FILES:
            return upload_po_excel_from_sap(request)
        elif request.method == 'GET' and 'requisition_id' in request.GET:
            return get_sap_pos_for_requisition(request)

    # ================= HELPER FUNCTION FOR REMARK VALIDATION =================
    def is_internal_suppression_remark(remark):
        """
        Check if the remark contains the internal suppression instruction.
        
        Args:
            remark (str): The remark text to check
            
        Returns:
            bool: True if remark contains internal suppression instruction
        """
        if not remark:
            return False
            
        
        # Normalize the string for comparison
        normalized = normalize('NFKD', str(remark).strip())
        
        # Replace smart quotes with straight quotes
        normalized = normalized.replace('"', "'")
        normalized = normalized.replace('"', "'")
        normalized = normalized.replace('"', "'")
        normalized = normalized.replace('"', "'")
        
        # Collapse multiple spaces and normalize whitespace
        normalized = re.sub(r'\s+', ' ', normalized)
        
        # Trim again after normalization
        normalized = normalized.strip().lower()
        
        # Define the canonical suppression string (case-insensitive)
        suppression_string = "please don't mail to vendor"
        
        # Check if the normalized remark contains the suppression string
        return suppression_string in normalized

    # ================= PO GENERATION =================
    if request.method == "POST":
        po_number = request.POST.get("po_number")
        party_name = request.POST.get("party_name")
        email = request.POST.get("email")
        requisition_id = request.POST.get("requisition_id")
        sap_po_selected = request.POST.get("sap_po_selected", "false") == "true"
        sap_po_id = request.POST.get("sap_po_id")

        if not requisition_id:
            return redirect("view_purchase_requisitions")

        try:
            requisition = PurchaseRequisition.objects.get(id=requisition_id)

            hod_approval = HODApproval.objects.filter(
                requisition=requisition,
                status="APPROVED"
            ).first()

            if not hod_approval or requisition.status == "PO GENERATED":
                return redirect("view_purchase_requisitions")

            # ========== SAP PO VALIDATION (NO is_used UPDATE) ==========
            if sap_po_selected and sap_po_id:
                try:
                    sap_po = SAPMaterialPOMapping.objects.get(id=sap_po_id)

                    # Resolve requisition product group
                    product_group = None
                    indent_mapping = ProductMapping.objects.filter(
                        system='INDENT_EASY',
                        product_name__iexact=requisition.stock_item,
                        is_active=True
                    ).first()

                    if indent_mapping:
                        relation = ProductMappingRelation.objects.filter(
                            product_mapping=indent_mapping
                        ).first()
                        if relation and relation.group:
                            product_group = relation.group

                    # Validate group match
                    if product_group and sap_po.product_group != product_group:
                        messages.error(
                            request,
                            "Selected SAP PO does not match the product group"
                        )
                        return redirect("view_purchase_requisitions")

                    # ✅ AUDIT ONLY (DO NOT SET is_used = True)
                    sap_po.used_in_requisition = requisition
                    sap_po.used_by = request.user
                    sap_po.used_at = timezone.now()
                    sap_po.save(update_fields=[
                        'used_in_requisition',
                        'used_by',
                        'used_at'
                    ])

                except SAPMaterialPOMapping.DoesNotExist:
                    messages.error(request, "Selected SAP PO not found")
                    return redirect("view_purchase_requisitions")

            # ========== PO NUMBER GENERATION ==========
            unique_id = uuid.uuid4()
            po_number_with_unique_id = f"{po_number}:{unique_id}"

            with transaction.atomic():
                requisition.po_number = po_number_with_unique_id
                requisition.status = "PO GENERATED"
                requisition.save()

                # ========== BUSINESS CRITICAL: CHECK FOR INTERNAL SUPPRESSION REMARK ==========
                # Check if remark contains "Please Don't Mail To Vendor"
                is_suppressed_remark = is_internal_suppression_remark(requisition.remark)
                
                # Create PurchaseDepartment with mail_sent = True if suppressed remark found
                PurchaseDepartment.objects.create(
                    requisition=requisition,
                    po_number=po_number_with_unique_id,
                    po_generated_by=request.user,
                    po_generation_date=timezone.now(),
                    party_name=party_name,
                    email=email,
                    mail_sent=is_suppressed_remark  # Automatically mark as sent if suppressed
                )
                
                # Log the suppression for audit trail
                if is_suppressed_remark:
                    print(f"SUPPRESSION: Auto-set mail_sent=True for requisition {requisition.requisition_number}")
                    print(f"REASON: Remark contains internal suppression instruction: '{requisition.remark}'")

            messages.success(
                request,
                f"PO generated successfully: {po_number}"
            )
            return redirect("view_purchase_requisitions")

        except PurchaseRequisition.DoesNotExist:
            return redirect("view_purchase_requisitions")

    # ================= FETCH REQUISITIONS =================
    requisitions = (
        PurchaseRequisition.objects.filter(
            Q(status="APPROVED") | Q(status="PO GENERATED"),
            hodapproval__status="APPROVED",
        )
        .annotate(
            status_order=Case(
                When(status="APPROVED", then=Value(0)),
                When(status="PO GENERATED", then=Value(1)),
                default=Value(2),
                output_field=IntegerField(),
            )
        )
        .order_by("status_order", "-created_at")
    )

    # ================= PREFETCH PRODUCT MAPPINGS =================
    product_names = list(
        requisitions.values_list('stock_item', flat=True).distinct()
    )

    indent_mappings = ProductMapping.objects.filter(
        system='INDENT_EASY',
        product_name__in=product_names,
        is_active=True
    ).prefetch_related('groups__group__mappings__product_mapping')

    product_mapping_dict = {
        mapping.product_name: mapping for mapping in indent_mappings
    }

    # ================= ENRICH REQUISITIONS =================
    for requisition in requisitions:
        hod_approval = HODApproval.objects.filter(
            requisition=requisition,
            status="APPROVED"
        ).first()

        requisition.hod_name = (
            hod_approval.approved_by.get_full_name()
            if hod_approval and hod_approval.approved_by
            else "Not Approved"
        )

        try:
            product = Product.objects.get(name=requisition.stock_item)
            vendors = ProductVendor.objects.filter(product=product)
            requisition.product_vendors = [{
                "product": product.name,
                "vendors": [v.vendor.name for v in vendors]
            }]
        except Product.DoesNotExist:
            requisition.product_vendors = []

        original_product_name = requisition.stock_item

        if original_product_name in product_mapping_dict:
            indent_mapping = product_mapping_dict[original_product_name]
            relation = indent_mapping.groups.first()

            if relation:
                group = relation.group

                nddb_mapping = group.mappings.filter(
                    product_mapping__system='NDDB',
                    product_mapping__is_active=True
                ).first()

                if nddb_mapping:
                    requisition.mapped_product_name = nddb_mapping.product_mapping.product_name
                    requisition.mapped_system = 'NDDB'
                else:
                    sap_mapping = group.mappings.filter(
                        product_mapping__system='SAP',
                        product_mapping__is_active=True
                    ).first()

                    if sap_mapping:
                        requisition.mapped_product_name = sap_mapping.product_mapping.product_name
                        requisition.mapped_system = 'SAP'
                    else:
                        requisition.mapped_product_name = original_product_name
                        requisition.mapped_system = 'INDENT_EASY'
            else:
                requisition.mapped_product_name = original_product_name
                requisition.mapped_system = 'INDENT_EASY'
        else:
            requisition.mapped_product_name = original_product_name
            requisition.mapped_system = 'INDENT_EASY'

    return render(
        request,
        "purchase_requisition.html",
        {"requisitions": requisitions},
    )




# =========== VENDOR EMAIL RETRIEVAL API ==============
# Vendor contact information lookup endpoint
# Provides email address retrieval for vendor-based communications

@login_required(login_url='login')
def get_vendor_email(request):
    """
    Vendor Email Address Lookup API
    
    Retrieves and returns email addresses associated with a specific vendor.
    Supports comma-separated email lists for multiple contact addresses.
    
    Use Cases:
        - Purchase order email notifications
        - Vendor communication automation
        - Email pre-filling in forms
        - Vendor contact information validation
    
    Features:
        - Exact vendor name matching (case-sensitive)
        - Support for multiple comma-separated emails
        - Comprehensive error handling with appropriate HTTP status codes
        - Clean email list processing with whitespace trimming
    
    Args:
        request: HTTP GET request with 'vendor_name' parameter
    
    Query Parameters:
        vendor_name: Name of the vendor to retrieve email for (required)
    
    Returns:
        JsonResponse: Email address(es) or error message
    
    Success Response (200):
        {
            "email": ["vendor@example.com", "contact@vendor.com"]
        }
    
    Error Responses:
        404: Vendor not found or no email associated
        405: Invalid request method
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATE REQUEST METHOD
    # ------------------------------------------------------------
    if request.method != "GET":
        return JsonResponse(
            {"error": "Invalid request method"}, 
            status=405
        )
    
    # ------------------------------------------------------------
    # SECTION 2: EXTRACT VENDOR NAME PARAMETER
    # ------------------------------------------------------------
    vendor_name = request.GET.get("vendor_name")
    
    # ------------------------------------------------------------
    # SECTION 3: RETRIEVE VENDOR EMAIL INFORMATION
    # ------------------------------------------------------------
    # Search for vendor by exact name match
    vendors = Vendor.objects.filter(name=vendor_name)
    
    # ------------------------------------------------------------
    # SECTION 4: PROCESS VENDOR EXISTENCE CHECK
    # ------------------------------------------------------------
    if vendors.exists():
        # Retrieve the first matching vendor
        vendor = vendors.first()
        email = vendor.email
        
        # --------------------------------------------------------
        # SUBSECTION: Process Email Data
        # --------------------------------------------------------
        if email:
            # Split comma-separated emails and clean whitespace
            email_list = [email.strip() for email in email.split(",")]
            
            return JsonResponse({"email": email_list})
        
        else:
            # Vendor exists but has no email address
            return JsonResponse(
                {"error": "No email found for the vendor"}, 
                status=404
            )
    
    # ------------------------------------------------------------
    # SECTION 5: HANDLE VENDOR NOT FOUND SCENARIO
    # ------------------------------------------------------------
    else:
        return JsonResponse(
            {"error": "Vendor not found"}, 
            status=404
        )


