                add_log(f"   Material Name: {material['material_name']}")
                add_log(f"   PO Number: {material['po_number']}")
                add_log(f"   Quantity: {material['quantity']}")
                add_log(f"   Vendor: {material['vendor']}")
                
                # Check why it's unmapped
