# ======================================================================================================================
# EXCESS QUANTITY APPROVAL EMAIL FUNCTION
# ======================================================================================================================
# Handles email notifications for excess quantity approval requests
# Processes requisition data, identifies excess quantities, and sends structured approval emails

@csrf_exempt
@login_required(login_url='login')
def send_approval_email(request):
    """
    Excess Quantity Approval Email Handler
    
    Processes POST requests to send approval emails for goods received in excess quantities.
    The function identifies items with quantity discrepancies, generates structured HTML emails,
    and sends them to designated approvers for review and authorization.
    
    Key Functionality:
        - Parses and validates requisition data from POST requests
        - Identifies products with excess received quantities
        - Generates professional HTML email with tabular data presentation
        - Sends approval requests to predefined approver email addresses
    
    Data Processing Flow:
        1. Validate request method and extract POST data
        2. Parse requisition numbers and stock items from JSON
        3. Calculate excess quantities by comparing ordered vs. received
        4. Filter items with positive excess quantities only
        5. Generate HTML email with tabular data representation
        6. Send email to approvers with user attribution
    
    Security & Validation:
        - CSRF exempt for external service integration
        - Input validation for all required fields
        - Quantity data type validation and error handling
        - User authentication context for attribution
    
    Parameters:
        request (HttpRequest): The HTTP request object containing POST data
    
    Returns:
        JsonResponse: Success response with email confirmation
        JsonResponse: Error response with descriptive message
    """
    
    # ------------------------------------------------------------
    # SECTION 1: REQUEST METHOD VALIDATION
    # ------------------------------------------------------------
    # Only process POST requests for email submission
    if request.method != "POST":
        return JsonResponse(
            {"status": "error", "message": "Invalid request method."}
        )
    
    try:
        # --------------------------------------------------------
        # SECTION 2: POST DATA EXTRACTION AND VALIDATION
        # --------------------------------------------------------
        # Extract and validate required parameters from POST data
        requisition_numbers = request.POST.get("requisition_numbers")  # Comma-separated requisition numbers
        stock_items_json = request.POST.get("stock_items", "[]")       # JSON string of stock items
        
        # Validate presence of required data fields
        if not requisition_numbers or not stock_items_json:
            return JsonResponse(
                {"status": "error", "message": "Missing required fields."}
            )
        
        # Parse stock items from JSON string
        stock_items = json.loads(stock_items_json)
        
        # Process requisition numbers into list format
        requisition_numbers = [num.strip() for num in requisition_numbers.split(",")]
        
        # Log input data for debugging and audit purposes
        print(f"Email Request - Requisition Numbers: {requisition_numbers}")
        print(f"Email Request - Stock Items: {stock_items}")
        
        # --------------------------------------------------------
        # SECTION 3: EXCESS QUANTITY IDENTIFICATION
        # --------------------------------------------------------
        # Initialize list to store requisition details with excess quantities
        requisition_details = []
        
        # Process each stock item to identify excess quantities
        for item in stock_items:
            try:
                # Extract item data with validation
                product_name = item.get("product_name")
                quantity_ordered = int(item.get("quantity_ordered", 0))
                quantity_received = int(item.get("quantity_received", 0))
                
                # Calculate excess quantity
                excess_qty = quantity_received - quantity_ordered
                
                # Only include items with positive excess quantities
                if excess_qty > 0:
                    requisition_details.append({
                        "item": product_name,
                        "quantity_ordered": quantity_ordered,
                        "quantity_received": quantity_received,
                        "excess_qty": excess_qty,
                        "remarks": "Please approve this excess quantity.",
                    })
                    
            except (ValueError, TypeError):
                # Skip items with invalid quantity data types
                continue
        
        # --------------------------------------------------------
        # SECTION 4: DATA VALIDATION AND SANITY CHECK
        # --------------------------------------------------------
        # Verify that at least one item has excess quantities
        if not requisition_details:
            return JsonResponse(
                {
                    "status": "error",
                    "message": "No items with excess quantities found.",
                }
            )
        
        # --------------------------------------------------------
        # SECTION 5: EMAIL CONTENT GENERATION
        # --------------------------------------------------------
        # Prepare user information for email attribution
        user = request.user
        
        # Email subject line
        subject = "Approval Required for Quantity Received"
        
        # --------------------------------------------------------
        # SUBSECTION: Generate HTML Table for Item Details
        # --------------------------------------------------------
        item_table = """
        <table border="1" cellpadding="5" cellspacing="0" style="border-collapse: collapse; width: 100%;">
            <thead>
                <tr>
                    <th>Item</th>
                    <th>Request Qty</th>
                    <th>Received Qty</th>
                    <th>Excess Qty</th>
                    <th>Remarks</th>
                </tr>
            </thead>
            <tbody>
        """
        
        # Add table rows for each item with excess quantities
        for detail in requisition_details:
            item_table += f"""
            <tr>
                <td>{detail['item']}</td>
                <td>{detail['quantity_ordered']}</td>
                <td>{detail['quantity_received']}</td>
                <td>{detail['excess_qty']}</td>
                <td>{detail['remarks']}</td>
            </tr>
            """
        
        item_table += "</tbody></table>"
        
        # --------------------------------------------------------
        # SUBSECTION: Construct Complete HTML Email Message
        # --------------------------------------------------------
        message = f"""
        <html>
        <body>
            <h3>Approval Required</h3>
            <p>Dear Sir,</p>
            <p>Greetings!!</p>
            <p>We have received an excess quantity against the following items:</p>
            {item_table}
            <p>We kindly seek your approval to proceed with the Goods Receipt Note (GRN) for the excess quantities.</p>
            <p>Looking forward to your approval.</p>
            <p>Best regards,</p>
            <p>{user.get_full_name()}</p>
            <p>{user.employee_code}</p>
            <p>{user.department}, {user.location}</p>
        </body>
        </html>
        """
        
        # --------------------------------------------------------
        # SECTION 6: EMAIL DELIVERY CONFIGURATION
        # --------------------------------------------------------
        # Configure email parameters
        from_email = user.email  # Sender email from authenticated user
        to_email = ["rahul.singh@shwetdharamilk.com"]  # Fixed approver email address
        
        # Create EmailMessage object with HTML content
        email = EmailMessage(
            subject=subject,
            body=message,
            from_email=from_email,
            to=to_email,
            reply_to=[from_email]  # Set reply-to for direct responses
        )
        email.content_subtype = "html"  # Specify HTML content type
        
        # --------------------------------------------------------
        # SECTION 7: EMAIL TRANSMISSION
        # --------------------------------------------------------
        # Send email with error handling for delivery failures
        email.send(fail_silently=False)
        
        # --------------------------------------------------------
        # SECTION 8: SUCCESS RESPONSE
        # --------------------------------------------------------
        return JsonResponse(
            {"status": "success", "message": "Email sent successfully."}
        )
    
    # ------------------------------------------------------------
    # SECTION 9: EXCEPTION HANDLING
    # ------------------------------------------------------------
    except Exception as e:
        # Log unexpected errors for debugging
        print(f"Email Sending Error: {e}")
        
        # Return user-friendly error response
        return JsonResponse(
            {"status": "error", "message": str(e)}
        )

# ======================================================================================================================
# GRN EMAIL SUBMISSION FUNCTION
# ======================================================================================================================
# Handles GRN submission emails with merged PDF attachments
# Processes GRN data, generates professional emails, merges documents, and sends to stakeholders

@login_required(login_url="login")
@csrf_exempt
def send_grn_email(request):
    """
    GRN Submission Email Handler
    
    Processes POST requests to send Goods Received Note (GRN) submission emails to relevant stakeholders.
    The function validates user permissions, retrieves requisition data, generates professional HTML emails,
    merges supporting documents into a single PDF, and distributes to vendors, purchase, and finance departments.
    
    Key Functionality:
        - Validates user authorization based on location
        - Retrieves and validates requisition and GRN data
        - Generates structured HTML email with tabular GRN details
        - Merges GRN reports and chaalan files into single PDF attachment
        - Distributes emails to vendor, purchase, finance, and HOD stakeholders
        - Updates requisition status to track email transmission
    
    Email Distribution:
        Primary Recipients: Purchase department, Finance department, Vendor
        CC Recipients: Head of Department (product-specific)
        Dynamic Attachments: Merged PDF of GRN report and chaalan documents
    
    Security & Validation:
        - Requires user authentication with login redirect
        - CSRF exempt for file upload functionality
        - Location-based authorization validation
        - Comprehensive data validation at each processing stage
    
    Parameters:
        request (HttpRequest): HTTP request object containing GRN data and file attachments
    
    Returns:
        HttpResponseRedirect: Redirect to animation page on successful email transmission
        JsonResponse: Error responses with appropriate status codes and messages
    """
    
    # ------------------------------------------------------------
    # SECTION 1: REQUEST METHOD VALIDATION
    # ------------------------------------------------------------
    # Validate that request method is POST for form submission
    if request.method != "POST":
        return JsonResponse({"error": "Invalid request method."}, status=400)
    
    # ------------------------------------------------------------
    # SECTION 2: FORM DATA EXTRACTION
    # ------------------------------------------------------------
    # Extract all form data from POST request
    request_no = request.POST.get("request_no")
    request_date = request.POST.get("request_date")
    item = request.POST.get("item")
    request_qty = request.POST.get("request_qty")
    received_qty = request.POST.get("received_qty")
    po_number = request.POST.get("po_number")
    remarks = request.POST.get("remarks")
    employee_name = request.POST.get("employee_name")
    employee_code = request.POST.get("employee_code")
    department = request.POST.get("department")
    location = request.POST.get("location")
    
    # Extract file attachments from FILES data
    chaalan_file = request.FILES.get("chaalan_file")
    grn_report = request.FILES.get("grn_report")
    
    # ------------------------------------------------------------
    # SECTION 3: INPUT VALIDATION AND DEBUG LOGGING
    # ------------------------------------------------------------
    # Log all extracted data for debugging and audit trail
    print(f"GRN Email Request - Request No: {request_no}")
    print(f"GRN Email Request - Request Date: {request_date}")
    print(f"GRN Email Request - Item: {item}")
    print(f"GRN Email Request - Request Qty: {request_qty}")
    print(f"GRN Email Request - Received Qty: {received_qty}")
    print(f"GRN Email Request - PO Number: {po_number}")
    print(f"GRN Email Request - Remarks: {remarks}")
    print(f"GRN Email Request - Employee: {employee_name} ({employee_code})")
    print(f"GRN Email Request - Department: {department}, Location: {location}")
    print(f"GRN Email Request - Chaalan File: {chaalan_file}")
    print(f"GRN Email Request - GRN Report: {grn_report}")
    
    try:
        # --------------------------------------------------------
        # SECTION 4: REQUISITION DATA RETRIEVAL AND VALIDATION
        # --------------------------------------------------------
        # Retrieve purchase requisition with comprehensive validation
        requisition = get_object_or_404(
            PurchaseRequisition,
            requisition_number=request_no,
            po_number=po_number,
            stock_item=item,
        )
        print(f"Requisition Found: {requisition}")
        
        # --------------------------------------------------------
        # SUBSECTION: User Authorization Validation
        # --------------------------------------------------------
        # Verify user has permission based on location matching
        if requisition.created_by.location != request.user.location:
            print(f"Authorization Failed - User Location: {request.user.location}, Requisition Location: {requisition.created_by.location}")
            return JsonResponse(
                {"error": "You are not authorized to send this email."}, 
                status=403
            )
        
        # --------------------------------------------------------
        # SECTION 5: GRN AND VENDOR DATA RETRIEVAL
        # --------------------------------------------------------
        # Retrieve GRN record for the specified PO and item
        grn = get_object_or_404(DoGRN, po_number=po_number, stock_item=item)
        print(f"GRN Record Found: {grn}")
        
        # --------------------------------------------------------
        # SUBSECTION: Vendor Information Retrieval
        # --------------------------------------------------------
        # Find vendor associated with the product
        vendor = ProductVendor.objects.filter(product__name=item).first()
        if vendor:
            vendor_email = vendor.vendor.email
            print(f"Vendor Found: {vendor.vendor}")
        else:
            print(f"Vendor Not Found for Product: {item}")
            return JsonResponse({"error": "Vendor not found."}, status=404)
        
        # --------------------------------------------------------
        # SECTION 6: RECIPIENT LIST CONFIGURATION
        # --------------------------------------------------------
        # Configure email recipients from system settings
        purchase_email = 'purchase@shwetdharamilk.com'
        finance_email = 'finance@shwetdharamilk.com'
        
        # Retrieve HOD email for the product
        product = get_object_or_404(Product, name=item)
        hod_email = product.hod.email if product.hod else None
        
        # Configure recipient lists
        recipient_list = [purchase_email, finance_email, vendor_email]
        cc_list = []
        
        # Add HOD to CC list if available
        if hod_email:
            cc_list.append(hod_email)
        
        # --------------------------------------------------------
        # SECTION 7: EMAIL CONTENT GENERATION
        # --------------------------------------------------------
        # Email subject line
        subject = "GRN Submission for Received Items (This is a test mail please Ignore)"
        
        # --------------------------------------------------------
        # SUBSECTION: Generate HTML Email Body
        # --------------------------------------------------------
        message = f"""
        <html>
        <body>
        <p>Dear Sir,</p>
        <p>We have received the items as per the details mentioned below:</p>
        <table border="1" cellpadding="5" cellspacing="0">
            <tr>
                <th>Request No</th>
                <th>Request Date</th>
                <th>Item</th>
                <th>Request Qty</th>
                <th>Received Qty</th>
                <th>PO Number</th>
                <th>Remarks</th>
            </tr>
            <tr>
                <td>{request_no}</td>
                <td>{request_date}</td>
                <td>{item}</td>
                <td>{request_qty}</td>
                <td>{received_qty}</td>
                <td>{po_number}</td>
                <td>{remarks}</td>
            </tr>
        </table>
        <p>The detailed GRN and required supporting documents are attached for your reference.</p>
        <p>Regards,<br>
        {employee_name}<br>
        {employee_code}<br>
        {department} & {location}</p>
        </body>
        </html>
        """
        
        # --------------------------------------------------------
        # SECTION 8: EMAIL OBJECT CREATION
        # --------------------------------------------------------
        # Create EmailMessage with HTML content
        email = EmailMessage(
            subject=subject,
            body=message,
            from_email=settings.DEFAULT_FROM_EMAIL,
            to=recipient_list,
            cc=cc_list
        )
        email.content_subtype = "html"  # Set content type to HTML
        
        # --------------------------------------------------------
        # SECTION 9: PDF MERGING AND ATTACHMENT PREPARATION
        # --------------------------------------------------------
        # Configure Indian Standard Time for timestamping
        ist = pytz.timezone("Asia/Kolkata")
        current_time = timezone.now().astimezone(ist).strftime("%d-%m-%Y-%H-%M")
        
        # Initialize PDF writer for document merging
        pdf_writer = PdfFileWriter()
        
        # --------------------------------------------------------
        # SUBSECTION: Add GRN Report to PDF
        # --------------------------------------------------------
        if grn_report:
            grn_report.seek(0)
            grn_pdf_reader = PdfFileReader(grn_report)
            for page_num in range(grn_pdf_reader.getNumPages()):
                pdf_writer.addPage(grn_pdf_reader.getPage(page_num))
        
        # --------------------------------------------------------
        # SUBSECTION: Add Chaalan File to PDF
        # --------------------------------------------------------
        if chaalan_file:
            chaalan_file.seek(0)
            
            # Handle image files by converting to PDF
            if chaalan_file.content_type in ["image/jpeg", "image/png"]:
                image = Image.open(chaalan_file)
                pdf_bytes = BytesIO()
                image.save(pdf_bytes, format="PDF")
                pdf_bytes.seek(0)
                chaalan_pdf_reader = PdfFileReader(pdf_bytes)
            else:
                # Handle existing PDF files
                chaalan_pdf_reader = PdfFileReader(chaalan_file)
            
            # Add all chaalan pages to merged PDF
            for page_num in range(chaalan_pdf_reader.getNumPages()):
                pdf_writer.addPage(chaalan_pdf_reader.getPage(page_num))
        
        # --------------------------------------------------------
        # SUBSECTION: Save Merged PDF to Buffer
        # --------------------------------------------------------
        pdf_buffer = BytesIO()
        pdf_writer.write(pdf_buffer)
        pdf_buffer.seek(0)
        
        # --------------------------------------------------------
        # SECTION 10: EMAIL ATTACHMENT AND TRANSMISSION
        # --------------------------------------------------------
        # Attach merged PDF with timestamped filename
        email.attach(
            f"GRN_and_Chaalan_{current_time}.pdf",
            pdf_buffer.read(),
            "application/pdf",
        )
        
        # Send email with error handling
        email.send()
        
        # --------------------------------------------------------
        # SECTION 11: REQUISITION STATUS UPDATE
        # --------------------------------------------------------
        # Update requisition to track email transmission
        requisition.send_grn_mail = True
        requisition.save()
        print(f"Requisition Updated - GRN Email Flag Set: {requisition.send_grn_mail}")
        
        # --------------------------------------------------------
        # SECTION 12: SUCCESS REDIRECTION
        # --------------------------------------------------------
        # Redirect to animation page upon successful email transmission
        return redirect("send_mail_of_grn_animation")
    
    # ------------------------------------------------------------
    # SECTION 13: EXCEPTION HANDLING
    # ------------------------------------------------------------
    except PurchaseRequisition.DoesNotExist:
        print(f"Requisition Not Found - Request No: {request_no}, PO: {po_number}, Item: {item}")
        return JsonResponse({"error": "Requisition not found."}, status=404)
        
    except DoGRN.DoesNotExist:
        print(f"GRN Not Found - PO: {po_number}, Item: {item}")
        return JsonResponse({"error": "GRN not found."}, status=404)
        
    except Exception as e:
        # Catch-all exception handler for unexpected errors
        print(f"Unexpected Error in GRN Email Function: {e}")
        return JsonResponse({"error": "An unexpected error occurred."}, status=500)


