# ======================================================================================================================
# LOCATION-BASED INVENTORY QUERY FUNCTION
# ======================================================================================================================
# Provides filtered inventory views based on geographical locations
# Enables administrators to view and analyze inventory distribution across different sites

@login_required(login_url='login')
def inventory_by_location(request):
    """
    Location-Based Inventory Query Handler
    
    Generates filtered inventory views based on geographical locations within the organization.
    This function serves as a reporting tool for administrators to monitor stock levels,
    distribution patterns, and location-specific inventory management.
    
    Key Functionality:
        - Extracts all unique locations from the Inventory database
        - Filters inventory data based on user-selected locations
        - Provides comprehensive context for template rendering
        - Supports both summary views (all locations) and detailed views (specific location)
    
    Use Cases:
        - Inventory distribution analysis across multiple sites
        - Location-specific stock level monitoring
        - Comparative analysis between different operational locations
        - Data-driven decision making for inventory allocation
    
    Data Flow:
        1. Extract all unique locations from inventory records
        2. Check for location filter in GET parameters
        3. Apply location filter if specified
        4. Prepare context data for template rendering
    
    Template Integration:
        Renders 'admin/inventory_by_location.html' with:
            - List of all available locations
            - Currently selected location (if any)
            - Filtered inventory data (if location selected)
    
    Parameters:
        request (HttpRequest): HTTP request object containing optional location parameter
    
    Returns:
        HttpResponse: Rendered inventory report template with location-based context
    """
    
    # ------------------------------------------------------------
    # SECTION 1: LOCATION DATA EXTRACTION
    # ------------------------------------------------------------
    # Extract all unique locations from the Inventory model
    # Uses distinct() to eliminate duplicates and flat=True for simple values
    locations = Inventory.objects.values_list(
        "mcc_bmc_user__location", 
        flat=True
    ).distinct()
    
    # Log location extraction for monitoring and debugging
    print(f"Location Inventory Query - Available Locations: {list(locations)}")
    
    # ------------------------------------------------------------
    # SECTION 2: LOCATION FILTER PROCESSING
    # ------------------------------------------------------------
    # Extract location filter from GET parameters
    # Defaults to None if no location is specified
    selected_location = request.GET.get("location", None)
    
    # Initialize inventories variable
    inventories = None
    
    # ------------------------------------------------------------
    # SECTION 3: FILTERED INVENTORY RETRIEVAL
    # ------------------------------------------------------------
    # Apply location filter if a specific location is selected
    if selected_location:
        # Filter inventory records by the selected location
        inventories = Inventory.objects.filter(
            mcc_bmc_user__location=selected_location
        )
        
        # Log filtered query results for audit trail
        print(f"Location Inventory Query - Selected Location: {selected_location}")
        print(f"Location Inventory Query - Records Found: {inventories.count()}")
        
    else:
        # Log when no location filter is applied
        print(f"Location Inventory Query - No location filter applied, showing location summary")
    
    # ------------------------------------------------------------
    # SECTION 4: CONTEXT DATA PREPARATION
    # ------------------------------------------------------------
    # Prepare comprehensive context data for template rendering
    context = {
        "locations": locations,            # All available locations for dropdown/selection
        "selected_location": selected_location,  # Currently selected location (if any)
        "inventories": inventories,        # Filtered inventory data (if location selected)
    }
    
    # Log context preparation for debugging
    print(f"Location Inventory Query - Context Prepared - Locations: {len(locations)}, "
          f"Selected: {selected_location}, "
          f"Inventory Records: {inventories.count() if inventories else 'None'}")
    
    # ------------------------------------------------------------
    # SECTION 5: TEMPLATE RENDERING AND RESPONSE
    # ------------------------------------------------------------
    # Render the inventory report template with prepared context
    return render(request, "admin/inventory_by_location.html", context)








# ======================================================================================================================
# STN-BASED GRN PROCESSING FUNCTION
# ======================================================================================================================
# Handles complete Goods Received Note (GRN) processing against Stock Transfer Notes (STN)
# Manages multi-step workflow from data capture to inventory updates and email notifications

@login_required(login_url="login")
def do_grn_against_stn(request, stn_number):
    """
    STN-Based GRN Processing Handler
    
    Processes Goods Received Note (GRN) submissions against Stock Transfer Notes (STN) with
    comprehensive workflow management. Handles both GET requests for form display and POST 
    requests for full GRN processing including inventory updates, PDF generation, and email 
    notifications.
    
    Key Functionality:
        - Validates STN number and user authentication
        - Processes multi-item GRN submissions with file attachments
        - Updates inventory with TRANSFER_IN operations
        - Generates professional PDF reports with signatures
        - Creates merged PDFs with supporting documents
        - Sends email notifications to relevant departments
        - Maintains comprehensive audit trails
    
    Workflow Stages:
        1. STN Validation and Form Display (GET)
        2. Data Processing and File Management (POST)
        3. Inventory Updates and History Tracking
        4. PDF Report Generation and Merging
        5. Email Notification and Delivery
    
    Security & Validation:
        - Requires user authentication with login redirect
        - Validates STN existence and accessibility
        - Ensures transaction atomicity for data integrity
        - Performs user location-based authorization
        - Validates file types and sizes
    
    Parameters:
        request (HttpRequest): HTTP request object
        stn_number (str): Stock Transfer Note number for processing
    
    Returns:
        HttpResponse: PDF download on successful processing
        HttpResponse: GRN form for GET requests
        HttpResponse: Error pages with appropriate status codes
    """
    
    # ------------------------------------------------------------
    # SECTION 1: STN NUMBER VALIDATION
    # ------------------------------------------------------------
    # Validate STN number parameter
    if not stn_number or stn_number.strip().lower() == "none":
        return render(request, "stn_404.html", status=404)
    
    # ------------------------------------------------------------
    # SECTION 2: POST REQUEST PROCESSING
    # ------------------------------------------------------------
    # Handle form submission and comprehensive GRN processing
    if request.method == "POST":
        try:
            # ----------------------------------------------------
            # SUBSECTION: Transaction Management
            # ----------------------------------------------------
            # Use atomic transaction to ensure data consistency
            with transaction.atomic():
                
                # -------------------------------------------------
                # SUBSECTION: Form Data Extraction and Processing
                # -------------------------------------------------
                # Extract and process STN date
                stn_date_str = request.POST.get("stn_date")
                stn_date = None
                if stn_date_str:
                    try:
                        stn_date = datetime.strptime(stn_date_str, "%Y-%m-%d").date()
                    except ValueError:
                        pass  # Handle gracefully if date format is invalid
                
                # Extract file attachments
                stn_file = request.FILES.get("stn_file")
                eway_bill_file = request.FILES.get("eway_bill_file")
                rejected_files = request.FILES.getlist("rejected_file[]")
                
                # Extract stock item data arrays
                stock_items = request.POST.getlist("stock_item[]")
                quantities_ordered = request.POST.getlist("quantity_ordered[]")
                quantities_received = request.POST.getlist("quantity_received[]")
                quantities_rejected = request.POST.getlist("quantity_rejected[]")
                
                # -------------------------------------------------
                # SUBSECTION: User Information and Session Context
                # -------------------------------------------------
                # Extract current user information for processing
                current_user_location = request.user.location
                employee_code = request.user.employee_code
                
                # -------------------------------------------------
                # SUBSECTION: GRN Entry Processing Loop
                # -------------------------------------------------
                # Initialize collection for GRN entries
                grn_entries = []
                
                # Process each stock item in the submission
                for i, stock_item in enumerate(stock_items):
                    # Extract rejected file for current item
                    rejected_file = rejected_files[i] if i < len(rejected_files) else None
                    
                    # Parse quantity values
                    quantity_received = int(quantities_received[i])
                    quantity_rejected = int(quantities_rejected[i])
                    
                    # -------------------------------------------------
                    # SUBSECTION: File Management and Storage
                    # -------------------------------------------------
                    # Generate timestamp for consistent file naming
                    timestamp = timezone.now().strftime("%Y%m%d%H%M%S")
                    
                    # Initialize file path variables
                    stn_file_path = None
                    eway_bill_file_path = None
                    rejected_file_path = None
                    
                    # Process STN file (only once for first item)
                    if stn_file and i == 0:
                        stn_filename = f"{timestamp}_STN_{stn_number}_{stn_file.name}"
                        stn_file_path = save_file_with_name(
                            stn_file, "grn_against_stn", employee_code, stn_filename
                        )
                    
                    # Process Eway Bill file (only once for first item)
                    if eway_bill_file and i == 0:
                        eway_filename = f"{timestamp}_EWAY_{stn_number}_{eway_bill_file.name}"
                        eway_bill_file_path = save_file_with_name(
                            eway_bill_file, "grn_against_stn", employee_code, eway_filename
                        )
                    
                    # Process Rejected file (per item)
                    if rejected_file:
                        rejected_filename = f"{timestamp}_REJECTED_{stn_number}_{stock_item}_{rejected_file.name}"
                        rejected_file_path = save_file_with_name(
                            rejected_file, "grn_against_stn", employee_code, rejected_filename
                        )
                    
                    # -------------------------------------------------
                    # SUBSECTION: GRN Database Entry Creation
                    # -------------------------------------------------
                    # Create DoGRNAgainstSTN record
                    grn_entry = DoGRNAgainstSTN(
                        stn_number=stn_number,
                        employee_name=request.POST.get("employee_name"),
                        employee_code=employee_code,
                        location=current_user_location,
                        department=request.POST.get("department"),
                        stn_date=stn_date,
                        stn_file=stn_file_path,
                        eway_bill_file=eway_bill_file_path,
                        stock_item=stock_item,
                        quantity_ordered=int(quantities_ordered[i]),
                        quantity_received=quantity_received,
                        quantity_rejected=quantity_rejected,
                        rejected_file=rejected_file_path,
                    )
                    grn_entry.save()
                    grn_entries.append(grn_entry)
                    
                    # -------------------------------------------------
                    # SUBSECTION: Inventory Management - TRANSFER_IN
                    # -------------------------------------------------
                    # Retrieve or create product record
                    product = Product.objects.filter(name=stock_item).first()
                    if not product:
                        # Create product record with default values
                        product = Product.objects.create(
                            name=stock_item,
                            uom='PCS'  # Default unit of measure
                        )
                    
                    # Get or create inventory record for user and product
                    inventory, created = Inventory.objects.get_or_create(
                        mcc_bmc_user=request.user,
                        product=product,
                        defaults={'quantity': 0}
                    )
                    
                    # Capture previous quantity for history tracking
                    previous_quantity = inventory.quantity
                    
                    # Perform TRANSFER_IN operation
                    inventory.quantity += quantity_received
                    inventory.save()
                    
                    # -------------------------------------------------
                    # SUBSECTION: Inventory History Tracking
                    # -------------------------------------------------
                    # Create inventory history record
                    inventory_history = InventoryHistory.objects.create(
                        inventory=inventory,
                        action='TRANSFER_IN',
                        quantity_change=quantity_received,
                        previous_quantity=previous_quantity,
                        new_quantity=inventory.quantity,
                        reference_number=stn_number,
                        notes=f"Stock received via GRN against STN {stn_number}. "
                              f"From: Source Location, To: {current_user_location}. "
                              f"Received: {quantity_received}, Rejected: {quantity_rejected}",
                        performed_by=request.user
                    )
                
                # -------------------------------------------------
                # SUBSECTION: Requisition Status Updates
                # -------------------------------------------------
                # Update GRN status for related requisitions
                for stock_item in stock_items:
                    logistic_entry = LogisticDepartment.objects.filter(
                        stn_number=stn_number, stock_item=stock_item
                    ).first()
                    if logistic_entry and logistic_entry.requisition:
                        logistic_entry.requisition.grn_done = True
                        logistic_entry.requisition.save()
                
                # -------------------------------------------------
                # SUBSECTION: Supplier and User Details Collection
                # -------------------------------------------------
                # Retrieve supplier information
                suppliers = LogisticDepartment.objects.filter(stn_number=stn_number)
                if not suppliers.exists():
                    return render(request, "stn_404.html", status=404)
                supplier = suppliers.first()
                
                # Prepare signature and stamp URLs
                user = request.user
                prepared_by_signature = checked_by_signature = approved_by_stamp = None
                if user:
                    if hasattr(user, "signature") and user.signature:
                        prepared_by_signature = request.build_absolute_uri(user.signature.url)
                        checked_by_signature = prepared_by_signature
                    if hasattr(user, "mohar") and user.mohar:
                        approved_by_stamp = request.build_absolute_uri(user.mohar.url)
                
                # -------------------------------------------------
                # SUBSECTION: GRN PDF Report Generation
                # -------------------------------------------------
                # Prepare context for PDF template
                context = {
                    "stn_number": stn_number,
                    "grn_entries": grn_entries,
                    "logo_url": request.build_absolute_uri(static("images/shwetdharalogo.png")),
                    "grn_date": now().strftime("%d-%b-%Y"),
                    "supplier_name": supplier.from_location,
                    "supplier_address": supplier.to_location,
                    "stn_date": stn_date.strftime("%d/%m/%Y") if stn_date else "N/A",
                    "prepared_by_signature": prepared_by_signature,
                    "checked_by_signature": checked_by_signature,
                    "approved_by_stamp": approved_by_stamp,
                    "received_location": current_user_location,
                }
                
                # Render HTML template and convert to PDF
                html_string = render_to_string("stn_grn_template.html", context)
                grn_pdf_buffer = BytesIO()
                HTML(string=html_string).write_pdf(grn_pdf_buffer)
                grn_pdf_buffer.seek(0)
                
                # Save generated GRN PDF
                timestamp = timezone.now().strftime("%Y%m%d%H%M%S")
                grn_pdf_filename = f"{timestamp}_GRN_STN_{stn_number}.pdf"
                grn_pdf_file_path = save_file_with_name(
                    ContentFile(grn_pdf_buffer.getvalue()), 
                    "grn_against_stn", 
                    employee_code, 
                    grn_pdf_filename
                )
                
                # -------------------------------------------------
                # SUBSECTION: PDF Merging with Supporting Documents
                # -------------------------------------------------
                # Create merged PDF with GRN and STN documents
                merged_pdf_buffer = BytesIO()
                merger = PdfMerger()
                merger.append(grn_pdf_buffer)
                
                # Process and add STN file to merged PDF
                if stn_file_path:
                    try:
                        stn_file_full_path = default_storage.path(stn_file_path)
                        if os.path.exists(stn_file_full_path):
                            # Handle PDF STN files
                            if stn_file.name.lower().endswith('.pdf'):
                                merger.append(stn_file_full_path)
                            else:
                                # Handle image files (convert to PDF)
                                try:
                                    img = Image.open(stn_file_full_path)
                                    img_pdf_buffer = BytesIO()
                                    c = canvas.Canvas(img_pdf_buffer, pagesize=letter)
                                    
                                    # Calculate image scaling
                                    img_width, img_height = img.size
                                    aspect = img_height / float(img_width)
                                    pdf_width = 500
                                    pdf_height = pdf_width * aspect
                                    
                                    # Draw image on PDF canvas
                                    c.drawImage(stn_file_full_path, 50, 50, width=pdf_width, height=pdf_height)
                                    c.showPage()
                                    c.save()
                                    
                                    # Add converted image to merger
                                    img_pdf_buffer.seek(0)
                                    merger.append(img_pdf_buffer)
                                except Exception as e:
                                    pass  # Silently handle image conversion errors
                    except Exception as e:
                        pass  # Silently handle STN file processing errors
                
                # Finalize merged PDF
                merger.write(merged_pdf_buffer)
                merger.close()
                merged_pdf_buffer.seek(0)
                
                # Save merged PDF
                merged_pdf_filename = f"{timestamp}_MERGED_GRN_STN_{stn_number}.pdf"
                merged_pdf_file_path = save_file_with_name(
                    ContentFile(merged_pdf_buffer.getvalue()), 
                    "grn_against_stn", 
                    employee_code, 
                    merged_pdf_filename
                )
                
                # -------------------------------------------------
                # SUBSECTION: Email Notification Configuration
                # -------------------------------------------------
                # Determine HOD email from requisition
                hod_email = None
                if suppliers.exists() and suppliers.first().requisition:
                    hod = suppliers.first().requisition.created_by
                    if hod and hod.email:
                        hod_email = hod.email
                
                # Configure recipient lists
                to_emails = []
                if hod_email:
                    to_emails.append(hod_email)
                to_emails.extend([
                    "ashishgoud8787@shwetdharamilk.com",
                    "finance@shwetdharamilk.com"
                ])
                
                cc_emails = [""]
                
                # Compose email message
                subject = f"GRN Against STN {stn_number}"
                message = (
                    f"Dear Team,\n\n"
                    f"Please find attached the GRN document for STN {stn_number}.\n\n"
                    f"Location: {current_user_location}\n"
                    f"Employee: {request.user.get_full_name()} ({employee_code})\n"
                    f"Stock Items Processed:\n"
                )
                
                # Add item details to email
                for entry in grn_entries:
                    message += f"- {entry.stock_item}: {entry.quantity_received} units received, {entry.quantity_rejected} units rejected\n"
                
                message += (
                    f"\nInventory has been updated at {current_user_location} location.\n\n"
                    f"Regards,\n"
                    f"{request.user.get_full_name()}\n"
                    f"{request.user.department}"
                )
                
                # Create email object
                email = EmailMessage(
                    subject=subject,
                    body=message,
                    from_email=settings.DEFAULT_FROM_EMAIL,
                    to=to_emails,
                    cc=cc_emails,
                )
                
                # Attach merged PDF
                email.attach(
                    f"GRN_with_STN_{stn_number}.pdf",
                    merged_pdf_buffer.getvalue(),
                    "application/pdf"
                )
                
                # -------------------------------------------------
                # SUBSECTION: Email Transmission
                # -------------------------------------------------
                # Send email with error handling
                email.send(fail_silently=False)
                
                # -------------------------------------------------
                # SUBSECTION: PDF Download Response
                # -------------------------------------------------
                # Prepare HTTP response with merged PDF
                response = HttpResponse(
                    merged_pdf_buffer.getvalue(),
                    content_type="application/pdf"
                )
                response["Content-Disposition"] = f'attachment; filename="GRN_with_STN_{stn_number}.pdf"'
                return response
        
        # ------------------------------------------------------------
        # SECTION 3: EXCEPTION HANDLING
        # ------------------------------------------------------------
        except Exception as e:
            # Return user-friendly error response
            return HttpResponse("An error occurred while processing the form.", status=500)
    
    # ------------------------------------------------------------
    # SECTION 4: GET REQUEST PROCESSING
    # ------------------------------------------------------------
    # Handle initial form display for GRN submission
    
    # Validate STN existence
    suppliers = LogisticDepartment.objects.filter(stn_number=stn_number)
    if not suppliers.exists():
        return render(request, "stn_404.html", status=404)
    
    # Prepare form context
    supplier = suppliers.first()
    context = {
        "stn_number": stn_number,
        "supplier_name": supplier.from_location,
        "supplier_address": supplier.to_location,
        "current_location": request.user.location,
    }
    
    # Render GRN submission form
    return render(request, "do_grn_against_stn.html", context)
    








