# ======================================================================================================================
# ADVANCE SALE PROCESSING FUNCTION
# ======================================================================================================================
# Handles advance sale transactions with SAP integration and cycle tracking
# Manages complete workflow from request validation to PDF generation and reporting

logger = logging.getLogger(__name__)

# In your views.py, update the advance_sale function:
# Add these imports at the top if not already present

@login_required(login_url="login")
def download_advance_sale_pdf(request, sale_id):
    """
    Download PDF for advance sale - polls until ready
    """
    try:
        sale = get_object_or_404(AdvanceSale, id=sale_id)
        
        # Check if user has permission to download
        if request.user != sale.dispatched_by and not request.user.is_superuser:
            return JsonResponse({'error': 'Permission denied'}, status=403)
        
        # If PDF is ready, serve it
        if sale.pdf_generated and sale.pdf_file:
            response = FileResponse(
                sale.pdf_file.open("rb"),
                as_attachment=True,
                filename=f"advance_sale_{sale.unique_code}.pdf"
            )
            return response
        
        # PDF is still generating
        return JsonResponse({
            'status': 'processing',
            'message': 'PDF is being generated',
            'retry_after': 2,  # seconds
            'check_url': f'/check-pdf-status/{sale_id}/'
        }, status=202)
    
    except AdvanceSale.DoesNotExist:
        return JsonResponse({'error': 'Sale not found'}, status=404)

@login_required(login_url="login")
def check_pdf_status(request, sale_id):
    """
    Check if PDF is ready
    """
    try:
        sale = get_object_or_404(AdvanceSale, id=sale_id)
        
        return JsonResponse({
            'pdf_generated': sale.pdf_generated,
            'has_pdf_file': bool(sale.pdf_file),
            'sale_id': sale.id,
            'unique_code': sale.unique_code,
            'status': 'ready' if sale.pdf_generated else 'processing'
        })
    
    except AdvanceSale.DoesNotExist:
        return JsonResponse({'error': 'Sale not found'}, status=404)

