# ======================================================================================================================
# ADVANCE SALE TRANSACTION PROCESSING FUNCTION
# ======================================================================================================================
# Processes complete advance sale transactions with SAP integration, cycle tracking, and inventory management
# Handles multi-step workflow from validation to database updates and reporting
# In views.py, replace the existing process_advance_sale_transaction function:

def process_advance_sale_transaction_atomic(user, bmc_or_mcc, mpp_with_code, items, unique_code, cycle, request):
    """
    Atomic Advance Sale Transaction Processor
    Returns advance_sale_id for queuing messages
    """
    
    print("\n🔄 PROCESS_ADVANCE_SALE_TRANSACTION_ATOMIC")
    print("="*80)
    
    # Use database transaction to ensure atomicity
    with transaction.atomic():
        try:
            print("🔒 Starting atomic transaction...")
            
            # Check for duplicate transaction (idempotency)
            if AdvanceSale.objects.filter(unique_code=unique_code).exists():
                raise Exception(f"Transaction with code {unique_code} already exists")
            
            # Inventory validation
            print("🔍 Validating inventory...")
            inventory_validations = pre_validate_inventory_with_sap_mapping(user, items)
            
            if not inventory_validations:
                raise Exception("Inventory validation failed")
            
            template_entry = None
            
            print("💰 Processing items and updating inventory...")
            for validation in inventory_validations:
                product = validation['product']
                sap_product = validation['sap_product']
                quantity_to_deduct = validation['quantity_to_deduct']
                item_data = validation['item_data']
                user_location = validation['user_location']
                
                print(f"   📦 Processing {product.name}: {quantity_to_deduct} units")
                
                # Get inventory with row-level locking
                inventory_items = Inventory.objects.filter(
                    mcc_bmc_user__location=user_location,
                    product=product
                ).select_for_update().order_by('-quantity')
                
                remaining_to_deduct = quantity_to_deduct
                
                for inventory_item in inventory_items:
                    if remaining_to_deduct <= 0:
                        break
                    
                    deduct_from_this = min(remaining_to_deduct, inventory_item.quantity)
                    
                    if deduct_from_this > 0:
                        previous_quantity = inventory_item.quantity
                        new_quantity = previous_quantity - deduct_from_this
                        
                        # Update inventory with lock
                        inventory_item.quantity = new_quantity
                        inventory_item.save()
                        
                        # Create inventory history
                        InventoryHistory.objects.create(
                            inventory=inventory_item,
                            action='SALE',
                            quantity_change=-deduct_from_this,
                            previous_quantity=previous_quantity,
                            new_quantity=new_quantity,
                            reference_number=unique_code,
                            notes=f"Advance sale to MPP: {mpp_with_code.name_with_code}, Cycle: {cycle.name}",
                            performed_by=user
                        )
                        
                        remaining_to_deduct -= deduct_from_this
                        print(f"     ➖ Deducted {deduct_from_this} from inventory #{inventory_item.id}")
                
                if remaining_to_deduct > 0:
                    raise Exception(f"Failed to deduct full quantity for {product.name}. Remaining: {remaining_to_deduct}")
                
                # Manage sale template
                print("   📝 Managing sale template...")
                try:
                    config, created = SaleTemplateConfig.objects.get_or_create(
                        cycle=cycle,
                        defaults={'is_active': True}
                    )
                    
                    template_entry, created = SaleTemplateEntry.objects.get_or_create(
                        config=config,
                        location=user.location,
                        mpp=mpp_with_code.name_with_code,
                        product_name=sap_product.product_name if sap_product else item_data.get('stockItem'),
                        defaults={
                            'advance_sale_quantity': item_data.get('quantity', 0),
                            'filled_quantity': item_data.get('quantity', 0),
                            'uploaded_by': user,
                            'status': 'OK' if item_data.get('quantity', 0) > 0 else 'NOT_SOLD'
                        }
                    )
                    
                    if not created:
                        template_entry.filled_quantity += item_data.get('quantity', 0)
                        template_entry.save()
                        print(f"     📈 Updated existing template entry")
                    
                except Exception as e:
                    print(f"     ⚠️ Template management error: {e}")
                    # Don't fail transaction if template fails
            
            # ================================================
            # CRITICAL: CREATE ADVANCE SALE RECORD
            # ================================================
            print("\n💾 Creating Advance Sale record...")
            
            # Calculate total quantity
            total_quantity = sum(item.get('quantity', 0) for item in items)
            
            # Create advance sale
            advance_sale = AdvanceSale.objects.create(
                bmc_or_mcc=bmc_or_mcc.name,
                mpp_with_code=mpp_with_code.name_with_code,
                uom=items[0].get('uom', 'PCS') if items else 'PCS',
                stock_item=items[0].get('stockItem') if items else '',
                quantity=total_quantity,
                dispatched_by=user,
                unique_code=unique_code,
                cycle=cycle,
                template_entry=template_entry,
                sale_date=timezone.now().date()
            )
            
            print(f"✅ Advance Sale created: ID {advance_sale.id}")
            
            # ================================================
            # TRANSACTION COMMITS HERE - ALL OR NOTHING
            # ================================================
            
            print("\n✅ ATOMIC TRANSACTION COMPLETED SUCCESSFULLY!")
            print(f"   Advance Sale ID: {advance_sale.id}")
            print(f"   Unique Code: {unique_code}")
            print(f"   Items Processed: {len(items)}")
            
            return {
                'success': True,
                'message': 'Advance sale submitted successfully!',
                'unique_code': unique_code,
                'advance_sale_id': advance_sale.id,
                'records_created': 1,
                'inventory_updated': True,
            }
            
        except Exception as e:
            print(f"❌ TRANSACTION FAILED: {str(e)}")
            raise
                
def prepare_messages_for_queue(mpp_with_code, items, unique_code, cycle):
    """
    Prepare messages for background queueing with MPP name + code
    """
    print("\n📱 PREPARE_MESSAGES_FOR_QUEUE CALLED")
    
    messages_data = {
        'sms': [],
        'whatsapp': [],
        'items': items,
        'unique_code': unique_code,
        'cycle_name': cycle.name,
        'mpp_name': mpp_with_code.name_with_code,
        'mpp_transaction_code': mpp_with_code.mpp_transaction_code,
        'timestamp': timezone.now().isoformat()
    }
    
    # Create MPP display name with transaction code
    mpp_display_name = mpp_with_code.name_with_code
    if mpp_with_code.mpp_transaction_code:
        mpp_display_name = f"{mpp_with_code.name_with_code} {mpp_with_code.mpp_transaction_code}"
    
    print(f"   📋 MPP Display Name: {mpp_display_name}")

    # SMS and WhatsApp notifications on cutting a sale have been disabled per requirement.
    # No SMS or WhatsApp message is prepared/queued here; the returned lists stay empty
    # so the caller queues nothing for this sale.

    print(f"📊 Messages data prepared: {len(messages_data['sms'])} SMS, {len(messages_data['whatsapp'])} WhatsApp")
    return messages_data

# ======================================================================================================================
# INVENTORY PRE-VALIDATION FUNCTION WITH SAP MAPPING
# ======================================================================================================================
# Pre-validates inventory availability with SAP product mapping before transaction processing
# Ensures sufficient stock exists and validates SAP integration for all transaction items

def pre_validate_inventory_with_sap_mapping(user, items):
    """
    Inventory Pre-Validation with SAP Mapping
    
    Performs comprehensive inventory validation for advance sale transactions with SAP product
    mapping integration. Validates product existence, SAP mapping availability, and inventory
    sufficiency across all users at the specified location.
    
    Validation Components:
        1. Product existence verification in local catalog
        2. SAP product mapping retrieval and validation
        3. Inventory quantity calculation across all location users
        4. Quantity sufficiency validation against requested amounts
        5. Comprehensive error reporting for validation failures
    
    SAP Integration:
        - Retrieves SAP-mapped product information for each item
        - Provides warning for unmapped products (does not block transaction)
        - Enables SAP system integration for inventory reporting
        - Supports cross-system inventory synchronization
    
    Location-Based Inventory Calculation:
        - Aggregates inventory across all users at the same location
        - Provides consolidated availability view
        - Supports multi-user inventory management at shared locations
        - Enables location-level inventory control
    
    Parameters:
        user (User): User object for location determination and ownership
        items (list): List of item dictionaries with stockItem and quantity keys
    
    Returns:
        list: Validation results with product, SAP mapping, and quantity information
        Raises: ValidationError for insufficient inventory or missing products
    
    Validation Result Structure:
        Each validation result includes:
            - product: Local Product object
            - sap_product: SAP-mapped ProductMapping object (or None)
            - quantity_to_deduct: Requested quantity
            - item_data: Original item data
            - user_location: User's location for inventory calculation
            - total_available: Total available inventory at location
    """
    
    # ------------------------------------------------------------
    # SECTION 1: VALIDATION INITIALIZATION
    # ------------------------------------------------------------
    # Initialize validation results collection
    inventory_validations = []
    
    # Extract user location for inventory aggregation
    user_location = user.location
    
    # ------------------------------------------------------------
    # SECTION 2: ITEM VALIDATION LOOP
    # ------------------------------------------------------------
    # Validate each item in the transaction request
    for item in items:
        
        # --------------------------------------------------------
        # SUBSECTION 2.1: ITEM DATA EXTRACTION
        # --------------------------------------------------------
        # Extract item details from request data
        stock_item_name = item.get('stockItem')
        quantity_to_deduct = item.get('quantity', 0)
        
        # --------------------------------------------------------
        # SUBSECTION 2.2: PRODUCT EXISTENCE VALIDATION
        # --------------------------------------------------------
        # Validate product exists in local product catalog
        try:
            product = Product.objects.get(name=stock_item_name)
        except Product.DoesNotExist:
            raise ValidationError(f'Product not found: {stock_item_name}')
        
        # --------------------------------------------------------
        # SUBSECTION 2.3: SAP PRODUCT MAPPING RETRIEVAL
        # --------------------------------------------------------
        # Retrieve SAP-mapped product information
        sap_product = get_sap_mapped_product(stock_item_name)
        
        # Note: Missing SAP mapping generates warning but does not block transaction
        # This allows for gradual SAP integration without disrupting operations
        
        # --------------------------------------------------------
        # SUBSECTION 2.4: LOCATION INVENTORY CALCULATION
        # --------------------------------------------------------
        # Calculate total available inventory across all users at location
        total_available = Inventory.objects.filter(
            mcc_bmc_user__location=user_location,
            product=product
        ).aggregate(total_quantity=Sum('quantity'))['total_quantity'] or 0
        
        # --------------------------------------------------------
        # SUBSECTION 2.5: INVENTORY SUFFICIENCY VALIDATION
        # --------------------------------------------------------
        # Validate requested quantity against available inventory
        if total_available < quantity_to_deduct:
            raise ValidationError(
                f'Insufficient inventory for {stock_item_name}. '
                f'Available: {total_available}, Requested: {quantity_to_deduct}'
            )
        
        # --------------------------------------------------------
        # SUBSECTION 2.6: VALIDATION RESULT COMPILATION
        # --------------------------------------------------------
        # Compile successful validation result
        inventory_validations.append({
            'product': product,
            'sap_product': sap_product,
            'quantity_to_deduct': quantity_to_deduct,
            'item_data': item,
            'user_location': user_location,
            'total_available': total_available
        })
    
    # ------------------------------------------------------------
    # SECTION 3: VALIDATION COMPLETION
    # ------------------------------------------------------------
    # Return comprehensive validation results for transaction processing
    return inventory_validations


# ======================================================================================================================
# PDF RECEIPT GENERATION FUNCTION WITH SAP MAPPING
# ======================================================================================================================
# Generates PDF receipts for advance sale transactions with SAP product mapping and cycle information
# Creates professional documentation with comprehensive transaction details and SAP integration

def generate_pdf_receipt_with_sap_mapping(user, bmc_or_mcc, mpp_with_code, items, unique_code, cycle, request):
    """
    PDF Receipt Generator with SAP Mapping and Cycle Information
    
    Generates professional PDF receipts for advance sale transactions with comprehensive
    SAP product mapping, financial cycle tracking, and organizational branding. Creates
    detailed documentation suitable for financial reporting and audit trails.
    
    Key Features:
        - SAP product mapping integration for each transaction item
        - Financial cycle information inclusion
        - Organizational logo and branding
        - Structured itemized receipt format
        - File system storage with organized directory structure
    
    PDF Generation Process:
        1. Item enhancement with SAP mapping information
        2. Branding asset retrieval and URL resolution
        3. Template context preparation with comprehensive data
        4. HTML to PDF conversion with proper styling
        5. File system storage with organized directory structure
        6. URL generation for access and distribution
    
    File Organization:
        - Directory structure: advance_sales/{mpp_code}/{date_folder}/
        - Filename format: advance_sale_{mpp_code}_{cycle_code}_{date}_{timestamp}.pdf
        - Supports organized archival and retrieval
    
    Returns:
        dict: PDF generation results including URL, path, size, content, and filename
        None: If PDF generation fails due to processing errors
    
    Result Structure:
        - url: Full URL for accessing the generated PDF
        - path: File system storage path
        - size: PDF file size in bytes
        - content: Raw PDF content for direct download
        - filename: Generated filename for client reference
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: TIMESTAMP AND FOLDER PREPARATION
        # ------------------------------------------------------------
        # Generate timestamps for date formatting and folder organization
        dispatch_date = timezone.now()
        formatted_date = dispatch_date.strftime('%d/%m/%Y')
        date_folder = dispatch_date.strftime('%d_%m_%Y')
        
        # ------------------------------------------------------------
        # SECTION 2: ITEM ENHANCEMENT WITH SAP MAPPING
        # ------------------------------------------------------------
        # Enhance transaction items with SAP product mapping information
        enhanced_items = []
        for item in items:
            # Retrieve SAP mapping for current product
            sap_product = get_sap_mapped_product(item.get('stockItem'))
            
            # Create enhanced item with SAP information
            enhanced_item = item.copy()
            enhanced_item['sap_product_name'] = sap_product.product_name if sap_product else item.get('stockItem')
            enhanced_item['sap_product_code'] = sap_product.product_code if sap_product else 'N/A'
            enhanced_items.append(enhanced_item)
        
        # ------------------------------------------------------------
        # SECTION 3: BRANDING ASSET RETRIEVAL
        # ------------------------------------------------------------
        # Retrieve and format organizational logo URL
        logo_static_path = 'images/shwetdharalogo.png'
        logo_url = None
        try:
            # Check static file storage for logo existence
            if staticfiles_storage.exists(logo_static_path):
                logo_url = staticfiles_storage.url(logo_static_path)
            else:
                logo_url = f"{settings.STATIC_URL}{logo_static_path}"
            
            # Ensure absolute URL format
            if logo_url and not logo_url.startswith(('http://', 'https://')):
                logo_url = request.build_absolute_uri(logo_url)
                
            mpp_display_name = mpp_with_code.name_with_code
            if mpp_with_code.mpp_transaction_code:
                mpp_display_name = f"{mpp_with_code.name_with_code} ({mpp_with_code.mpp_transaction_code})"
        except Exception as e:
            # Fallback URL generation on retrieval failure
            logo_url = request.build_absolute_uri(f'/static/{logo_static_path}')
        
        # ------------------------------------------------------------
        # SECTION 4: TEMPLATE CONTEXT PREPARATION
        # ------------------------------------------------------------
        # Prepare comprehensive context for PDF template rendering
        context = {
            "bmc_or_mcc": bmc_or_mcc.name,
            "mpp_original": mpp_with_code.name_with_code,
            "mpp_with_code":mpp_display_name,
            "dispatched_by": user.get_full_name() or user.email,
            "dispatch_date": formatted_date,
            "items": enhanced_items,
            "unique_code": unique_code,
            "location": getattr(user, 'location', 'N/A'),
            "has_sap_mapping": any(item.get('sap_product_code') != 'N/A' for item in enhanced_items),
            "cycle_info": {
                "name": cycle.name,
                "date_range": f"{cycle.start_date.strftime('%d-%b-%Y')} to {cycle.end_date.strftime('%d-%b-%Y')}",
                "month": cycle.monthly_cycle.month,
                "year": cycle.monthly_cycle.year
            },
            "logo_url": logo_url,
            "signature_url": None
        }
        
        # ------------------------------------------------------------
        # SECTION 5: HTML TO PDF CONVERSION
        # ------------------------------------------------------------
        # Render HTML template and convert to PDF format
        html_string = render_to_string("advance_sale_receipt.html", context)
        pdf_content = HTML(
            string=html_string,
            base_url=request.build_absolute_uri("/")
        ).write_pdf()
        
        # ------------------------------------------------------------
        # SECTION 6: FILENAME AND PATH GENERATION
        # ------------------------------------------------------------
        # Generate structured filename with transaction identifiers
        mpp_code = mpp_with_code.name_with_code.replace(' ', '_')
        cycle_code = cycle.name.replace(' ', '_').replace('-', '_')
        pdf_filename = f"advance_sale_{mpp_code}_{cycle_code}_{date_folder}_{int(time.time())}.pdf"
        pdf_file_path = f"advance_sales/{mpp_code}/{date_folder}/{pdf_filename}"
        
        # ------------------------------------------------------------
        # SECTION 7: DIRECTORY STRUCTURE PREPARATION
        # ------------------------------------------------------------
        # Ensure directory structure exists for file storage
        full_path = default_storage.path(pdf_file_path)
        directory = os.path.dirname(full_path)
        os.makedirs(directory, exist_ok=True)
        
        # ------------------------------------------------------------
        # SECTION 8: PDF FILE STORAGE
        # ------------------------------------------------------------
        # Save generated PDF to file system storage
        default_storage.save(pdf_file_path, ContentFile(pdf_content))
        
        # ------------------------------------------------------------
        # SECTION 9: URL GENERATION FOR ACCESS
        # ------------------------------------------------------------
        # Generate access URLs for the stored PDF
        pdf_url = default_storage.url(pdf_file_path)
        full_pdf_url = request.build_absolute_uri(pdf_url)
        
        # ------------------------------------------------------------
        # SECTION 10: RESULT COMPILATION AND RETURN
        # ------------------------------------------------------------
        # Return comprehensive PDF generation results
        return {
            'url': full_pdf_url,
            'path': pdf_file_path,
            'size': len(pdf_content),
            'content': pdf_content,
            'filename': pdf_filename
        }
    
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 11: PDF GENERATION FAILURE HANDLING
        # ------------------------------------------------------------
        # Log and handle PDF generation errors
        logger.error("PDF GENERATION FAILED", exc_info=True)
        return None

