# ======================================================================================================================
# SAP-MAPPED PRODUCTS WITH INVENTORY RETRIEVAL FUNCTION
# ======================================================================================================================
# Retrieves SAP-mapped products with aggregated inventory for the current user's location
# Provides filtered product data specifically for advance sale transactions

@login_required(login_url="login")
def get_products_with_inventory(request):
    """
    SAP-Mapped Products with Inventory Retrieval
    
    Retrieves products that have both inventory availability at the user's location
    and SAP system mapping. This function provides filtered product data specifically
    for advance sale transactions, ensuring only SAP-integrated products are available.
    
    Key Features:
        - Location-based inventory aggregation across all users
        - SAP mapping validation for each product
        - Filtering based on material type or product name
        - Comprehensive inventory calculation and reporting
        - Authentication and location-based access control
    
    Inventory Calculation:
        - Aggregates inventory across all users in the same location
        - Calculates total available quantity for each product
        - Filters out products with zero inventory
        - Provides detailed product metadata including pricing
    
    SAP Mapping Validation:
        - Validates SAP system mapping for each product
        - Filters out products without SAP integration
        - Provides SAP product codes and names for system integration
        - Ensures transactional consistency with enterprise systems
    
    Authentication & Authorization:
        - Requires user authentication with login redirect
        - Location-based inventory access control
        - User-specific data filtering and presentation
    
    Parameters:
        request (HttpRequest): HTTP request with optional 'material' filter parameter
    
    Returns:
        JsonResponse: List of SAP-mapped products with inventory and metadata
        Empty list: For unauthenticated users or no matching products
    """
    
    # ------------------------------------------------------------
    # SECTION 1: AUTHENTICATION VALIDATION
    # ------------------------------------------------------------
    # Validate user authentication status
    if not request.user.is_authenticated:
        return JsonResponse([], safe=False)
    
    # ------------------------------------------------------------
    # SECTION 2: REQUEST PARAMETER EXTRACTION
    # ------------------------------------------------------------
    # Extract filter parameters from request
    material_filter = request.GET.get('material', '')
    user_location = request.user.location
    
    # ------------------------------------------------------------
    # SECTION 3: LOCATION-BASED USER IDENTIFICATION
    # ------------------------------------------------------------
    # Identify all users sharing the same location for inventory aggregation
    users_in_same_location = CustomUser.objects.filter(location=user_location)
    
    # ------------------------------------------------------------
    # SECTION 4: INVENTORY AGGREGATION AND CALCULATION
    # ------------------------------------------------------------
    # Aggregate inventory quantities across all users in the location
    inventory_aggregated = (
        Inventory.objects.filter(
            mcc_bmc_user__in=users_in_same_location
        )
        .values(
            'product_id',
            'product__name',
            'product__material_type',
            'product__uom',
            'product__price',
            'product__size'
        )
        .annotate(total_quantity=Sum('quantity'))
    )
    
    # ------------------------------------------------------------
    # SECTION 5: INVENTORY DATA STRUCTURING
    # ------------------------------------------------------------
    # Create dictionary for efficient inventory data lookup
    inventory_dict = {}
    for item in inventory_aggregated:
        inventory_dict[item['product_id']] = {
            'total_quantity': item['total_quantity'],
            'name': item['product__name'],
            'material_type': item['product__material_type'],
            'uom': item['product__uom'],
            'price': item['product__price'],
            'size': item['product__size']
        }
    
    # ------------------------------------------------------------
    # SECTION 6: PRODUCT IDENTIFICATION WITH INVENTORY
    # ------------------------------------------------------------
    # Extract product IDs that have available inventory
    product_ids_with_inventory = list(inventory_dict.keys())
    
    # ------------------------------------------------------------
    # SECTION 7: ACTIVE PRODUCT FILTERING
    # ------------------------------------------------------------
    # Retrieve active products with available inventory
    products_with_stock = Product.objects.filter(
        id__in=product_ids_with_inventory,
        is_active=True
    )
    
    # ------------------------------------------------------------
    # SECTION 8: MATERIAL FILTER APPLICATION
    # ------------------------------------------------------------
    # Apply material-based filtering if specified
    if material_filter:
        products_with_stock = products_with_stock.filter(
            Q(name__icontains=material_filter) | 
            Q(material_type__icontains=material_filter)
        )
    
    # ------------------------------------------------------------
    # SECTION 9: SAP-MAPPED PRODUCT PROCESSING
    # ------------------------------------------------------------
    # Process each product with inventory for SAP mapping validation
    products_data = []
    
    for product in products_with_stock:
        # --------------------------------------------------------
        # SUBSECTION 9.1: INVENTORY INFORMATION RETRIEVAL
        # --------------------------------------------------------
        # Retrieve inventory information for current product
        inventory_info = inventory_dict.get(product.id)
        
        # Skip products without inventory data
        if not inventory_info:
            continue
        
        # --------------------------------------------------------
        # SUBSECTION 9.2: INVENTORY METADATA EXTRACTION
        # --------------------------------------------------------
        # Extract comprehensive inventory metadata
        available_stock = inventory_info['total_quantity']
        product_name = inventory_info['name']
        material_type = inventory_info['material_type']
        uom = inventory_info['uom']
        price = inventory_info['price']
        
        # --------------------------------------------------------
        # SUBSECTION 9.3: SAP MAPPING LOOKUP (optional)
        # --------------------------------------------------------
        # Look up SAP mapping for reference. SAP mapping is NOT required to sell —
        # INDENT-based products (no SAP mapping) are sellable too. The mapping is
        # attached as metadata so SAP-mapped products still show their SAP code.
        sap_mapping_info = get_sap_mapped_product_info_for_advance_sale(product.name)

        # --------------------------------------------------------
        # SUBSECTION 9.4: PRODUCT DATA COMPILATION
        # --------------------------------------------------------
        # Include EVERY in-stock product (SAP-mapped or INDENT-based).
        products_data.append({
            'id': product.id,
            'name': product_name,
            'material': material_type or product_name,
            'uom': uom,
            'price': float(price) if price else 0.0,
            'available_stock': available_stock,
            'size': product.size,
            'sap_mapping': {
                'sap_product_name': sap_mapping_info['mapped_product_name'] or product_name,
                'sap_product_code': sap_mapping_info.get('sap_product_code', 'N/A'),
                'has_mapping': sap_mapping_info['has_mapping']
            }
        })
    
    # ------------------------------------------------------------
    # SECTION 10: RESPONSE PREPARATION AND DELIVERY
    # ------------------------------------------------------------
    # Return JSON response with SAP-mapped product data
    return JsonResponse(products_data, safe=False)

# ======================================================================================================================
# SAP-MAPPED PRODUCT INFORMATION RETRIEVAL FUNCTION
# ======================================================================================================================
# Retrieves SAP-mapped product information for advance sale transactions with comprehensive fallback strategies
# Supports multiple mapping resolution approaches for robust system integration

def get_sap_mapped_product_info_for_advance_sale(product_name):
    """
    SAP-Mapped Product Information Retrieval for Advance Sales
    
    Retrieves comprehensive SAP-mapped product information for advance sale transactions
    with multiple fallback strategies for mapping resolution. This function supports
    system integration between INDENT_EASY and SAP systems with robust error handling.
    
    Mapping Resolution Hierarchy:
        1. Primary: INDENT_EASY to SAP mapping via product mapping groups
        2. Secondary: Direct SAP mapping by exact product name match
        3. Tertiary: Fuzzy matching with product name components
        4. Fallback: Return original product name with no-mapping indication
    
    Key Features:
        - Multi-strategy mapping resolution
        - Product mapping group traversal
        - Name-based fuzzy matching
        - Comprehensive error handling
        - System integration status reporting
    
    Error Handling:
        - Graceful degradation on mapping failures
        - Detailed error logging for troubleshooting
        - Fallback to original product data
        - System status indication for integration monitoring
    
    Returns:
        dict: Comprehensive mapping information including:
            - mapped_product_name: SAP product name (or original if no mapping)
            - sap_product_code: SAP product code or 'N/A'
            - mapped_system: System identifier ('SAP' or 'INDENT_EASY')
            - has_mapping: Boolean indicating successful mapping
    
    Usage Example:
        >>> mapping_info = get_sap_mapped_product_info_for_advance_sale("Premium Widget")
        >>> if mapping_info['has_mapping']:
        >>>     print(f"SAP Product: {mapping_info['mapped_product_name']}")
        >>>     print(f"SAP Code: {mapping_info['sap_product_code']}")
        >>> else:
        >>>     print("Product not mapped to SAP system")
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: PRIMARY MAPPING - INDENT_EASY TO SAP VIA GROUPS
        # ------------------------------------------------------------
        # Attempt primary mapping strategy through product mapping groups
        indent_easy_mapping = ProductMapping.objects.filter(
            system='INDENT_EASY',
            product_name=product_name,
            is_active=True
        ).first()
        
        # Process primary mapping if found
        if indent_easy_mapping:
            # --------------------------------------------------------
            # SUBSECTION 1.1: MAPPING GROUP IDENTIFICATION
            # --------------------------------------------------------
            # Identify product mapping group for cross-system resolution
            mapping_relation = ProductMappingRelation.objects.filter(
                product_mapping=indent_easy_mapping
            ).first()
            
            # Process group-based mapping if relation exists
            if mapping_relation:
                group = mapping_relation.group
                
                # ----------------------------------------------------
                # SUBSECTION 1.2: SAP MAPPING RETRIEVAL VIA GROUP
                # ----------------------------------------------------
                # Retrieve SAP mapping from the same product mapping group
                sap_mapping = ProductMapping.objects.filter(
                    system='SAP',
                    groups__group=group,
                    is_active=True
                ).first()
                
                # Return SAP mapping if successfully resolved
                if sap_mapping:
                    return {
                        "mapped_product_name": sap_mapping.product_name,
                        "sap_product_code": sap_mapping.product_code or 'N/A',
                        "mapped_system": 'SAP',
                        "has_mapping": True
                    }
        
        # ------------------------------------------------------------
        # SECTION 2: SECONDARY MAPPING - DIRECT SAP NAME MATCH
        # ------------------------------------------------------------
        # Attempt direct SAP mapping by product name similarity
        sap_mapping_direct = ProductMapping.objects.filter(
            system='SAP',
            product_name__icontains=product_name,
            is_active=True
        ).first()
        
        # Return direct mapping if found
        if sap_mapping_direct:
            return {
                "mapped_product_name": sap_mapping_direct.product_name,
                "sap_product_code": sap_mapping_direct.product_code or 'N/A',
                "mapped_system": 'SAP',
                "has_mapping": True
            }
        
        # ------------------------------------------------------------
        # SECTION 3: TERTIARY MAPPING - FUZZY NAME COMPONENT MATCHING
        # ------------------------------------------------------------
        # Attempt fuzzy matching with product name components
        product_name_parts = product_name.lower().split()
        
        for part in product_name_parts:
            # Filter for significant name components
            if len(part) > 3:
                sap_mapping_fuzzy = ProductMapping.objects.filter(
                    system='SAP',
                    product_name__icontains=part,
                    is_active=True
                ).first()
                
                # Return fuzzy mapping if found
                if sap_mapping_fuzzy:
                    return {
                        "mapped_product_name": sap_mapping_fuzzy.product_name,
                        "sap_product_code": sap_mapping_fuzzy.product_code or 'N/A',
                        "mapped_system": 'SAP',
                        "has_mapping": True
                    }
        
        # ------------------------------------------------------------
        # SECTION 4: MAPPING FAILURE - FALLBACK RESULT
        # ------------------------------------------------------------
        # Return fallback result when no mapping strategies succeed
        return {
            "mapped_product_name": product_name,
            "sap_product_code": 'N/A',
            "mapped_system": 'INDENT_EASY',
            "has_mapping": False
        }
        
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 5: EXCEPTION HANDLING AND ERROR RECOVERY
        # ------------------------------------------------------------
        # Handle exceptions with comprehensive error recovery
        return {
            "mapped_product_name": product_name,
            "sap_product_code": 'N/A',
            "mapped_system": 'INDENT_EASY',
            "has_mapping": False
        }
        
