# PENDING POD ADVANCE SALES RETRIEVAL ENDPOINT
# ======================================================================================================================
# Retrieves advance sale transactions pending Proof of Delivery (POD) upload
# Provides comprehensive listing for POD management and user interface integration

@login_required(login_url='login')
def get_pending_pod_advance_sales(request):
    """
    Pending POD Advance Sales Retrieval Endpoint
    
    Retrieves advance sale transactions that are pending Proof of Delivery (POD) uploads
    for the authenticated user. This endpoint supports POD management workflows by
    providing comprehensive transaction listings with detailed metadata for user review.
    
    Key Functionality:
        - Retrieves user-specific advance sale records pending POD upload
        - Provides comprehensive transaction metadata for review
        - Supports POD management workflows and user interface integration
        - Enables batch processing and selection of pending transactions
    
    Transaction Metadata Included:
        - Transaction identification and unique codes
        - Product details including stock items and quantities
        - Organizational information (BMC/MCC, MPP codes)
        - Dispatch timestamps and transaction dates
        - Unit of measure and quantity information
    
    Authentication & Filtering:
        - Requires user authentication for access control
        - Filters records by authenticated user ownership
        - Returns only records with pod_uploaded=False status
        - Orders results by dispatch timestamp for prioritization
    
    Returns:
        JsonResponse: Comprehensive listing of pending POD transactions
        JsonResponse: Error response with appropriate status codes and messages
    """
    
    # ------------------------------------------------------------
    # SECTION 1: REQUEST METHOD VALIDATION
    # ------------------------------------------------------------
    # Validate request method is GET for data retrieval
    if request.method != 'GET':
        return JsonResponse({
            'success': False, 
            'message': 'Only GET method allowed'
        }, status=405)
    
    try:
        # --------------------------------------------------------
        # SECTION 2: PENDING SALES DATABASE RETRIEVAL
        # --------------------------------------------------------
        # Retrieve advance sale records pending POD upload
        pending_sales = AdvanceSale.objects.filter(
            dispatched_by=request.user,
            pod_uploaded=False
        ).order_by('-dispatched_at')
        
        # --------------------------------------------------------
        # SECTION 3: TRANSACTION DATA PROCESSING
        # --------------------------------------------------------
        # Process sale records into structured data format
        sales_data = []
        
        for sale in pending_sales:
            # Compile comprehensive sale information
            sale_info = {
                'id': sale.id,
                'bmc_or_mcc': sale.bmc_or_mcc,
                'uom': sale.uom,
                'stock_item': sale.stock_item,
                'quantity': sale.quantity,
                'dispatched_at': sale.dispatched_at.strftime("%Y-%m-%d %H:%M"),
                'mpp_with_code': sale.mpp_with_code,
                'unique_code': str(sale.unique_code)
            }
            sales_data.append(sale_info)
        
        # --------------------------------------------------------
        # SECTION 4: SUCCESS RESPONSE PREPARATION
        # --------------------------------------------------------
        # Prepare comprehensive success response
        response_data = {
            'success': True,
            'sales': sales_data,
            'total_count': len(sales_data),
            'user': request.user.email
        }
        
        return JsonResponse(response_data)
        
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 5: EXCEPTION HANDLING AND ERROR RESPONSE
        # ------------------------------------------------------------
        # Handle unexpected exceptions with error response
        return JsonResponse({
            'success': False,
            'message': f'Error fetching pending sales: {str(e)}',
            'sales': []
        }, status=500)

# ======================================================================================================================
# POD (PROOF OF DELIVERY) DASHBOARD VIEW
# ======================================================================================================================
# Provides comprehensive POD management dashboard with financial cycle organization
# Displays pending POD uploads grouped by transaction with cycle-wise categorization

@login_required(login_url="login")
def pod_dashboard(request):
    """
    POD Dashboard View with Financial Cycle Organization
    
    Provides a comprehensive dashboard for managing Proof of Delivery (POD) uploads
    with financial cycle organization, pending transaction grouping, and user-specific
    data visualization. This view supports POD management workflows with cycle-based
    transaction categorization.
    
    Key Functionality:
        - Retrieves current financial cycle information using advance sale logic
        - Groups pending POD transactions by unique codes for efficient management
        - Categorizes transactions by financial cycles for organizational reporting
        - Provides comprehensive dashboard data for user interface rendering
    
    Dashboard Components:
        1. Current financial cycle information and display
        2. Pending POD transactions grouped by unique transaction codes
        3. Product-level details for each pending transaction
        4. Cycle-based categorization for organizational reporting
    
    Financial Cycle Integration:
        - Uses same cycle logic as advance sale transactions for consistency
        - Supports fallback cycle determination when financial cycles are unavailable
        - Provides cycle-based transaction organization for reporting
    
    Authentication & Data Filtering:
        - Requires user authentication with login redirect
        - Filters transactions by user ownership for data security
        - Organizes data by dispatch timestamp for workflow prioritization
    
    Returns:
        HttpResponse: Rendered POD dashboard template with comprehensive context
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: CURRENT DATE AND CYCLE INITIALIZATION
        # ------------------------------------------------------------
        # Determine current date for cycle calculations
        current_date = timezone.now().date()
        
        # Initialize cycle variables
        current_cycle = None
        available_cycles = []
        
        # ------------------------------------------------------------
        # SECTION 2: FINANCIAL CYCLE RETRIEVAL
        # ------------------------------------------------------------
        # Attempt to retrieve financial cycles using advance sale logic
        try:
            from .models import Cycle
            from datetime import timedelta
            
            # Retrieve active cycles from last 60 days
            two_months_ago = current_date - timedelta(days=60)
            
            cycles = Cycle.objects.filter(
                is_active=True,
                start_date__gte=two_months_ago
            ).select_related('monthly_cycle').order_by('start_date')
            
            # Process retrieved cycles
            if cycles.exists():
                available_cycles = cycles
                
                # Identify current cycle based on date range
                for cycle in cycles:
                    if cycle.start_date <= current_date <= cycle.end_date:
                        current_cycle = cycle
                        break
                
                # Apply fallback if no current cycle found
                if not current_cycle:
                    current_cycle = get_fallback_cycle(current_date)
            else:
                # Apply fallback when no cycles are available
                current_cycle = get_fallback_cycle(current_date)
                
        except Exception as e:
            # Apply fallback on cycle retrieval errors
            current_cycle = get_fallback_cycle(current_date)
        
        # ------------------------------------------------------------
        # SECTION 3: PENDING POD TRANSACTIONS RETRIEVAL
        # ------------------------------------------------------------
        # Retrieve user-specific pending POD transactions
        pending_pods = AdvanceSale.objects.filter(
            dispatched_by=request.user,
            pod_uploaded=False
        ).order_by('-dispatched_at')
        
        # ------------------------------------------------------------
        # SECTION 4: TRANSACTION GROUPING BY UNIQUE CODES
        # ------------------------------------------------------------
        # Group transactions by unique codes for dashboard organization
        unique_sales = {}
        
        for pod in pending_pods:
            # Initialize unique sale entry if not exists
            if pod.unique_code not in unique_sales:
                unique_sales[pod.unique_code] = {
                    'unique_code': pod.unique_code,
                    'bmc_or_mcc': pod.bmc_or_mcc,
                    'mpp_with_code': pod.mpp_with_code,
                    'dispatched_at': pod.dispatched_at,
                    'products': [],
                    'cycle': get_cycle_for_pod(pod, available_cycles)
                }
            
            # Add product details to unique sale
            unique_sales[pod.unique_code]['products'].append({
                'stock_item': pod.stock_item,
                'quantity': pod.quantity,
                'uom': pod.uom
            })
        
        # ------------------------------------------------------------
        # SECTION 5: DASHBOARD CONTEXT PREPARATION
        # ------------------------------------------------------------
        # Convert grouped sales to list format
        pending_sales = list(unique_sales.values())
        
        # Prepare comprehensive context for template rendering
        context = {
            'user': request.user,
            'current_cycle': current_cycle,
            'cycle_name': get_cycle_display_name(current_cycle),
            'total_pending': len(pending_sales),
            'pending_sales': pending_sales
        }
        
        # ------------------------------------------------------------
        # SECTION 6: TEMPLATE RENDERING AND RESPONSE
        # ------------------------------------------------------------
        # Render POD dashboard template with prepared context
        return render(request, 'pod_dashboard.html', context)
        
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 7: EXCEPTION HANDLING
        # ------------------------------------------------------------
        # Handle exceptions gracefully to maintain user experience
        # Note: Consider implementing more specific error handling
        # and potentially an error template for production use
        raise
# ======================================================================================================================
# FALLBACK CYCLE DETERMINATION FUNCTION
# ======================================================================================================================
# Provides fallback financial cycle determination when formal finance cycles are unavailable
# Supports system continuity with date-based cycle calculations for transaction processing

def get_fallback_cycle(current_date):
    """
    Fallback Financial Cycle Determination
    
    Provides fallback financial cycle determination when formal finance department cycles
    are unavailable or not configured. This function ensures system continuity by providing
    date-based cycle calculations for transaction processing and reporting.
    
    Cycle Determination Logic:
        - Cycle 1: Days 1-10 of the month
        - Cycle 2: Days 11-20 of the month
        - Cycle 3: Days 21-31 of the month
    
    Key Features:
        - Date-based cycle calculation for system continuity
        - Calendar day-based cycle segmentation
        - Fallback identification for system transparency
        - Consistent cycle structure for transaction processing
    
    Fallback Cycle Structure:
        - Unique identifier with fallback indication
        - Descriptive cycle name and number
        - Date range representation
        - Fallback flag for system identification
    
    Use Cases:
        - Finance cycle system maintenance or unavailability
        - New system implementation without formal cycle configuration
        - Emergency operations during system disruptions
        - Testing and development environments
    
    Parameters:
        current_date (date): Current date object for cycle determination
    
    Returns:
        dict: Fallback cycle information with comprehensive metadata
    """
    
    # ------------------------------------------------------------
    # SECTION 1: DATE COMPONENT EXTRACTION
    # ------------------------------------------------------------
    # Extract day component from current date
    current_day = current_date.day
    
    # ------------------------------------------------------------
    # SECTION 2: CYCLE 1 DETERMINATION (DAYS 1-10)
    # ------------------------------------------------------------
    # Determine fallback cycle for first third of month
    if current_day <= 10:
        return {
            'id': '1-10-fallback',
            'name': 'Cycle 1',
            'cycle_number': '1',
            'date_range': '1st-10th',
            'is_fallback': True
        }
    
    # ------------------------------------------------------------
    # SECTION 3: CYCLE 2 DETERMINATION (DAYS 11-20)
    # ------------------------------------------------------------
    # Determine fallback cycle for second third of month
    elif current_day <= 20:
        return {
            'id': '11-20-fallback',
            'name': 'Cycle 2',
            'cycle_number': '2',
            'date_range': '11th-20th',
            'is_fallback': True
        }
    
    # ------------------------------------------------------------
    # SECTION 4: CYCLE 3 DETERMINATION (DAYS 21-31)
    # ------------------------------------------------------------
    # Determine fallback cycle for final third of month
    else:
        return {
            'id': '21-31-fallback',
            'name': 'Cycle 3',
            'cycle_number': '3',
            'date_range': '21st-31st',
            'is_fallback': True
        }

# ======================================================================================================================
# POD CYCLE DETERMINATION AND DISPLAY UTILITIES
# ======================================================================================================================
# Utility functions for POD cycle management, display formatting, and cycle-based filtering
# Supports comprehensive cycle handling for Proof of Delivery management workflows

def get_cycle_for_pod(pod, available_cycles):
    """
    POD Cycle Determination
    
    Determines the appropriate financial cycle for a POD based on dispatch date,
    with fallback to date-based cycle calculation when finance cycles are unavailable.
    
    Cycle Resolution Hierarchy:
        1. Primary: Match dispatch date with finance cycle date ranges
        2. Secondary: Date-based cycle calculation (1-10, 11-20, 21-31)
        3. Tertiary: "Unknown" for exceptional cases
    
    Parameters:
        pod (AdvanceSale): POD transaction object
        available_cycles (list): Available finance cycles for matching
    
    Returns:
        str: Cycle identifier (cycle ID or date-based range)
    """
    try:
        # ------------------------------------------------------------
        # SECTION 1: DISPATCH DATE EXTRACTION
        # ------------------------------------------------------------
        # Extract dispatch date from POD transaction
        dispatch_date = pod.dispatched_at.date()
        
        # ------------------------------------------------------------
        # SECTION 2: FINANCE CYCLE MATCHING (PRIMARY RESOLUTION)
        # ------------------------------------------------------------
        # Attempt to match dispatch date with available finance cycles
        if available_cycles:
            for cycle in available_cycles:
                if cycle.start_date <= dispatch_date <= cycle.end_date:
                    return str(cycle.id)  # Return finance cycle ID
        
        # ------------------------------------------------------------
        # SECTION 3: DATE-BASED CYCLE CALCULATION (SECONDARY RESOLUTION)
        # ------------------------------------------------------------
        # Fallback to simple date-based cycle determination
        if dispatch_date.day <= 10:
            return "1-10"
        elif dispatch_date.day <= 20:
            return "11-20"
        else:
            return "21-31"
    except:
        # ------------------------------------------------------------
        # SECTION 4: EXCEPTION HANDLING (TERTIARY RESOLUTION)
        # ------------------------------------------------------------
        # Return unknown identifier for exceptional cases
        return "Unknown"


def get_cycle_display_name(cycle):
    """
    Cycle Display Name Formatter
    
    Formats cycle objects into human-readable display names with appropriate
    formatting for both finance cycles and fallback cycles.
    
    Formatting Logic:
        - Finance Cycles: "Cycle Name (DD-DD Month)"
        - Fallback Cycles: "Cycle Name (Date Range)"
        - Unknown: "Select a cycle"
    
    Parameters:
        cycle (dict/object): Cycle object or dictionary
    
    Returns:
        str: Formatted display name for user interface
    """
    # ------------------------------------------------------------
    # SECTION 1: FALLBACK CYCLE FORMATTING
    # ------------------------------------------------------------
    # Format dictionary-based fallback cycles
    if isinstance(cycle, dict):
        # --------------------------------------------------------
        # SUBSECTION 1.1: FALLBACK CYCLE SPECIFIC FORMATTING
        # --------------------------------------------------------
        if cycle.get('is_fallback'):
            return f"{cycle['name']} ({cycle.get('date_range', '')})"
        # --------------------------------------------------------
        # SUBSECTION 1.2: GENERIC DICTIONARY FORMATTING
        # --------------------------------------------------------
        return cycle.get('name', 'Unknown Cycle')
    
    # ------------------------------------------------------------
    # SECTION 2: FINANCE CYCLE OBJECT FORMATTING
    # ------------------------------------------------------------
    # Format object-based finance cycles
    elif hasattr(cycle, 'name'):
        return f"{cycle.name} ({cycle.start_date.strftime('%d')}-{cycle.end_date.strftime('%d')} {cycle.monthly_cycle.month})"
    
    # ------------------------------------------------------------
    # SECTION 3: DEFAULT FORMATTING
    # ------------------------------------------------------------
    # Return default display text
    return "Select a cycle"


