# ======================================================================================================================
# SIMPLE CYCLE DETERMINATION UTILITIES
# ======================================================================================================================

def get_cycle_from_date(date):
    """
    Simple Cycle Determination from Date
    
    Determines basic cycle identifier from a given date using simple
    date-based segmentation (1-10, 11-20, 21-31).
    
    Parameters:
        date (date): Date object for cycle determination
    
    Returns:
        str: Simple cycle identifier
    """
    # ------------------------------------------------------------
    # SECTION 1: DATE COMPONENT EXTRACTION
    # ------------------------------------------------------------
    # Extract day component from date
    day = date.day
    
    # ------------------------------------------------------------
    # SECTION 2: CYCLE DETERMINATION LOGIC
    # ------------------------------------------------------------
    # Apply simple date-based cycle segmentation
    if day <= 10:
        return "1-10"
    elif day <= 20:
        return "11-20"
    else:
        return "21-31"




