# PENDING PODS RETRIEVAL API WITH CYCLE FILTERING
# ======================================================================================================================
@csrf_exempt
@login_required(login_url="login")
def get_pending_pods(request):

    if request.method != 'GET':
        return JsonResponse({'success': False, 'error': 'Invalid request method'}, status=405)

    try:
        cycle_id = request.GET.get('cycle_id')

        pending_pods = AdvanceSale.objects.filter(
            dispatched_by=request.user,
            pod_uploaded=False
        )

        # ✅ THE ONLY CORRECT FILTER
        if cycle_id:
            pending_pods = pending_pods.filter(cycle_id=cycle_id)

        pending_pods = pending_pods.select_related('cycle').order_by('-dispatched_at')

        unique_sales = {}

        for pod in pending_pods:
            if pod.unique_code not in unique_sales:
                unique_sales[pod.unique_code] = {
                    'id': pod.id,
                    'unique_code': pod.unique_code,
                    'bmc_or_mcc': pod.bmc_or_mcc,
                    'mpp_with_code': pod.mpp_with_code,
                    'dispatched_at': pod.dispatched_at.strftime('%d/%m/%Y %H:%M'),
                    'products': [],
                    # ✅ USE STORED CYCLE
                    'cycle': pod.cycle.name if pod.cycle else 'No Cycle'
                }

            unique_sales[pod.unique_code]['products'].append({
                'stock_item': pod.stock_item,
                'quantity': pod.quantity,
                'uom': pod.uom
            })

        pending_sales = list(unique_sales.values())

        return JsonResponse({
            'success': True,
            'pending_pods': pending_sales,
            'count': len(pending_sales)
        })

    except Exception as e:
        return JsonResponse({'success': False, 'error': str(e)}, status=500)


# ======================================================================================================================
# SIMPLE CYCLE DETERMINATION FROM DATE FUNCTION
# ======================================================================================================================
# Provides basic date-based cycle determination for POD transactions
# Uses simple calendar segmentation for quick cycle identification

def get_cycle_for_pod_simple(date_obj):
    """
    Simple POD Cycle Determination from Date
    
    Provides basic cycle determination from a date object using simple
    calendar-based segmentation. This function offers a lightweight
    alternative for cycle identification without complex finance cycle logic.
    
    Cycle Segmentation:
        - Cycle 1: Days 1-10 of the month
        - Cycle 2: Days 11-20 of the month  
        - Cycle 3: Days 21-31 of the month
    
    Use Cases:
        - Quick cycle identification for display purposes
        - Simplified filtering without finance cycle dependencies
        - Fallback calculations when finance cycles are unavailable
        - Performance-critical operations requiring minimal processing
    
    Parameters:
        date_obj (date): Date object for cycle determination
    
    Returns:
        str: Simple cycle identifier string ("1-10", "11-20", "21-31")
    """
    
    # ------------------------------------------------------------
    # SECTION 1: DATE COMPONENT EXTRACTION
    # ------------------------------------------------------------
    # Extract day component from date object for cycle determination
    day = date_obj.day
    
    # ------------------------------------------------------------
    # SECTION 2: CYCLE 1 DETERMINATION (DAYS 1-10)
    # ------------------------------------------------------------
    # Identify Cycle 1 for first third of month
    if day <= 10:
        return "1-10"
    
    # ------------------------------------------------------------
    # SECTION 3: CYCLE 2 DETERMINATION (DAYS 11-20)
    # ------------------------------------------------------------
    # Identify Cycle 2 for second third of month
    elif day <= 20:
        return "11-20"
    
    # ------------------------------------------------------------
    # SECTION 4: CYCLE 3 DETERMINATION (DAYS 21-31)
    # ------------------------------------------------------------
    # Identify Cycle 3 for final third of month
    else:
        return "21-31"


