# Supports multi-record updates with unique code verification and file management

@csrf_exempt
@login_required(login_url="login")
def upload_pod(request):
    """
    POD File Upload and Verification Handler
    
    Processes Proof of Delivery (POD) file uploads with comprehensive validation,
    verification code checking, and multi-record updates. Ensures secure upload
    with user authorization, file validation, and transaction verification.
    
    Key Functionality:
        - Verification code validation against unique transaction codes
        - Multi-record updates for transactions with shared unique codes
        - Comprehensive file type and size validation
        - User authorization and transaction ownership verification
    
    Upload Process:
        1. Request validation and parameter extraction (FormData)
        2. Transaction verification using unique codes
        3. File validation and security checks
        4. Multi-record database updates
        5. Success confirmation with upload statistics
    
    Security Features:
        - User authentication requirement
        - Verification code matching for transaction authorization
        - File type and size restrictions
        - Transaction ownership validation
    
    Returns:
        JsonResponse: Success response with upload statistics
        JsonResponse: Error response with appropriate status codes and messages
    """
    
    # ------------------------------------------------------------
    # SECTION 1: REQUEST METHOD VALIDATION
    # ------------------------------------------------------------
    # Validate request method is POST for file upload
    if request.method != 'POST':
        print(f"❌ Invalid request method: {request.method}")
        return JsonResponse({
            'success': False,
            'error': 'Invalid request method'
        }, status=405)
    
    try:
        # --------------------------------------------------------
        # SECTION 2: REQUEST DATA EXTRACTION
        # --------------------------------------------------------
        # Extract verification data from FormData request
        unique_code = request.POST.get('unique_code')
        verification_code = request.POST.get('verification_code')
        
        print("=" * 50)
        print("📦 POD UPLOAD REQUEST RECEIVED")
        print("=" * 50)
        print(f"👤 User: {request.user.username} ({request.user.get_full_name()})")
        print(f"👤 User ID: {request.user.id}")
        print(f"🔑 Unique Code: {unique_code}")
        print(f"🔢 Verification Code: {verification_code}")
        print(f"📝 POST Data Keys: {list(request.POST.keys())}")
        print(f"📁 FILES Data Keys: {list(request.FILES.keys())}")
        
        # --------------------------------------------------------
        # SECTION 3: PENDING TRANSACTIONS RETRIEVAL
        # --------------------------------------------------------
        # Retrieve pending POD transactions for authenticated user
        advance_sales = AdvanceSale.objects.filter(
            unique_code=unique_code, 
            dispatched_by=request.user,
            pod_uploaded=False  # Only retrieve pending uploads
        )
        
        print(f"🔍 Found {advance_sales.count()} pending transactions for code: {unique_code}")
        
        # --------------------------------------------------------
        # SECTION 4: TRANSACTION EXISTENCE VALIDATION
        # --------------------------------------------------------
        # Validate that pending transactions exist for the unique code
        if not advance_sales.exists():
            print(f"❌ No pending POD found for unique code: {unique_code}")
            return JsonResponse({
                'success': False,
                'error': 'No pending POD found for this unique code.'
            }, status=404)
        
        # --------------------------------------------------------
        # SECTION 5: VERIFICATION CODE VALIDATION
        # --------------------------------------------------------
        # Validate provided verification code matches unique code
        expected_code_prefix = unique_code[:10]
        provided_code_prefix = verification_code[:10] if verification_code else ""
        
        print(f"📋 Expected code prefix (first 10 chars): {expected_code_prefix}")
        print(f"📋 Provided code prefix (first 10 chars): {provided_code_prefix}")
        
        # --------------------------------------------------------
        # SUBSECTION 5.1: VERIFICATION FAILURE HANDLING
        # --------------------------------------------------------
        # Handle verification code mismatch
        if expected_code_prefix != provided_code_prefix:
            print(f"❌ Verification code mismatch!")
            print(f"   Expected: {expected_code_prefix}")
            print(f"   Received: {provided_code_prefix}")
            return JsonResponse({
                'success': False,
                'error': 'Invalid verification code. Please check the code and try again.'
            }, status=400)
        
        print("✅ Verification code matched successfully!")
        
        # --------------------------------------------------------
        # SECTION 6: FILE UPLOAD VALIDATION
        # --------------------------------------------------------
        # Validate that POD file was included in request
        if 'pod_file' not in request.FILES:
            print("❌ No file uploaded in request.FILES")
            return JsonResponse({
                'success': False,
                'error': 'No file uploaded. Please select a POD file.'
            }, status=400)
        
        # --------------------------------------------------------
        # SUBSECTION 6.1: FILE OBJECT EXTRACTION
        # --------------------------------------------------------
        # Extract file object from request
        pod_file = request.FILES['pod_file']
        
        print(f"📄 File Name: {pod_file.name}")
        print(f"📊 File Size: {pod_file.size} bytes ({pod_file.size/1024:.2f} KB)")
        print(f"📋 Content Type: {pod_file.content_type}")
        
        # --------------------------------------------------------
        # SUBSECTION 6.2: FILE TYPE VALIDATION
        # --------------------------------------------------------
        # Validate file extension against allowed types
        allowed_extensions = ['.pdf', '.jpg', '.jpeg', '.png', '.doc', '.docx']
        file_extension = '.' + pod_file.name.split('.')[-1].lower()
        
        print(f"🔍 File Extension: {file_extension}")
        print(f"✅ Allowed Extensions: {allowed_extensions}")
        
        if file_extension not in allowed_extensions:
            print(f"❌ Invalid file extension: {file_extension}")
            return JsonResponse({
                'success': False,
                'error': 'Invalid file type. Please upload PDF, JPG, PNG, or DOC files only.'
            }, status=400)
        
        print("✅ File extension is valid!")
        
        # --------------------------------------------------------
        # SUBSECTION 6.3: FILE SIZE VALIDATION
        # --------------------------------------------------------
        # Validate file size against maximum limit (10MB)
        max_size = 10 * 1024 * 1024  # 10MB
        print(f"📏 Max allowed size: {max_size} bytes ({max_size/1024/1024:.1f} MB)")
        print(f"📏 Actual file size: {pod_file.size} bytes ({pod_file.size/1024/1024:.2f} MB)")
        
        if pod_file.size > max_size:
            print(f"❌ File too large! {pod_file.size} > {max_size}")
            return JsonResponse({
                'success': False,
                'error': 'File too large. Maximum size is 10MB.'
            }, status=400)
        
        print("✅ File size is within limits!")
        
        # --------------------------------------------------------
        # SECTION 7: GET FIRST TRANSACTION FOR PATH INFO
        # --------------------------------------------------------
        # Get the first transaction to extract MPP and date info
        first_sale = advance_sales.first()
        print(f"\n📋 First Transaction Details:")
        print(f"   ID: {first_sale.id}")
        print(f"   MPP Code: {first_sale.mpp_with_code}")
        print(f"   Dispatched Date: {first_sale.dispatched_at}")
        print(f"   BMC/MCC: {first_sale.bmc_or_mcc}")
        
        # --------------------------------------------------------
        # SECTION 8: CREATE FILE PATH AND DIRECTORY
        # --------------------------------------------------------
        # Generate file path based on transaction details
        from django.utils import timezone
        import os
        
        # Get MPP code and create safe directory name
        mpp_code = first_sale.mpp_with_code or "unknown_mpp"
        # Replace any problematic characters in MPP code
        safe_mpp_code = "".join(c for c in mpp_code if c.isalnum() or c in (' ', '-', '_')).rstrip()
        safe_mpp_code = safe_mpp_code.replace(' ', '_')
        
        # Get dispatch date for folder structure
        dispatch_date = first_sale.dispatched_at or timezone.now()
        date_folder = dispatch_date.strftime('%d_%m_%Y')
        
        # Create filename with timestamp
        timestamp = timezone.now().strftime('%H%M%S_%d%m%Y')
        clean_filename = pod_file.name.replace(' ', '_')
        new_filename = f"pod_{timestamp}_{clean_filename}"
        
        # Create the full path
        pod_file_path = f"advance_sales/{safe_mpp_code}/{date_folder}/{new_filename}"
        
        print(f"\n📁 File Path Structure:")
        print(f"   MPP Code: {mpp_code}")
        print(f"   Safe MPP Code: {safe_mpp_code}")
        print(f"   Date Folder: {date_folder}")
        print(f"   Original Filename: {pod_file.name}")
        print(f"   Clean Filename: {clean_filename}")
        print(f"   New Filename: {new_filename}")
        print(f"   Full Path: {pod_file_path}")
        
        # Create directory if it doesn't exist
        from django.core.files.storage import default_storage
        import os
        
        # Get the absolute path
        absolute_path = default_storage.path(pod_file_path)
        directory = os.path.dirname(absolute_path)
        
        print(f"\n📂 Directory Information:")
        print(f"   Absolute Path: {absolute_path}")
        print(f"   Directory: {directory}")
        
        # Create directory if it doesn't exist
        os.makedirs(directory, exist_ok=True)
        print(f"✅ Directory created/verified: {directory}")
        
        # Check if directory exists
        if os.path.exists(directory):
            print(f"✅ Directory exists and is accessible")
        else:
            print(f"❌ Directory does not exist!")
        
        # --------------------------------------------------------
        # SECTION 9: SAVE THE FILE
        # --------------------------------------------------------
        print(f"\n💾 Saving file...")
        
        # Save the file using default storage
        saved_path = default_storage.save(pod_file_path, pod_file)
        
        print(f"✅ File saved successfully!")
        print(f"   Saved Path (from storage): {saved_path}")
        print(f"   Expected Path: {pod_file_path}")
        
        # Verify the file was saved
        if default_storage.exists(saved_path):
            file_size = default_storage.size(saved_path)
            print(f"✅ File exists in storage. Size: {file_size} bytes")
            
            # Get full URL if needed
            from django.conf import settings
            media_url = settings.MEDIA_URL
            file_url = f"{media_url}{saved_path}"
            print(f"   File URL: {file_url}")
        else:
            print(f"❌ File NOT found in storage!")
        
        # --------------------------------------------------------
        # SECTION 10: MULTI-RECORD DATABASE UPDATES
        # --------------------------------------------------------
        # Get transaction details before update
        transaction_ids = list(advance_sales.values_list('id', flat=True))
        print(f"\n🔄 Updating {len(transaction_ids)} transactions with IDs: {transaction_ids}")
        
        # Update all associated advance sale records
        updated_count = advance_sales.update(
            pod_file=saved_path,  # Use the saved path
            pod_uploaded=True,
            pod_uploaded_at=timezone.now()
        )
        
        print(f"✅ Successfully updated {updated_count} records")
        
        # Get updated records to verify
        updated_records = AdvanceSale.objects.filter(id__in=transaction_ids)
        for record in updated_records:
            print(f"   Record ID {record.id}: POD File = {record.pod_file}")
        
        # --------------------------------------------------------
        # SECTION 11: SUCCESS RESPONSE PREPARATION
        # --------------------------------------------------------
        # Prepare comprehensive success response
        response_data = {
            'success': True,
            'message': f'POD uploaded successfully for {updated_count} delivery item(s)!',
            'unique_code': unique_code,
            'updated_count': updated_count,
            'uploaded_at': timezone.now().strftime('%d/%m/%Y %H:%M'),
            'file_path': saved_path,
            'file_url': file_url if 'file_url' in locals() else None
        }
        
        print(f"\n📤 Sending success response: {response_data}")
        print("=" * 50)
        
        return JsonResponse(response_data)
        
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 12: EXCEPTION HANDLING AND ERROR RESPONSE
        # ------------------------------------------------------------
        # Handle unexpected exceptions with comprehensive error response
        import traceback
        print(f"\n❌ UNEXPECTED ERROR: {str(e)}")
        print("Stack Trace:")
        print(traceback.format_exc())
        print("=" * 50)
        
        return JsonResponse({
            'success': False,
            'error': 'An error occurred while uploading the POD. Please try again.',
            'debug_error': str(e)  # Only for debugging, remove in production
        }, status=500)
        
            

