# ======================================================================================================================
# POD FOLDER STRUCTURE AND FILENAME UTILITIES
# ======================================================================================================================
# Provides comprehensive utilities for generating organized POD file storage structures
# and sanitizing filenames for filesystem compatibility

def generate_pod_folder_structure(advance_sale, user):
    """
    Organized POD Folder Structure Generator
    
    Generates hierarchical folder structures for POD file storage with comprehensive
    organizational categorization including year, month, cycle, MPP, date, and user
    information. Ensures systematic file organization for easy retrieval and management.
    
    Folder Hierarchy:
        Root/PODs/
            ├── Year/
            │   ├── Month_Number_Month_Name/
            │   │   ├── Cycle_X/
            │   │   │   ├── MPP_Code/
            │   │   │   │   ├── DD/
            │   │   │   │   │   └── User_EmployeeCode_FirstName/
    
    Key Features:
        - Hierarchical organization for systematic file management
        - Time-based categorization (year, month, date)
        - Business categorization (cycles, MPP codes)
        - User-based segregation for access control
        - Automatic directory creation
    
    Parameters:
        advance_sale (AdvanceSale): Advance sale transaction object
        user (User): User object for user-specific folder creation
    
    Returns:
        str: Generated folder structure path for file storage
    """
    
    # ------------------------------------------------------------
    # SECTION 1: TIME-BASED FOLDER COMPONENTS
    # ------------------------------------------------------------
    # Extract time-based components for folder organization
    current_date = timezone.now()
    
    # --------------------------------------------------------
    # SUBSECTION 1.1: YEAR COMPONENT GENERATION
    # --------------------------------------------------------
    # Generate year folder component
    year = current_date.strftime("%Y")
    
    # --------------------------------------------------------
    # SUBSECTION 1.2: MONTH COMPONENT GENERATION
    # --------------------------------------------------------
    # Generate month folder with numeric and textual representation
    month = current_date.strftime("%m_%B")  # Format: "11_November"
    
    # --------------------------------------------------------
    # SUBSECTION 1.3: DATE COMPONENT GENERATION
    # --------------------------------------------------------
    # Generate day folder component
    date_folder = current_date.strftime("%d")
    
    # ------------------------------------------------------------
    # SECTION 2: BUSINESS-BASED FOLDER COMPONENTS
    # ------------------------------------------------------------
    # Extract business logic components for organizational hierarchy
    
    # --------------------------------------------------------
    # SUBSECTION 2.1: CYCLE COMPONENT GENERATION
    # --------------------------------------------------------
    # Determine cycle from dispatch date for business categorization
    dispatch_date = advance_sale.dispatched_at
    cycle = get_cycle_from_date(dispatch_date)
    
    # --------------------------------------------------------
    # SUBSECTION 2.2: MPP COMPONENT GENERATION
    # --------------------------------------------------------
    # Generate sanitized MPP code for filesystem compatibility
    mpp_code = sanitize_filename(advance_sale.mpp_with_code)
    
    # --------------------------------------------------------
    # SUBSECTION 2.3: USER COMPONENT GENERATION
    # --------------------------------------------------------
    # Generate user-specific folder with employee identification
    user_folder = sanitize_filename(f"{user.employee_code}_{user.first_name}")
    
    # ------------------------------------------------------------
    # SECTION 3: HIERARCHICAL FOLDER STRUCTURE CONSTRUCTION
    # ------------------------------------------------------------
    # Construct comprehensive folder hierarchy using os.path.join
    
    folder_structure = os.path.join(
        "PODs",  # Root folder for all POD documents
        year,
        month,
        f"Cycle_{cycle}",
        mpp_code,
        date_folder,
        user_folder
    )
    
    # ------------------------------------------------------------
    # SECTION 4: DIRECTORY STRUCTURE CREATION
    # ------------------------------------------------------------
    # Ensure hierarchical directory structure exists in filesystem
    
    full_path = os.path.join(settings.MEDIA_ROOT, folder_structure)
    os.makedirs(full_path, exist_ok=True)
    
    # ------------------------------------------------------------
    # SECTION 5: STRUCTURE RETURN
    # ------------------------------------------------------------
    # Return generated folder structure for file storage
    return folder_structure


def sanitize_filename(filename):
    """
    Filesystem-Safe Filename Sanitizer
    
    Sanitizes filenames to ensure filesystem compatibility by removing or
    replacing problematic characters. Prevents filesystem errors and maintains
    cross-platform compatibility.
    
    Sanitization Process:
        1. Replace problematic characters with underscores
        2. Remove multiple consecutive underscores
        3. Trim leading/trailing underscores and spaces
        4. Apply length limiting for filesystem compatibility
    
    Problematic Characters Handled:
        - Windows reserved characters: < > : " / \\ | ? *
        - Filesystem delimiters and special characters
        - Unicode and control characters
    
    Parameters:
        filename (str): Original filename to sanitize
    
    Returns:
        str: Sanitized filename safe for filesystem storage
    """
    
    # ------------------------------------------------------------
    # SECTION 1: INPUT VALIDATION
    # ------------------------------------------------------------
    # Handle None or empty filename inputs
    if not filename:
        return "Unknown"
    
    # ------------------------------------------------------------
    # SECTION 2: CHARACTER SANITIZATION
    # ------------------------------------------------------------
    # Replace filesystem-problematic characters with underscores
    sanitized = re.sub(r'[<>:"/\\|?*]', '_', str(filename))
    
    # ------------------------------------------------------------
    # SECTION 3: MULTIPLE UNDERSCORE REDUCTION
    # ------------------------------------------------------------
    # Reduce consecutive underscores to single underscores
    sanitized = re.sub(r'_+', '_', sanitized)
    
    # ------------------------------------------------------------
    # SECTION 4: BOUNDARY CHARACTER TRIMMING
    # ------------------------------------------------------------
    # Remove leading and trailing underscores and spaces
    sanitized = sanitized.strip(' _')
    
    # ------------------------------------------------------------
    # SECTION 5: LENGTH LIMITING
    # ------------------------------------------------------------
    # Apply filesystem-compatible length limitation
    if len(sanitized) > 50:
        sanitized = sanitized[:50]
    
    # ------------------------------------------------------------
    # SECTION 6: FINAL VALIDATION AND RETURN
    # ------------------------------------------------------------
    # Ensure non-empty return value
    return sanitized if sanitized else "Unknown"

@login_required(login_url='login')
def advance_sale_admin(request):
    return render(request, 'advance_sale_admin.html')


@login_required(login_url='login')
def get_advance_sale_data(request):
    """
    Advance Sale Data AJAX Retrieval Endpoint - Unified for both staff and regular users
    
    Provides AJAX endpoint for dynamic loading of authenticated user's Advance Sale
    documents with comprehensive pagination, filtering, and search capabilities.
    
    Key Features:
        - Server-side pagination for large datasets
        - Multi-dimensional filtering (month, cycle, status, search)
        - Cycle-based filtering that considers the cycle's month, not the sale date
        - JSON serialization for frontend integration
        - Comprehensive error handling and response formatting
    
    Returns:
        JsonResponse: Paginated Advance Sale data with metadata and navigation information
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: PAGINATION PARAMETER EXTRACTION
        # ------------------------------------------------------------
        page = int(request.GET.get('page', 1))
        per_page = int(request.GET.get('per_page', 10))
        
        # ------------------------------------------------------------
        # SECTION 2: FILTER PARAMETER EXTRACTION
        # ------------------------------------------------------------
        month = request.GET.get('month', datetime.now().strftime('%Y-%m'))
        cycle = request.GET.get('cycle', 'all')
        status = request.GET.get('status', 'all')
        search_query = request.GET.get('search', '')
        
        # ------------------------------------------------------------
        # SECTION 3: PAGINATION OFFSET CALCULATION
        # ------------------------------------------------------------
        offset = (page - 1) * per_page
        
        # ------------------------------------------------------------
        # SECTION 4: MONTH PARAMETER VALIDATION AND PARSING
        # ------------------------------------------------------------
        try:
            filter_date = datetime.strptime(month, '%Y-%m')
            filter_year = filter_date.year
            filter_month_num = filter_date.month
            filter_month_name = filter_date.strftime('%B')
        except ValueError:
            current_date = datetime.now()
            filter_year = current_date.year
            filter_month_num = current_date.month
            filter_month_name = current_date.strftime('%B')
        
        # ------------------------------------------------------------
        # SECTION 5: BASE QUERYSET CONSTRUCTION
        # ------------------------------------------------------------
        # For staff users, show all sales; for regular users, show only their sales
        if request.user.is_staff:
            base_queryset = AdvanceSale.objects.all()
        else:
            base_queryset = AdvanceSale.objects.filter(
                dispatched_by=request.user
            )
        
        # --------------------------------------------------------
        # SECTION 6: MONTH-BASED FILTER APPLICATION
        # --------------------------------------------------------
        # Filter by the cycle's monthly cycle, not the sale date
        # This handles the case where sales in Feb belong to Jan's cycle
        base_queryset = base_queryset.filter(
            cycle__monthly_cycle__month=filter_month_name,
            cycle__monthly_cycle__year=filter_year
        ).order_by('-dispatched_at')
        
        # --------------------------------------------------------
        # SECTION 7: CYCLE-BASED FILTER APPLICATION
        # --------------------------------------------------------
        if cycle != 'all':
            try:
                cycle_number = int(cycle)
                base_queryset = base_queryset.filter(cycle__cycle_number=cycle_number)
            except ValueError:
                # Fallback for old style cycle values
                if cycle == '1-10':
                    base_queryset = base_queryset.filter(cycle__cycle_number=1)
                elif cycle == '11-20':
                    base_queryset = base_queryset.filter(cycle__cycle_number=2)
                elif cycle == '21-31':
                    base_queryset = base_queryset.filter(cycle__cycle_number=3)
        
        # --------------------------------------------------------
        # SECTION 8: STATUS-BASED FILTER APPLICATION
        # --------------------------------------------------------
        if status != 'all':
            if status == 'pdf_generated':
                base_queryset = base_queryset.filter(pdf_generated=True, pdf_file__isnull=False)
            elif status == 'no_pdf':
                base_queryset = base_queryset.filter(Q(pdf_generated=False) | Q(pdf_file__isnull=True))
            elif status == 'pod_uploaded':
                base_queryset = base_queryset.filter(pod_uploaded=True, pod_file__isnull=False)
        
        # --------------------------------------------------------
        # SECTION 9: SEARCH-BASED FILTER APPLICATION
        # --------------------------------------------------------
        if search_query:
            base_queryset = base_queryset.filter(
                Q(unique_code__icontains=search_query) |
                Q(bmc_or_mcc__icontains=search_query) |
                Q(mpp_with_code__icontains=search_query) |
                Q(stock_item__icontains=search_query) |
                Q(cycle__name__icontains=search_query) |
                Q(cycle__sap_number__icontains=search_query)
            )
        
        # ------------------------------------------------------------
        # SECTION 10: TOTAL COUNT CALCULATION
        # ------------------------------------------------------------
        total_count = base_queryset.count()
        
        # ------------------------------------------------------------
        # SECTION 11: STATISTICS CALCULATION (BEFORE PAGINATION)
        # ------------------------------------------------------------
        # Calculate statistics on the base queryset BEFORE pagination
        # This is the key fix - use base_queryset, not the paginated/sliced queryset
        
        # Get all unique cycle numbers in the filtered queryset
        cycle_numbers = base_queryset.values_list('cycle__cycle_number', flat=True).distinct()
        
        # Initialize stats
        stats = {
            'total': total_count,
            'pdf_generated': base_queryset.filter(pdf_generated=True, pdf_file__isnull=False).count(),
            'pod_uploaded': base_queryset.filter(pod_uploaded=True, pod_file__isnull=False).count(),
        }
        
        # Add cycle-specific counts
        for cycle_num in cycle_numbers:
            if cycle_num:
                stats[f'cycle_{cycle_num}'] = base_queryset.filter(cycle__cycle_number=cycle_num).count()
        
        # Add standard cycle names for compatibility
        stats['cycle_1_10'] = base_queryset.filter(cycle__cycle_number=1).count()
        stats['cycle_11_20'] = base_queryset.filter(cycle__cycle_number=2).count()
        stats['cycle_21_31'] = base_queryset.filter(cycle__cycle_number=3).count()
        
        # ------------------------------------------------------------
        # SECTION 12: PAGINATED DATA RETRIEVAL
        # ------------------------------------------------------------
        # Use Django's Paginator for better pagination
        paginator = Paginator(base_queryset, per_page)
        try:
            sales_page = paginator.page(page)
        except:
            sales_page = paginator.page(1)
            page = 1
        
        # Get the paginated sales
        advance_sales = sales_page.object_list
        
        # ------------------------------------------------------------
        # SECTION 13: ADVANCE SALE DATA SERIALIZATION
        # ------------------------------------------------------------
        sale_data = []
        
        for sale in advance_sales:
            # Get PDF file URL
            pdf_file_url = None
            if sale.pdf_file and hasattr(sale.pdf_file, 'url'):
                pdf_file_url = sale.pdf_file.url
            
            # Get POD file URL
            pod_file_url = None
            if sale.pod_file and hasattr(sale.pod_file, 'url'):
                pod_file_url = sale.pod_file.url
            
            # Get cycle information
            cycle_info = {
                'name': sale.cycle.name if sale.cycle else 'N/A',
                'number': sale.cycle.cycle_number if sale.cycle else None,
                'sap_number': sale.cycle.sap_number if sale.cycle else None,
                'monthly_cycle': sale.cycle.monthly_cycle.get_month_display() if sale.cycle and sale.cycle.monthly_cycle else 'N/A',
            }
            
            sale_record = {
                'id': sale.id,
                'unique_code': sale.unique_code or f'SALE-{sale.id}',
                'bmc_or_mcc': sale.bmc_or_mcc or 'N/A',
                'mpp_with_code': sale.mpp_with_code or 'N/A',
                'stock_item': sale.stock_item or 'N/A',
                'quantity': sale.quantity or 0,
                'uom': sale.uom or 'N/A',
                'dispatched_at': sale.dispatched_at.strftime('%Y-%m-%d %H:%M:%S') if sale.dispatched_at else 'N/A',
                'sale_date': sale.sale_date.strftime('%Y-%m-%d') if sale.sale_date else 'N/A',
                'sale_month': sale.sale_date.strftime('%B %Y') if sale.sale_date else 'N/A',
                'pdf_generated': sale.pdf_generated,
                'pdf_file_url': pdf_file_url,
                'pod_uploaded': sale.pod_uploaded,
                'pod_uploaded_at': sale.pod_uploaded_at.strftime('%Y-%m-%d %H:%M:%S') if sale.pod_uploaded_at else None,
                'pod_file_url': pod_file_url,
                'cycle_name': sale.cycle.name if sale.cycle else 'N/A',
                'cycle_number': sale.cycle.cycle_number if sale.cycle else None,
                'sap_cycle_number': sale.cycle.sap_number if sale.cycle else None,
                'cycle_month': sale.cycle.monthly_cycle.get_month_display() if sale.cycle and sale.cycle.monthly_cycle else 'N/A',
                'dispatched_by_name': f"{sale.dispatched_by.first_name} {sale.dispatched_by.last_name}" if sale.dispatched_by else 'N/A',
                # Add this for debugging - shows actual sale date vs cycle month
                'actual_sale_month': sale.dispatched_at.strftime('%B %Y') if sale.dispatched_at else 'N/A',
            }
            sale_data.append(sale_record)
        
        # ------------------------------------------------------------
        # SECTION 14: PAGINATION METADATA CALCULATION
        # ------------------------------------------------------------
        total_pages = paginator.num_pages
        
        # ------------------------------------------------------------
        # SECTION 15: SUCCESS RESPONSE PREPARATION
        # ------------------------------------------------------------
        response_data = {
            'success': True,
            'sales': sale_data,
            'stats': stats,
            'total_count': total_count,
            'current_page': sales_page.number,
            'per_page': per_page,
            'total_pages': total_pages,
            'filters': {
                'selected_month': month,
                'selected_cycle': cycle,
                'selected_status': status,
                'search_query': search_query,
                'month_display': filter_date.strftime('%B %Y') if 'filter_date' in locals() else datetime.now().strftime('%B %Y'),
            }
        }
        
        return JsonResponse(response_data)
        
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 16: EXCEPTION HANDLING AND ERROR RESPONSE
        # ------------------------------------------------------------
        import traceback
        traceback.print_exc()
        return JsonResponse({
            'success': False,
            'message': 'An error occurred while fetching advance sale data',
            'error': str(e)
        }, status=500)
        
