@login_required(login_url='login')
def get_advance_sale_data_for_admin(request):
    """Get advance sale data for the admin dashboard"""
    if not request.user.is_staff:
        return JsonResponse({'success': False, 'message': 'Unauthorized'}, status=403)
    
    try:
        # Get all advance sale data with related information
        advance_sales = AdvanceSale.objects.select_related(
            'dispatched_by',
            'cycle',
            'template_entry'
        ).order_by('-sale_date', '-dispatched_at')
        
        print("=== File Debug Information ===")
        
        data = []
        for sale in advance_sales:
            pod_file_url = None
            pod_file_name = None
            file_exists = False
            
            if sale.pod_file:
                # Get the current file path from database
                db_file_path = sale.pod_file.name
                pod_file_name = os.path.basename(db_file_path)
                
                # Try to find the actual file location
                actual_file_path = None
                
                # Method 1: Check the stored path
                if os.path.exists(sale.pod_file.path):
                    actual_file_path = sale.pod_file.path
                    print(f"✓ Sale ID {sale.id}: File found at stored path")
                
                # Method 2: Check in advance_sales directory structure
                if not actual_file_path and sale.sale_date:
                    try:
                        # Construct path based on MPP and date
                        mpp_name = sale.mpp_with_code.replace(' ', '_') if sale.mpp_with_code else 'UNKNOWN'
                        sale_date = sale.sale_date
                        
                        # Format: media/advance_sales/MPP_NAME/DD_MM_YYYY/filename.pdf
                        date_str = sale_date.strftime('%d_%m_%Y')
                        constructed_path = os.path.join(
                            settings.MEDIA_ROOT,
                            'advance_sales',
                            mpp_name,
                            date_str,
                            pod_file_name
                        )
                        
                        if os.path.exists(constructed_path):
                            actual_file_path = constructed_path
                            print(f"✓ Sale ID {sale.id}: File found at constructed path: {constructed_path}")
                    except Exception as e:
                        print(f"  Error constructing path for sale {sale.id}: {e}")
                
                # Method 3: Search recursively in advance_sales directory
                if not actual_file_path:
                    advance_sales_dir = os.path.join(settings.MEDIA_ROOT, 'advance_sales')
                    if os.path.exists(advance_sales_dir):
                        for root, dirs, files in os.walk(advance_sales_dir):
                            if pod_file_name in files:
                                actual_file_path = os.path.join(root, pod_file_name)
                                print(f"✓ Sale ID {sale.id}: File found via search at: {actual_file_path}")
                                break
                
                if actual_file_path:
                    file_exists = True
                    # Create a relative URL from the actual file path
                    relative_path = os.path.relpath(actual_file_path, settings.MEDIA_ROOT)
                    # Convert Windows path to URL path
                    relative_path = relative_path.replace('\\', '/')
                    pod_file_url = f"/media/{relative_path}"
                    print(f"  Final URL: {pod_file_url}")
                else:
                    print(f"✗ Sale ID {sale.id}: File NOT FOUND - {pod_file_name}")
            
            data.append({
                'id': sale.id,
                'unique_code': sale.unique_code,
                'bmc_or_mcc': sale.bmc_or_mcc,
                'mpp_with_code': sale.mpp_with_code,
                'cycle_name': sale.cycle.name if sale.cycle else None,
                'stock_item': sale.stock_item,
                'uom': sale.uom,
                'quantity': sale.quantity,
                'sale_date': sale.sale_date.isoformat() if sale.sale_date else None,
                'dispatched_by_name': f"{sale.dispatched_by.first_name} {sale.dispatched_by.last_name}" if sale.dispatched_by else None,
                'dispatched_at': sale.dispatched_at.isoformat() if sale.dispatched_at else None,
                'pod_uploaded': sale.pod_uploaded,
                'pod_uploaded_at': sale.pod_uploaded_at.isoformat() if sale.pod_uploaded_at else None,
                'pod_file': pod_file_url if file_exists else None,
                'pod_file_url': pod_file_url if file_exists else None,
                'pod_file_name': pod_file_name,
                'file_exists': file_exists,
            })
        
        print(f"\n=== Summary ===")
        total_with_pod = len([s for s in advance_sales if s.pod_uploaded])
        files_found = len([d for d in data if d.get('file_exists')])
        print(f"Total records with POD: {total_with_pod}")
        print(f"Files actually found: {files_found}")
        print(f"Files missing: {total_with_pod - files_found}")
        
        return JsonResponse({'success': True, 'data': data})
        
    except Exception as e:
        print(f"Error: {str(e)}")
        import traceback
        traceback.print_exc()
        return JsonResponse({'success': False, 'message': str(e)})


CustomUser = get_user_model()

# ======================================================================================================================
# SALE TEMPLATE DOWNLOAD DISPATCH FUNCTION
# ======================================================================================================================
# Handles sale template download requests with routing between initial template and results download
# Provides intelligent routing based on template type and request parameters

@login_required(login_url='login')
def download_sale_template(request):
    """
    Sale Template Download Dispatcher
    
    Handles sale template download requests by routing to appropriate template generation
    functions based on request parameters. Distinguishes between initial template downloads
    and color-coded results downloads for template comparison workflows.
    
    Routing Logic:
        - Initial Template: When 'results' parameter is false or unspecified
        - Results Template: When 'results' parameter is true (color-coded comparison)
    
    Validation:
        - Validates required month and cycle parameters
        - Verifies request method is POST for data security
        - Provides parameter validation and error handling
    
    Returns:
        HttpResponse: Excel template file download based on request type
        HttpResponse: Error response with status codes for invalid requests
    """
    
    # ------------------------------------------------------------
    # SECTION 1: REQUEST METHOD VALIDATION
    # ------------------------------------------------------------
    # Validate request method is POST for template download
    if request.method != 'POST':
        return HttpResponse("Invalid request method", status=405)
    
    try:
        # --------------------------------------------------------
        # SECTION 2: REQUEST PARAMETER EXTRACTION
        # --------------------------------------------------------
        # Extract template generation parameters from POST data
        month = request.POST.get('month')
        cycle = request.POST.get('cycle')
        
        # --------------------------------------------------------
        # SECTION 3: REQUIRED PARAMETER VALIDATION
        # --------------------------------------------------------
        # Validate presence of essential template parameters
        if not month or not cycle:
            return HttpResponse("Month and Cycle are required", status=400)
        
        # --------------------------------------------------------
        # SECTION 4: TEMPLATE TYPE DETERMINATION
        # --------------------------------------------------------
        # Determine whether to generate initial template or results template
        is_results = request.POST.get('results', 'false').lower() == 'true'
        
        # --------------------------------------------------------
        # SECTION 5: TEMPLATE GENERATION ROUTING
        # --------------------------------------------------------
        # Route to appropriate template generation function
        if is_results:
            return download_color_coded_results(request, month, cycle)
        else:
            return download_initial_template(request, month, cycle)
            
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 6: EXCEPTION HANDLING
        # ------------------------------------------------------------
        # Handle unexpected exceptions with error response
        return HttpResponse(f"Template download error: {str(e)}", status=500)


# ======================================================================================================================
# INITIAL SALE TEMPLATE GENERATION FUNCTION
# ======================================================================================================================
# Generates initial sale template with advance sale data for financial reconciliation
# Provides structured Excel template with valid locations and MPPs for data entry

def download_initial_template(request, month, cycle):
    """
    Initial Sale Template Generator
    
    Generates comprehensive Excel templates for financial reconciliation with advance sale data.
    Includes validated locations and MPPs, advance sale quantities, and blank columns for
    finance department data entry. Supports systematic reconciliation workflows.
    
    Template Structure:
        - Location and MPP validation against user data
        - Advance sale quantities from system data
        - Blank entry columns for finance department input
        - Product-based organization with dual columns per product
    
    Data Validation:
        - Validates MPP locations against user location database
        - Filters invalid or empty location data
        - Provides fallback data when primary sources unavailable
    
    Excel Features:
        - Header styling with formatting
        - Proper column sizing and alignment
        - Instructions sheet for user guidance
        - No color coding in initial template
    
    Returns:
        HttpResponse: Excel template file download with advance sale data
    """
    
    # ------------------------------------------------------------
    # SECTION 1: TEMPLATE CONFIGURATION INITIALIZATION
    # ------------------------------------------------------------
    # Create or retrieve sale template configuration
    config, created = SaleTemplateConfig.objects.get_or_create(
        month=month,
        cycle=cycle,
        defaults={'is_active': True}
    )
    
    # ------------------------------------------------------------
    # SECTION 2: USER LOCATION DATA RETRIEVAL
    # ------------------------------------------------------------
    # Retrieve distinct user locations for validation
    user_locations = CustomUser.objects.exclude(
        location__isnull=True
    ).exclude(
        location=""
    ).values_list("location", flat=True).distinct()
    
    # ------------------------------------------------------------
    # SECTION 3: VALID MPP DATA RETRIEVAL AND VALIDATION
    # ------------------------------------------------------------
    # Retrieve MPP data with location validation
    all_mpps = MPPWithCode.objects.exclude(
        location__isnull=True
    ).exclude(
        location=""
    ).exclude(
        location="Unknown Location"
    ).select_related('bmc_or_mcc')
    
    # --------------------------------------------------------
    # SUBSECTION 3.1: LOCATION-BASED MPP VALIDATION
    # --------------------------------------------------------
    # Filter MPPs to only those with valid user locations
    valid_mpps = []
    for mpp in all_mpps:
        if mpp.location and mpp.location in user_locations:
            valid_mpps.append(mpp)
    
    # --------------------------------------------------------
    # SUBSECTION 3.2: FALLBACK MPP DATA RETRIEVAL
    # --------------------------------------------------------
    # Retrieve fallback MPP data when no valid MPPs found
    if not valid_mpps:
        # Map month names to numeric values
        month_map = {
            'January': 1, 'February': 2, 'March': 3, 'April': 4, 'May': 5, 'June': 6,
            'July': 7, 'August': 8, 'September': 9, 'October': 10, 'November': 11, 'December': 12
        }
        month_num = month_map.get(month, timezone.now().month)
        current_year = timezone.now().year
        
        # ----------------------------------------------------
        # SUBSECTION 3.2.1: DATE RANGE CALCULATION
        # ----------------------------------------------------
        # Calculate date range based on cycle selection
        if cycle == "1-10":
            start_date = timezone.datetime(current_year, month_num, 1)
            end_date = timezone.datetime(current_year, month_num, 10)
        elif cycle == "11-20":
            start_date = timezone.datetime(current_year, month_num, 11)
            end_date = timezone.datetime(current_year, month_num, 20)
        else:
            last_day = calendar.monthrange(current_year, month_num)[1]
            start_date = timezone.datetime(current_year, month_num, 21)
            end_date = timezone.datetime(current_year, month_num, last_day)
        
        # ----------------------------------------------------
        # SUBSECTION 3.2.2: ADVANCE SALES DATA RETRIEVAL
        # ----------------------------------------------------
        # Retrieve advance sales for fallback data extraction
        advance_sales = AdvanceSale.objects.filter(
            dispatched_at__date__range=[start_date.date(), end_date.date()]
        ).select_related('dispatched_by')
        
        # ----------------------------------------------------
        # SUBSECTION 3.2.3: UNIQUE DATA COMPILATION
        # ----------------------------------------------------
        # Compile unique location-MPP combinations from advance sales
        unique_combinations = set()
        for sale in advance_sales:
            location = sale.dispatched_by.location if sale.dispatched_by and sale.dispatched_by.location else "Unknown"
            mpp = sale.mpp_with_code or "Unknown MPP"
            if location != "Unknown" and mpp != "Unknown MPP":
                unique_combinations.add((location, mpp))
        
        # ----------------------------------------------------
        # SUBSECTION 3.2.4: FALLBACK MPP CREATION
        # ----------------------------------------------------
        # Create mock MPP objects from advance sales data
        for location, mpp_name in unique_combinations:
            class MockMPP:
                def __init__(self, location, name):
                    self.location = location
                    self.name_with_code = name
            valid_mpps.append(MockMPP(location, mpp_name))
    
    # ------------------------------------------------------------
    # SECTION 4: DATE RANGE CALCULATION FOR ADVANCE SALES
    # ------------------------------------------------------------
    # Calculate date range for advance sales data retrieval
    current_year = timezone.now().year
    month_map = {
        'January': 1, 'February': 2, 'March': 3, 'April': 4, 'May': 5, 'June': 6,
        'July': 7, 'August': 8, 'September': 9, 'October': 10, 'November': 11, 'December': 12
    }
    month_num = month_map.get(month, timezone.now().month)
    
    # --------------------------------------------------------
    # SUBSECTION 4.1: CYCLE-BASED DATE RANGE DETERMINATION
    # --------------------------------------------------------
    if cycle == "1-10":
        start_date = timezone.datetime(current_year, month_num, 1)
        end_date = timezone.datetime(current_year, month_num, 10)
    elif cycle == "11-20":
        start_date = timezone.datetime(current_year, month_num, 11)
        end_date = timezone.datetime(current_year, month_num, 20)
    else:
        start_date = timezone.datetime(current_year, month_num, 21)
        last_day = calendar.monthrange(current_year, month_num)[1]
        end_date = timezone.datetime(current_year, month_num, last_day)
    
    # --------------------------------------------------------
    # SECTION 5: ADVANCE SALES DATA RETRIEVAL AND MAPPING
    # --------------------------------------------------------
    # Retrieve and map advance sales data for template population
    advance_sales = AdvanceSale.objects.filter(
        dispatched_at__date__range=[start_date.date(), end_date.date()]
    ).select_related('dispatched_by')
    
    # --------------------------------------------------------
    # SUBSECTION 5.1: ADVANCE SALES DATA MAPPING
    # --------------------------------------------------------
    # Create mapping of advance sale quantities by location, MPP, and product
    advance_sale_map = {}
    
    for sale in advance_sales:
        location = sale.dispatched_by.location if sale.dispatched_by and sale.dispatched_by.location else "Unknown Location"
        mpp = sale.mpp_with_code or "Unknown MPP"
        stock_item = sale.stock_item or "Unknown Product"
        quantity = sale.quantity or 0
        
        # Only include valid location-MPP combinations
        if location != "Unknown Location" and mpp != "Unknown MPP":
            key = (location, mpp, stock_item)
            if key not in advance_sale_map:
                advance_sale_map[key] = 0
            advance_sale_map[key] += quantity
    
    # --------------------------------------------------------
    # SECTION 6: PRODUCT DATA COMPILATION
    # --------------------------------------------------------
    # Compile product list from advance sales or active products
    products_with_sales = set()
    for sale in advance_sales:
        if sale.stock_item:
            products_with_sales.add(sale.stock_item)
    
    # --------------------------------------------------------
    # SUBSECTION 6.1: FALLBACK PRODUCT RETRIEVAL
    # --------------------------------------------------------
    # Retrieve all active products when no sales data available
    if not products_with_sales:
        all_active_products = Product.objects.filter(is_active=True).values_list('name', flat=True)
        products_with_sales = set(all_active_products)
    
    # --------------------------------------------------------
    # SUBSECTION 6.2: PRODUCT LIST SORTING
    # --------------------------------------------------------
    # Sort product list for consistent template organization
    all_products = sorted(list(products_with_sales))
    
    # ------------------------------------------------------------
    # SECTION 7: EXCEL WORKBOOK AND WORKSHEET INITIALIZATION
    # ------------------------------------------------------------
    # Create Excel workbook and primary worksheet
    wb = Workbook()
    ws = wb.active
    ws.title = "Sales Template"
    
    # --------------------------------------------------------
    # SUBSECTION 7.1: CELL STYLING DEFINITIONS
    # --------------------------------------------------------
    # Define consistent styling for template cells
    header_fill = PatternFill(start_color="2C5F2D", end_color="2C5F2D", fill_type="solid")
    header_font = Font(color="FFFFFF", bold=True)
    border = Border(
        left=Side(style='thin'),
        right=Side(style='thin'),
        top=Side(style='thin'),
        bottom=Side(style='thin')
    )
    
    # ------------------------------------------------------------
    # SECTION 8: TEMPLATE HEADER GENERATION
    # ------------------------------------------------------------
    # Generate dual-column headers for each product
    headers = ['Location', 'MPP']
    product_columns = {}
    
    # --------------------------------------------------------
    # SUBSECTION 8.1: DUAL-COLUMN HEADER CREATION
    # --------------------------------------------------------
    # Create advance sale and entry columns for each product
    col_idx = 3
    for product in all_products:
        # Advance Sale column (read-only system data)
        headers.append(f"{product} (Advance Sale)")
        product_columns[f"{product}_advance"] = col_idx
        col_idx += 1
        
        # Entry column (blank for finance department input)
        headers.append(f"{product} (Your Entry)")
        product_columns[f"{product}_entry"] = col_idx
        col_idx += 1
    
    # --------------------------------------------------------
    # SUBSECTION 8.2: HEADER CELL POPULATION AND STYLING
    # --------------------------------------------------------
    # Populate and style header row
    for col_idx, header in enumerate(headers, start=1):
        cell = ws.cell(row=1, column=col_idx, value=header)
        cell.fill = header_fill
        cell.font = header_font
        cell.border = border
        cell.alignment = Alignment(horizontal='center')
    
    # ------------------------------------------------------------
    # SECTION 9: TEMPLATE DATA ROW POPULATION
    # ------------------------------------------------------------
    # Populate template rows with location, MPP, and advance sale data
    row_idx = 2
    
    # --------------------------------------------------------
    # SUBSECTION 9.1: VALID MPP SORTING
    # --------------------------------------------------------
    # Sort valid MPPs by location and name for organized presentation
    if valid_mpps:
        valid_mpps.sort(key=lambda x: (x.location.lower(), x.name_with_code.lower()))
        
        # ----------------------------------------------------
        # SUBSECTION 9.1.1: DATA ROW ITERATION
        # ----------------------------------------------------
        # Iterate through sorted MPPs and populate template rows
        for mpp in valid_mpps:
            location = mpp.location
            mpp_name = mpp.name_with_code
            
            # -------------------------------------------------
            # SUBSECTION 9.1.2: LOCATION AND MPP COLUMNS
            # -------------------------------------------------
            # Populate location and MPP identifier columns
            ws.cell(row=row_idx, column=1, value=location).border = border
            ws.cell(row=row_idx, column=2, value=mpp_name).border = border
            
            # -------------------------------------------------
            # SUBSECTION 9.1.3: PRODUCT DATA COLUMNS
            # -------------------------------------------------
            # Populate advance sale and entry columns for each product
            for product in all_products:
                # Retrieve advance sale quantity for product
                advance_quantity = advance_sale_map.get((location, mpp_name, product), 0)
                
                # -------------------------------------------------
                # SUBSECTION 9.1.4: ADVANCE SALE COLUMN POPULATION
                # -------------------------------------------------
                # Populate advance sale column with system data
                advance_col = product_columns[f"{product}_advance"]
                cell = ws.cell(row=row_idx, column=advance_col, value=advance_quantity)
                cell.border = border
                cell.alignment = Alignment(horizontal='center')
                
                # -------------------------------------------------
                # SUBSECTION 9.1.5: ENTRY COLUMN INITIALIZATION
                # -------------------------------------------------
                # Initialize entry column as blank for user input
                entry_col = product_columns[f"{product}_entry"]
                cell = ws.cell(row=row_idx, column=entry_col, value="")
                cell.border = border
                cell.alignment = Alignment(horizontal='center')
            
            row_idx += 1
    
    # --------------------------------------------------------
    # SUBSECTION 9.2: FALLBACK DATA ROW CREATION
    # --------------------------------------------------------
    # Create sample data row when no valid MPPs available
    else:
        ws.cell(row=2, column=1, value="Sample Location").border = border
        ws.cell(row=2, column=2, value="Sample MPP").border = border
        for product in all_products:
            advance_col = product_columns[f"{product}_advance"]
            ws.cell(row=2, column=advance_col, value=0).border = border
            entry_col = product_columns[f"{product}_entry"]
            ws.cell(row=2, column=entry_col, value="").border = border
        row_idx = 3
    
    # ------------------------------------------------------------
    # SECTION 10: INSTRUCTIONS WORKSHEET CREATION
    # ------------------------------------------------------------
    # Create comprehensive instructions worksheet for user guidance
    ws_instructions = wb.create_sheet("Instructions")
    
    # --------------------------------------------------------
    # SUBSECTION 10.1: INSTRUCTION DATA DEFINITION
    # --------------------------------------------------------
    # Define comprehensive instruction content
    instructions = [
        ["SALE TEMPLATE INSTRUCTIONS", "", "", ""],
        ["", "", "", ""],
        ["Step", "Description", "Example", ""],
        ["1", "This template shows locations and MPPs with sales data", "MPPs with sales are listed", ""],
        ["2", "Values in '(Advance Sale)' columns are actual sales from system", "These are read-only - DO NOT CHANGE", ""],
        ["3", "Fill your recorded quantities in '(Your Entry)' columns", "Enter the quantity you recorded in finance system", ""],
        ["4", "Zero (0) in Advance Sale means no sales for that product", "Leave as blank or 0 if you also had no sales", ""],
        ["5", "After filling ALL '(Your Entry)' columns, upload this template", "System will compare Advance Sale vs Your Entry", ""],
        ["6", "Download color-coded results after upload", "See matching status with color coding", ""],
        ["", "", "", ""],
        ["IMPORTANT NOTES:", "", "", ""],
        ["", "• Advance Sale columns: Actual sales from system (READ-ONLY)", "", ""],
        ["", "• Your Entry columns: What you recorded in finance system (FILL THESE)", "", ""],
        ["", "• Do not change Location and MPP columns", "", ""],
        ["", "• Do not change any '(Advance Sale)' columns", "", ""],
        ["", "• Fill ALL '(Your Entry)' columns before uploading", "", ""],
        ["", "• Do not add/remove columns", "", ""],
        ["", "• Save file and upload using Upload button", "", ""],
    ]
    
    # --------------------------------------------------------
    # SUBSECTION 10.2: INSTRUCTION DATA POPULATION
    # --------------------------------------------------------
    # Populate instructions worksheet with formatted content
    for instruction_row_idx, instruction in enumerate(instructions, start=1):
        for col_idx, value in enumerate(instruction, start=1):
            cell = ws_instructions.cell(row=instruction_row_idx, column=col_idx, value=value)
            if instruction_row_idx == 1:
                cell.font = Font(bold=True, size=14)
            elif instruction_row_idx == 3:
                cell.fill = header_fill
                cell.font = header_font
    
    # ------------------------------------------------------------
    # SECTION 11: COLUMN WIDTH ADJUSTMENT
    # ------------------------------------------------------------
    # Automatically adjust column widths based on content
    for column in ws.columns:
        max_length = 0
        column_letter = get_column_letter(column[0].column)
        for cell in column:
            try:
                if len(str(cell.value)) > max_length:
                    max_length = len(str(cell.value))
            except:
                pass
        adjusted_width = (max_length + 2)
        ws.column_dimensions[column_letter].width = adjusted_width
    
    # ------------------------------------------------------------
    # SECTION 12: HTTP RESPONSE PREPARATION
    # ------------------------------------------------------------
    # Prepare HTTP response with Excel file download
    response = HttpResponse(content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')
    filename = f"sale_template_{month}_{cycle.replace(' ', '_')}.xlsx"
    response['Content-Disposition'] = f'attachment; filename="{filename}"'
    
    # ------------------------------------------------------------
    # SECTION 13: WORKBOOK SAVING AND RESPONSE RETURN
    # ------------------------------------------------------------
    # Save workbook to HTTP response and return
    wb.save(response)
    return response
# ======================================================================================================================
# SALE TEMPLATE UPLOAD PROCESSOR WITH ATOMIC TRANSACTIONS
# ======================================================================================================================
# Processes uploaded sale templates with comprehensive validation, data comparison,
# and immediate color-coded Excel generation using atomic database transactions

