# SALE TEMPLATE UPLOAD PROCESSOR WITH ATOMIC TRANSACTIONS
# ======================================================================================================================
# Processes uploaded sale templates with comprehensive validation, data comparison,
# and immediate color-coded Excel generation using atomic database transactions

@transaction.atomic
@login_required(login_url='login')
def upload_sale_template(request):
    """
    Process SAP Excel uploads directly and reconcile with advance sales
    """
    print("="*80)
    print("🚀 UPLOAD_SALE_TEMPLATE FUNCTION STARTED")
    print("="*80)
    
    if request.method != 'POST' or not request.FILES.get('sale_file'):
        print("❌ Invalid request: Not POST or no file")
        return JsonResponse({
            'success': False,
            'message': 'Invalid request'
        })
    
    try:
        uploaded_file = request.FILES['sale_file']
        month = request.POST.get('month')
        cycle_name = request.POST.get('cycle')
        
        print(f"\n📥 RECEIVED UPLOAD:")
        print(f"   Month: {month}")
        print(f"   Cycle parameter: {cycle_name}")
        print(f"   File: {uploaded_file.name}")
        print(f"   File size: {uploaded_file.size} bytes")
        
        # ============================================
        # FIND CYCLE AND CONFIG
        # ============================================
        
        try:
            # Try to find cycle by ID first
            try:
                cycle_id = int(cycle_name)
                print(f"\n🔄 TRYING TO FIND CYCLE BY ID: {cycle_id}")
                cycle = Cycle.objects.filter(id=cycle_id).select_related('monthly_cycle').first()
                
                if not cycle:
                    print(f"❌ No cycle found with ID {cycle_id}")
                    return JsonResponse({
                        'success': False,
                        'message': f'No cycle found for {month} - {cycle_name}. Please create the cycle first.'
                    })
                    
                print(f"✅ Found cycle by ID {cycle_id}:")
                print(f"   Name: '{cycle.name}'")
                print(f"   Monthly Cycle: '{cycle.monthly_cycle.name if cycle.monthly_cycle else 'None'}'")
                print(f"   Monthly Cycle Month: '{cycle.monthly_cycle.month if cycle.monthly_cycle else 'None'}'")
                
            except ValueError:
                print(f"❌ Cycle parameter '{cycle_name}' is not a valid ID")
                return JsonResponse({
                    'success': False,
                    'message': f'No cycle found for {month} - {cycle_name}. Please create the cycle first.'
                })
            
            print(f"\n🎯 SELECTED CYCLE:")
            print(f"   ID: {cycle.id}")
            print(f"   Name: '{cycle.name}'")
            print(f"   Monthly Cycle: '{cycle.monthly_cycle.name}'")
            print(f"   Monthly Cycle Month: '{cycle.monthly_cycle.month}'")
            print(f"   Start Date: {cycle.start_date}")
            print(f"   End Date: {cycle.end_date}")
            
            # Get or create SaleTemplateConfig
            config, created = SaleTemplateConfig.objects.get_or_create(
                cycle=cycle,
                defaults={'is_active': True}
            )
            
            if created:
                print(f"\n📝 CREATED NEW SaleTemplateConfig:")
                print(f"   Config ID: {config.id}")
                print(f"   Cycle: {config.cycle.name}")
            else:
                print(f"\n✅ FOUND EXISTING SaleTemplateConfig:")
                print(f"   Config ID: {config.id}")
                print(f"   Cycle: {config.cycle.name}")
                print(f"   Is Active: {config.is_active}")
                
        except Exception as e:
            print(f"❌ Error finding cycle/config: {str(e)}")
            import traceback
            traceback.print_exc()
            raise
        
        # ============================================
        # READ EXCEL WITH SPECIFIC SAP FORMAT
        # ============================================
        
        try:
            print(f"\n📊 READING SAP EXCEL FILE...")
            print(f"   File: {uploaded_file.name}")
            
            # Read with no header first to find data start
            raw_df = pd.read_excel(uploaded_file, header=None, dtype=str)
            print(f"   Raw file shape: {raw_df.shape}")
            
            # Find header row (where 'Plant' appears in first few columns)
            header_row_index = None
            for idx in range(min(10, len(raw_df))):
                row_values = raw_df.iloc[idx].astype(str).str.strip().tolist()
                # Check first 5 columns for 'Plant'
                if any('plant' in str(val).lower() for val in row_values[:5]):
                    header_row_index = idx
                    print(f"   Found header at row {idx}: {row_values[:5]}")
                    break
            
            if header_row_index is None:
                header_row_index = 4  # Default for SAP reports
                print(f"⚠️  Using default header row: {header_row_index}")
            
            print(f"\n✅ Using header row index: {header_row_index}")
            
            # Read data with header
            df = pd.read_excel(uploaded_file, skiprows=header_row_index, dtype=str)
            df.columns = df.columns.astype(str).str.strip()
            df = df.fillna('')
            
            print(f"   Processed dataframe shape: {df.shape}")
            print(f"   Total rows: {len(df)}")
            
            if len(df) == 0:
                print(f"❌ No data found in Excel file")
                return JsonResponse({
                    'success': False,
                    'message': 'No data found in Excel file.'
                })
            
            # Show all columns with indices
            print(f"\n📋 ALL COLUMNS ({len(df.columns)}):")
            for i, col in enumerate(df.columns):
                print(f"   [{i:2d}] '{col}'")
            
        except Exception as e:
            print(f"❌ Error reading Excel file: {str(e)}")
            import traceback
            traceback.print_exc()
            return JsonResponse({
                'success': False,
                'message': f'Error reading Excel file: {str(e)}'
            })
        
        # ============================================
        # IDENTIFY SPECIFIC COLUMNS - DEBUG VERSION
        # ============================================
        
        print(f"\n🔍 IDENTIFYING COLUMNS WITH DEBUG:")
        
        # MMP Code column (CRITICAL)
        mmp_code_col = None
        for col in df.columns:
            col_lower = str(col).lower()
            if 'mmp' in col_lower:
                mmp_code_col = col
                print(f"✅ Found MMP column: '{col}'")
                # Show sample values
                if len(df) > 0:
                    samples = df[col].head(3).tolist()
                    print(f"   Sample values: {samples}")
                break
        
        if not mmp_code_col:
            print(f"❌ NO MMP COLUMN FOUND!")
            print(f"   Available columns: {list(df.columns)}")
            return JsonResponse({
                'success': False,
                'message': 'MMP code column not found. Available columns shown in console.'
            })
        
        # Item Description column
        item_desc_col = None
        for col in df.columns:
            col_lower = str(col).lower()
            if 'item' in col_lower and 'desc' in col_lower:
                item_desc_col = col
                print(f"✅ Found Item Description: '{col}'")
                break
        
        if not item_desc_col:
            print(f"❌ NO ITEM DESCRIPTION COLUMN FOUND!")
            return JsonResponse({
                'success': False,
                'message': 'Item Description column not found.'
            })
        
        # Reg.Qty column
        reg_qty_col = None
        for col in df.columns:
            col_lower = str(col).lower()
            if 'reg' in col_lower and 'qty' in col_lower:
                reg_qty_col = col
                print(f"✅ Found Reg.Qty: '{col}'")
                break
        
        if not reg_qty_col:
            print(f"⚠️  No Reg.Qty column found, looking for alternatives...")
            for col in df.columns:
                col_lower = str(col).lower()
                if 'qty' in col_lower or 'quantity' in col_lower:
                    reg_qty_col = col
                    print(f"✅ Found quantity column: '{col}'")
                    break
        
        # Plant Description column
        plant_desc_col = None
        for col in df.columns:
            col_lower = str(col).lower()
            if 'plant' in col_lower and 'desc' in col_lower:
                plant_desc_col = col
                print(f"✅ Found Plant Description: '{col}'")
                break
        
        # ============================================
        # CREATE UPLOAD HISTORY
        # ============================================
        
        upload_history = SaleUploadHistory.objects.create(
            config=config,
            file_name=uploaded_file.name,
            uploaded_by=request.user,
            total_records=len(df)
        )
        print(f"\n📝 CREATED UPLOAD HISTORY ID: {upload_history.id}")
        
        # ============================================
        # LOAD MPP MAPPINGS WITH DETAILED DEBUG
        # ============================================
        
        print(f"\n🔍 LOADING MPP MAPPINGS...")
        
        mpp_objects = MPPWithCode.objects.all().select_related('bmc_or_mcc')
        
        # Create comprehensive mapping
        mpp_map_by_code = {}
        mpp_map_by_name = {}
        
        for mpp in mpp_objects:
            # Map by transaction code (with and without leading zeros)
            if mpp.mpp_transaction_code:
                code = str(mpp.mpp_transaction_code).strip()
                mpp_map_by_code[code] = mpp
                
                # Remove leading zeros
                no_zeros = re.sub(r'^0+', '', code)
                if no_zeros and no_zeros != code:
                    mpp_map_by_code[no_zeros] = mpp
                    print(f"   Mapped: '{no_zeros}' -> '{mpp.name_with_code}' (from '{code}')")
            
            # Map by name
            if mpp.name_with_code:
                name = str(mpp.name_with_code).strip().upper()
                mpp_map_by_name[name] = mpp
                
                # Also map name without code in parentheses
                name_clean = re.sub(r'\s*\(\d+\)', '', name).strip()
                if name_clean and name_clean != name:
                    mpp_map_by_name[name_clean] = mpp
        
        print(f"   Total MPPs loaded: {len(mpp_objects)}")
        print(f"   Code mappings: {len(mpp_map_by_code)}")
        print(f"   Name mappings: {len(mpp_map_by_name)}")
        
        # Show SHAHPUR BARA mapping specifically
        print(f"\n🔍 SPECIFIC MAPPING FOR SHAHPUR BARA:")
        if '2247' in mpp_map_by_code:
            mpp = mpp_map_by_code['2247']
            print(f"   Code '2247' maps to: {mpp.name_with_code} (ID: {mpp.id})")
        
        # ============================================
        # NORMALIZE PRODUCT NAMES
        # ============================================
        
        def normalize_product_name(product_name):
            if not product_name:
                return ""
            normalized = str(product_name).upper().strip()
            normalized = re.sub(r'\s+', ' ', normalized)
            normalized = normalized.replace('CF-', 'CF-')
            normalized = normalized.replace('CATTLE FEED', 'CF')
            normalized = normalized.replace('SAG', 'SAG')
            normalized = re.sub(r'(\d+)\s*(KG|KGS)', r'\1 KG', normalized)
            normalized = re.sub(r'\s*\(.*\)', '', normalized)
            return normalized.strip()
        
        # ============================================
        # AGGREGATE ADVANCE SALES WITH DEBUG
        # ============================================
        
        print(f"\n📅 AGGREGATING ADVANCE SALES FOR CYCLE {cycle.id}...")
        
        advance_sales = AdvanceSale.objects.filter(
            cycle=cycle
        ).select_related('dispatched_by')
        
        advance_data = {}
        advance_details = {}  # Store details for debugging
        
        for sale in advance_sales:
            # Get location
            location = "UNKNOWN"
            if sale.dispatched_by and sale.dispatched_by.location:
                location = sale.dispatched_by.location.strip().upper()
            
            # Get MPP
            mpp_raw = str(sale.mpp_with_code or "").strip().upper()
            mpp_code = None
            mpp_obj = None
            
            # Try to find by name first
            if mpp_raw in mpp_map_by_name:
                mpp_obj = mpp_map_by_name[mpp_raw]
                mpp_code = mpp_obj.mpp_transaction_code or str(mpp_obj.id)
            else:
                # Try to extract code from parentheses
                match = re.search(r'\((\d+)\)', mpp_raw)
                if match:
                    code = match.group(1)
                    if code in mpp_map_by_code:
                        mpp_obj = mpp_map_by_code[code]
                        mpp_code = mpp_obj.mpp_transaction_code or code
            
            if not mpp_code:
                mpp_code = mpp_raw
            
            # Clean code
            mpp_code = re.sub(r'^0+', '', str(mpp_code)).strip()
            
            # Get product
            product = (sale.stock_item or "").strip()
            if not product:
                continue
            
            normalized_product = normalize_product_name(product)
            
            quantity = sale.quantity or 0
            if quantity <= 0:
                continue
            
            key = (location, mpp_code, normalized_product)
            
            if key not in advance_data:
                advance_data[key] = 0
                advance_details[key] = {
                    'mpp_raw': mpp_raw,
                    'mpp_code': mpp_code,
                    'product_raw': product,
                    'sale_ids': []
                }
            
            advance_data[key] += quantity
            advance_details[key]['sale_ids'].append(sale.id)
        
        print(f"✅ Aggregated {len(advance_data)} advance combinations")
        
        # Show SHAHPUR BARA specifically
        print(f"\n🔍 ADVANCE DATA FOR SHAHPUR BARA:")
        for key, qty in advance_data.items():
            location, mpp_code, product = key
            if '2247' in mpp_code or 'SHAHPUR' in advance_details[key]['mpp_raw']:
                details = advance_details[key]
                print(f"   Key: {key}")
                print(f"     Raw MPP: {details['mpp_raw']}")
                print(f"     Cleaned Code: {mpp_code}")
                print(f"     Product: {product}")
                print(f"     Quantity: {qty}")
                print(f"     Sale IDs: {details['sale_ids']}")
        
        # ============================================
        # AGGREGATE SAP DATA WITH DETAILED DEBUG
        # ============================================
        
        print(f"\n📊 AGGREGATING SAP DATA...")
        
        sap_data = {}
        sap_details = {}
        mmp_stats = {'total': 0, 'matched': 0, 'unmatched': 0}
        
        for index, row in df.iterrows():
            try:
                mmp_stats['total'] += 1
                
                # Get MMP code
                mmp_raw = str(row[mmp_code_col]).strip()
                if not mmp_raw:
                    continue
                
                # Clean code
                mmp_clean = re.sub(r'^0+', '', mmp_raw).strip()
                
                # DEBUG: Log SHAHPUR BARA rows
                if mmp_raw == '002247' or mmp_clean == '2247':
                    print(f"\n🔍 FOUND SHAHPUR BARA IN SAP ROW {index}:")
                    print(f"   Raw MMP: '{mmp_raw}'")
                    print(f"   Cleaned: '{mmp_clean}'")
                    print(f"   Product: '{row[item_desc_col] if item_desc_col else 'N/A'}'")
                    print(f"   Quantity: '{row[reg_qty_col] if reg_qty_col else 'N/A'}'")
                
                # Find MPP
                mpp_obj = None
                resolved_code = mmp_clean
                
                # Try with cleaned code first
                if mmp_clean in mpp_map_by_code:
                    mpp_obj = mpp_map_by_code[mmp_clean]
                    mmp_stats['matched'] += 1
                # Try with raw code (with zeros)
                elif mmp_raw in mpp_map_by_code:
                    mpp_obj = mpp_map_by_code[mmp_raw]
                    mmp_stats['matched'] += 1
                else:
                    mmp_stats['unmatched'] += 1
                    if mmp_stats['unmatched'] <= 3:
                        print(f"   ⚠️ Row {index}: MMP '{mmp_raw}' not in master data")
                
                # Get location
                location = "UNKNOWN"
                if plant_desc_col and row[plant_desc_col]:
                    location = str(row[plant_desc_col]).strip().upper()
                
                # Get product
                product = str(row[item_desc_col]).strip()
                if not product:
                    continue
                
                normalized_product = normalize_product_name(product)
                
                # Get quantity
                quantity = 0
                if reg_qty_col:
                    try:
                        qty_str = str(row[reg_qty_col]).replace(',', '').strip()
                        quantity = float(qty_str) if qty_str else 0
                    except:
                        quantity = 0
                
                if quantity <= 0:
                    continue
                
                # Use MPP transaction code if available
                if mpp_obj and mpp_obj.mpp_transaction_code:
                    resolved_code = mpp_obj.mpp_transaction_code
                
                key = (location, resolved_code, normalized_product)
                
                if key not in sap_data:
                    sap_data[key] = 0
                    sap_details[key] = {
                        'mmp_raw': mmp_raw,
                        'mpp_code': resolved_code,
                        'product_raw': product,
                        'rows': []
                    }
                
                sap_data[key] += quantity
                sap_details[key]['rows'].append(index)
                
            except Exception as e:
                print(f"⚠️  Error processing SAP row {index}: {str(e)}")
                continue
        
        print(f"\n📊 SAP PROCESSING STATS:")
        print(f"   Total rows: {mmp_stats['total']}")
        print(f"   Matched MMP codes: {mmp_stats['matched']}")
        print(f"   Unmatched MMP codes: {mmp_stats['unmatched']}")
        print(f"   Unique SAP combinations: {len(sap_data)}")
        
        # Show SHAHPUR BARA in SAP data
        print(f"\n🔍 SAP DATA FOR SHAHPUR BARA/2247:")
        for key, qty in sap_data.items():
            location, mpp_code, product = key
            if '2247' in str(mpp_code):
                details = sap_details[key]
                print(f"   Key: {key}")
                print(f"     Raw MMP: {details['mmp_raw']}")
                print(f"     Resolved Code: {mpp_code}")
                print(f"     Product: {product}")
                print(f"     Quantity: {qty}")
                print(f"     Rows: {details['rows']}")
        
        # ============================================
        # PERFORM RECONCILIATION WITH DEBUG
        # ============================================
        
        print(f"\n🔄 PERFORMING RECONCILIATION...")
        
        all_keys = set(list(advance_data.keys()) + list(sap_data.keys()))
        print(f"   Total unique combinations: {len(all_keys)}")
        
        processed_data = []
        success_count = 0
        error_count = 0
        
        for key in sorted(all_keys):
            location, mpp_code, normalized_product = key
            
            try:
                advance_qty = advance_data.get(key, 0)
                sap_qty = sap_data.get(key, 0)
                
                # Get display product name
                display_product = normalized_product
                if key in sap_details:
                    display_product = sap_details[key]['product_raw']
                elif key in advance_details:
                    display_product = advance_details[key]['product_raw']
                
                display_product = ' '.join(word.capitalize() for word in display_product.split())
                
                # Get MPP display name
                mpp_display = mpp_code
                if mpp_code in mpp_map_by_code:
                    mpp_obj = mpp_map_by_code[mpp_code]
                    if mpp_obj.name_with_code:
                        mpp_display = f"{mpp_obj.name_with_code} ({mpp_code})"
                
                # Reconciliation logic
                if advance_qty > sap_qty:
                    to_be_sent = 0
                    to_be_deducted = advance_qty - sap_qty
                elif sap_qty > advance_qty:
                    to_be_sent = sap_qty - advance_qty
                    to_be_deducted = 0
                elif sap_qty == advance_qty and sap_qty > 0:
                    to_be_sent = 0
                    to_be_deducted = 0
                else:
                    to_be_sent = 0
                    to_be_deducted = 0
                
                # Determine status
                if sap_qty == advance_qty and sap_qty > 0:
                    status = 'OK'
                    status_display = 'PERFECT MATCH'
                    match_quality = 'Perfect Match'
                    color = '90EE90'
                elif sap_qty > advance_qty:
                    status = 'OVER_SOLD'
                    status_display = 'OVER RECORDED'
                    match_quality = f'Over by {sap_qty - advance_qty}'
                    color = 'FFB6C1'
                elif sap_qty < advance_qty:
                    if sap_qty > 0:
                        status = 'UNDER_SOLD'
                        status_display = 'UNDER RECORDED'
                        match_quality = f'Under by {advance_qty - sap_qty}'
                        color = 'FFD700'
                    else:
                        status = 'NOT_SOLD'
                        status_display = 'NOT RECORDED'
                        match_quality = 'No Entry Made'
                        color = 'D3D3D3'
                else:
                    status = 'NOT_SOLD'
                    status_display = 'NOT RECORDED'
                    match_quality = 'No Entry Made'
                    color = 'D3D3D3'
                
                if status == 'NOT_SOLD':
                    to_be_sent = 0
                    to_be_deducted = 0
                
                # SPECIAL DEBUG FOR SHAHPUR BARA
                if '2247' in mpp_code and 'CF- SAG 25 KG' in normalized_product.upper():
                    print(f"\n🔍 RECONCILIATION DEBUG FOR SHAHPUR BARA:")
                    print(f"   Key: {key}")
                    print(f"   Advance Qty: {advance_qty}")
                    print(f"   SAP Qty: {sap_qty}")
                    print(f"   Status: {status_display}")
                    print(f"   To be sent: {to_be_sent}")
                    print(f"   To be deducted: {to_be_deducted}")
                
                processed_data.append({
                    'location': location,
                    'mpp': mpp_display,
                    'mpp_code': mpp_code,
                    'product': display_product,
                    'advance_quantity': advance_qty,
                    'filled_quantity': sap_qty,
                    'status': status,
                    'status_display': status_display,
                    'match_quality': match_quality,
                    'to_be_sent': to_be_sent,
                    'to_be_deducted': to_be_deducted,
                    'color': color
                })
                
                # Save to database
                try:
                    entry, created = SaleTemplateEntry.objects.get_or_create(
                        config=config,
                        location=location,
                        mpp=mpp_code,
                        product_name=display_product,
                        defaults={
                            'advance_sale_quantity': advance_qty,
                            'filled_quantity': sap_qty,
                            'status': status,
                            'uploaded_by': request.user
                        }
                    )
                    
                    if not created:
                        entry.advance_sale_quantity = advance_qty
                        entry.filled_quantity = sap_qty
                        entry.status = status
                        entry.uploaded_by = request.user
                        entry.save()
                        
                except Exception as e:
                    print(f"⚠️  Error saving to database: {str(e)}")
                
                success_count += 1
                
            except Exception as e:
                error_count += 1
                print(f"❌ Error processing {normalized_product}: {str(e)}")
                import traceback
                traceback.print_exc()
        
        # Update upload history
        upload_history.success_count = success_count
        upload_history.error_count = error_count
        upload_history.save()
        
        print(f"\n✅ RECONCILIATION COMPLETE:")
        print(f"   Successfully processed: {success_count}")
        print(f"   Errors: {error_count}")
        
        # Show final statistics
        status_counts = {}
        for item in processed_data:
            status_counts[item['status']] = status_counts.get(item['status'], 0) + 1
        
        print(f"\n📊 FINAL STATISTICS:")
        for status, count in status_counts.items():
            print(f"   {status}: {count}")
        
        # ============================================
        # GENERATE EXCEL REPORT
        # ============================================
        
        if processed_data:
            print(f"\n📁 GENERATING EXCEL REPORT...")
            excel_file = generate_color_coded_excel(processed_data, month, cycle.name, success_count, error_count)
            
            response = HttpResponse(
                excel_file,
                content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
            )
            filename = f"sap_reconciliation_{month}_{cycle.name.replace(' ', '_')}.xlsx"
            response['Content-Disposition'] = f'attachment; filename="{filename}"'
            
            print(f"\n✅ FILE GENERATED: {filename}")
            print(f"   Total rows in output: {len(processed_data)}")
            
            print(f"\n" + "="*80)
            print("✅ UPLOAD_SALE_TEMPLATE COMPLETED SUCCESSFULLY")
            print("="*80)
            
            return response
        
        else:
            print(f"\n❌ No data processed")
            return JsonResponse({
                'success': False,
                'message': 'No data was processed from the upload.'
            })
            
    except Exception as e:
        print(f"\n❌ UNEXPECTED ERROR: {str(e)}")
        import traceback
        traceback.print_exc()
        
        print(f"\n" + "="*80)
        print("❌ UPLOAD_SALE_TEMPLATE FAILED")
        print("="*80)
        
        return JsonResponse({
            'success': False,
            'message': f'Error processing file: {str(e)}'
        })


def generate_color_coded_excel(processed_data, month, cycle, success_count, error_count):
    """
    Generate comprehensive Excel report with all reconciled data
    """
    
    output = io.BytesIO()
    wb = Workbook()
    ws = wb.active
    ws.title = "Sales Reconciliation"
    
    # Define styles
    header_fill = PatternFill(start_color="2C5F2D", end_color="2C5F2D", fill_type="solid")
    header_font = Font(color="FFFFFF", bold=True)
    
    border = Border(
        left=Side(style='thin'),
        right=Side(style='thin'),
        top=Side(style='thin'),
        bottom=Side(style='thin')
    )
    
    # Define color fills for status
    status_colors = {
        'PERFECT MATCH': '90EE90',  # Green
        'OVER RECORDED': 'FFB6C1',  # Pink
        'UNDER RECORDED': 'FFD700',  # Yellow
        'NOT RECORDED': 'D3D3D3',   # Gray
    }
    
    # Headers
    headers = [
        'Location',
        'MPP Code',
        'MPP Name',
        'Product',
        'Advance Sale Qty',
        'SAP Entry Qty',
        'Status',
        'Match Quality',
        'To Be Sent To MPP',
        'To Be Deducted'
    ]
    
    # Write headers
    for col_idx, header in enumerate(headers, start=1):
        cell = ws.cell(row=1, column=col_idx, value=header)
        cell.fill = header_fill
        cell.font = header_font
        cell.border = border
        cell.alignment = Alignment(horizontal='center')
    
    # Write data
    row_idx = 2
    for data in processed_data:
        ws.cell(row=row_idx, column=1, value=data['location']).border = border
        ws.cell(row=row_idx, column=2, value=data['mpp_code']).border = border
        ws.cell(row=row_idx, column=3, value=data['mpp']).border = border
        ws.cell(row=row_idx, column=4, value=data['product']).border = border
        ws.cell(row=row_idx, column=5, value=data['advance_quantity']).border = border
        ws.cell(row=row_idx, column=6, value=data['filled_quantity']).border = border
        ws.cell(row=row_idx, column=7, value=data['status_display']).border = border
        ws.cell(row=row_idx, column=8, value=data['match_quality']).border = border
        ws.cell(row=row_idx, column=9, value=data['to_be_sent']).border = border
        ws.cell(row=row_idx, column=10, value=data['to_be_deducted']).border = border
        
        # Apply color coding to status cell
        status_cell = ws.cell(row=row_idx, column=7)
        color_hex = status_colors.get(data['status_display'], 'FFFFFF')
        status_cell.fill = PatternFill(start_color=color_hex, end_color=color_hex, fill_type="solid")
        status_cell.font = Font(bold=True)
        
        row_idx += 1
    
    # Create summary sheet
    ws_summary = wb.create_sheet("Summary")
    
    total_records = len(processed_data)
    
    # Calculate statistics
    status_counts = {}
    total_to_be_sent = 0
    total_to_be_deducted = 0
    
    for data in processed_data:
        status = data['status_display']
        status_counts[status] = status_counts.get(status, 0) + 1
        total_to_be_sent += data['to_be_sent']
        total_to_be_deducted += data['to_be_deducted']
    
    summary_data = [
        ["SALES RECONCILIATION REPORT", "", "", ""],
        ["", "", "", ""],
        ["Period", f"{month} - {cycle}", "", ""],
        ["Generated On", timezone.now().strftime("%Y-%m-%d %H:%M:%S"), "", ""],
        ["Total Products Reconciled", total_records, "", ""],
        ["", "", "", ""],
        ["PROCESSING STATISTICS", "", "", ""],
        ["Successfully Processed", success_count, "", ""],
        ["Errors/Skipped", error_count, "", ""],
        ["", "", "", ""],
        ["RECONCILIATION SUMMARY", "", "", ""],
        ["Total To Be Sent To MPP", total_to_be_sent, "", ""],
        ["Total To Be Deducted", total_to_be_deducted, "", ""],
        ["", "", "", ""],
        ["MATCH QUALITY ANALYSIS", "", "", ""],
        ["Status", "Count", "Percentage", "Description"],
    ]
    
    # Add status breakdown
    for status, count in status_counts.items():
        percentage = (count / total_records) * 100 if total_records > 0 else 0
        
        if status == 'PERFECT MATCH':
            desc = "Perfect Match (SAP Entry = Advance Sale)"
        elif status == 'OVER RECORDED':
            desc = "Over Recorded (SAP Entry > Advance Sale)"
        elif status == 'UNDER RECORDED':
            desc = "Under Recorded (SAP Entry < Advance Sale)"
        else:
            desc = "Not Recorded (SAP Entry = 0)"
        
        summary_data.append([status, count, f"{percentage:.1f}%", desc])
    
    # Write summary data
    for row_idx, row_data in enumerate(summary_data, start=1):
        for col_idx, value in enumerate(row_data, start=1):
            cell = ws_summary.cell(row=row_idx, column=col_idx, value=value)
            
            # Apply formatting
            if row_idx == 1:
                cell.font = Font(bold=True, size=16, color="2C5F2D")
            elif row_idx in [3, 4, 5, 7, 11, 15]:
                cell.font = Font(bold=True)
            elif row_idx == 15:
                cell.fill = header_fill
                cell.font = header_font
    
    # Create legend sheet
    ws_legend = wb.create_sheet("Color Legend")
    
    legend_data = [
        ["COLOR CODING LEGEND", "", ""],
        ["", "", ""],
        ["Color", "Status", "Description"],
        ["🟢 GREEN", "PERFECT MATCH", "SAP entry exactly matches advance sale"],
        ["🔴 PINK", "OVER RECORDED", "SAP entry is higher than advance sale"],
        ["🟡 YELLOW", "UNDER RECORDED", "SAP entry is lower than advance sale"],
        ["⚪ GRAY", "NOT RECORDED", "No SAP entry made (0 quantity)"],
        ["", "", ""],
        ["COLUMN EXPLANATION", "", ""],
        ["Location", "Plant name from SAP", ""],
        ["MPP Code", "MPP transaction code from SAP/MPP master data", ""],
        ["MPP Name", "MPP name with code for reference", ""],
        ["Product", "Normalized product name", ""],
        ["Advance Sale Qty", "Total quantity from advance sales system", ""],
        ["SAP Entry Qty", "Total quantity from uploaded SAP file", ""],
        ["Status", "Reconciliation result with color coding", ""],
        ["Match Quality", "Detailed variance description", ""],
        ["To Be Sent To MPP", "Additional quantity to send to MPP", ""],
        ["To Be Deducted", "Excess quantity to deduct", ""],
    ]
    
    # Write legend data
    for row_idx, row_data in enumerate(legend_data, start=1):
        for col_idx, value in enumerate(row_data, start=1):
            cell = ws_legend.cell(row=row_idx, column=col_idx, value=value)
            
            if row_idx == 1:
                cell.font = Font(bold=True, size=14, color="2C5F2D")
            elif row_idx == 3:
                cell.fill = header_fill
                cell.font = header_font
            elif row_idx == 9:
                cell.font = Font(bold=True)
    
    # Adjust column widths for better readability
    for sheet in [ws, ws_summary, ws_legend]:
        for column in sheet.columns:
            max_length = 0
            column_letter = get_column_letter(column[0].column)
            
            for cell in column:
                try:
                    if len(str(cell.value)) > max_length:
                        max_length = len(str(cell.value))
                except:
                    pass
            
            adjusted_width = min((max_length + 2), 50)
            sheet.column_dimensions[column_letter].width = adjusted_width
    
    # Save workbook
    wb.save(output)
    output.seek(0)
    
    return output.getvalue()


