@login_required(login_url='login')
def get_sale_upload_history(request):
    """
    Get sale upload history for display in UI
    """
    try:
        # Get history ordered by most recent
        histories = SaleUploadHistory.objects.all().order_by('-uploaded_at')[:50]
        
        data = []
        for history in histories:
            # Safely get config and cycle information
            config_data = {}
            if history.config and history.config.cycle:
                cycle = history.config.cycle
                config_data = {
                    'id': history.config.id,
                    'cycle_id': cycle.id,
                    'cycle_name': cycle.name,
                    'month': cycle.monthly_cycle.month if cycle.monthly_cycle else 'Unknown',
                    'start_date': cycle.start_date.strftime('%Y-%m-%d') if cycle.start_date else '',
                    'end_date': cycle.end_date.strftime('%Y-%m-%d') if cycle.end_date else ''
                }
            
            data.append({
                'id': history.id,
                'file_name': history.file_name,
                'uploaded_by': history.uploaded_by.email if history.uploaded_by else 'Unknown',
                'total_records': history.total_records,
                'success_count': history.success_count,
                'error_count': history.error_count,
                'uploaded_at': history.uploaded_at.strftime('%Y-%m-%d %H:%M:%S'),
                'config': config_data
            })
        
        return JsonResponse({'history': data})
        
    except Exception as e:
        print(f"❌ Error in get_sale_upload_history: {str(e)}")
        import traceback
        traceback.print_exc()
        return JsonResponse({
            'success': False,
            'error': str(e)
        }, status=500)


@login_required(login_url='login')
def debug_sap_columns(request):
    if request.method == 'POST' and request.FILES.get('file'):
        uploaded_file = request.FILES['file']
        try:
            df = pd.read_excel(uploaded_file)
            columns = df.columns.tolist()
            return JsonResponse({
                'success': True,
                'columns': columns,
                'first_row': df.iloc[0].to_dict() if len(df) > 0 else {}
            })
        except Exception as e:
            return JsonResponse({
                'success': False,
                'error': str(e)
            })
    return JsonResponse({'success': False, 'message': 'No file uploaded'})

@login_required(login_url='login')
def view_advance_sales(request):
    print("\n" + "="*80)
    print("🏁 ADVANCE SALE VIEW CALLED - DYNAMIC CYCLE FILTERING")
    print("="*80)
    
    # ------------------------------------------------------------
    # SECTION 1: FILTER PARAMETER EXTRACTION
    # ------------------------------------------------------------
    month = request.GET.get('month', datetime.now().strftime('%Y-%m'))
    cycle = request.GET.get('cycle', 'all')
    status = request.GET.get('status', 'all')
    search_query = request.GET.get('search', '')
    
    print(f"📊 FILTER PARAMETERS:")
    print(f"   Month: {month}")
    print(f"   Cycle: {cycle}")
    print(f"   Status: {status}")
    print(f"   Search: {search_query}")
    
    # ------------------------------------------------------------
    # SECTION 2: MONTH PARAMETER VALIDATION AND PARSING
    # ------------------------------------------------------------
    try:
        # Parse the month parameter (format: YYYY-MM)
        filter_date = datetime.strptime(month, '%Y-%m')
        year = filter_date.year
        month_num = filter_date.month
        
        # Convert numeric month to month name (e.g., 1 -> "January")
        month_names = ["January", "February", "March", "April", "May", "June",
                      "July", "August", "September", "October", "November", "December"]
        month_name = month_names[month_num - 1]  # month_num is 1-12, list is 0-11
        
        print(f"✅ Month parsed successfully: {month_name} {year}")
    except (ValueError, IndexError) as e:
        current_date = datetime.now()
        year = current_date.year
        month_num = current_date.month
        month_names = ["January", "February", "March", "April", "May", "June",
                      "July", "August", "September", "October", "November", "December"]
        month_name = month_names[month_num - 1]
        month = current_date.strftime('%Y-%m')
        print(f"⚠️  Month parsing failed, using default: {month_name} {year}")
        print(f"   Error: {e}")
    
    # ------------------------------------------------------------
    # SECTION 3: GET DYNAMIC CYCLES FOR SELECTED MONTH
    # ------------------------------------------------------------
    print(f"\n🔍 LOOKING FOR CYCLES FOR MONTH: {month_name} {year}")
    
    # Get the specific monthly cycle for the selected month
    monthly_cycle = MonthlyCycle.objects.filter(
        month=month_name,
        year=year
    ).first()
    
    if monthly_cycle:
        print(f"✅ Found monthly cycle: {monthly_cycle.month} {monthly_cycle.year} (ID: {monthly_cycle.id})")
    else:
        print(f"❌ NO MONTHLY CYCLE FOUND for {month_name} {year}")
        print(f"   Searching for: month='{month_name}', year={year}")
        # List all available monthly cycles for debugging
        all_cycles = MonthlyCycle.objects.all()
        print(f"   All available monthly cycles:")
        for mc in all_cycles:
            print(f"   - {mc.month} {mc.year}")
    
    # Get all cycles for the selected month from database
    cycles_for_month = Cycle.objects.filter(
        monthly_cycle__month=month_name,
        monthly_cycle__year=year
    ).order_by('cycle_number')
    
    print(f"🔍 CYCLES QUERY: monthly_cycle__month='{month_name}', monthly_cycle__year={year}")
    print(f"📋 Found {cycles_for_month.count()} cycles for {month_name} {year}")
    
    # Create cycle choices for template
    cycle_choices = []
    for cycle_obj in cycles_for_month:
        # Determine display name based on cycle number
        if cycle_obj.cycle_number == 1:
            display_name = f"Cycle 1-10 (SAP: {cycle_obj.sap_number})"
        elif cycle_obj.cycle_number == 2:
            display_name = f"Cycle 11-20 (SAP: {cycle_obj.sap_number})"
        elif cycle_obj.cycle_number == 3:
            display_name = f"Cycle 21-31 (SAP: {cycle_obj.sap_number})"
        else:
            display_name = f"Cycle {cycle_obj.cycle_number} - Extra (SAP: {cycle_obj.sap_number})"
        
        cycle_choices.append({
            'id': cycle_obj.id,
            'number': cycle_obj.cycle_number,
            'value': str(cycle_obj.cycle_number),  # Use cycle number as value
            'name': cycle_obj.name,
            'display': display_name,
            'sap_number': cycle_obj.sap_number,
            'is_selected': str(cycle_obj.cycle_number) == cycle,
        })
        
        print(f"   • Cycle {cycle_obj.cycle_number}: {cycle_obj.name} (SAP: {cycle_obj.sap_number})")
    
    print(f"📝 Cycle choices created: {len(cycle_choices)} options")
    
    # ------------------------------------------------------------
    # SECTION 4: USER-SPECIFIC ADVANCE SALE DOCUMENTS RETRIEVAL
    # ------------------------------------------------------------
    # Retrieve authenticated user's Advance Sale documents with base filtering
    advance_sales = AdvanceSale.objects.filter(
        dispatched_by=request.user
    ).order_by('-dispatched_at')
    
    print(f"\n👤 USER'S TOTAL ADVANCE SALES: {advance_sales.count()}")
    
    # --------------------------------------------------------
    # SUBSECTION 4.1: DUAL MONTH FILTERING STRATEGY
    # --------------------------------------------------------
    # We need to show sales based on TWO criteria:
    # 1. Sales where the cycle belongs to the selected month (cycle's monthly cycle)
    # 2. Sales made in the selected month (sale date)
    print(f"\n🔍 DUAL FILTERING STRATEGY FOR MONTH: {month_name} {year}")
    
    # First, get sales based on CYCLE's monthly cycle
    sales_by_cycle_month = advance_sales.filter(
        cycle__monthly_cycle__month=month_name,
        cycle__monthly_cycle__year=year
    )
    print(f"📅 Sales where CYCLE belongs to {month_name} {year}: {sales_by_cycle_month.count()}")
    
    # Second, get sales based on SALE DATE (dispatched_at)
    sales_by_sale_date = advance_sales.filter(
        dispatched_at__year=year,
        dispatched_at__month=month_num
    )
    print(f"📅 Sales made IN {month_name} {year} (by date): {sales_by_sale_date.count()}")
    
    # Combine both querysets (UNION)
    # Get distinct sales that match either criteria
    cycle_month_ids = sales_by_cycle_month.values_list('id', flat=True)
    sale_date_ids = sales_by_sale_date.values_list('id', flat=True)
    all_ids = set(list(cycle_month_ids) + list(sale_date_ids))
    
    print(f"📊 Total unique sales for {month_name} {year}: {len(all_ids)}")
    
    # Filter the main queryset by these IDs
    if all_ids:
        advance_sales = advance_sales.filter(id__in=all_ids)
    else:
        advance_sales = advance_sales.none()
    
    print(f"📅 After dual month filter: {advance_sales.count()} sales")
    
    # --------------------------------------------------------
    # SECTION 5: CYCLE-BASED FILTER APPLICATION
    # --------------------------------------------------------
    # Apply cycle-based filtering based on parameter selection
    if cycle != 'all':
        try:
            cycle_number = int(cycle)
            advance_sales = advance_sales.filter(cycle__cycle_number=cycle_number)
            print(f"🔄 After cycle filter (Cycle {cycle_number}): {advance_sales.count()} sales")
        except ValueError:
            # Fallback to old logic for compatibility
            if cycle == '1-10':
                advance_sales = advance_sales.filter(cycle__cycle_number=1)
                print(f"🔄 After cycle filter (Cycle 1-10): {advance_sales.count()} sales")
            elif cycle == '11-20':
                advance_sales = advance_sales.filter(cycle__cycle_number=2)
                print(f"🔄 After cycle filter (Cycle 11-20): {advance_sales.count()} sales")
            elif cycle == '21-31':
                advance_sales = advance_sales.filter(cycle__cycle_number=3)
                print(f"🔄 After cycle filter (Cycle 21-31): {advance_sales.count()} sales")
    else:
        print(f"🔄 No cycle filter applied (showing all cycles)")
    
    # --------------------------------------------------------
    # SECTION 6: STATUS-BASED FILTER APPLICATION
    # --------------------------------------------------------
    # Apply status-based filtering
    if status != 'all':
        if status == 'pdf_generated':
            advance_sales = advance_sales.filter(pdf_generated=True, pdf_file__isnull=False)
            print(f"📄 After PDF generated filter: {advance_sales.count()} sales")
        elif status == 'no_pdf':
            advance_sales = advance_sales.filter(Q(pdf_generated=False) | Q(pdf_file__isnull=True))
            print(f"📄 After no PDF filter: {advance_sales.count()} sales")
        elif status == 'pod_uploaded':
            advance_sales = advance_sales.filter(pod_uploaded=True, pod_file__isnull=False)
            print(f"📦 After POD uploaded filter: {advance_sales.count()} sales")
    else:
        print(f"📄 No status filter applied")
    
    # --------------------------------------------------------
    # SECTION 7: SEARCH-BASED FILTER APPLICATION
    # --------------------------------------------------------
    # Apply text-based search filtering across multiple fields
    if search_query:
        advance_sales = advance_sales.filter(
            Q(unique_code__icontains=search_query) |
            Q(bmc_or_mcc__icontains=search_query) |
            Q(mpp_with_code__icontains=search_query) |
            Q(stock_item__icontains=search_query) |
            Q(cycle__name__icontains=search_query) |
            Q(cycle__sap_number__icontains=search_query)
        )
        print(f"🔍 After search filter ('{search_query}'): {advance_sales.count()} sales")
    else:
        print(f"🔍 No search filter applied")
    
    # ------------------------------------------------------------
    # SECTION 8: STATISTICAL ANALYSIS CALCULATION
    # ------------------------------------------------------------
    total_count = advance_sales.count()
    pdf_generated_count = advance_sales.filter(pdf_generated=True, pdf_file__isnull=False).count()
    pod_uploaded_count = advance_sales.filter(pod_uploaded=True, pod_file__isnull=False).count()
    
    # --------------------------------------------------------
    # SUBSECTION 8.4: CYCLE-WISE DISTRIBUTION CALCULATION
    # --------------------------------------------------------
    cycle_counts = {}
    for cycle_obj in cycles_for_month:
        count = advance_sales.filter(cycle__cycle_number=cycle_obj.cycle_number).count()
        cycle_counts[cycle_obj.cycle_number] = count
        print(f"📊 Cycle {cycle_obj.cycle_number} ({cycle_obj.sap_number}) count: {count}")
    
    # Determine cycle-specific count for display
    cycle_specific_count = total_count
    if cycle != 'all':
        try:
            cycle_number = int(cycle)
            cycle_specific_count = cycle_counts.get(cycle_number, 0)
            print(f"🎯 Selected cycle {cycle_number} count: {cycle_specific_count}")
        except ValueError:
            if cycle == '1-10':
                cycle_specific_count = cycle_counts.get(1, 0)
                print(f"🎯 Selected cycle 1-10 count: {cycle_specific_count}")
            elif cycle == '11-20':
                cycle_specific_count = cycle_counts.get(2, 0)
                print(f"🎯 Selected cycle 11-20 count: {cycle_specific_count}")
            elif cycle == '21-31':
                cycle_specific_count = cycle_counts.get(3, 0)
                print(f"🎯 Selected cycle 21-31 count: {cycle_specific_count}")
    else:
        print(f"🎯 All cycles total count: {cycle_specific_count}")
    
    # ------------------------------------------------------------
    # SECTION 9: TEMPORAL NAVIGATION DATA GENERATION
    # ------------------------------------------------------------
    current_date = datetime.now()
    month_choices = []
    
    # Generate month choices for 12-month historical navigation
    for i in range(12):
        date = current_date.replace(day=1) - timedelta(days=i*30)
        month_choices.append({
            'value': date.strftime('%Y-%m'),
            'display': date.strftime('%B %Y'),
            'selected': date.strftime('%Y-%m') == month
        })
    
    print(f"\n🗓️  Month choices generated: {len(month_choices)} months")
    
    # ------------------------------------------------------------
    # SECTION 10: TEMPLATE CONTEXT DATA COMPILATION
    # ------------------------------------------------------------
    # Determine cycle display name
    if cycle == 'all':
        selected_cycle_display = 'All Cycles'
    else:
        try:
            cycle_number = int(cycle)
            # Find the cycle object
            cycle_obj = cycles_for_month.filter(cycle_number=cycle_number).first()
            if cycle_obj:
                if cycle_obj.cycle_number == 1:
                    selected_cycle_display = f"Cycle 1-10 (SAP: {cycle_obj.sap_number})"
                elif cycle_obj.cycle_number == 2:
                    selected_cycle_display = f"Cycle 11-20 (SAP: {cycle_obj.sap_number})"
                elif cycle_obj.cycle_number == 3:
                    selected_cycle_display = f"Cycle 21-31 (SAP: {cycle_obj.sap_number})"
                else:
                    selected_cycle_display = f"Cycle {cycle_obj.cycle_number} - Extra (SAP: {cycle_obj.sap_number})"
            else:
                selected_cycle_display = f"Cycle {cycle}"
        except ValueError:
            selected_cycle_display = cycle
    
    print(f"\n📋 CONTEXT SUMMARY:")
    print(f"   Total sales count: {total_count}")
    print(f"   PDF generated count: {pdf_generated_count}")
    print(f"   POD uploaded count: {pod_uploaded_count}")
    print(f"   Cycle specific count: {cycle_specific_count}")
    print(f"   Selected cycle display: {selected_cycle_display}")
    print(f"   Has cycles: {len(cycle_choices) > 0}")
    print(f"   Cycle choices: {len(cycle_choices)}")
    print(f"   Month choices: {len(month_choices)}")
    
    context = {
        'advance_sales': advance_sales,
        'total_sales_count': total_count,
        'pdf_generated_count': pdf_generated_count,
        'pod_uploaded_count': pod_uploaded_count,
        'cycle_specific_count': cycle_specific_count,
        'cycle_counts': cycle_counts,
        'cycle_choices': cycle_choices,
        'month_choices': month_choices,
        'selected_month': month,
        'selected_cycle': cycle,
        'selected_status': status,
        'selected_cycle_display': selected_cycle_display,
        'search_query': search_query,
        'current_month': current_date.strftime('%Y-%m'),
        'current_month_display': current_date.strftime('%B %Y'),
        'month_name': month_name,
        'year': year,
        'has_cycles': len(cycle_choices) > 0,
    }
    
    print(f"\n📄 Rendering template: view_advance_sales.html")
    print("="*80 + "\n")
    
    return render(request, 'view_advance_sales.html', context)
