# ======================================================================================================================
# POD DOCUMENTS VIEW WITH FILTERING FUNCTIONALITY
# ======================================================================================================================
# Provides comprehensive view of user's POD documents with advanced filtering capabilities
# Supports month, cycle, and search-based filtering for efficient document management

@login_required(login_url='login')
def view_pods(request):
    """
    POD Documents View with Advanced Filtering
    
    Displays user's Proof of Delivery (POD) documents with comprehensive filtering
    capabilities including month selection, cycle filtering, and text search. Provides
    statistical analysis and temporal navigation for efficient document management.
    
    Key Features:
        - Multi-dimensional filtering (month, cycle, search)
        - Statistical analysis with cycle-wise counts
        - Temporal navigation with month selection dropdown
        - User-specific document filtering for data security
        - Comprehensive context data for template rendering
    
    Filtering Dimensions:
        1. Month Filter: Calendar month selection for temporal filtering
        2. Cycle Filter: Financial cycle filtering (1-10, 11-20, 21-31, all)
        3. Search Filter: Text-based search across multiple document fields
    
    Statistical Analysis:
        - Total POD count for selected filters
        - Cycle-wise distribution counts
        - Month-based aggregation for historical analysis
    
    Authentication & Data Security:
        - Requires user authentication for access control
        - Filters documents by authenticated user ownership
        - Maintains data privacy and document security
    
    Returns:
        HttpResponse: Rendered POD documents view with comprehensive context
    """
    
    # ------------------------------------------------------------
    # SECTION 1: FILTER PARAMETER EXTRACTION
    # ------------------------------------------------------------
    # Extract filtering parameters from GET request with defaults
    month = request.GET.get('month', datetime.now().strftime('%Y-%m'))
    cycle = request.GET.get('cycle', 'all')
    search_query = request.GET.get('search', '')
    
    # ------------------------------------------------------------
    # SECTION 2: MONTH PARAMETER VALIDATION AND PARSING
    # ------------------------------------------------------------
    # Parse and validate month parameter for date-based filtering
    try:
        filter_date = datetime.strptime(month, '%Y-%m')
        year = filter_date.year
        month_num = filter_date.month
    except ValueError:
        # --------------------------------------------------------
        # SUBSECTION 2.1: DEFAULT DATE FALLBACK
        # --------------------------------------------------------
        # Apply default date values on parsing failure
        current_date = datetime.now()
        year = current_date.year
        month_num = current_date.month
        month = current_date.strftime('%Y-%m')
    
    # ------------------------------------------------------------
    # SECTION 3: USER-SPECIFIC POD DOCUMENTS RETRIEVAL
    # ------------------------------------------------------------
    # Retrieve authenticated user's POD documents with base filtering
    pods = AdvanceSale.objects.filter(
        dispatched_by=request.user,
        pod_uploaded=True
    ).order_by('-dispatched_at')
    
    # --------------------------------------------------------
    # SUBSECTION 3.1: MONTH-BASED FILTER APPLICATION
    # --------------------------------------------------------
    # Apply month-based filtering to document retrieval
    pods = pods.filter(dispatched_at__year=year, dispatched_at__month=month_num)
    
    # --------------------------------------------------------
    # SECTION 4: CYCLE-BASED FILTER APPLICATION
    # --------------------------------------------------------
    # Apply cycle-based filtering based on parameter selection
    if cycle != 'all':
        if cycle == '1-10':
            pods = pods.filter(dispatched_at__day__range=[1, 10])
        elif cycle == '11-20':
            pods = pods.filter(dispatched_at__day__range=[11, 20])
        elif cycle == '21-31':
            pods = pods.filter(dispatched_at__day__range=[21, 31])
    
    # --------------------------------------------------------
    # SECTION 5: SEARCH-BASED FILTER APPLICATION
    # --------------------------------------------------------
    # Apply text-based search filtering across multiple fields
    if search_query:
        pods = pods.filter(
            Q(unique_code__icontains=search_query) |
            Q(bmc_or_mcc__icontains=search_query) |
            Q(mpp_with_code__icontains=search_query) |
            Q(stock_item__icontains=search_query)
        )
    
    # ------------------------------------------------------------
    # SECTION 6: STATISTICAL ANALYSIS CALCULATION
    # ------------------------------------------------------------
    # Calculate comprehensive statistics for context data
    
    # --------------------------------------------------------
    # SUBSECTION 6.1: TOTAL COUNT CALCULATION
    # --------------------------------------------------------
    # Calculate total POD count for selected filters
    total_count = pods.count()
    
    # --------------------------------------------------------
    # SUBSECTION 6.2: CYCLE-WISE DISTRIBUTION CALCULATION
    # --------------------------------------------------------
    # Calculate cycle-wise distribution counts for statistical analysis
    cycle_1_10_count = pods.filter(dispatched_at__day__range=[1, 10]).count()
    cycle_11_20_count = pods.filter(dispatched_at__day__range=[11, 20]).count()
    cycle_21_31_count = pods.filter(dispatched_at__day__range=[21, 31]).count()
    
    # ------------------------------------------------------------
    # SECTION 7: TEMPORAL NAVIGATION DATA GENERATION
    # ------------------------------------------------------------
    # Generate month selection data for user interface dropdown
    current_date = datetime.now()
    month_choices = []
    
    # --------------------------------------------------------
    # SUBSECTION 7.1: MONTH CHOICES ITERATION
    # --------------------------------------------------------
    # Generate month choices for 12-month historical navigation
    for i in range(12):
        date = current_date.replace(day=1) - timedelta(days=i*30)
        month_choices.append({
            'value': date.strftime('%Y-%m'),
            'display': date.strftime('%B %Y'),
            'selected': date.strftime('%Y-%m') == month
        })
    
    # ------------------------------------------------------------
    # SECTION 8: TEMPLATE CONTEXT DATA COMPILATION
    # ------------------------------------------------------------
    # Compile comprehensive context data for template rendering
    context = {
        'pods': pods,
        'total_pods_count': total_count,
        'cycle_1_10_count': cycle_1_10_count,
        'cycle_11_20_count': cycle_11_20_count,
        'cycle_21_31_count': cycle_21_31_count,
        'month_choices': month_choices,
        'selected_month': month,
        'selected_cycle': cycle,
        'search_query': search_query,
        'current_month': current_date.strftime('%Y-%m'),
        'current_month_display': current_date.strftime('%B %Y'),
    }
    
    # ------------------------------------------------------------
    # SECTION 9: TEMPLATE RENDERING AND RESPONSE
    # ------------------------------------------------------------
    # Render POD documents view template with comprehensive context
    return render(request, 'view_pods.html', context)

# ======================================================================================================================
# USER POD DATA AJAX RETRIEVAL ENDPOINT
# ======================================================================================================================
# Provides AJAX endpoint for dynamic loading of user's POD documents with pagination
# Supports comprehensive filtering, pagination, and search functionality for responsive UI

@login_required(login_url='login')
def get_user_pods(request):
    """
    User POD Data AJAX Retrieval Endpoint
    
    Provides AJAX endpoint for dynamic loading of authenticated user's Proof of Delivery
    documents with comprehensive pagination, filtering, and search capabilities. Supports
    responsive user interface with server-side data loading and pagination.
    
    Key Features:
        - Server-side pagination for large datasets
        - Multi-dimensional filtering (month, cycle, search)
        - JSON serialization for frontend integration
        - Comprehensive error handling and response formatting
        - Performance optimization with query limiting
    
    Pagination Support:
        - Configurable page size with default optimization
        - Page number calculation for navigation
        - Total page count calculation
        - Offset-based data retrieval for efficiency
    
    Filtering Capabilities:
        - Month-based temporal filtering
        - Cycle-based financial period filtering
        - Text-based search across multiple fields
        - Combined filter application for precise results
    
    Data Serialization:
        - POD metadata with comprehensive fields
        - File information with URLs and names
        - Timestamp formatting for user display
        - Status indicators for document tracking
    
    Returns:
        JsonResponse: Paginated POD data with metadata and navigation information
        JsonResponse: Error response with detailed error information on failure
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: PAGINATION PARAMETER EXTRACTION
        # ------------------------------------------------------------
        # Extract pagination parameters from GET request with defaults
        page = int(request.GET.get('page', 1))
        per_page = int(request.GET.get('per_page', 10))
        
        # ------------------------------------------------------------
        # SECTION 2: FILTER PARAMETER EXTRACTION
        # ------------------------------------------------------------
        # Extract filtering parameters from GET request with defaults
        month = request.GET.get('month', datetime.now().strftime('%Y-%m'))
        cycle = request.GET.get('cycle', 'all')
        search_query = request.GET.get('search', '')
        
        # ------------------------------------------------------------
        # SECTION 3: PAGINATION OFFSET CALCULATION
        # ------------------------------------------------------------
        # Calculate database offset for paginated data retrieval
        offset = (page - 1) * per_page
        
        # ------------------------------------------------------------
        # SECTION 4: MONTH PARAMETER VALIDATION AND PARSING
        # ------------------------------------------------------------
        # Parse and validate month parameter for date-based filtering
        try:
            filter_date = datetime.strptime(month, '%Y-%m')
            year = filter_date.year
            month_num = filter_date.month
        except ValueError:
            # --------------------------------------------------------
            # SUBSECTION 4.1: DEFAULT DATE FALLBACK
            # --------------------------------------------------------
            # Apply current date values on parsing failure
            current_date = datetime.now()
            year = current_date.year
            month_num = current_date.month
        
        # ------------------------------------------------------------
        # SECTION 5: BASE QUERYSET CONSTRUCTION
        # ------------------------------------------------------------
        # Construct base queryset with essential filters
        pods = AdvanceSale.objects.filter(
            dispatched_by=request.user,
            pod_uploaded=True,
            dispatched_at__year=year,
            dispatched_at__month=month_num
        ).order_by('-dispatched_at')
        
        # --------------------------------------------------------
        # SECTION 6: CYCLE-BASED FILTER APPLICATION
        # --------------------------------------------------------
        # Apply cycle-based filtering to queryset
        if cycle != 'all':
            if cycle == '1-10':
                pods = pods.filter(dispatched_at__day__range=[1, 10])
            elif cycle == '11-20':
                pods = pods.filter(dispatched_at__day__range=[11, 20])
            elif cycle == '21-31':
                pods = pods.filter(dispatched_at__day__range=[21, 31])
        
        # --------------------------------------------------------
        # SECTION 7: SEARCH-BASED FILTER APPLICATION
        # --------------------------------------------------------
        # Apply text-based search filtering across multiple fields
        if search_query:
            pods = pods.filter(
                Q(unique_code__icontains=search_query) |
                Q(bmc_or_mcc__icontains=search_query) |
                Q(mpp_with_code__icontains=search_query) |
                Q(stock_item__icontains=search_query)
            )
        
        # ------------------------------------------------------------
        # SECTION 8: TOTAL COUNT CALCULATION
        # ------------------------------------------------------------
        # Calculate total record count for pagination metadata
        total_count = pods.count()
        
        # ------------------------------------------------------------
        # SECTION 9: PAGINATED DATA RETRIEVAL
        # ------------------------------------------------------------
        # Apply pagination limits to queryset for efficient data retrieval
        pods = pods[offset:offset + per_page]
        
        # ------------------------------------------------------------
        # SECTION 10: POD DATA SERIALIZATION
        # ------------------------------------------------------------
        # Initialize data structure for serialized POD information
        pod_data = []
        
        # --------------------------------------------------------
        # SUBSECTION 10.1: POD OBJECT ITERATION
        # --------------------------------------------------------
        # Serialize each POD object for JSON response
        for pod in pods:
            # ----------------------------------------------------
            # SUBSECTION 10.1.1: FILE INFORMATION EXTRACTION
            # ----------------------------------------------------
            # Extract file information with null safety
            pod_file_name = os.path.basename(pod.pod_file.name) if pod.pod_file else 'No file'
            
            # ----------------------------------------------------
            # SUBSECTION 10.1.2: TIMESTAMP FORMATTING
            # ----------------------------------------------------
            # Format timestamps for user-friendly display
            dispatched_at_formatted = pod.dispatched_at.strftime('%Y-%m-%d %H:%M:%S') if pod.dispatched_at else 'N/A'
            pod_uploaded_at_formatted = pod.pod_uploaded_at.strftime('%Y-%m-%d %H:%M:%S') if pod.pod_uploaded_at else 'N/A'
            
            # ----------------------------------------------------
            # SUBSECTION 10.1.3: COMPREHENSIVE DATA COMPILATION
            # ----------------------------------------------------
            # Compile comprehensive POD data structure
            pod_record = {
                'id': pod.id,
                'unique_code': pod.unique_code or 'N/A',
                'bmc_or_mcc': pod.bmc_or_mcc or 'N/A',
                'mpp_with_code': pod.mpp_with_code or 'N/A',
                'stock_item': pod.stock_item or 'N/A',
                'quantity': pod.quantity or 0,
                'uom': pod.uom or 'N/A',
                'dispatched_at': dispatched_at_formatted,
                'pod_uploaded_at': pod_uploaded_at_formatted,
                'pod_file_url': pod.pod_file.url if pod.pod_file else None,
                'pod_file_name': pod_file_name,
                'status': 'delivered'
            }
            
            # ----------------------------------------------------
            # SUBSECTION 10.1.4: DATA COLLECTION
            # ----------------------------------------------------
            # Append serialized POD record to data collection
            pod_data.append(pod_record)
        
        # ------------------------------------------------------------
        # SECTION 11: PAGINATION METADATA CALCULATION
        # ------------------------------------------------------------
        # Calculate pagination metadata for frontend navigation
        total_pages = (total_count + per_page - 1) // per_page
        
        # ------------------------------------------------------------
        # SECTION 12: SUCCESS RESPONSE PREPARATION
        # ------------------------------------------------------------
        # Prepare comprehensive success response with data and metadata
        return JsonResponse({
            'success': True,
            'pods': pod_data,
            'total_count': total_count,
            'current_page': page,
            'per_page': per_page,
            'total_pages': total_pages
        })
        
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 13: EXCEPTION HANDLING AND ERROR RESPONSE
        # ------------------------------------------------------------
        # Handle unexpected exceptions with detailed error response
        return JsonResponse({
            'success': False,
            'error': str(e)
        }, status=500)
        
# ======================================================================================================================
# POD FILE DOWNLOAD ENDPOINT
# ======================================================================================================================
# Provides secure POD file download functionality with user authentication and file validation
# Ensures proper access control and file delivery with comprehensive error handling

@login_required(login_url='login')
def download_pod(request, pod_id):
    """
    POD File Download Endpoint
    
    Provides secure download functionality for Proof of Delivery (POD) files with
    comprehensive user authentication, file validation, and access control. Ensures
    that users can only download their own POD documents with proper error handling.
    
    Key Features:
        - User authentication and ownership validation
        - File existence verification on server filesystem
        - Proper content type and attachment headers
        - Comprehensive error handling with user feedback
        - Secure file delivery with access control
    
    Security Measures:
        - User authentication requirement
        - POD ownership validation (user-specific access)
        - File existence verification before delivery
        - POD upload status validation (must be uploaded)
    
    Error Handling:
        - POD not found (404 response)
        - File not found on server (404 response)
        - User permission denial (implicit via get_object_or_404)
        - Generic server errors (500 response)
    
    File Delivery:
        - Binary file delivery with proper content type
        - Filename preservation from original upload
        - Attachment disposition for browser download
        - File existence verification before opening
    
    Parameters:
        request (HttpRequest): HTTP request object
        pod_id (int): Primary key identifier for POD document
    
    Returns:
        HttpResponse: Binary file download with proper headers
        JsonResponse: Error response with appropriate status codes
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: POD DOCUMENT RETRIEVAL AND VALIDATION
        # ------------------------------------------------------------
        # Retrieve POD document with comprehensive validation checks
        pod = get_object_or_404(
            AdvanceSale, 
            id=pod_id, 
            dispatched_by=request.user,  # User ownership validation
            pod_uploaded=True  # POD upload status validation
        )
        
        # ------------------------------------------------------------
        # SECTION 2: FILE EXISTENCE VALIDATION
        # ------------------------------------------------------------
        # Validate that POD file exists in document record
        if not pod.pod_file:
            return JsonResponse({
                'success': False,
                'error': 'POD file not found'
            }, status=404)
        
        # ------------------------------------------------------------
        # SECTION 3: SERVER FILESYSTEM FILE VALIDATION
        # ------------------------------------------------------------
        # Validate that file exists on server filesystem
        file_path = pod.pod_file.path
        
        if not os.path.exists(file_path):
            return JsonResponse({
                'success': False,
                'error': 'File not found on server'
            }, status=404)
        
        # ------------------------------------------------------------
        # SECTION 4: FILE OPENING AND CONTENT READING
        # ------------------------------------------------------------
        # Open file in binary mode and read content for delivery
        with open(file_path, 'rb') as f:
            file_content = f.read()
        
        # ------------------------------------------------------------
        # SECTION 5: HTTP RESPONSE PREPARATION
        # ------------------------------------------------------------
        # Prepare HTTP response with file content and download headers
        
        # --------------------------------------------------------
        # SUBSECTION 5.1: CONTENT TYPE CONFIGURATION
        # --------------------------------------------------------
        # Configure octet-stream content type for binary file delivery
        response = HttpResponse(file_content, content_type='application/octet-stream')
        
        # --------------------------------------------------------
        # SUBSECTION 5.2: CONTENT DISPOSITION CONFIGURATION
        # --------------------------------------------------------
        # Configure attachment headers for browser download behavior
        filename = os.path.basename(file_path)
        response['Content-Disposition'] = f'attachment; filename="{filename}"'
        
        # ------------------------------------------------------------
        # SECTION 6: FILE DELIVERY RESPONSE
        # ------------------------------------------------------------
        # Return prepared HTTP response with file content
        return response
            
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 7: EXCEPTION HANDLING AND ERROR RESPONSE
        # ------------------------------------------------------------
        # Handle unexpected exceptions with comprehensive error response
        return JsonResponse({
            'success': False,
            'error': str(e)
        }, status=500)
        
        
# ======================================================================================================================
# POD FILTERING AND STATISTICS AJAX ENDPOINT
# ======================================================================================================================
# Provides AJAX endpoint for dynamic POD filtering and statistical analysis
# Enables real-time statistics calculation for user interface updates

@login_required(login_url='login')
def filter_pods(request):
    """
    POD Filtering and Statistics AJAX Endpoint
    
    Provides AJAX endpoint for dynamic filtering of POD documents and real-time
    statistical analysis. Supports multi-dimensional filtering with comprehensive
    statistics calculation for user interface updates and dashboard analytics.
    
    Key Features:
        - Real-time filtering statistics calculation
        - Multi-dimensional filtering (month, cycle, search)
        - Cycle-wise distribution analysis
        - AJAX response for dynamic UI updates
        - Comprehensive error handling and validation
    
    Statistical Analysis:
        - Total document count for selected filters
        - Cycle-wise distribution counts
        - Combined filter effect analysis
        - Real-time statistics updates
    
    Filtering Dimensions:
        1. Month Filter: Calendar month selection
        2. Cycle Filter: Financial cycle periods (1-10, 11-20, 21-31, all)
        3. Search Filter: Text-based search across multiple fields
    
    Performance Optimization:
        - Efficient database queries with proper indexing
        - Aggregate calculations without full data retrieval
        - Parameter validation for query optimization
        - Minimal data transfer for statistics only
    
    Returns:
        JsonResponse: Filtering statistics with success status
        JsonResponse: Error response with detailed error information
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: FILTER PARAMETER EXTRACTION
        # ------------------------------------------------------------
        # Extract filtering parameters from GET request with defaults
        month = request.GET.get('month', datetime.now().strftime('%Y-%m'))
        cycle = request.GET.get('cycle', 'all')
        search_query = request.GET.get('search', '')
        
        # ------------------------------------------------------------
        # SECTION 2: MONTH PARAMETER VALIDATION AND PARSING
        # ------------------------------------------------------------
        # Parse and validate month parameter for date-based filtering
        try:
            filter_date = datetime.strptime(month, '%Y-%m')
            year = filter_date.year
            month_num = filter_date.month
        except ValueError:
            # --------------------------------------------------------
            # SUBSECTION 2.1: DEFAULT DATE FALLBACK
            # --------------------------------------------------------
            # Apply current date values on parsing failure
            current_date = datetime.now()
            year = current_date.year
            month_num = current_date.month
        
        # ------------------------------------------------------------
        # SECTION 3: BASE QUERYSET CONSTRUCTION
        # ------------------------------------------------------------
        # Construct base queryset with essential user and date filters
        pods = AdvanceSale.objects.filter(
            dispatched_by=request.user,
            pod_uploaded=True,
            dispatched_at__year=year,
            dispatched_at__month=month_num
        )
        
        # --------------------------------------------------------
        # SECTION 4: CYCLE-BASED FILTER APPLICATION
        # --------------------------------------------------------
        # Apply cycle-based filtering to queryset
        if cycle != 'all':
            if cycle == '1-10':
                pods = pods.filter(dispatched_at__day__range=[1, 10])
            elif cycle == '11-20':
                pods = pods.filter(dispatched_at__day__range=[11, 20])
            elif cycle == '21-31':
                pods = pods.filter(dispatched_at__day__range=[21, 31])
        
        # --------------------------------------------------------
        # SECTION 5: SEARCH-BASED FILTER APPLICATION
        # --------------------------------------------------------
        # Apply text-based search filtering across multiple fields
        if search_query:
            pods = pods.filter(
                Q(unique_code__icontains=search_query) |
                Q(bmc_or_mcc__icontains=search_query) |
                Q(mpp_with_code__icontains=search_query) |
                Q(stock_item__icontains=search_query)
            )
        
        # ------------------------------------------------------------
        # SECTION 6: STATISTICAL ANALYSIS CALCULATION
        # ------------------------------------------------------------
        # Calculate comprehensive statistics for filtered dataset
        
        # --------------------------------------------------------
        # SUBSECTION 6.1: TOTAL COUNT CALCULATION
        # --------------------------------------------------------
        # Calculate total document count for selected filters
        total_count = pods.count()
        
        # --------------------------------------------------------
        # SUBSECTION 6.2: CYCLE-WISE DISTRIBUTION CALCULATION
        # --------------------------------------------------------
        # Calculate cycle-wise distribution counts from base queryset
        cycle_1_10_count = pods.filter(dispatched_at__day__range=[1, 10]).count()
        cycle_11_20_count = pods.filter(dispatched_at__day__range=[11, 20]).count()
        cycle_21_31_count = pods.filter(dispatched_at__day__range=[21, 31]).count()
        
        # ------------------------------------------------------------
        # SECTION 7: RESPONSE DATA PREPARATION
        # ------------------------------------------------------------
        # Prepare comprehensive response data structure
        
        response_data = {
            'success': True,
            'stats': {
                'total': total_count,
                'cycle_1_10': cycle_1_10_count,
                'cycle_11_20': cycle_11_20_count,
                'cycle_21_31': cycle_21_31_count
            }
        }
        
        # ------------------------------------------------------------
        # SECTION 8: SUCCESS RESPONSE DELIVERY
        # ------------------------------------------------------------
        # Return JSON response with filtering statistics
        return JsonResponse(response_data)
        
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 9: EXCEPTION HANDLING AND ERROR RESPONSE
        # ------------------------------------------------------------
        # Handle unexpected exceptions with comprehensive error response
        return JsonResponse({
            'success': False,
            'error': str(e)
        }, status=500)
        
                
# ======================================================================================================================
# INVENTORY QUANTITY ADJUSTMENT ENDPOINT
# ======================================================================================================================
# Provides inventory quantity adjustment functionality for finance department operations
# Supports consolidated quantity management across all users in a specific location

@csrf_exempt
@require_http_methods(["POST"])
@login_required(login_url="login")
def adjust_inventory_quantity(request):
    """
    Inventory Quantity Adjustment Endpoint for Finance Department
    
    Provides comprehensive inventory quantity adjustment functionality allowing the
    finance department to set total inventory quantities for specific locations and
    products. Consolidates inventory across all users in a location with proper
    audit trails and history tracking.
    
    Key Functionality:
        - Consolidated inventory quantity management by location
        - Multi-user inventory distribution with proper consolidation
        - Comprehensive audit trails with inventory history records
        - Location-based user identification and inventory allocation
    
    Adjustment Logic:
        1. Calculate total inventory quantity needed for location
        2. Distribute total quantity to first user in location
        3. Zero out inventory for other users in same location
        4. Create detailed history records for each adjustment
    
    Audit Features:
        - Individual user quantity tracking before/after adjustment
        - Finance department attribution for accountability
        - Detailed adjustment reason documentation
        - Comprehensive logging for audit compliance
    
    Security & Validation:
        - CSRF exemption for finance system integration
        - POST method restriction for data modification
        - User authentication with login requirement
        - Comprehensive input validation and error handling
    
    Returns:
        JsonResponse: Success response with adjustment statistics
        JsonResponse: Error response with appropriate status codes and messages
    """
    
    try:
        # ------------------------------------------------------------
        # SECTION 1: REQUEST DATA PARSING AND VALIDATION
        # ------------------------------------------------------------
        # Parse JSON request body and validate data structure
        data = json.loads(request.body)
        
        # --------------------------------------------------------
        # SUBSECTION 1.1: ADJUSTMENT PARAMETER EXTRACTION
        # --------------------------------------------------------
        # Extract adjustment parameters from request data
        location = data.get('location')
        product_id = data.get('product_id')
        new_total_quantity = data.get('new_quantity')  # Total quantity for entire location
        adjustment_reason = data.get('adjustment_reason', 'Finance Department Adjustment')
        
        # --------------------------------------------------------
        # SUBSECTION 1.2: REQUIRED FIELD VALIDATION
        # --------------------------------------------------------
        # Validate presence of essential adjustment parameters
        if not all([location, product_id, new_total_quantity]):
            return JsonResponse({
                'success': False,
                'error': 'Missing required fields: location, product_id, new_quantity'
            })
        
        try:
            # ------------------------------------------------------------
            # SECTION 2: LOCATION-BASED USER IDENTIFICATION
            # ------------------------------------------------------------
            # Identify all users in the specified location for inventory management
            users_in_same_location = CustomUser.objects.filter(location=location)
            
            # --------------------------------------------------------
            # SUBSECTION 2.1: LOCATION VALIDATION
            # --------------------------------------------------------
            # Validate that users exist in the specified location
            if not users_in_same_location.exists():
                return JsonResponse({
                    'success': False,
                    'error': f'No users found for location: {location}'
                })
            
            # ------------------------------------------------------------
            # SECTION 3: PRODUCT IDENTIFICATION AND VALIDATION
            # ------------------------------------------------------------
            # Retrieve and validate product for inventory adjustment
            product = Product.objects.get(id=product_id)
            
            # ------------------------------------------------------------
            # SECTION 4: INVENTORY ADJUSTMENT PROCESSING
            # ------------------------------------------------------------
            # Initialize tracking variables for adjustment statistics
            updated_count = 0
            total_previous_quantity = 0
            total_new_quantity = 0
            
            # --------------------------------------------------------
            # SUBSECTION 4.1: USER INVENTORY ITERATION
            # --------------------------------------------------------
            # Process inventory adjustment for each user in the location
            for i, user in enumerate(users_in_same_location):
                # ----------------------------------------------------
                # SUBSECTION 4.1.1: INVENTORY RECORD RETRIEVAL
                # ----------------------------------------------------
                # Get or create inventory record for user and product
                inventory, created = Inventory.objects.get_or_create(
                    mcc_bmc_user=user,
                    product=product,
                    defaults={'quantity': 0}
                )
                
                # ----------------------------------------------------
                # SUBSECTION 4.1.2: PREVIOUS QUANTITY TRACKING
                # ----------------------------------------------------
                # Track individual user's previous inventory quantity
                user_previous_quantity = inventory.quantity
                total_previous_quantity += user_previous_quantity
                
                # ----------------------------------------------------
                # SUBSECTION 4.1.3: NEW QUANTITY ALLOCATION STRATEGY
                # ----------------------------------------------------
                # Apply consolidated inventory strategy:
                # - First user receives total location quantity
                # - Other users have inventory zeroed out for consolidation
                if i == 0:
                    user_new_quantity = new_total_quantity
                else:
                    user_new_quantity = 0
                
                # ----------------------------------------------------
                # SUBSECTION 4.1.4: TOTAL QUANTITY TRACKING
                # ----------------------------------------------------
                # Track total new quantity for validation
                total_new_quantity += user_new_quantity
                
                # ----------------------------------------------------
                # SUBSECTION 4.1.5: QUANTITY CHANGE CALCULATION
                # ----------------------------------------------------
                # Calculate individual user quantity change for history tracking
                quantity_change = user_new_quantity - user_previous_quantity
                
                # ----------------------------------------------------
                # SUBSECTION 4.1.6: INVENTORY RECORD UPDATE
                # ----------------------------------------------------
                # Update inventory record with new quantity
                inventory.quantity = user_new_quantity
                inventory.save()
                
                # ----------------------------------------------------
                # SUBSECTION 4.1.7: INVENTORY HISTORY RECORD CREATION
                # ----------------------------------------------------
                # Create comprehensive history record for audit trail
                InventoryHistory.objects.create(
                    inventory=inventory,
                    action='ADJUSTMENT',
                    quantity_change=quantity_change,
                    previous_quantity=user_previous_quantity,
                    new_quantity=user_new_quantity,
                    reference_number=f'FINANCE_ADJ_{request.user.employee_code}',
                    notes=f'Finance Department Adjustment: {adjustment_reason}',
                    performed_by=request.user
                )
                
                # ----------------------------------------------------
                # SUBSECTION 4.1.8: UPDATE COUNTER INCREMENTATION
                # ----------------------------------------------------
                # Increment success counter for response statistics
                updated_count += 1
            
            # ------------------------------------------------------------
            # SECTION 5: SUCCESS RESPONSE PREPARATION
            # ------------------------------------------------------------
            # Prepare comprehensive success response with adjustment statistics
            return JsonResponse({
                'success': True,
                'message': f'Successfully updated {product.name} total quantity to {new_total_quantity} for {location}',
                'previous_quantity': total_previous_quantity,
                'new_quantity': total_new_quantity,
                'users_updated': updated_count
            })
            
        except Product.DoesNotExist:
            # ------------------------------------------------------------
            # SECTION 6: PRODUCT NOT FOUND ERROR HANDLING
            # ------------------------------------------------------------
            # Handle scenario where specified product does not exist
            return JsonResponse({
                'success': False,
                'error': 'Product not found'
            })
            
        except Exception as e:
            # ------------------------------------------------------------
            # SECTION 7: GENERAL ADJUSTMENT ERROR HANDLING
            # ------------------------------------------------------------
            # Handle unexpected errors during inventory adjustment process
            return JsonResponse({
                'success': False,
                'error': str(e)
            })
            
    except json.JSONDecodeError:
        # ------------------------------------------------------------
        # SECTION 8: JSON PARSING ERROR HANDLING
        # ------------------------------------------------------------
        # Handle invalid JSON data in request body
        return JsonResponse({
            'success': False,
            'error': 'Invalid JSON data'
        })
        
# ======================================================================================================================
# LOCATION-SPECIFIC PRODUCT INVENTORY RETRIEVAL ENDPOINT
# ======================================================================================================================
# Retrieves comprehensive product inventory data aggregated for specific locations
# Supports location-based inventory management and quantity adjustment operations

@login_required(login_url="login")
def get_location_products(request):
    """
    Location-Specific Product Inventory Retrieval Endpoint
    
    Retrieves comprehensive product inventory data aggregated for all users within
    a specified location. Supports location-based inventory management for finance
    department operations and quantity adjustment workflows.
    
    Key Functionality:
        - Location-based user identification and aggregation
        - Consolidated inventory quantity calculation across users
        - Product metadata retrieval with comprehensive details
        - Structured JSON response for frontend integration
    
    Data Aggregation:
        - Aggregates inventory quantities across all users in location
        - Calculates total quantity per product for location
        - Retrieves product metadata (name, size, unit of measure)
        - Provides organized data structure for inventory management
    
    Use Cases:
        - Finance department inventory adjustment preparation
        - Location-based inventory reporting and analysis
        - Product availability assessment by location
        - Inventory consolidation planning and execution
    
    Authentication & Validation:
        - Requires user authentication with login redirect
        - Validates location parameter presence and format
        - Verifies existence of users in specified location
        - Provides comprehensive error handling and user feedback
    
    Parameters:
        request (HttpRequest): HTTP request object with location GET parameter
    
    Returns:
        JsonResponse: Aggregated product inventory data for specified location
        JsonResponse: Error response with appropriate status codes and messages
    """
    
    # ------------------------------------------------------------
    # SECTION 1: LOCATION PARAMETER EXTRACTION AND VALIDATION
    # ------------------------------------------------------------
    # Extract location parameter from GET request
    location = request.GET.get('location')
    
    # --------------------------------------------------------
    # SUBSECTION 1.1: REQUIRED PARAMETER VALIDATION
    # --------------------------------------------------------
    # Validate presence of essential location parameter
    if not location:
        return JsonResponse({'error': 'Location parameter is required'}, status=400)
    
    try:
        # ------------------------------------------------------------
        # SECTION 2: LOCATION-BASED USER IDENTIFICATION
        # ------------------------------------------------------------
        # Identify all users associated with the specified location
        users_in_same_location = CustomUser.objects.filter(location=location)
        
        # --------------------------------------------------------
        # SUBSECTION 2.1: LOCATION EXISTENCE VALIDATION
        # --------------------------------------------------------
        # Validate that users exist in the specified location
        if not users_in_same_location.exists():
            return JsonResponse({'error': f'No users found for location: {location}'}, status=404)
        
        # ------------------------------------------------------------
        # SECTION 3: AGGREGATED INVENTORY DATA RETRIEVAL
        # ------------------------------------------------------------
        # Retrieve and aggregate inventory data across location users
        inventory_aggregated = (
            Inventory.objects.filter(mcc_bmc_user__in=users_in_same_location)
            .values(
                'product__id',
                'product__name',
                'product__size',
                'product__uom'
            )
            .annotate(total_quantity=Sum('quantity'))
            .order_by('product__name')
        )
        
        # ------------------------------------------------------------
        # SECTION 4: PRODUCT DATA PROCESSING AND COMPILATION
        # ------------------------------------------------------------
        # Initialize data structure for processed product information
        products_data = []
        
        # --------------------------------------------------------
        # SUBSECTION 4.1: AGGREGATED INVENTORY ITERATION
        # --------------------------------------------------------
        # Process aggregated inventory data into structured format
        for item in inventory_aggregated:
            # ----------------------------------------------------
            # SUBSECTION 4.1.1: PRODUCT DATA STRUCTURE COMPILATION
            # ----------------------------------------------------
            # Compile comprehensive product data structure
            product_record = {
                'id': item['product__id'],
                'name': item['product__name'],
                'current_quantity': item['total_quantity'],
                'uom': item['product__uom'] or 'units',
                'size': item['product__size'] or 'N/A'
            }
            
            # ----------------------------------------------------
            # SUBSECTION 4.1.2: DATA COLLECTION
            # ----------------------------------------------------
            # Append processed product record to data collection
            products_data.append(product_record)
        
        # ------------------------------------------------------------
        # SECTION 5: SUCCESS RESPONSE PREPARATION
        # ------------------------------------------------------------
        # Prepare comprehensive success response with location context
        return JsonResponse({
            'products': products_data,
            'location': location
        })
        
    except Exception as e:
        # ------------------------------------------------------------
        # SECTION 6: EXCEPTION HANDLING AND ERROR RESPONSE
        # ------------------------------------------------------------
        # Handle unexpected exceptions with comprehensive error response
        return JsonResponse({'error': str(e)}, status=500)
    
        


class GetMappedProductsView(View):
    """API endpoint to get mapped products data"""
    def get(self, request):
        try:
            # Get all mapped product relations with related data
            relations = ProductMappingRelation.objects.select_related(
                'group', 
                'product_mapping'
            ).order_by('group__name', 'product_mapping__system')
            
            # Prepare data for response
            data = []
            for relation in relations:
                product = relation.product_mapping
                data.append({
                    'id': relation.id,
                    'group_id': relation.group.id,
                    'group_name': relation.group.name,
                    'group_description': relation.group.description or '',
                    'group_status': 'Active' if relation.group.is_active else 'Inactive',
                    'system': product.system,
                    'system_display': product.get_system_display(),
                    'product_name': product.product_name,
                    'product_code': product.product_code or '',
                    'description': product.description or '',
                    'uom': product.uom or '',
                    'size': product.size or '',
                    'material_type': product.material_type or '',
                    'is_primary': relation.is_primary,
                    'mapping_status': 'Active' if product.is_active else 'Inactive',
                    'created_at': product.created_at.strftime('%Y-%m-%d %H:%M:%S'),
                    'updated_at': product.updated_at.strftime('%Y-%m-%d %H:%M:%S'),
                })
            
            return JsonResponse({
                'success': True,
                'data': data,
                'total_count': len(data)
            })
            
        except Exception as e:
            return JsonResponse({
                'success': False,
                'message': f'Error loading mapped products: {str(e)}'
            }, status=500)

class UpdateMappedProductsView(View):
    """API endpoint to update mapped products with proper error handling"""
    @csrf_exempt
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)
    
    def post(self, request):
        try:
            data = json.loads(request.body)
            changes = data.get('changes', [])
            
            if not changes:
                return JsonResponse({
                    'success': False,
                    'message': 'No changes provided'
                }, status=400)
            
            results = {
                'updated_count': 0,
                'failed_count': 0,
                'errors': [],
                'created_count': 0,
                'success_count': 0
            }
            
            # Process each change separately to avoid transaction issues
            for change in changes:
                try:
                    # Process each change in its own transaction
                    self.process_single_change(change, results)
                except Exception as e:
                    results['failed_count'] += 1
                    results['errors'].append(f'Error processing change: {str(e)}')
            
            return JsonResponse({
                'success': True,
                'message': 'Changes processed successfully',
                'results': results
            })
            
        except json.JSONDecodeError:
            return JsonResponse({
                'success': False,
                'message': 'Invalid JSON data'
            }, status=400)
        except Exception as e:
            return JsonResponse({
                'success': False,
                'message': f'Error processing request: {str(e)}'
            }, status=500)
    
    def process_single_change(self, change, results):
        """Process a single mapping change with its own transaction"""
        relation_id = change.get('id')
        field_changes = change.get('changes', {})
        
        if not relation_id or not field_changes:
            results['failed_count'] += 1
            results['errors'].append(f'Invalid change data for relation {relation_id}')
            return
        
        try:
            # Use atomic transaction for each individual change
            with transaction.atomic():
                # Get the relation
                try:
                    relation = ProductMappingRelation.objects.select_related(
                        'group', 'product_mapping'
                    ).get(id=relation_id)
                except ProductMappingRelation.DoesNotExist:
                    results['failed_count'] += 1
                    results['errors'].append(f'Relation with ID {relation_id} not found')
                    return
                
                # Track what was updated
                updated_fields = []
                
                # Update group fields if present
                group_updated = False
                if 'group_name' in field_changes:
                    new_group_name = field_changes['group_name'].strip()
                    if new_group_name and new_group_name != relation.group.name:
                        # Check if group name already exists (excluding current group)
                        if ProductMappingGroup.objects.filter(
                            name=new_group_name
                        ).exclude(id=relation.group.id).exists():
                            raise IntegrityError(f'Group name "{new_group_name}" already exists')
                        relation.group.name = new_group_name
                        updated_fields.append('group_name')
                        group_updated = True
                
                if 'group_description' in field_changes:
                    new_desc = field_changes['group_description']
                    if new_desc != relation.group.description:
                        relation.group.description = new_desc
                        updated_fields.append('group_description')
                        group_updated = True
                
                if 'group_status' in field_changes:
                    status_value = field_changes['group_status']
                    new_status = status_value in ['Active', 'active', 'ACTIVE', True, 'true', 'True']
                    if new_status != relation.group.is_active:
                        relation.group.is_active = new_status
                        updated_fields.append('group_status')
                        group_updated = True
                
                # Save group if updated
                if group_updated:
                    relation.group.save()
                
                # Update product mapping fields if present
                product = relation.product_mapping
                product_updated = False
                
                # Check for unique constraint violations before making changes
                if 'product_name' in field_changes:
                    new_product_name = field_changes['product_name'].strip()
                    if new_product_name and new_product_name != product.product_name:
                        # Check if product name already exists in same system (excluding current product)
                        if ProductMapping.objects.filter(
                            system=product.system,
                            product_name=new_product_name
                        ).exclude(id=product.id).exists():
                            raise IntegrityError(
                                f'Product name "{new_product_name}" already exists in {product.get_system_display()} system'
                            )
                        product.product_name = new_product_name
                        updated_fields.append('product_name')
                        product_updated = True
                
                if 'product_code' in field_changes:
                    new_code = field_changes['product_code']
                    if new_code != product.product_code:
                        product.product_code = new_code
                        updated_fields.append('product_code')
                        product_updated = True
                
                if 'description' in field_changes:
                    new_desc = field_changes['description']
                    if new_desc != product.description:
                        product.description = new_desc
                        updated_fields.append('description')
                        product_updated = True
                
                if 'uom' in field_changes:
                    new_uom = field_changes['uom']
                    if new_uom != product.uom:
                        product.uom = new_uom
                        updated_fields.append('uom')
                        product_updated = True
                
                if 'size' in field_changes:
                    new_size = field_changes['size']
                    if new_size != product.size:
                        product.size = new_size
                        updated_fields.append('size')
                        product_updated = True
                
                if 'material_type' in field_changes:
                    new_material_type = field_changes['material_type']
                    if new_material_type != product.material_type:
                        product.material_type = new_material_type
                        updated_fields.append('material_type')
                        product_updated = True
                
                if 'is_primary' in field_changes:
                    new_primary = bool(field_changes['is_primary'])
                    if new_primary != relation.is_primary:
                        relation.is_primary = new_primary
                        updated_fields.append('is_primary')
                
                if 'mapping_status' in field_changes:
                    status_value = field_changes['mapping_status']
                    new_status = status_value in ['Active', 'active', 'ACTIVE', True, 'true', 'True']
                    if new_status != product.is_active:
                        product.is_active = new_status
                        updated_fields.append('mapping_status')
                        product_updated = True
                
                # Save product and relation if updated
                if product_updated:
                    product.save()
                
                if 'is_primary' in field_changes:
                    relation.save()
                
                # Update results
                if updated_fields:
                    results['updated_count'] += 1
                    results['success_count'] += 1
                else:
                    results['failed_count'] += 1
                    results['errors'].append(f'No valid fields to update for relation {relation_id}')
                    
        except IntegrityError as e:
            # Handle database integrity errors (unique constraints)
            error_msg = str(e)
            if 'unique' in error_msg.lower() or 'duplicate' in error_msg.lower():
                results['failed_count'] += 1
                if 'system_product_name' in error_msg:
                    results['errors'].append(
                        f'Relation {relation_id}: Product name already exists in this system. Choose a different name.'
                    )
                elif 'group.name' in error_msg:
                    results['errors'].append(
                        f'Relation {relation_id}: Group name already exists. Choose a different name.'
                    )
                else:
                    results['errors'].append(f'Relation {relation_id}: {error_msg}')
            else:
                results['failed_count'] += 1
                results['errors'].append(f'Relation {relation_id}: Database error - {error_msg}')
        except Exception as e:
            results['failed_count'] += 1
            results['errors'].append(f'Relation {relation_id}: {str(e)}')

# =========== MPP EXCEL UPLOAD PROCESSOR ==============
# Comprehensive MPP data upload via Excel files with transaction code support
# Processes and validates Excel data for BMC and MPP creation/updates

# =========== MPP EXCEL UPLOAD PROCESSOR ==============
# Comprehensive MPP data upload via Excel files with transaction code support
# Processes and validates Excel data for BMC and MPP creation/updates
# IMPLEMENTATION: This uses REPLACE ALL logic - only Excel records remain in DB


logger = logging.getLogger(__name__)

class MPPExcelUploadView(View):
    """
    MPP Excel File Upload and Processing View with REPLACE ALL logic
    
    Handles Excel file uploads containing MPP data with optional transaction codes.
    Uses REPLACE ALL strategy: Only records from Excel remain in database after upload.
    
    Key Features:
    1. Excel file validation (type, size, structure)
    2. Data cleaning and normalization
    3. REPLACE ALL logic: Delete existing records, create Excel records only
    4. Transaction code-based deduplication
    5. Status normalization (ACTIVE/DEACTIVE)
    6. Comprehensive error handling and reporting
    7. Audit trail of changes
    
    Processing Logic:
        - First deletes ALL existing MPP records
        - Then creates ONLY records from Excel file
        - Result: Database matches Excel exactly
    """
    
    @method_decorator(csrf_exempt)
    @method_decorator(login_required)
    def dispatch(self, *args, **kwargs):
        return super().dispatch(*args, **kwargs)

    def post(self, request):
        """
        Handle Excel File Upload via POST Request with REPLACE ALL logic
        
        Args:
            request (HttpRequest): HTTP request containing Excel file
            
        Returns:
            JsonResponse: Processing results with success/failure status
        """
        try:
            # ------------------------------------------------------------
            # SECTION 1: FILE PRESENCE VALIDATION
            # ------------------------------------------------------------
            if 'file' not in request.FILES:
                return JsonResponse({
                    'success': False,
                    'message': 'No file uploaded'
                }, status=400)

            excel_file = request.FILES['file']
            
            # ------------------------------------------------------------
            # SECTION 2: FILE TYPE VALIDATION
            # ------------------------------------------------------------
            if not excel_file.name.endswith(('.xlsx', '.xls')):
                return JsonResponse({
                    'success': False,
                    'message': 'Invalid file type. Please upload Excel file (.xlsx, .xls)'
                }, status=400)

            # ------------------------------------------------------------
            # SECTION 3: FILE SIZE VALIDATION
            # ------------------------------------------------------------
            if excel_file.size > 10 * 1024 * 1024:
                return JsonResponse({
                    'success': False,
                    'message': 'File size exceeds 10MB limit'
                }, status=400)

            # ------------------------------------------------------------
            # SECTION 4: PROCESS EXCEL FILE WITH REPLACE ALL LOGIC
            # ------------------------------------------------------------
            result = self.process_excel_file_replace_all(excel_file)
            return JsonResponse(result)

        except Exception as e:
            # ------------------------------------------------------------
            # SECTION 5: ERROR HANDLING AND LOGGING
            # ------------------------------------------------------------
            logger.error(f"Error processing Excel upload: {str(e)}")
            return JsonResponse({
                'success': False,
                'message': f'Error processing file: {str(e)}'
            }, status=500)

    def process_excel_file_replace_all(self, excel_file):
        """
        Excel File Processing with REPLACE ALL logic
        
        Orchestrates the complete Excel processing workflow:
            1. Read Excel file into DataFrame
            2. Validate required columns
            3. Clean and normalize data
            4. DELETE ALL existing MPP records
            5. Create ONLY Excel records in database
            6. Generate processing statistics
        
        Args:
            excel_file (UploadedFile): Excel file from request.FILES
            
        Returns:
            dict: Processing results with statistics and status
        """
        try:
            # ------------------------------------------------------------
            # SECTION 1: READ EXCEL FILE
            # ------------------------------------------------------------
            df = pd.read_excel(excel_file)
            
            # ------------------------------------------------------------
            # SECTION 2: CHECK FOR TRANSACTION CODE COLUMN
            # ------------------------------------------------------------
            has_transaction_code = 'mpp_transaction_code' in df.columns
            
            # ------------------------------------------------------------
            # SECTION 3: VALIDATE REQUIRED COLUMNS
            # ------------------------------------------------------------
            required_columns = ['bmc_name', 'mpp_name']
            if has_transaction_code:
                required_columns.append('mpp_transaction_code')
                
            missing_columns = [col for col in required_columns if col not in df.columns]
            
            if missing_columns:
                return {
                    'success': False,
                    'message': f'Missing required columns: {", ".join(missing_columns)}'
                }

            # ------------------------------------------------------------
            # SECTION 4: CLEAN AND NORMALIZE DATA
            # ------------------------------------------------------------
            df_clean = self.clean_dataframe(df, has_transaction_code)
            
            if df_clean.empty:
                return {
                    'success': False,
                    'message': 'No valid data found in the Excel file'
                }

            # ------------------------------------------------------------
            # SECTION 5: PROCESS WITH REPLACE ALL LOGIC
            # ------------------------------------------------------------
            stats = self.process_data_replace_all(df_clean, has_transaction_code)
            
            return {
                'success': True,
                'message': 'MPP data replaced successfully - Database now matches Excel file',
                'stats': stats
            }

        except Exception as e:
            logger.error(f"Error processing Excel file: {str(e)}")
            raise

    def clean_dataframe(self, df, has_transaction_code):
        """
        DataFrame Cleaning and Normalization
        
        Args:
            df (DataFrame): Raw Excel data
            has_transaction_code (bool): Whether transaction code column exists
            
        Returns:
            DataFrame: Cleaned and normalized data
        """
        df_clean = df.copy()
        
        # ------------------------------------------------------------
        # SECTION 1: STRING COLUMN CLEANING
        # ------------------------------------------------------------
        string_columns = ['bmc_name', 'mpp_name', 'mob_no', 'status']
        if has_transaction_code:
            string_columns.append('mpp_transaction_code')
            
        for col in string_columns:
            if col in df_clean.columns:
                df_clean[col] = df_clean[col].astype(str).str.strip()
        
        # ------------------------------------------------------------
        # SECTION 2: MISSING DATA FILTERING
        # ------------------------------------------------------------
        required_fields = ['bmc_name', 'mpp_name']
        if has_transaction_code:
            required_fields.append('mpp_transaction_code')
            
        # Remove rows with NaN in required fields
        df_clean = df_clean.dropna(subset=required_fields)
        
        # Filter out empty strings and 'nan' values
        mask = (
            (df_clean['bmc_name'].str.len() > 0) & 
            (df_clean['bmc_name'] != 'nan') &
            (df_clean['mpp_name'].str.len() > 0) & 
            (df_clean['mpp_name'] != 'nan')
        )
        
        if has_transaction_code:
            mask = mask & (
                (df_clean['mpp_transaction_code'].str.len() > 0) & 
                (df_clean['mpp_transaction_code'] != 'nan')
            )
            
        df_clean = df_clean[mask]
        
        # ------------------------------------------------------------
        # SECTION 3: MOBILE NUMBER CLEANING
        # ------------------------------------------------------------
        if 'mob_no' in df_clean.columns:
            def clean_mobile_number(x):
                try:
                    if pd.isna(x) or str(x).strip().lower() in ['nan', 'none', 'null', '']:
                        return None
                    cleaned = re.sub(r'\D', '', str(x))
                    return cleaned if cleaned else None
                except:
                    return None
            
            df_clean['mob_no'] = df_clean['mob_no'].apply(clean_mobile_number)
        
        # ------------------------------------------------------------
        # SECTION 4: STATUS VALUE NORMALIZATION
        # ------------------------------------------------------------
        if 'status' in df_clean.columns:
            def normalize_status(status_value):
                if pd.isna(status_value) or str(status_value).strip().lower() in ['nan', 'none', 'null', '']:
                    return 'ACTIVE'  # Default to ACTIVE if not specified
                
                status_str = str(status_value).strip()
                
                # Direct mapping for common formats
                if status_str == 'Active':
                    return 'ACTIVE'
                elif status_str == 'DeActive':
                    return 'DEACTIVE'
                
                # Case-insensitive mapping for various representations
                status_lower = status_str.lower()
                if status_lower in ['active', 'activated', 'actived', 'enabled', 'enable', 'yes', 'true', '1', 'on']:
                    return 'ACTIVE'
                elif status_lower in ['deactive', 'deactivated', 'inactive', 'disabled', 'disable', 'no', 'false', '0', 'off']:
                    return 'DEACTIVE'
                
                return 'ACTIVE'  # Default to ACTIVE
            
            df_clean['status'] = df_clean['status'].apply(normalize_status)
        else:
            # Add default status column if not present
            df_clean['status'] = 'ACTIVE'

        return df_clean

    def process_data_replace_all(self, df, has_transaction_code):
        """
        Database Processing with REPLACE ALL logic
        
        Processing Strategy:
            1. Collect ALL records to be created from Excel
            2. DELETE ALL existing MPP records
            3. Create BMC records if needed
            4. Create ALL MPP records from Excel
            5. Database now contains ONLY Excel records
        
        Args:
            df (DataFrame): Cleaned MPP data
            has_transaction_code (bool): Transaction code availability
            
        Returns:
            dict: Comprehensive processing statistics and results
        """
        stats = {
            'total_records_in_excel': len(df),
            'bmc_created': 0,
            'mpp_created': 0,
            'mpp_deleted': 0,
            'errors': [],
            'status_counts_before': {},
            'status_counts_after': {},
            'processed_mpps': [],
            'failed_mpps': [],
            'duplicate_transaction_codes_in_excel': [],
            'has_transaction_code': has_transaction_code,
            'operation': 'REPLACE_ALL',
            'timestamp': datetime.now().isoformat()
        }

        try:
            with transaction.atomic():
                # ------------------------------------------------------------
                # SECTION 1: PRE-PROCESSING STATUS AUDIT
                # ------------------------------------------------------------
                stats['status_counts_before'] = {
                    'ACTIVE': MPPWithCode.objects.filter(status='ACTIVE').count(),
                    'DEACTIVE': MPPWithCode.objects.filter(status='DEACTIVE').count(),
                    'TOTAL': MPPWithCode.objects.count()
                }
                
                # ------------------------------------------------------------
                # SECTION 2: COLLECT ALL EXCEL RECORDS FIRST
                # ------------------------------------------------------------
                excel_records_to_create = []
                bmc_mapping = {}
                transaction_code_tracker = set()
                
                # Track BMCs from Excel
                unique_bmcs = df['bmc_name'].unique()
                
                # ------------------------------------------------------------
                # SECTION 3: PROCESS EXCEL DATA FOR CREATION
                # ------------------------------------------------------------
                for index, row in df.iterrows():
                    try:
                        bmc_name = row['bmc_name']
                        mpp_name = row['mpp_name']
                        
                        # Validate required fields
                        if not bmc_name or bmc_name == 'nan' or not mpp_name or mpp_name == 'nan':
                            error_msg = f"Row {index + 2}: Missing BMC name or MPP name"
                            stats['errors'].append(error_msg)
                            stats['failed_mpps'].append(f"Row {index+2}: {bmc_name} - {mpp_name}")
                            continue
                        
                        # Create/get BMC
                        if bmc_name not in bmc_mapping:
                            if bmc_name and bmc_name != 'nan':
                                bmc_mcc, created = BMCOrMCC.objects.get_or_create(name=bmc_name)
                                bmc_mapping[bmc_name] = bmc_mcc
                                if created:
                                    stats['bmc_created'] += 1
                        
                        bmc_mcc = bmc_mapping[bmc_name]
                        
                        # --------------------------------------------------------
                        # SUBSECTION: TRANSACTION CODE VALIDATION
                        # --------------------------------------------------------
                        transaction_code = None
                        if has_transaction_code:
                            transaction_code = row.get('mpp_transaction_code')
                            if not transaction_code or transaction_code == 'nan':
                                error_msg = f"Row {index + 2}: Missing MPP Transaction Code"
                                stats['errors'].append(error_msg)
                                stats['failed_mpps'].append(f"Row {index+2}: {bmc_name} - {mpp_name}")
                                continue
                            
                            # Check for duplicates within Excel
                            if transaction_code in transaction_code_tracker:
                                stats['duplicate_transaction_codes_in_excel'].append(f"Row {index+2}: {transaction_code}")
                                continue
                            
                            transaction_code_tracker.add(transaction_code)
                        
                        # --------------------------------------------------------
                        # SUBSECTION: PREPARE MPP DATA
                        # --------------------------------------------------------
                        mpp_data = {
                            'bmc_or_mcc': bmc_mcc,
                            'name_with_code': mpp_name,
                            'status': row.get('status', 'ACTIVE')
                        }
                        
                        # Mobile number
                        mob_no = row.get('mob_no')
                        if mob_no and str(mob_no) != 'nan' and str(mob_no).strip():
                            mpp_data['sahayak_mobile_number'] = str(mob_no)[:15]
                        
                        # Transaction code
                        if has_transaction_code and transaction_code:
                            mpp_data['mpp_transaction_code'] = transaction_code
                        
                        # Add to creation list
                        excel_records_to_create.append(mpp_data)
                        stats['processed_mpps'].append(f"{bmc_name} - {mpp_name}")
                            
                    except Exception as e:
                        error_msg = f"Row {index + 2}: {str(e)}"
                        stats['errors'].append(error_msg)
                        stats['failed_mpps'].append(f"Row {index+2}: {row.get('bmc_name', 'N/A')} - {row.get('mpp_name', 'N/A')}")
                        logger.error(f"Error processing row {index + 2}: {str(e)}")
                        continue
                
                # ------------------------------------------------------------
                # SECTION 4: REPLACE ALL OPERATION
                # ------------------------------------------------------------
                # Count how many MPPs will be deleted
                stats['mpp_deleted'] = MPPWithCode.objects.count()
                
                # Delete ALL existing MPP records
                deleted_count, _ = MPPWithCode.objects.all().delete()
                stats['mpp_deleted'] = deleted_count if deleted_count else 0
                
                # ------------------------------------------------------------
                # SECTION 5: CREATE NEW RECORDS FROM EXCEL
                # ------------------------------------------------------------
                mpp_objects = []
                for mpp_data in excel_records_to_create:
                    try:
                        # Create MPP record
                        mpp = MPPWithCode(**mpp_data)
                        mpp_objects.append(mpp)
                        stats['mpp_created'] += 1
                    except Exception as e:
                        error_msg = f"Error creating MPP record: {str(e)}"
                        stats['errors'].append(error_msg)
                        logger.error(f"Error creating MPP: {str(e)}")
                
                # Bulk create all MPP records
                if mpp_objects:
                    MPPWithCode.objects.bulk_create(mpp_objects)
                
                # ------------------------------------------------------------
                # SECTION 6: POST-PROCESSING STATUS AUDIT
                # ------------------------------------------------------------
                stats['status_counts_after'] = {
                    'ACTIVE': MPPWithCode.objects.filter(status='ACTIVE').count(),
                    'DEACTIVE': MPPWithCode.objects.filter(status='DEACTIVE').count(),
                    'TOTAL': MPPWithCode.objects.count()
                }
                
                return stats

        except Exception as e:
            logger.error(f"Transaction failed: {str(e)}")
            raise
    
    # Keep the original process_data method for backward compatibility
    def process_data(self, df, has_transaction_code):
        """
        Original database processing (for backward compatibility)
        Use process_data_replace_all for the new REPLACE ALL logic
        """
        return self.process_data_replace_all(df, has_transaction_code)


