    def _get_all_existing_vendor_mappings(self):
        """
        Retrieve All Existing Vendor-Product Mappings
        
        Queries database for all vendor-product associations.
        Joins Product, Vendor, and ProductVendor tables for complete data.
        
        Data Aggregation:
            - Product details with codes and names
            - Vendor information with contact details
            - Association metadata and timestamps
            - Priority and primary status (if implemented)
        
        Returns:
            list: Dictionary objects containing complete mapping data
        """
        existing_mappings = []
        
        # Get all vendor-product associations
        # Note: Currently ProductVendor only tracks basic association
        # You may need to extend the model for priority and primary fields
        
        associations = ProductVendor.objects.select_related(
            'product', 'vendor'
        ).order_by('product__name', 'vendor__name')
        
        for association in associations:
            mapping_data = {
                'product_code': association.product.product_code,
                'product_name': association.product.name,
                'vendor_name': association.vendor.name,
                'vendor_email': association.vendor.email or '',
                'priority': '',  # Add if you implement priority field
                'is_primary': '',  # Add if you implement primary field
                'uom': association.product.uom or '',
                'added_at': association.added_at
            }
            existing_mappings.append(mapping_data)
        
        return existing_mappings
    
