@login_required
@user_passes_test(lambda u: u.is_finance)
def delete_cycle(request, cycle_id):
    """
    Cycle Deletion with Reordering
    
    Deletes a specific cycle and reorders remaining cycles
    within the same monthly cycle to maintain sequential numbering.
    
    Args:
        cycle_id: ID of cycle to delete
    
    Returns:
        JsonResponse: Deletion results with success/error status
    """
    
    if request.method == 'POST':
        try:
            cycle = Cycle.objects.get(id=cycle_id)
            monthly_cycle_id = cycle.monthly_cycle.id
            
            cycle.delete()
            
            # Reorder remaining cycles
            reorder_cycles(monthly_cycle_id)
            
            return JsonResponse({'success': True, 'message': 'Cycle deleted successfully'})
            
        except Cycle.DoesNotExist:
            return JsonResponse({'success': False, 'error': 'Cycle not found'})
        except Exception:
            return JsonResponse({'success': False, 'error': 'Error deleting cycle'})
    
    return JsonResponse({'success': False, 'error': 'Invalid request method'})

def reorder_cycles(monthly_cycle_id):
    """
    Cycle Number Reordering Utility
    
    Reassigns sequential cycle numbers after deletion operations
    to maintain proper ordering within a monthly cycle.
    
    Args:
        monthly_cycle_id: ID of monthly cycle to reorder
    """
    
    cycles = Cycle.objects.filter(monthly_cycle_id=monthly_cycle_id).order_by('start_date')
    
    for index, cycle in enumerate(cycles, 1):
        cycle.cycle_number = index
        cycle.save()

