@login_required
def get_available_cycles(request):
    """
    Returns cycles for the latest 4 MonthlyCycle records
    based on database order (NOT calendar date).
    """

    print("\n========== get_available_cycles CALLED ==========")

    # Month order mapping (for correct sorting)
    month_order = {
        'January': 1, 'February': 2, 'March': 3, 'April': 4,
        'May': 5, 'June': 6, 'July': 7, 'August': 8,
        'September': 9, 'October': 10, 'November': 11, 'December': 12
    }

    # 1️⃣ Fetch latest 4 MonthlyCycle records (DB truth)
    latest_monthly_cycles = (
        MonthlyCycle.objects
        .all()
        .order_by('-year', '-id')[:4]
    )

    print(f"[INFO] MonthlyCycle fetched: {latest_monthly_cycles.count()}")

    for mc in latest_monthly_cycles:
        print(f"   -> {mc.month} {mc.year} (ID: {mc.id})")

    # 2️⃣ Sort them chronologically (old → new) for UI
    latest_monthly_cycles = sorted(
        latest_monthly_cycles,
        key=lambda mc: (mc.year, month_order.get(mc.month, 0))
    )

    print("\n[RESULT] Final 4 months (chronological order):")
    for mc in latest_monthly_cycles:
        print(f"   - {mc.month} {mc.year}")

    cycles_data = []

    # 3️⃣ Attach cycles
    print("\n[STEP] Attaching cycles")

    for monthly_cycle in latest_monthly_cycles:
        cycles = (
            Cycle.objects
            .filter(monthly_cycle=monthly_cycle)
            .order_by('cycle_number')
        )

        print(
            f"\n[MONTH] {monthly_cycle.month} {monthly_cycle.year} "
            f"(Cycles: {cycles.count()})"
        )

        for cycle in cycles:
            print(
                f"   - Cycle ID: {cycle.id}, "
                f"Name: {cycle.name}, "
                f"Active: {cycle.is_active}"
            )

            cycles_data.append({
                'id': cycle.id,
                'name': f"{monthly_cycle.month} {monthly_cycle.year} - {cycle.name}",
                'date_range': f"({cycle.date_range_display})",
                'monthly_cycle_id': monthly_cycle.id,
                'monthly_cycle_name': monthly_cycle.name,
                'month': monthly_cycle.month,
                'year': monthly_cycle.year,
                'cycle_name': cycle.name,
                'sap_number': cycle.sap_number,
                'start_date': cycle.start_date.strftime('%Y-%m-%d'),
                'end_date': cycle.end_date.strftime('%Y-%m-%d'),
                'cycle_number': cycle.cycle_number,
                'is_active': cycle.is_active,
                'has_cycles': True
            })

    print("\n[FINAL] Total cycles returned:", len(cycles_data))
    print("========== END get_available_cycles ==========\n")

    return JsonResponse({
        'success': True,
        'cycles': cycles_data
    })


@login_required(login_url='login')
@user_passes_test(lambda u: u.is_finance)
def delete_monthly_cycle(request, monthly_cycle_id):
    """
    Monthly Cycle Complete Deletion
    
    Deletes an entire monthly cycle including all associated sub-cycles.
    Performs atomic transaction for data integrity.
    
    Args:
        monthly_cycle_id: ID of monthly cycle to delete
    
    Returns:
        JsonResponse: Deletion results with success/error status
    """
    
    if request.method == 'POST':
        try:
            with transaction.atomic():
                monthly_cycle = MonthlyCycle.objects.get(id=monthly_cycle_id)
                month_name = f"{monthly_cycle.month} {monthly_cycle.year}"
                
                # Delete all associated cycles first
                monthly_cycle.cycles.all().delete()
                
                # Delete the monthly cycle
                monthly_cycle.delete()
                
                return JsonResponse({
                    'success': True, 
                    'message': f'Monthly cycle "{month_name}" deleted successfully'
                })
                
        except MonthlyCycle.DoesNotExist:
            return JsonResponse({'success': False, 'error': 'Monthly cycle not found'})
        except Exception:
            return JsonResponse({'success': False, 'error': 'Error deleting monthly cycle'})
    
    return JsonResponse({'success': False, 'error': 'Invalid request method'})

@login_required(login_url='login')
@user_passes_test(lambda u: u.is_finance)
def get_next_sap_numbers(request):
    """
    Next SAP Number Calculation
    
    Calculates and returns the next available SAP numbers for new cycles
    based on existing SAP number assignments in the system.
    
    Returns:
        JsonResponse: Next three available SAP numbers
    """
    
    try:
        # Find last used SAP number
        last_sap_cycle = Cycle.objects.filter(sap_number__isnull=False).order_by('-sap_number').first()
        
        if last_sap_cycle and last_sap_cycle.sap_number.isdigit():
            last_sap_number = int(last_sap_cycle.sap_number)
        else:
            # Check for baseline from January Cycle 3
            jan_cycle3 = Cycle.objects.filter(
                monthly_cycle__month='January',
                cycle_number=3,
                sap_number__isnull=False
            ).order_by('-sap_number').first()
            
            if jan_cycle3 and jan_cycle3.sap_number.isdigit():
                last_sap_number = int(jan_cycle3.sap_number)
            else:
                # Default starting point
                last_sap_number = 10
        
        # Calculate next three sequential SAP numbers
        next_sap_numbers = {
            'cycle1': last_sap_number + 1,
            'cycle2': last_sap_number + 2,
            'cycle3': last_sap_number + 3
        }
        
        return JsonResponse({
            'success': True,
            'next_sap_numbers': next_sap_numbers,
            'last_sap_number': last_sap_number
        })
        
    except Exception:
        return JsonResponse({'success': False, 'error': 'Error calculating SAP numbers'})

@login_required(login_url='login')
@user_passes_test(lambda u: u.is_finance)
def update_cycle_sap_number(request):
    """
    Cycle SAP Number Update
    
    Updates the SAP number for a specific cycle with uniqueness validation
    to prevent duplicate SAP number assignments.
    
    Returns:
        JsonResponse: Update results with success/error status
    """
    
    if request.method == 'POST':
        try:
            cycle_id = request.POST.get('cycle_id')
            sap_number = request.POST.get('sap_number', '').strip()
            
            cycle = Cycle.objects.get(id=cycle_id)
            
            # Validate SAP number uniqueness
            if sap_number and Cycle.objects.filter(sap_number=sap_number).exclude(id=cycle_id).exists():
                return JsonResponse({
                    'success': False, 
                    'error': f'SAP number {sap_number} is already in use'
                })
            
            # Update SAP number
            cycle.sap_number = sap_number if sap_number else None
            cycle.save()
            
            return JsonResponse({
                'success': True,
                'message': f'SAP number updated to {sap_number}' if sap_number else 'SAP number cleared',
                'sap_number': sap_number
            })
            
        except Cycle.DoesNotExist:
            return JsonResponse({'success': False, 'error': 'Cycle not found'})
        except Exception:
            return JsonResponse({'success': False, 'error': 'Error updating SAP number'})
    
    return JsonResponse({'success': False, 'error': 'Invalid request method'})

