@login_required(login_url='login')
def toggle_cycle_status(request, cycle_id):
    """
    Cycle Activation/Deactivation Toggle
    
    Toggles the active status of a cycle with exclusive activation
    enforcement (only one cycle can be active at a time).
    
    Args:
        cycle_id: ID of cycle to toggle
    
    Returns:
        JsonResponse: Status toggle results
    """
    
    if request.method == 'POST':
        try:
            cycle = Cycle.objects.get(id=cycle_id)
            
            # Activating a cycle: deactivate all others first
            if not cycle.is_active:
                Cycle.objects.exclude(id=cycle_id).update(is_active=False)
                cycle.is_active = True
                action = 'activated'
            else:
                # Deactivating only this cycle
                cycle.is_active = False
                action = 'deactivated'
            
            cycle.save()
            
            return JsonResponse({
                'success': True,
                'message': f'Cycle {action} successfully!',
                'is_active': cycle.is_active
            })
            
        except Cycle.DoesNotExist:
            return JsonResponse({'success': False, 'error': 'Cycle not found'})
        except Exception:
            return JsonResponse({'success': False, 'error': 'Error toggling cycle status'})
    
    return JsonResponse({'success': False, 'error': 'Invalid request method'})

@login_required(login_url='login')
def update_cycle(request, cycle_id):
    """
    Comprehensive Cycle Update
    
    Updates multiple attributes of a cycle including dates, name,
    SAP number, description, and active status.
    
    Args:
        cycle_id: ID of cycle to update
    
    Returns:
        JsonResponse: Update results with success/error status
    """
    
    if request.method == 'POST':
        try:
            cycle = Cycle.objects.get(id=cycle_id)
            
            # Parse dates from DD-MM-YYYY format
            if 'start_date' in request.POST:
                start_date_str = request.POST.get('start_date')
                day, month, year = map(int, start_date_str.split('-'))
                cycle.start_date = date(year, month, day)
            
            if 'end_date' in request.POST:
                end_date_str = request.POST.get('end_date')
                day, month, year = map(int, end_date_str.split('-'))
                cycle.end_date = date(year, month, day)
            
            # Update other fields
            if 'name' in request.POST:
                cycle.name = request.POST.get('name')
            
            if 'sap_number' in request.POST:
                cycle.sap_number = request.POST.get('sap_number')
            
            if 'description' in request.POST:
                cycle.description = request.POST.get('description')
            
            if 'is_active' in request.POST:
                cycle.is_active = request.POST.get('is_active') == 'true'
            
            cycle.full_clean()
            cycle.save()
            
            return JsonResponse({
                'success': True,
                'message': 'Cycle updated successfully'
            })
            
        except Cycle.DoesNotExist:
            return JsonResponse({'success': False, 'error': 'Cycle not found'})
        except ValidationError as e:
            return JsonResponse({'success': False, 'error': str(e)})
        except Exception:
            return JsonResponse({'success': False, 'error': 'Error updating cycle'})
    
    return JsonResponse({'success': False, 'error': 'Invalid request method'})

