@login_required(login_url='login')
@user_passes_test(lambda u: u.is_finance)
def save_new_cycle(request):
    """
    New Cycle Creation with Exclusive Activation
    
    Creates a new custom cycle with proper SAP number assignment
    and handles the "only one active cycle" enforcement rule.
    
    Returns:
        JsonResponse: Creation results with success/error status
    """
    
    if request.method == 'POST':
        try:
            # Extract form parameters
            monthly_cycle_id = request.POST.get('monthly_cycle_id')
            name = request.POST.get('name')
            sap_number = request.POST.get('sap_number', '')
            start_date_str = request.POST.get('start_date')
            end_date_str = request.POST.get('end_date')
            description = request.POST.get('description', '')
            is_active = request.POST.get('is_active') == 'true'
            
            monthly_cycle = MonthlyCycle.objects.get(id=monthly_cycle_id)
            
            # Calculate next cycle number
            last_cycle = monthly_cycle.cycles.order_by('-cycle_number').first()
            next_cycle_number = last_cycle.cycle_number + 1 if last_cycle else 1
            
            # Parse dates from DD-MM-YYYY format
            start_day, start_month, start_year = map(int, start_date_str.split('-'))
            end_day, end_month, end_year = map(int, end_date_str.split('-'))
            
            # Create new cycle (initially inactive)
            cycle = Cycle(
                monthly_cycle=monthly_cycle,
                name=name,
                sap_number=sap_number,
                cycle_number=next_cycle_number,
                start_date=date(start_year, start_month, start_day),
                end_date=date(end_year, end_month, end_day),
                description=description,
                is_active=False  # Created as inactive initially
            )
            
            cycle.full_clean()
            cycle.save()
            
            # Handle activation with exclusive rule
            if is_active:
                Cycle.objects.exclude(id=cycle.id).update(is_active=False)
                cycle.is_active = True
                cycle.save()
            
            return JsonResponse({
                'success': True, 
                'message': 'Cycle created successfully',
                'cycle_id': cycle.id
            })
            
        except MonthlyCycle.DoesNotExist:
            return JsonResponse({'success': False, 'error': 'Monthly cycle not found'})
        except ValidationError as e:
            return JsonResponse({'success': False, 'error': str(e)})
        except Exception:
            return JsonResponse({'success': False, 'error': 'Error creating cycle'})
    
    return JsonResponse({'success': False, 'error': 'Invalid request method'})


# ======================================================================================================================
# WHATSAPP REGISTRATION VALIDATION AND REPORTING (UPDATED WITH API INTEGRATION)
# ======================================================================================================================


@login_required(login_url='login')
def check_whatsapp_registration(request):
    """
    Check WhatsApp registration status for all MPP mobile numbers
    Uses WhatsApp Business API to verify if numbers are registered on WhatsApp
    """
    try:
        # Get configuration to check if API is available
        whatsapp_config = getattr(settings, 'WHATSAPP_BUSINESS_API', {})
        access_token = whatsapp_config.get('ACCESS_TOKEN')
        phone_number_id = whatsapp_config.get('PHONE_NUMBER_ID')
        
        api_available = bool(access_token and phone_number_id)
        
        # Get all active MPPs with mobile numbers
        mpps = MPPWithCode.objects.filter(
            status='ACTIVE',
            sahayak_mobile_number__isnull=False
        ).exclude(
            sahayak_mobile_number=''
        ).select_related('bmc_or_mcc')
        
        results = []
        stats = {
            'total': 0,
            'whatsapp_registered': 0,
            'whatsapp_not_registered': 0,
            'invalid_number': 0,
            'check_failed': 0,
            'never_messaged': 0,
            'message_failed': 0,
            'api_checked': 0,
            'api_registered': 0,
            'api_not_registered': 0,
            'api_failed': 0,
            'api_token_expired': 0
        }
        
        # Get WhatsApp message history for each MPP
        whatsapp_logs = WhatsAppLog.objects.values('mobile_number', 'status').annotate(
            last_message=models.Max('created_at'),
            total_messages=models.Count('id'),
            failed_messages=models.Count('id', filter=models.Q(status='FAILED')),
            success_messages=models.Count('id', filter=models.Q(status='SENT'))
        )
        
        # Create a dictionary of WhatsApp message history
        whatsapp_history = {}
        for log in whatsapp_logs:
            mobile = log['mobile_number']
            if mobile not in whatsapp_history:
                whatsapp_history[mobile] = {
                    'last_message': log['last_message'],
                    'total_messages': log['total_messages'],
                    'failed_messages': log['failed_messages'],
                    'success_messages': log['success_messages']
                }
        
        # Also check MessageQueue for WhatsApp messages
        whatsapp_queue = MessageQueue.objects.filter(
            message_type='WHATSAPP'
        ).values('mobile_number').annotate(
            queue_failed=models.Count('id', filter=models.Q(status='FAILED')),
            queue_sent=models.Count('id', filter=models.Q(status='SENT'))
        )
        
        for queue in whatsapp_queue:
            mobile = queue['mobile_number']
            if mobile in whatsapp_history:
                whatsapp_history[mobile]['queue_failed'] = queue['queue_failed']
                whatsapp_history[mobile]['queue_sent'] = queue['queue_sent']
            else:
                whatsapp_history[mobile] = {
                    'queue_failed': queue['queue_failed'],
                    'queue_sent': queue['queue_sent'],
                    'total_messages': 0,
                    'failed_messages': 0,
                    'success_messages': 0
                }
        
        # Track API calls - INCREASED LIMIT to cover all MPPs
        api_call_count = 0
        max_api_calls = mpps.count()  # Set limit to total MPP count (1683)
        api_delay = 0.5  # Reduced delay to speed up processing
        
        for mpp in mpps:
            stats['total'] += 1
            
            mobile = mpp.sahayak_mobile_number.strip()
            
            # Initialize result
            result = {
                'mpp_id': mpp.id,
                'mpp_name': mpp.name_with_code,
                'mpp_transaction_code': mpp.mpp_transaction_code,
                'bmc_mcc': mpp.bmc_or_mcc.name if mpp.bmc_or_mcc else 'N/A',
                'mobile_number': mobile,
                'whatsapp_status': 'UNKNOWN',
                'verification_method': 'Historical Data',
                'last_message_date': None,
                'total_messages': 0,
                'failed_messages': 0,
                'success_messages': 0,
                'failure_rate': 0,
                'issues': [],
                'recommendations': [],
                'api_result': None
            }
            
            # Check 1: Basic number validation
            if not re.match(r'^[6-9]\d{9}$', mobile):
                result['whatsapp_status'] = 'INVALID_NUMBER'
                result['issues'].append('Invalid Indian mobile number format')
                result['recommendations'].append('Should start with 6-9 and be 10 digits')
                stats['invalid_number'] += 1
                results.append(result)
                continue
            
            # Check 2: Historical WhatsApp message data
            message_history = whatsapp_history.get(mobile, {})
            
            historical_status_determined = False
            
            if message_history:
                result['total_messages'] = message_history.get('total_messages', 0) + \
                                          message_history.get('queue_failed', 0) + \
                                          message_history.get('queue_sent', 0)
                result['failed_messages'] = message_history.get('failed_messages', 0) + \
                                           message_history.get('queue_failed', 0)
                result['success_messages'] = message_history.get('success_messages', 0) + \
                                            message_history.get('queue_sent', 0)
                result['last_message_date'] = message_history.get('last_message')
                
                if result['total_messages'] > 0:
                    result['failure_rate'] = (result['failed_messages'] / result['total_messages']) * 100
                    
                    # Determine status based on historical data
                    if result['success_messages'] > 0:
                        result['whatsapp_status'] = 'WHATSAPP_REGISTERED'
                        result['verification_method'] = 'Message Delivery Success'
                        stats['whatsapp_registered'] += 1
                        historical_status_determined = True
                    elif result['failed_messages'] > 0 and result['success_messages'] == 0:
                        result['whatsapp_status'] = 'WHATSAPP_NOT_REGISTERED'
                        result['verification_method'] = 'Message Delivery Failure'
                        result['issues'].append('All WhatsApp messages failed')
                        result['recommendations'].append('Check if number is registered on WhatsApp')
                        stats['whatsapp_not_registered'] += 1
                        historical_status_determined = True
                    else:
                        result['whatsapp_status'] = 'NEEDS_VERIFICATION'
                        stats['check_failed'] += 1
                else:
                    result['whatsapp_status'] = 'NEVER_MESSAGED'
                    result['issues'].append('No WhatsApp messages sent to this number')
                    result['recommendations'].append('Send test WhatsApp message')
                    stats['never_messaged'] += 1
            else:
                result['whatsapp_status'] = 'NEVER_MESSAGED'
                result['issues'].append('No message history found')
                result['recommendations'].append('Send test WhatsApp message')
                stats['never_messaged'] += 1
            
            # Check 3: Real-time WhatsApp API verification
            # Only use API if we need verification OR if historical data is inconclusive
            use_api = False
            
            if api_available and api_call_count < max_api_calls:
                if (not historical_status_determined or 
                    result['whatsapp_status'] in ['NEEDS_VERIFICATION', 'NEVER_MESSAGED', 'UNKNOWN']):
                    use_api = True
            
            if use_api:
                try:
                    api_call_count += 1
                    stats['api_checked'] += 1
                    
                    # Call the real WhatsApp API (sends actual message)
                    whatsapp_status = check_whatsapp_api_registration_real(mobile, mpp.name_with_code)
                    
                    result['api_result'] = whatsapp_status
                    result['verification_method'] = 'API Verification'
                    
                    if whatsapp_status == 'registered':
                        result['whatsapp_status'] = 'WHATSAPP_REGISTERED'
                        result['recommendations'].append('Test message sent successfully')
                        stats['whatsapp_registered'] += 1
                        stats['api_registered'] += 1
                        
                        # If historical data said not registered but API says registered, update
                        if 'All WhatsApp messages failed' in result['issues']:
                            result['issues'] = []
                            result['recommendations'] = ['Message delivery issues may be temporary']
                            
                    elif whatsapp_status == 'not_registered':
                        result['whatsapp_status'] = 'WHATSAPP_NOT_REGISTERED'
                        result['issues'].append('Confirmed not registered on WhatsApp via API')
                        result['recommendations'].append('Contact MPP for alternative number')
                        stats['whatsapp_not_registered'] += 1
                        stats['api_not_registered'] += 1
                    
                    elif whatsapp_status == 'token_expired':
                        result['issues'].append('WhatsApp API access token has expired')
                        result['recommendations'].append('Renew WhatsApp Business API access token in Meta Developer Console')
                        stats['api_failed'] += 1
                        stats['api_token_expired'] += 1
                        
                        if not historical_status_determined:
                            result['whatsapp_status'] = 'CHECK_FAILED'
                            result['verification_method'] = 'API Token Expired'
                    
                    elif whatsapp_status == 'rate_limited':
                        result['issues'].append('API rate limited - try again later')
                        result['recommendations'].append('Wait 1 hour before retrying')
                        stats['api_failed'] += 1
                        
                        if not historical_status_determined:
                            result['whatsapp_status'] = 'CHECK_FAILED'
                            result['verification_method'] = 'API Rate Limited'
                    
                    elif whatsapp_status == 'invalid_token':
                        result['issues'].append('WhatsApp API token is invalid or expired')
                        result['recommendations'].append('Check WhatsApp Business API configuration')
                        stats['api_failed'] += 1
                        
                    elif whatsapp_status in ['api_timeout', 'connection_error']:
                        result['issues'].append(f'API connection issue: {whatsapp_status}')
                        result['recommendations'].append('Check network connection and API endpoint')
                        stats['api_failed'] += 1
                        
                        if not historical_status_determined:
                            result['whatsapp_status'] = 'CHECK_FAILED'
                            result['verification_method'] = f'API {whatsapp_status}'
                    
                    else:
                        # API failed or returned error
                        result['issues'].append(f'API check failed: {whatsapp_status}')
                        result['recommendations'].append('Review API logs for details')
                        stats['api_failed'] += 1
                        
                        if not historical_status_determined:
                            result['whatsapp_status'] = 'CHECK_FAILED'
                            result['verification_method'] = 'API Failed - Using historical data'
                    
                    # Add small delay to avoid rate limiting
                    if api_call_count < max_api_calls:
                        import time
                        time.sleep(api_delay)
                        
                except Exception as e:
                    result['issues'].append(f'API exception: {str(e)}')
                    stats['api_failed'] += 1
            
            results.append(result)
        
        # Sort results by status for better organization
        results.sort(key=lambda x: (
            {'WHATSAPP_NOT_REGISTERED': 0, 'NEVER_MESSAGED': 1, 'INVALID_NUMBER': 2, 
             'CHECK_FAILED': 3, 'WHATSAPP_REGISTERED': 4, 'NEEDS_VERIFICATION': 5, 'UNKNOWN': 6}.get(x['whatsapp_status'], 7),
            x['failure_rate'] if x['failure_rate'] else 0,
            x['mpp_name']
        ))
        
        # Generate Excel report
        excel_bytes = generate_whatsapp_registration_report_enhanced(results, stats, api_available)
        
        # ✅ FIXED: Create response with Excel file - Properly handle bytes
        response = HttpResponse(
            content=excel_bytes,
            content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        )
        filename = f"whatsapp_registration_report_{timezone.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
        response['Content-Disposition'] = f'attachment; filename="{filename}"'
        response['Content-Length'] = len(excel_bytes)
        
        return response
        
    except Exception as e:
        import traceback
        traceback.print_exc()
        return JsonResponse({
            'success': False,
            'message': f'Error checking WhatsApp registration: {str(e)}'
        })


def check_whatsapp_api_registration_real(mobile_number, mpp_name=None):
    """
    REAL implementation of WhatsApp API check by SENDING TEMPLATE MESSAGE with dummy data
    Returns 'registered' if message sends successfully, 'not_registered' if fails
    """
    try:
        # Get configuration from settings
        whatsapp_config = getattr(settings, 'WHATSAPP_BUSINESS_API', {})
        access_token = whatsapp_config.get('ACCESS_TOKEN')
        phone_number_id = whatsapp_config.get('PHONE_NUMBER_ID')
        api_version = whatsapp_config.get('API_VERSION', 'v22.0')
        base_url = whatsapp_config.get('BASE_URL', 'https://graph.facebook.com')
        template_name = whatsapp_config.get('TEMPLATE_NAME', 'shwetdhara_remainder_template')
        template_language = whatsapp_config.get('TEMPLATE_LANGUAGE', 'hi')
        
        if not access_token or not phone_number_id:
            return 'api_not_configured'
        
        # Clean and format mobile number
        mobile = str(mobile_number).strip()
        
        # Ensure proper formatting
        if mobile.startswith('+91'):
            clean_number = mobile
        elif mobile.startswith('91'):
            clean_number = f"+{mobile}"
        else:
            clean_number = f"+91{mobile}"
        
        # WhatsApp Business API endpoint for sending messages
        url = f"{base_url}/{api_version}/{phone_number_id}/messages"
        
        headers = {
            "Authorization": f"Bearer {access_token}",
            "Content-Type": "application/json"
        }
        
        # Create dummy data for template variables
        if mpp_name:
            mpp_display = f"{mpp_name} [कृपया पिछली और इस मैसेज को इग्नोर करें ये सिर्फ टेस्टिंग के लिए था ]"
        else:
            mpp_display = f"Test MPP {mobile[-4:]}"
        
        # Use current timestamp as dummy order number
        dummy_order = f"TEST-{int(timezone.now().timestamp()) % 1000000}"
        dummy_products = "CF- 25 KG - 1 [कृपया पिछली और इस मैसेज को इग्नोर करें ये सिर्फ टेस्टिंग के लिए था ]"
        
        # Use TEMPLATE instead of plain text - same as your working sales messages
        payload = {
            "messaging_product": "whatsapp",
            "recipient_type": "individual",
            "to": clean_number,
            "type": "template",
            "template": {
                "name": template_name,
                "language": {
                    "code": template_language
                },
                "components": [
                    {
                        "type": "body",
                        "parameters": [
                            {
                                "type": "text",
                                "text": mpp_display
                            },
                            {
                                "type": "text",
                                "text": dummy_products
                            },
                            {
                                "type": "text",
                                "text": dummy_order
                            }
                        ]
                    }
                ]
            }
        }
        
        # Make API request to SEND template message
        response = requests.post(
            url,
            headers=headers,
            json=payload,
            timeout=30
        )
        
        if response.status_code == 200:
            data = response.json()
            
            # Create a log entry for this test message
            try:
                WhatsAppLog.objects.create(
                    mobile_number=mobile,
                    message=f"Template: {template_name} - {mpp_display}",
                    mpp_name=mpp_name or '',
                    status='SENT',
                    sent_via='META_API',
                    template_name=template_name,
                    template_variables={
                        '1': mpp_display,
                        '2': dummy_products,
                        '3': dummy_order
                    },
                    sent_at=timezone.now(),
                    api_response=data
                )
            except Exception:
                pass
            
            return 'registered'
        
        elif response.status_code == 400:
            error_data = response.json()
            error_message = error_data.get('error', {}).get('message', 'Unknown error')
            error_code = error_data.get('error', {}).get('code', 0)
            error_subcode = error_data.get('error', {}).get('error_subcode', 0)
            
            # Create a log entry for the failed attempt
            try:
                WhatsAppLog.objects.create(
                    mobile_number=mobile,
                    message=f"Template: {template_name} - {mpp_display}",
                    mpp_name=mpp_name or '',
                    status='FAILED',
                    sent_via='META_API',
                    template_name=template_name,
                    template_variables={
                        '1': mpp_display,
                        '2': dummy_products,
                        '3': dummy_order
                    },
                    error_message=f"API Error {error_code}: {error_message[:200]}",
                    api_response=error_data
                )
            except Exception:
                pass
            
            # Check for specific WhatsApp API errors
            if error_code == 100 and 'not registered' in error_message.lower():
                return 'not_registered'
            elif error_code == 190:
                # OAuth token error
                if error_subcode == 463:  # Token expired
                    return 'token_expired'
                else:
                    return 'invalid_token'
            elif error_code == 131000:  # Message failed to send
                return 'message_failed'
            elif error_code == 100 and error_subcode == 2018155:
                # This error often means the number is not on WhatsApp
                return 'not_registered'
            elif error_code == 132000:  # Template not found
                return 'template_not_found'
            else:
                return 'api_error'
        
        elif response.status_code == 401:
            return 'token_expired'
        
        elif response.status_code == 429:
            return 'rate_limited'
        
        else:
            return 'api_error'
            
    except requests.exceptions.Timeout:
        return 'api_timeout'
    except requests.exceptions.ConnectionError:
        return 'connection_error'
    except Exception:
        return 'api_error'

def generate_whatsapp_registration_report_enhanced(results, stats, api_available):
    """
    Generate enhanced Excel report for WhatsApp registration status with API results
    """
    output = io.BytesIO()
    wb = Workbook()
    
    # ============================================
    # SHEET 1: REGISTRATION STATUS
    # ============================================
    ws = wb.active
    ws.title = "WhatsApp Registration Status"
    
    # Define styles
    header_fill = PatternFill(start_color="2C5F2D", end_color="2C5F2D", fill_type="solid")
    header_font = Font(color="FFFFFF", bold=True)
    
    status_colors = {
        'WHATSAPP_REGISTERED': '90EE90',  # Green
        'WHATSAPP_NOT_REGISTERED': 'FFB6C1',  # Pink
        'NEVER_MESSAGED': 'FFD700',  # Yellow
        'INVALID_NUMBER': 'FF6B6B',  # Red
        'NEEDS_VERIFICATION': '87CEEB',  # Sky Blue
        'CHECK_FAILED': 'D3D3D3',  # Gray
        'UNKNOWN': 'D3D3D3',  # Gray
    }
    
    border = Border(
        left=Side(style='thin'),
        right=Side(style='thin'),
        top=Side(style='thin'),
        bottom=Side(style='thin')
    )
    
    # Headers - Add API Result column if API was used
    headers = [
        'MPP ID',
        'MPP Name',
        'MPP Transaction Code',
        'BMC/MCC',
        'Mobile Number',
        'WhatsApp Status',
        'Verification Method',
        'Last Message Date',
        'Total Messages',
        'Success Messages',
        'Failed Messages',
        'Failure Rate %',
        'Issues',
        'Recommendations'
    ]
    
    if api_available:
        headers.append('API Result')
    
    # Write headers
    for col_idx, header in enumerate(headers, start=1):
        cell = ws.cell(row=1, column=col_idx, value=header)
        cell.fill = header_fill
        cell.font = header_font
        cell.border = border
        cell.alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)
    
    # Write data
    row_idx = 2
    for result in results:
        ws.cell(row=row_idx, column=1, value=result['mpp_id']).border = border
        ws.cell(row=row_idx, column=2, value=result['mpp_name']).border = border
        ws.cell(row=row_idx, column=3, value=result['mpp_transaction_code']).border = border
        ws.cell(row=row_idx, column=4, value=result['bmc_mcc']).border = border
        ws.cell(row=row_idx, column=5, value=result['mobile_number']).border = border
        ws.cell(row=row_idx, column=6, value=result['whatsapp_status']).border = border
        ws.cell(row=row_idx, column=7, value=result['verification_method']).border = border
        
        # Handle last_message_date safely
        last_message_date = result['last_message_date']
        if last_message_date:
            if hasattr(last_message_date, 'strftime'):
                cell_value = last_message_date.strftime('%Y-%m-%d %H:%M')
            else:
                try:
                    # Try to parse if it's a string
                    from django.utils.dateparse import parse_datetime
                    parsed = parse_datetime(str(last_message_date))
                    if parsed:
                        cell_value = parsed.strftime('%Y-%m-%d %H:%M')
                    else:
                        cell_value = str(last_message_date)
                except:
                    cell_value = str(last_message_date)
        else:
            cell_value = 'Never'
        
        ws.cell(row=row_idx, column=8, value=cell_value).border = border
        ws.cell(row=row_idx, column=9, value=result['total_messages']).border = border
        ws.cell(row=row_idx, column=10, value=result['success_messages']).border = border
        ws.cell(row=row_idx, column=11, value=result['failed_messages']).border = border
        ws.cell(row=row_idx, column=12, value=f"{result['failure_rate']:.1f}%").border = border
        ws.cell(row=row_idx, column=13, value="\n".join(result['issues'])).border = border
        ws.cell(row=row_idx, column=14, value="\n".join(result['recommendations'])).border = border
        
        # Add API result if available
        if api_available:
            api_result = result.get('api_result', 'Not Checked')
            if api_result:
                ws.cell(row=row_idx, column=15, value=str(api_result).upper()).border = border
        
        # Apply color coding to status cell
        status_cell = ws.cell(row=row_idx, column=6)
        color_hex = status_colors.get(result['whatsapp_status'], 'FFFFFF')
        status_cell.fill = PatternFill(start_color=color_hex, end_color=color_hex, fill_type="solid")
        status_cell.font = Font(bold=True)
        
        row_idx += 1
    
    # ============================================
    # SHEET 2: EXECUTIVE SUMMARY
    # ============================================
    ws_summary = wb.create_sheet("Executive Summary")
    
    summary_data = [
        ["WHATSAPP REGISTRATION AUDIT REPORT", "", "", ""],
        ["", "", "", ""],
        ["Generated On", timezone.now().strftime("%Y-%m-%d %H:%M:%S"), "", ""],
        ["Report Type", "Historical + API Verification" if api_available else "Historical Only", "", ""],
        ["", "", "", ""],
        ["EXECUTIVE SUMMARY", "", "", ""],
        ["Total MPPs Checked", stats['total'], "", ""],
        ["WhatsApp Registered", stats['whatsapp_registered'], 
         f"{(stats['whatsapp_registered']/stats['total'])*100:.1f}%" if stats['total'] > 0 else "0%", 
         "Confirmed WhatsApp users"],
        ["WhatsApp NOT Registered", stats['whatsapp_not_registered'],
         f"{(stats['whatsapp_not_registered']/stats['total'])*100:.1f}%" if stats['total'] > 0 else "0%",
         "Numbers not on WhatsApp (ACTION REQUIRED)"],
        ["Invalid Numbers", stats['invalid_number'],
         f"{(stats['invalid_number']/stats['total'])*100:.1f}%" if stats['total'] > 0 else "0%",
         "Format issues (needs correction)"],
        ["Never Messaged", stats['never_messaged'],
         f"{(stats['never_messaged']/stats['total'])*100:.1f}%" if stats['total'] > 0 else "0%",
         "No message history (needs testing)"],
        ["Check Failed", stats['check_failed'],
         f"{(stats['check_failed']/stats['total'])*100:.1f}%" if stats['total'] > 0 else "0%",
         "Requires manual verification"],
    ]
    
    # Add API statistics if API was available
    if api_available:
        summary_data.extend([
            ["", "", "", ""],
            ["API VERIFICATION STATISTICS", "", "", ""],
            ["API Calls Made", stats['api_checked'], "", ""],
            ["API - Registered", stats['api_registered'], 
             f"{(stats['api_registered']/stats['api_checked'])*100:.1f}%" if stats['api_checked'] > 0 else "0%",
             "Confirmed via API (messages sent)"],
            ["API - Not Registered", stats['api_not_registered'],
             f"{(stats['api_not_registered']/stats['api_checked'])*100:.1f}%" if stats['api_checked'] > 0 else "0%",
             "Confirmed not on WhatsApp via API"],
            ["API - Failed", stats['api_failed'],
             f"{(stats['api_failed']/stats['api_checked'])*100:.1f}%" if stats['api_checked'] > 0 else "0%",
             "API calls failed or timed out"],
        ])
        
        if stats.get('api_token_expired', 0) > 0:
            summary_data.extend([
                ["", "", "", ""],
                ["⚠️ CRITICAL ISSUE DETECTED", "", "", ""],
                ["API Token Expired", stats['api_token_expired'], "100%", 
                 "WhatsApp API access token needs renewal in Meta Developer Console"],
            ])
    
    summary_data.extend([
        ["", "", "", ""],
        ["CRITICAL FINDINGS:", "", "", ""],
        ["Immediate Action Required", stats['whatsapp_not_registered'] + stats['invalid_number'], "", 
         "These MPPs cannot receive WhatsApp communications"],
        ["Testing Required", stats['never_messaged'], "", 
         "Need to send test messages to verify"],
        ["", "", "", ""],
        ["RECOMMENDED ACTIONS:", "", "", ""],
        ["1. Contact MPPs with invalid numbers", "Update their mobile numbers", "", ""],
        ["2. Send test messages to untested numbers", "Verify WhatsApp registration", "", ""],
        ["3. Follow up with non-WhatsApp users", "Alternative communication methods", "", ""],
        ["4. Update system records", "Correct invalid/incorrect numbers", "", ""],
    ])
    
    # Write summary data
    for row_idx, row_data in enumerate(summary_data, start=1):
        for col_idx, value in enumerate(row_data, start=1):
            cell = ws_summary.cell(row=row_idx, column=col_idx, value=value)
            
