def send_whatsapp_message_via_api(mobile_number, message, mpp_name=None):
    """
    Send WhatsApp message using WhatsApp Business API
    """
    try:
        # Get configuration from settings
        whatsapp_config = getattr(settings, 'WHATSAPP_BUSINESS_API', {})
        access_token = whatsapp_config.get('ACCESS_TOKEN')
        phone_number_id = whatsapp_config.get('PHONE_NUMBER_ID')
        api_version = whatsapp_config.get('API_VERSION', 'v22.0')
        base_url = whatsapp_config.get('BASE_URL', 'https://graph.facebook.com')
        
        if not access_token or not phone_number_id:
            print("❌ WhatsApp API credentials not configured")
            return {'success': False, 'error': 'API not configured'}
        
        # Clean and format mobile number
        mobile = str(mobile_number).strip()
        
        # Ensure proper formatting
        if mobile.startswith('+91'):
            clean_number = mobile
        elif mobile.startswith('91'):
            clean_number = f"+{mobile}"
        else:
            clean_number = f"+91{mobile}"
        
        print(f"📤 Sending WhatsApp message to: {clean_number}")
        print(f"   Message: {message[:50]}...")
        
        # WhatsApp Business API endpoint
        url = f"{base_url}/{api_version}/{phone_number_id}/messages"
        
        headers = {
            "Authorization": f"Bearer {access_token}",
            "Content-Type": "application/json"
        }
        
        # For test messages, use text messages
        payload = {
            "messaging_product": "whatsapp",
            "recipient_type": "individual",
            "to": clean_number,
            "type": "text",
            "text": {
                "preview_url": False,
                "body": message
            }
        }
        
        # Make API request
        response = requests.post(
            url,
            headers=headers,
            json=payload,
            timeout=30
        )
        
        print(f"📡 API Response Status: {response.status_code}")
        
        if response.status_code == 200:
            data = response.json()
            message_id = data.get('messages', [{}])[0].get('id', '')
            
            print(f"✅ Message sent successfully")
            print(f"   Message ID: {message_id}")
            
            # Log the successful message
            whatsapp_log = WhatsAppLog.objects.create(
                mobile_number=mobile,
                message=message,
                mpp_name=mpp_name,
                status='SENT',
                sent_via='META_API',
                template_message_id=message_id,
                api_response=data,
                sent_at=timezone.now()
            )
            
            return {
                'success': True,
                'message_id': message_id,
                'log_id': whatsapp_log.id,
                'api_response': data
            }
        
        elif response.status_code == 400:
            error_data = response.json()
            print(f"❌ API Error (400): {error_data}")
            
            error_message = error_data.get('error', {}).get('message', 'Unknown error')
            error_code = error_data.get('error', {}).get('code', 0)
            
            # Create log for failed message
            whatsapp_log = WhatsAppLog.objects.create(
                mobile_number=mobile,
                message=message,
                mpp_name=mpp_name,
                status='FAILED',
                sent_via='META_API',
                error_message=f"Error {error_code}: {error_message}",
                api_response=error_data,
                sent_at=timezone.now()
            )
            
            if error_code == 100 and 'not registered' in error_message.lower():
                # Also create a NOT_REGISTERED log for tracking
                WhatsAppLog.objects.create(
                    mobile_number=mobile,
                    message=message,
                    mpp_name=mpp_name,
                    status='NOT_REGISTERED',
                    sent_via='META_API',
                    error_message=f"Error {error_code}: {error_message}",
                    api_response=error_data,
                    sent_at=timezone.now()
                )
                
                return {
                    'success': False,
                    'error': 'not_registered',
                    'error_message': 'Number not registered on WhatsApp',
                    'log_id': whatsapp_log.id
                }
            else:
                return {
                    'success': False,
                    'error': 'api_error',
                    'error_message': error_message,
                    'log_id': whatsapp_log.id
                }
        
        else:
            error_data = response.json() if response.content else {}
            print(f"❌ API Error ({response.status_code}): {error_data}")
            
            # Create log for failed message
            whatsapp_log = WhatsAppLog.objects.create(
                mobile_number=mobile,
                message=message,
                mpp_name=mpp_name,
                status='FAILED',
                sent_via='META_API',
                error_message=f"HTTP {response.status_code}",
                api_response=error_data,
                sent_at=timezone.now()
            )
            
            return {
                'success': False,
                'error': 'api_error',
                'error_message': f"HTTP {response.status_code}: {error_data}",
                'log_id': whatsapp_log.id
            }
            
    except Exception as e:
        print(f"❌ Unexpected error sending to {mobile_number}: {str(e)}")
        
        # Create log for exception
        WhatsAppLog.objects.create(
            mobile_number=mobile if 'mobile' in locals() else mobile_number,
            message=message if 'message' in locals() else '',
            mpp_name=mpp_name,
            status='FAILED',
            sent_via='META_API',
            error_message=str(e)
        )
        
        return {
            'success': False,
            'error': 'exception',
            'error_message': str(e)
        }


@login_required(login_url='login')
def send_whatsapp_test_messages(request):
    """
    Send test WhatsApp messages to verify registration status
    Uses real WhatsApp Business API
    """
    if request.method == 'POST':
        try:
            # Get parameters from POST data
            mpp_ids = request.POST.getlist('mpp_ids[]')
            message = request.POST.get('message', '[TEST] This is a test message from Shwetdhara system')
            
            if not mpp_ids:
                return JsonResponse({
                    'success': False,
                    'message': 'No MPPs selected for testing'
                })
            
            mpps = MPPWithCode.objects.filter(id__in=mpp_ids, status='ACTIVE')
            
            results = []
            success_count = 0
            failed_count = 0
            not_registered_count = 0
            
            for mpp in mpps:
                try:
                    # FIX: Convert to string and handle None values
                    mobile = str(mpp.sahayak_mobile_number).strip() if mpp.sahayak_mobile_number else ''
                    
                    # Validate mobile number format
                    if not re.match(r'^[6-9]\d{9}$', mobile):
                        result_status = 'FAILED'
                        error_message = 'Invalid number format'
                        failed_count += 1
                    else:
                        # Create test message with MPP info
                        test_message = f"{message}\n\nMPP: {mpp.name_with_code}\nCode: {mpp.mpp_transaction_code or 'N/A'}\nTime: {timezone.now().strftime('%Y-%m-%d %H:%M:%S')}"
                        
                        # Send message via WhatsApp API
                        api_result = send_whatsapp_message_via_api(mobile, test_message, mpp.name_with_code)
                        
                        if api_result['success']:
                            result_status = 'SENT'
                            success_count += 1
                            error_message = ''
                        else:
                            if api_result.get('error') == 'not_registered':
                                result_status = 'NOT_REGISTERED'
                                not_registered_count += 1
                            else:
                                result_status = 'FAILED'
                                failed_count += 1
                            error_message = api_result.get('error_message', 'Unknown error')
                    
                    # Create WhatsApp log
                    whatsapp_log = WhatsAppLog.objects.create(
                        mobile_number=mobile,
                        message=test_message if 'test_message' in locals() else message,
                        mpp_name=mpp.name_with_code,
                        status=result_status,
                        sent_via='META_API',
                        error_message=error_message if 'error_message' in locals() else '',
                        sent_at=timezone.now() if result_status == 'SENT' else None
                    )
                    
                    results.append({
                        'mpp_id': mpp.id,
                        'mpp_name': mpp.name_with_code,
                        'mobile': mobile,
                        'status': result_status,
                        'message_id': whatsapp_log.id,
                        'error': error_message if result_status != 'SENT' else None
                    })
                    
                except Exception as e:
                    failed_count += 1
                    # FIX: Also convert to string here
                    mobile_str = str(mpp.sahayak_mobile_number) if mpp.sahayak_mobile_number else ''
                    results.append({
                        'mpp_id': mpp.id,
                        'mpp_name': mpp.name_with_code,
                        'mobile': mobile_str,
                        'status': 'ERROR',
                        'error': str(e)
                    })
            
            return JsonResponse({
                'success': True,
                'message': f'Test messages sent: {success_count} success, {failed_count} failed, {not_registered_count} not registered',
                'results': results,
                'total': len(mpps),
                'success_count': success_count,
                'failed_count': failed_count,
                'not_registered_count': not_registered_count
            })
            
        except Exception as e:
            print(f"❌ Error sending test messages: {str(e)}")
            return JsonResponse({
                'success': False,
                'message': f'Error sending test messages: {str(e)}'
            })
    
    return JsonResponse({
        'success': False,
        'message': 'Invalid request method'
    })

@csrf_exempt
@login_required(login_url='login')
def send_test_whatsapp_message(request):
    """Send a test WhatsApp message to a single MPP using template API"""
    if request.method == 'POST':
        try:
            data = json.loads(request.body)
            mpp_id = data.get('mpp_id')
            mobile_number = data.get('mobile_number')
            custom_message = data.get('message')
            
            if not mpp_id or not mobile_number:
                return JsonResponse({
                    'success': False,
                    'message': 'MPP ID and mobile number are required'
                })
            
            # Get MPP details
            try:
                mpp = MPPWithCode.objects.get(id=mpp_id, status='ACTIVE')
            except MPPWithCode.DoesNotExist:
                return JsonResponse({
                    'success': False,
                    'message': 'MPP not found or inactive'
                })
            
            # Convert mobile_number to string and handle None
            mobile = str(mobile_number).strip() if mobile_number else ''
            
            # Validate mobile number format
            if not re.match(r'^[6-9]\d{9}$', mobile):
                return JsonResponse({
                    'success': False,
                    'message': 'Invalid mobile number format. Should be 10 digits starting with 6-9'
                })
            
            # Get WhatsApp configuration
            whatsapp_config = getattr(settings, 'WHATSAPP_BUSINESS_API', {})
            access_token = whatsapp_config.get('ACCESS_TOKEN')
            phone_number_id = whatsapp_config.get('PHONE_NUMBER_ID')
            
            if not access_token or not phone_number_id:
                return JsonResponse({
                    'success': False,
                    'message': 'WhatsApp API is not configured properly',
                    'error_type': 'api_not_configured'
                })
            
            # Prepare message content
            if custom_message:
                message_body = f"[TEST] {custom_message}"
            else:
                message_body = "[TEST] This is a test message to verify WhatsApp registration"
            
            mpp_info = f"{mpp.name_with_code} (Code: {mpp.mpp_transaction_code or 'N/A'})"
            timestamp = timezone.now().strftime('%Y-%m-%d %H:%M:%S')
            
            # Prepare template variables
            template_variables = {
                '1': mpp_info,  # MPP Information
                '2': message_body,  # Message body
                '3': timestamp  # Timestamp
            }
            
            print(f"📤 Sending test WhatsApp message to {mobile}")
            print(f"   MPP: {mpp_info}")
            print(f"   Message: {message_body}")
            
            # Send message via WhatsApp API
            api_result = send_whatsapp_template_message(
                mobile_number=mobile,
                template_name=whatsapp_config.get('TEMPLATE_NAME', 'shwetdhara_remainder_template'),
                template_language=whatsapp_config.get('TEMPLATE_LANGUAGE', 'hi'),
                template_variables=template_variables,
                mpp_name=mpp.name_with_code
            )
            
            # Create WhatsApp log
            whatsapp_log = WhatsAppLog.objects.create(
                mobile_number=mobile,
                message=message_body,
                mpp_name=mpp.name_with_code,
                status='SENT' if api_result['success'] else 'FAILED',
                sent_via='META_API',
                template_name=whatsapp_config.get('TEMPLATE_NAME'),
                template_variables=template_variables,
                error_message=api_result.get('error_message', '') if not api_result['success'] else '',
                api_response=api_result.get('api_response', {}),
                sent_at=timezone.now() if api_result['success'] else None
            )
            
            if api_result['success']:
                print(f"✅ Test message sent successfully to {mobile}")
                return JsonResponse({
                    'success': True,
                    'message': 'Test WhatsApp message sent successfully',
                    'log_id': whatsapp_log.id,
                    'message_id': api_result.get('message_id', ''),
                    'mobile_number': mobile,
                    'mpp_name': mpp.name_with_code,
                    'timestamp': timestamp
                })
            else:
                error_type = api_result.get('error', 'unknown')
                error_msg = api_result.get('error_message', 'Unknown error')
                
                print(f"❌ Failed to send test message to {mobile}: {error_type} - {error_msg}")
                
                # Map error types to user-friendly messages
                error_messages = {
                    'not_registered': 'This number is not registered on WhatsApp',
                    'template_not_found': f'WhatsApp template not found. Please check template configuration',
                    'token_expired': 'WhatsApp API token has expired. Please renew in Meta Developer Console',
                    'invalid_token': 'Invalid WhatsApp API token. Please check configuration',
                    'rate_limited': 'Rate limited. Please try again in a few minutes',
                    'api_not_configured': 'WhatsApp API is not configured properly',
                    'timeout': 'API request timed out. Please try again',
                    'connection_error': 'Connection error to WhatsApp API. Please check network',
                    'api_error': f'WhatsApp API error: {error_msg}'
                }
                
                user_message = error_messages.get(error_type, f'Failed to send message: {error_msg}')
                
                return JsonResponse({
                    'success': False,
                    'message': user_message,
                    'error_type': error_type,
                    'error_details': error_msg,
                    'log_id': whatsapp_log.id,
                    'mobile_number': mobile,
                    'mpp_name': mpp.name_with_code
                })
            
        except json.JSONDecodeError as e:
            return JsonResponse({
                'success': False,
                'message': f'Invalid JSON data: {str(e)}'
            })
        except Exception as e:
            print(f"❌ Error sending test message: {str(e)}")
            import traceback
            traceback.print_exc()
            return JsonResponse({
                'success': False,
                'message': f'Error sending test message: {str(e)}'
            })
    
    return JsonResponse({
        'success': False,
        'message': 'Invalid request method. Use POST'
    })



# Setup logger
logger = logging.getLogger(__name__)

def send_whatsapp_template_message(mobile_number, template_name, template_language='hi', 
                                   template_variables=None, mpp_name=None, unique_code=None):
    """
    Send WhatsApp message using template API and store the message_id for webhook tracking
    
    Args:
        mobile_number: Recipient mobile number
        template_name: WhatsApp template name
        template_language: Template language code (default: 'hi' for Hindi)
        template_variables: Dictionary of template variables
        mpp_name: MPP name for logging
        unique_code: Unique identifier for tracking
    
    Returns:
        dict: API result with success status and details
    """
    try:
        # Get configuration from settings
        whatsapp_config = getattr(settings, 'WHATSAPP_BUSINESS_API', {})
        access_token = whatsapp_config.get('ACCESS_TOKEN')
        phone_number_id = whatsapp_config.get('PHONE_NUMBER_ID')
        api_version = whatsapp_config.get('API_VERSION', 'v22.0')
        base_url = whatsapp_config.get('BASE_URL', 'https://graph.facebook.com')
        
        if not access_token or not phone_number_id:
            print("❌ WhatsApp API credentials not configured")
            logger.error("❌ WhatsApp API credentials not configured")
            return {
                'success': False, 
                'error': 'api_not_configured',
                'error_message': 'WhatsApp API credentials not configured in settings'
            }
        
        # Clean and format mobile number
        mobile = str(mobile_number).strip()
        
        # Ensure proper formatting
        if mobile.startswith('+91'):
            clean_number = mobile
        elif mobile.startswith('91'):
            clean_number = f"+{mobile}"
        else:
            clean_number = f"+91{mobile}"
        
        print(f"📤 Sending WhatsApp template to: {clean_number}")
        print(f"   Template: {template_name}")
        print(f"   Language: {template_language}")
        if template_variables:
            print(f"   Variables: {template_variables}")
        
        logger.info(f"📤 Sending WhatsApp template to: {clean_number}")
        logger.info(f"   Template: {template_name}")
        logger.info(f"   Language: {template_language}")
        if template_variables:
            logger.info(f"   Variables: {template_variables}")
        
        # WhatsApp Business API endpoint
        url = f"{base_url}/{api_version}/{phone_number_id}/messages"
        
        headers = {
            "Authorization": f"Bearer {access_token}",
            "Content-Type": "application/json"
        }
        
        # Prepare template components
        components = []
        
        # Add body component if there are variables
        if template_variables:
            body_params = []
            for i in range(1, 4):  # Assuming template has up to 3 variables
                if str(i) in template_variables:
                    body_params.append({
                        "type": "text",
                        "text": str(template_variables[str(i)])
                    })
            
            if body_params:
                components.append({
                    "type": "body",
                    "parameters": body_params
                })
        
        # Prepare payload
        payload = {
            "messaging_product": "whatsapp",
            "recipient_type": "individual",
            "to": clean_number,
            "type": "template",
            "template": {
                "name": template_name,
                "language": {
                    "code": template_language
                }
            }
        }
        
        # Add components if available
        if components:
            payload["template"]["components"] = components
        
        print(f"📡 API Payload: {json.dumps(payload, indent=2)}")
        logger.debug(f"📡 API Payload: {json.dumps(payload, indent=2)}")
        
        # Make API request
        response = requests.post(
            url,
            headers=headers,
            json=payload,
            timeout=30
        )
        
        print(f"📡 API Response Status: {response.status_code}")
        logger.info(f"📡 API Response Status: {response.status_code}")
        
        # Parse response
        if response.status_code == 200:
            data = response.json()
            message_id = data.get('messages', [{}])[0].get('id', '')
            
            print(f"✅ Message sent successfully!")
            print(f"   Message ID: {message_id}")
            print(f"   API Response: {json.dumps(data, indent=2)[:200]}...")
            
            logger.info(f"✅ Message sent successfully!")
            logger.info(f"   Message ID: {message_id}")
            logger.info(f"   API Response: {json.dumps(data, indent=2)[:200]}...")
            
            # Create WhatsAppLog with message_id
            whatsapp_log = WhatsAppLog.objects.create(
                mobile_number=mobile,
                message=f"Template: {template_name}",
                unique_code=unique_code,
                mpp_name=mpp_name,
                status='PENDING',  # Start as pending, webhook will update
                sent_via='META_API',
                template_name=template_name,
                template_message_id=message_id,  # CRITICAL: Store for webhook
                template_variables=template_variables,
                api_response=data,
                sent_at=timezone.now()  # Or None if you want webhook to set it
            )
            
            print(f"📝 Created WhatsAppLog ID {whatsapp_log.id} with message_id {message_id}")
            logger.info(f"📝 Created WhatsAppLog ID {whatsapp_log.id} with message_id {message_id}")
            
            return {
                'success': True,
                'message_id': message_id,
                'log_id': whatsapp_log.id,
                'registered': None,  # Webhook will tell us
                'api_response': data,
                'note': 'Message accepted. Delivery status pending webhook update.'
            }
        
        elif response.status_code == 400:
            error_data = response.json()
            print(f"❌ API Error (400): {json.dumps(error_data, indent=2)}")
            logger.error(f"❌ API Error (400): {json.dumps(error_data, indent=2)}")
            
            error_message = error_data.get('error', {}).get('message', 'Unknown error')
            error_code = error_data.get('error', {}).get('code', 0)
            error_subcode = error_data.get('error', {}).get('error_subcode', 0)
            
            # Map error codes to error types
            if error_code == 100 and 'not registered' in error_message.lower():
                return {
                    'success': False,
                    'error': 'not_registered',
                    'error_message': error_message,
                    'api_response': error_data
                }
            elif error_code == 190:
                if error_subcode == 463:  # Token expired
                    return {
                        'success': False,
                        'error': 'token_expired',
                        'error_message': error_message,
                        'api_response': error_data
                    }
                else:
                    return {
                        'success': False,
                        'error': 'invalid_token',
                        'error_message': error_message,
                        'api_response': error_data
                    }
            elif error_code == 132000:  # Template not found
                return {
                    'success': False,
                    'error': 'template_not_found',
                    'error_message': error_message,
                    'api_response': error_data
                }
            elif error_code == 100 and error_subcode == 2018155:
                # This error often means the number is not on WhatsApp
                return {
                    'success': False,
                    'error': 'not_registered',
                    'error_message': error_message,
                    'api_response': error_data
                }
            elif error_code == 131000:  # Message failed to send
                return {
                    'success': False,
                    'error': 'api_error',
                    'error_message': error_message,
                    'api_response': error_data
                }
            else:
                return {
                    'success': False,
                    'error': 'api_error',
                    'error_message': f"Error {error_code}: {error_message}",
                    'api_response': error_data
                }
        
        elif response.status_code == 401:
            print(f"❌ Authentication failed for {clean_number}")
            logger.error(f"❌ Authentication failed for {clean_number}")
            return {
                'success': False,
                'error': 'token_expired',
                'error_message': 'Unauthorized - Token may be expired or invalid',
                'api_response': {}
            }
        
        elif response.status_code == 429:
            print(f"⚠️ Rate limited for {clean_number}")
            logger.warning(f"⚠️ Rate limited for {clean_number}")
            return {
                'success': False,
                'error': 'rate_limited',
                'error_message': 'Rate limited - Too many requests',
                'api_response': {}
            }
        
        else:
            error_data = response.json() if response.content else {}
            print(f"❌ API Error ({response.status_code}): {error_data}")
            logger.error(f"❌ API Error ({response.status_code}): {error_data}")
            
            return {
                'success': False,
                'error': 'api_error',
                'error_message': f"HTTP {response.status_code}: {error_data}",
                'api_response': error_data
            }
            
    except requests.exceptions.Timeout:
        print(f"⏰ API timeout for {mobile_number}")
        logger.error(f"⏰ API timeout for {mobile_number}")
        return {
            'success': False,
            'error': 'timeout',
            'error_message': 'API request timed out'
        }
    except requests.exceptions.ConnectionError:
        print(f"🔌 Connection error for {mobile_number}")
        logger.error(f"🔌 Connection error for {mobile_number}")
        return {
            'success': False,
            'error': 'connection_error',
            'error_message': 'Connection error to WhatsApp API'
        }
    except Exception as e:
        print(f"❌ Unexpected error sending to {mobile_number}: {str(e)}")
        logger.error(f"❌ Unexpected error sending to {mobile_number}: {str(e)}")
        import traceback
        traceback.print_exc()
        return {
            'success': False,
            'error': 'exception',
            'error_message': str(e)
        }


@login_required(login_url='login')
def send_bulk_test_whatsapp_messages(request):
    """Send test WhatsApp messages in bulk with filters"""
    if request.method == 'POST':
        try:
            data = json.loads(request.body)
            status_filter = data.get('status_filter', 'ALL')
            bmc_filter = data.get('bmc_filter', 'ALL')
            
            # Build query
            mpps = MPPWithCode.objects.filter(
                status='ACTIVE',
                sahayak_mobile_number__isnull=False
            ).exclude(sahayak_mobile_number='')
            
            # Apply BMC filter
            if bmc_filter != 'ALL':
                mpps = mpps.filter(bmc_or_mcc__name=bmc_filter)
            
            # Apply status filter based on historical data
            if status_filter != 'ALL':
                # This is a simplified filter - in production you might want to check actual status
                if status_filter == 'NEVER_MESSAGED':
                    # Get mobile numbers that have never been messaged
                    messaged_numbers = WhatsAppLog.objects.values_list('mobile_number', flat=True).distinct()
                    mpps = mpps.exclude(sahayak_mobile_number__in=messaged_numbers)
            
            # INCREASED LIMIT to cover more MPPs
            mpps = mpps[:500]  # Increased from 50 to 500
            
            results = []
            success_count = 0
            failed_count = 0
            not_registered_count = 0
            
            for mpp in mpps:
                try:
                    # FIX: Convert to string and handle None values
                    mobile = str(mpp.sahayak_mobile_number).strip() if mpp.sahayak_mobile_number else ''
                    
                    # Skip invalid numbers
                    if not re.match(r'^[6-9]\d{9}$', mobile):
                        continue
                    
                    # Create test message
                    message = f"[BULK TEST] This is a bulk test message from Shwetdhara system\n\nMPP: {mpp.name_with_code}\nCode: {mpp.mpp_transaction_code or 'N/A'}\nTime: {timezone.now().strftime('%Y-%m-%d %H:%M:%S')}"
                    
                    # Send message via WhatsApp API
                    api_result = send_whatsapp_message_via_api(mobile, message, mpp.name_with_code)
                    
                    # Create log
                    whatsapp_log = WhatsAppLog.objects.create(
                        mobile_number=mobile,
                        message=message,
                        mpp_name=mpp.name_with_code,
                        status='SENT' if api_result['success'] else 'FAILED',
                        sent_via='META_API',
                        error_message=api_result.get('error_message', '') if not api_result['success'] else '',
                        sent_at=timezone.now() if api_result['success'] else None
                    )
                    
                    if api_result['success']:
                        success_count += 1
                        status = 'SENT'
                    elif api_result.get('error') == 'not_registered':
                        not_registered_count += 1
                        status = 'NOT_REGISTERED'
                    else:
                        failed_count += 1
                        status = 'FAILED'
                    
                    results.append({
                        'mpp_id': mpp.id,
                        'mpp_name': mpp.name_with_code,
                        'mobile': mobile,
                        'status': status,
                        'log_id': whatsapp_log.id
                    })
                    
                    # Add small delay between messages to avoid rate limiting
                    import time
                    time.sleep(0.5)  # Reduced delay for faster bulk sending
                    
                except Exception as e:
                    failed_count += 1
                    # FIX: Also convert to string here
                    mobile_str = str(mpp.sahayak_mobile_number) if mpp.sahayak_mobile_number else ''
                    results.append({
                        'mpp_id': mpp.id,
                        'mpp_name': mpp.name_with_code,
                        'mobile': mobile_str,
                        'status': 'ERROR',
                        'error': str(e)
                    })
            
            return JsonResponse({
                'success': True,
                'message': f'Bulk test completed: {success_count} success, {failed_count} failed, {not_registered_count} not registered',
                'results': results[:20],  # Return only first 20 results
                'total_sent': len(results),
                'success_count': success_count,
                'failed_count': failed_count,
                'not_registered_count': not_registered_count
            })
            
        except Exception as e:
            print(f"❌ Error in bulk test: {str(e)}")
            return JsonResponse({
                'success': False,
                'message': f'Error in bulk test: {str(e)}'
            })
    
    return JsonResponse({
        'success': False,
        'message': 'Invalid request method'
    })


@login_required(login_url='login')
def get_whatsapp_overview(request):
    """Get overview statistics for WhatsApp validation - UPDATED FOR CONSISTENCY"""
    try:
        print("\n" + "="*80)
        print("🔄 LOADING WHATSAPP OVERVIEW DATA (CONSISTENT VERSION)")
        print("="*80)
        
        # Get basic counts
        total_mpps = MPPWithCode.objects.filter(status='ACTIVE').count()
        mpps_with_numbers = MPPWithCode.objects.filter(
            status='ACTIVE',
            sahayak_mobile_number__isnull=False
        ).exclude(sahayak_mobile_number='').count()
        
        # Get WhatsApp API status
        whatsapp_config = getattr(settings, 'WHATSAPP_BUSINESS_API', {})
        api_available = bool(whatsapp_config.get('ACCESS_TOKEN') and whatsapp_config.get('PHONE_NUMBER_ID'))
        
        # Get unique BMC list
        bmc_list = list(BMCOrMCC.objects.filter(
            mpps__status='ACTIVE'
        ).values_list('name', flat=True).distinct().order_by('name'))
        
        # Calculate WhatsApp registration status counts - USING SAME LOGIC AS get_whatsapp_results
        print("📊 CALCULATING WHATSAPP REGISTRATION STATISTICS (CONSISTENT VERSION)...")
        
        # Get all active MPPs with mobile numbers
        active_mpps_with_numbers = MPPWithCode.objects.filter(
            status='ACTIVE',
            sahayak_mobile_number__isnull=False
        ).exclude(sahayak_mobile_number='')
        
        # Get WhatsApp logs with same time filter as get_whatsapp_results
        whatsapp_logs = WhatsAppLog.objects.filter(
            created_at__gte=timezone.now() - timedelta(days=90)
        )
        
        # Create dictionary to track WhatsApp data by mobile number (same as get_whatsapp_results)
        mobile_whatsapp_data = {}
        
        # Process WhatsApp logs (same logic as get_whatsapp_results)
        for log in whatsapp_logs:
            mobile = str(log.mobile_number).strip() if log.mobile_number else ''
            if not mobile:
                continue
                
            # Track best status for each mobile number (same logic)
            if mobile not in mobile_whatsapp_data:
                mobile_whatsapp_data[mobile] = {
                    'last_message_date': log.created_at,
                    'best_status': log.status
                }
            else:
                # Update if this log has a better status (same priority system)
                status_priority = {
                    'READ': 6,
                    'RECEIVED': 5,
                    'DELIVERED': 4,
                    'SENT': 3,
                    'PENDING': 2,
                    'FAILED': 1,
                    'NOT_REGISTERED': 0
                }
                
                current_priority = status_priority.get(mobile_whatsapp_data[mobile]['best_status'], 0)
                new_priority = status_priority.get(log.status, 0)
                
                if new_priority > current_priority:
                    mobile_whatsapp_data[mobile]['best_status'] = log.status
                    mobile_whatsapp_data[mobile]['last_message_date'] = log.created_at
                elif new_priority == current_priority and log.created_at > mobile_whatsapp_data[mobile]['last_message_date']:
                    mobile_whatsapp_data[mobile]['last_message_date'] = log.created_at
        
        # Initialize counters
        whatsapp_registered = 0
        whatsapp_not_registered = 0
        invalid_number = 0
        never_messaged = 0
        
        # Track processed mobile numbers to avoid duplicates
        processed_numbers = set()
        
        # Process each MPP (using same status determination logic as get_whatsapp_results)
        for mpp in active_mpps_with_numbers:
            # Convert to string and handle None (same as get_whatsapp_results)
            mobile = str(mpp.sahayak_mobile_number).strip() if mpp.sahayak_mobile_number else ''
            
            # Skip if already processed (handle duplicates)
            if mobile in processed_numbers:
                continue
            processed_numbers.add(mobile)
            
            # Check if number is valid (same validation as get_whatsapp_results)
            if not mobile or not mobile.strip():
                invalid_number += 1
                continue
            
            is_valid_number = re.match(r'^[6-9]\d{9}$', mobile)
            if not is_valid_number:
                invalid_number += 1
                continue
            
            # Determine WhatsApp status (EXACT SAME LOGIC as get_whatsapp_results)
            if mobile in mobile_whatsapp_data:
                best_status = mobile_whatsapp_data[mobile].get('best_status', '')
                
                # Map backend status to frontend status names (same mapping)
                if best_status in ['READ', 'RECEIVED', 'DELIVERED', 'SENT']:
                    whatsapp_registered += 1  # WHATSAPP_REGISTERED
                elif best_status == 'NOT_REGISTERED':
                    whatsapp_not_registered += 1  # WHATSAPP_NOT_REGISTERED
                elif best_status == 'FAILED':
                    whatsapp_not_registered += 1  # WHATSAPP_NOT_REGISTERED
                else:
                    never_messaged += 1  # NEVER_MESSAGED
            else:
                never_messaged += 1  # NEVER_MESSAGED
        
        # Remove MessageQueue check since get_whatsapp_results doesn't use it
        # This ensures consistency
        
        # Verify consistency
        total_calculated = (whatsapp_registered + whatsapp_not_registered + 
                          invalid_number + never_messaged)
        
        if total_calculated != mpps_with_numbers:
            print(f"⚠️  WARNING: Count mismatch! Calculated: {total_calculated}, Should be: {mpps_with_numbers}")
            # Find missing numbers
            all_mobile_numbers = set()
            for mpp in active_mpps_with_numbers:
                mobile = str(mpp.sahayak_mobile_number).strip() if mpp.sahayak_mobile_number else ''
                if mobile:
                    all_mobile_numbers.add(mobile)
            
            missing_numbers = all_mobile_numbers - processed_numbers
            if missing_numbers:
                print(f"⚠️  Missing {len(missing_numbers)} numbers in calculation")
                for num in list(missing_numbers)[:10]:  # Show first 10
                    print(f"    - {num}")
        
        # Prepare response data (same field names as get_whatsapp_results stats)
        stats = {
            'total': total_mpps,
            'whatsapp_registered': whatsapp_registered,
            'whatsapp_not_registered': whatsapp_not_registered,
            'never_messaged': never_messaged,
            'invalid_number': invalid_number,
        }
        
        print(f"\n📈 WHATSAPP OVERVIEW STATISTICS (CONSISTENT):")
        print(f"   Total MPPs: {stats['total']}")
        print(f"   WhatsApp Registered: {stats['whatsapp_registered']}")
        print(f"   WhatsApp Not Registered: {stats['whatsapp_not_registered']}")
        print(f"   Never Messaged: {stats['never_messaged']}")
        print(f"   Invalid Numbers: {stats['invalid_number']}")
        print(f"   Total with numbers: {mpps_with_numbers}")
        print(f"   Calculated total: {total_calculated}")
        print(f"   BMC Count: {len(bmc_list)}")
        print(f"   API Available: {api_available}")
        print("="*80)
        
        return JsonResponse({
            'success': True,
            'stats': stats,
            'bmc_list': bmc_list,
            'api_available': api_available
        })
        
    except Exception as e:
        print(f"\n❌ ERROR in get_whatsapp_overview: {str(e)}")
        import traceback
        traceback.print_exc()
        return JsonResponse({
            'success': False,
            'message': f'Error loading WhatsApp overview: {str(e)}'
        })
        

@login_required(login_url='login')
def get_whatsapp_results(request):
    """Get WhatsApp validation results with MPP details - UPDATED WITH CONSISTENT STATUS NAMES"""
    try:
        print(f"📊 DEBUG: Starting get_whatsapp_results")
        
        # Get all active MPPs with mobile numbers
        mpps = MPPWithCode.objects.filter(
            status='ACTIVE',
            sahayak_mobile_number__isnull=False
        ).exclude(
            sahayak_mobile_number=''
        ).select_related('bmc_or_mcc')
        
        print(f"📊 DEBUG: Found {mpps.count()} active MPPs with mobile numbers")
        
        # Get WhatsApp logs
        whatsapp_logs = WhatsAppLog.objects.filter(
            created_at__gte=timezone.now() - timedelta(days=90)
        )
        
        # Create dictionaries to track WhatsApp data by mobile number
        mobile_whatsapp_data = {}
        mobile_message_counts = {}
        
        # Process WhatsApp logs
        for log in whatsapp_logs:
            mobile = str(log.mobile_number).strip() if log.mobile_number else ''
            if not mobile:
                continue
                
            # Track best status for each mobile number
            if mobile not in mobile_whatsapp_data:
                mobile_whatsapp_data[mobile] = {
                    'last_message_date': log.created_at,
                    'best_status': log.status
                }
            else:
                # Update if this log has a better status
                status_priority = {
                    'READ': 6,
                    'RECEIVED': 5,
                    'DELIVERED': 4,
                    'SENT': 3,
                    'PENDING': 2,
                    'FAILED': 1,
                    'NOT_REGISTERED': 0
                }
                
                current_priority = status_priority.get(mobile_whatsapp_data[mobile]['best_status'], 0)
                new_priority = status_priority.get(log.status, 0)
                
                if new_priority > current_priority:
                    mobile_whatsapp_data[mobile]['best_status'] = log.status
                    mobile_whatsapp_data[mobile]['last_message_date'] = log.created_at
                elif new_priority == current_priority and log.created_at > mobile_whatsapp_data[mobile]['last_message_date']:
                    mobile_whatsapp_data[mobile]['last_message_date'] = log.created_at
            
            # Count total messages
            mobile_message_counts[mobile] = mobile_message_counts.get(mobile, 0) + 1
        
        results = []
        
        for mpp in mpps:
            mobile = str(mpp.sahayak_mobile_number).strip() if mpp.sahayak_mobile_number else ''
            
            # Check if number is valid
            is_valid_number = re.match(r'^[6-9]\d{9}$', mobile) if mobile else False
            
            # Get WhatsApp data
            whatsapp_info = mobile_whatsapp_data.get(mobile, {})
            
            # Determine WhatsApp status - USING FRONTEND-FRIENDLY NAMES
            if not mobile or not mobile.strip():
                whatsapp_status = 'INVALID_NUMBER'
            elif not is_valid_number:
                whatsapp_status = 'INVALID_NUMBER'
            elif mobile in mobile_whatsapp_data:
                best_status = whatsapp_info.get('best_status', '')
                
                # Map backend status to frontend status names
                if best_status in ['READ', 'RECEIVED', 'DELIVERED', 'SENT']:
                    whatsapp_status = 'WHATSAPP_REGISTERED'  # This matches frontend filter
                elif best_status == 'NOT_REGISTERED':
                    whatsapp_status = 'WHATSAPP_NOT_REGISTERED'  # This matches frontend filter
                elif best_status == 'FAILED':
                    whatsapp_status = 'WHATSAPP_NOT_REGISTERED'
                else:
                    whatsapp_status = 'NEVER_MESSAGED'  # This matches frontend filter
            else:
                whatsapp_status = 'NEVER_MESSAGED'  # This matches frontend filter
            
            # Calculate failure rate
            failure_rate = 0
            total_messages = mobile_message_counts.get(mobile, 0)
            if total_messages > 0 and mobile in mobile_whatsapp_data:
                all_logs = WhatsAppLog.objects.filter(mobile_number=mobile)
                failed_logs = all_logs.filter(status__in=['FAILED', 'NOT_REGISTERED']).count()
                failure_rate = (failed_logs / total_messages * 100) if total_messages > 0 else 0
            
            # Get other details
            bmc_mcc = mpp.bmc_or_mcc.name if mpp.bmc_or_mcc else ''
            mpp_name = getattr(mpp, 'name_with_code', getattr(mpp, 'mpp_name', getattr(mpp, 'name', 'Unknown')))
            
            results.append({
                'mpp_id': mpp.id,
                'mpp_name': mpp_name,
                'mpp_transaction_code': mpp.mpp_transaction_code or '',
                'bmc_mcc': bmc_mcc,
                'mobile_number': mobile,
                'whatsapp_status': whatsapp_status,  # Using frontend-friendly names
                'last_message_date': whatsapp_info.get('last_message_date').strftime('%Y-%m-%d %H:%M') if whatsapp_info.get('last_message_date') else None,
                'total_messages': total_messages,
                'failure_rate': round(failure_rate, 1)
            })
        
        # Sort results
        status_order = {
            'WHATSAPP_REGISTERED': 1,
            'WHATSAPP_NOT_REGISTERED': 2,
            'NEVER_MESSAGED': 3,
            'INVALID_NUMBER': 4
        }
        
        results.sort(key=lambda x: (
            status_order.get(x['whatsapp_status'], 99),
            x['last_message_date'] if x['last_message_date'] else '',
            x['mpp_name']
        ), reverse=True)
        
        # Debug: Print status distribution
        print(f"📊 Status Distribution:")
        for status in ['WHATSAPP_REGISTERED', 'WHATSAPP_NOT_REGISTERED', 'NEVER_MESSAGED', 'INVALID_NUMBER']:
            count = len([r for r in results if r['whatsapp_status'] == status])
            print(f"  {status}: {count}")
        
        return JsonResponse({
            'success': True,
            'data': results,
            'stats': {
                'total': len(results),
                'whatsapp_registered': len([r for r in results if r['whatsapp_status'] == 'WHATSAPP_REGISTERED']),
                'whatsapp_not_registered': len([r for r in results if r['whatsapp_status'] == 'WHATSAPP_NOT_REGISTERED']),
                'never_messaged': len([r for r in results if r['whatsapp_status'] == 'NEVER_MESSAGED']),
                'invalid_number': len([r for r in results if r['whatsapp_status'] == 'INVALID_NUMBER'])
            }
        })
        
    except Exception as e:
        print(f"❌ Error in get_whatsapp_results: {str(e)}")
        import traceback
        traceback.print_exc()
        return JsonResponse({
            'success': False,
            'message': str(e)
        })        

@login_required(login_url='login')
def export_mpp_list(request):
    """Export filtered MPP list to Excel"""
    try:
        # Get filter parameters
        status_filter = request.GET.get('status', 'ALL')
        bmc_filter = request.GET.get('bmc', 'ALL')
        search_filter = request.GET.get('search', '')
        
        # Filter MPPs based on parameters
        mpps = MPPWithCode.objects.filter(status='ACTIVE')
        
        if bmc_filter != 'ALL':
            mpps = mpps.filter(bmc_or_mcc__name=bmc_filter)
        
        if search_filter:
            mpps = mpps.filter(
                Q(name_with_code__icontains=search_filter) |
                Q(sahayak_mobile_number__icontains=search_filter) |
                Q(mpp_transaction_code__icontains=search_filter)
            )
        
        # Create Excel workbook
        output = io.BytesIO()
        wb = Workbook()
        ws = wb.active
        ws.title = "MPP List"
        
        # Add headers
        headers = ['MPP Name', 'MPP Code', 'BMC/MCC', 'Mobile Number', 'Status', 'Created Date']
        for col_idx, header in enumerate(headers, start=1):
            ws.cell(row=1, column=col_idx, value=header)
        
        # Add data
        row_idx = 2
        for mpp in mpps:
            ws.cell(row=row_idx, column=1, value=mpp.name_with_code)
            ws.cell(row=row_idx, column=2, value=mpp.mpp_transaction_code or '')
            ws.cell(row=row_idx, column=3, value=mpp.bmc_or_mcc.name if mpp.bmc_or_mcc else '')
            ws.cell(row=row_idx, column=4, value=mpp.sahayak_mobile_number or '')
            ws.cell(row=row_idx, column=5, value=mpp.status)
            ws.cell(row=row_idx, column=6, 
                   value=mpp.created_at.strftime('%Y-%m-%d %H:%M') if mpp.created_at else '')
            row_idx += 1
        
        # Adjust column widths
        for column in ws.columns:
            max_length = 0
            column_letter = get_column_letter(column[0].column)
            for cell in column:
                try:
                    if len(str(cell.value)) > max_length:
                        max_length = len(str(cell.value))
                except:
                    pass
            adjusted_width = min((max_length + 2), 30)
            ws.column_dimensions[column_letter].width = adjusted_width
        
        wb.save(output)
        output.seek(0)
        
        response = HttpResponse(
            output,
            content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        )
        filename = f"mpp_list_export_{timezone.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
        response['Content-Disposition'] = f'attachment; filename="{filename}"'
        
        return response
        
    except Exception as e:
        return JsonResponse({
            'success': False,
            'message': f'Error exporting MPP list: {str(e)}'
        })


