@login_required(login_url='login')
def whatsapp_analytics_dashboard(request):
    """Main WhatsApp analytics dashboard - ONLY FOR ADVANCE SALE MESSAGES"""
    
    # Get active filters from request
    date_filter = request.GET.get('date_filter', '7d')
    mpp_filter = request.GET.get('mpp', '')
    status_filter = request.GET.get('status', '')
    page_size = int(request.GET.get('page_size', 10))
    
    # Calculate date range based on filter
    end_date = timezone.now()
    if date_filter == 'today':
        start_date = end_date.replace(hour=0, minute=0, second=0, microsecond=0)
    elif date_filter == 'yesterday':
        start_date = end_date - timedelta(days=1)
        start_date = start_date.replace(hour=0, minute=0, second=0, microsecond=0)
        end_date = start_date + timedelta(days=1)
    elif date_filter == '7d':
        start_date = end_date - timedelta(days=7)
    elif date_filter == '30d':
        start_date = end_date - timedelta(days=30)
    elif date_filter == '90d':
        start_date = end_date - timedelta(days=90)
    else:
        start_date = end_date - timedelta(days=7)
    
    # Base queryset - ONLY ADVANCE SALE MESSAGES
    messages = WhatsAppLog.objects.filter(
        created_at__range=[start_date, end_date],
        purpose='ADVANCE_SALE'  # CRITICAL: Only show advance sale messages
    ).order_by('-created_at')
    
    # Apply additional filters
    if mpp_filter:
        messages = messages.filter(mpp_name__icontains=mpp_filter)
    
    if status_filter:
        messages = messages.filter(status=status_filter)
    
    # Basic statistics
    total_messages = messages.count()
    read_messages = messages.filter(status='READ').count()
    delivered_messages = messages.filter(status='DELIVERED').count()
    sent_messages = messages.filter(status='SENT').count()
    failed_messages = messages.filter(status='FAILED').count()
    not_registered = messages.filter(status='NOT_REGISTERED').count()
    
    # Calculate rates
    delivery_rate = (delivered_messages / total_messages * 100) if total_messages > 0 else 0
    read_rate = (read_messages / delivered_messages * 100) if delivered_messages > 0 else 0
    
    # Time to read analysis - ONLY FOR ADVANCE SALE
    time_stats = messages.filter(
        status='READ',
        sent_at__isnull=False,
        read_at__isnull=False
    ).annotate(
        time_to_read=ExpressionWrapper(
            F('read_at') - F('sent_at'),
            output_field=DurationField()
        )
    ).aggregate(
        avg_time=Avg('time_to_read'),
        min_time=Min('time_to_read'),
        max_time=Max('time_to_read'),
        count=Count('id')
    )
    
    # Read by hour distribution - ONLY ADVANCE SALE
    read_by_hour = messages.filter(
        status='READ',
        read_at__isnull=False
    ).annotate(
        hour=ExtractHour('read_at')
    ).values('hour').annotate(
        count=Count('id')
    ).order_by('hour')
    
    # Daily trend - ONLY ADVANCE SALE
    daily_trend = messages.filter(
        status='READ',
        read_at__isnull=False
    ).annotate(
        date=TruncDate('read_at')
    ).values('date').annotate(
        count=Count('id')
    ).order_by('date')
    
    # Top MPPs by reads - ONLY ADVANCE SALE
    top_mpps = messages.filter(
        status='READ',
        mpp_name__isnull=False
    ).values('mpp_name').annotate(
        read_count=Count('id'),
        avg_time_to_read=Avg(
            ExpressionWrapper(
                F('read_at') - F('sent_at'),
                output_field=DurationField()
            )
        ),
        last_read=Max('read_at')
    ).order_by('-read_count')[:10]
    
    # Recently active MPPs (last 24 hours) - ONLY ADVANCE SALE
    recent_active = messages.filter(
        status='READ',
        read_at__gte=timezone.now() - timedelta(hours=24)
    ).values('mobile_number', 'mpp_name').annotate(
        read_count=Count('id'),
        last_read=Max('read_at')
    ).order_by('-last_read')[:15]
    
    # Never read messages (delivered but not read in 24h+) - ONLY ADVANCE SALE
    never_read = messages.filter(
        status='DELIVERED',
        delivered_at__lte=timezone.now() - timedelta(hours=24)
    ).exclude(
        mobile_number__in=messages.filter(
            status='READ',
            read_at__gte=timezone.now() - timedelta(days=7)
        ).values('mobile_number')
    ).values('mobile_number', 'mpp_name', 'delivered_at').order_by('-delivered_at')[:20]
    
    # Status distribution - ONLY ADVANCE SALE
    status_distribution = messages.values('status').annotate(
        count=Count('id')
    ).order_by('-count')
    
    # Get available MPPs for filter dropdown - ONLY THOSE WITH ADVANCE SALES
    available_mpps = WhatsAppLog.objects.filter(
        purpose='ADVANCE_SALE',
        mpp_name__isnull=False
    ).values_list('mpp_name', flat=True).distinct().order_by('mpp_name')
    
    # Paginate messages for table
    paginator = Paginator(messages, 10)
    page_number = request.GET.get('page', 1)
    page_obj = paginator.get_page(page_number)
    
    # Calculate time to read for each message in the page
    for msg in page_obj:
        if msg.sent_at and msg.read_at:
            msg.time_to_read_seconds = (msg.read_at - msg.sent_at).total_seconds()
            msg.time_to_read_minutes = msg.time_to_read_seconds / 60
        else:
            msg.time_to_read_seconds = None
            msg.time_to_read_minutes = None
    
    context = {
        'page_title': 'WhatsApp Advance Sale Analytics',
        'dashboard_note': '⚠️ Only showing ADVANCE SALE messages',
        'total_messages': total_messages,
        'read_messages': read_messages,
        'delivered_messages': delivered_messages,
        'sent_messages': sent_messages,
        'failed_messages': failed_messages,
        'not_registered': not_registered,
        'delivery_rate': round(delivery_rate, 1),
        'read_rate': round(read_rate, 1),
        'time_stats': time_stats,
        'read_by_hour': list(read_by_hour),
        'daily_trend': list(daily_trend),
        'top_mpps': list(top_mpps),
        'recent_active': list(recent_active),
        'never_read': list(never_read),
        'status_distribution': list(status_distribution),
        'available_mpps': list(available_mpps),
        'date_filter': date_filter,
        'mpp_filter': mpp_filter,
        'status_filter': status_filter,
        'page_obj': page_obj,
        'start_date': start_date,
        'end_date': end_date,
        'page_size': page_size
    }
    
    return render(request, 'whatsapp_analytics/dashboard.html', context)

@login_required(login_url='login')
def whatsapp_analytics_api(request):
    """API endpoint for real-time data and charts - ONLY ADVANCE SALE"""
    
    # Get parameters
    date_filter = request.GET.get('date_filter', '7d')
    mpp_filter = request.GET.get('mpp', '')
    
    # Calculate date range
    end_date = timezone.now()
    if date_filter == 'today':
        start_date = end_date.replace(hour=0, minute=0, second=0, microsecond=0)
    elif date_filter == 'yesterday':
        start_date = end_date - timedelta(days=1)
        start_date = start_date.replace(hour=0, minute=0, second=0, microsecond=0)
        end_date = start_date + timedelta(days=1)
    elif date_filter == '7d':
        start_date = end_date - timedelta(days=7)
    elif date_filter == '30d':
        start_date = end_date - timedelta(days=30)
    elif date_filter == '90d':
        start_date = end_date - timedelta(days=90)
    else:
        start_date = end_date - timedelta(days=7)
    
    # Base queryset - ONLY ADVANCE SALE
    messages = WhatsAppLog.objects.filter(
        created_at__range=[start_date, end_date],
        purpose='ADVANCE_SALE'  # CRITICAL: Only advance sale messages
    )
    
    if mpp_filter:
        messages = messages.filter(mpp_name__icontains=mpp_filter)
    
    # Real-time stats - ONLY ADVANCE SALE
    last_24h = messages.filter(
        status='READ',
        read_at__gte=timezone.now() - timedelta(hours=24)
    ).count()
    
    today_start = timezone.now().replace(hour=0, minute=0, second=0, microsecond=0)
    today_reads = messages.filter(
        status='READ',
        read_at__gte=today_start
    ).count()
    
    # Recently active MPPs (last 1 hour) - ONLY ADVANCE SALE
    recent_active = messages.filter(
        status='READ',
        read_at__gte=timezone.now() - timedelta(hours=1)
    ).values('mobile_number', 'mpp_name').annotate(
        read_count=Count('id'),
        last_read=Max('read_at')
    ).order_by('-last_read')[:10]
    
    # Format data for frontend
    recent_active_list = []
    for mpp in recent_active:
        time_ago = timezone.now() - mpp['last_read']
        minutes_ago = int(time_ago.total_seconds() / 60)
        
        if minutes_ago < 60:
            time_text = f"{minutes_ago}m ago"
        else:
            hours_ago = int(minutes_ago / 60)
            time_text = f"{hours_ago}h ago"
        
        recent_active_list.append({
            'mobile_number': mpp['mobile_number'],
            'mpp_name': mpp['mpp_name'],
            'read_count': mpp['read_count'],
            'last_read': mpp['last_read'].isoformat(),
            'time_ago': time_text
        })
    
    data = {
        'last_24h_reads': last_24h,
        'today_reads': today_reads,
        'recent_active': recent_active_list,
        'last_updated': timezone.now().isoformat(),
        'data_source': 'ADVANCE_SALE messages only',
        'success': True
    }
    
    return JsonResponse(data)

@login_required(login_url='login')
def whatsapp_message_detail(request):
    """Detailed message view - ONLY ADVANCE SALE"""
    
    mobile_number = request.GET.get('mobile', '')
    mpp_name = request.GET.get('mpp', '')
    
    query = Q(purpose='ADVANCE_SALE')  # CRITICAL: Only advance sale messages
    
    if mobile_number:
        query &= Q(mobile_number=mobile_number)
    if mpp_name:
        query &= Q(mpp_name__icontains=mpp_name)
    
    messages = WhatsAppLog.objects.filter(query).order_by('-created_at')[:100]
    
    # Calculate statistics for this MPP/mobile - ONLY ADVANCE SALE
    stats = messages.aggregate(
        total=Count('id'),
        read=Count('id', filter=Q(status='READ')),
        delivered=Count('id', filter=Q(status='DELIVERED')),
        failed=Count('id', filter=Q(status='FAILED')),
        avg_time_to_read=Avg(
            ExpressionWrapper(
                F('read_at') - F('sent_at'),
                output_field=DurationField()
            ),
            filter=Q(status='READ')
        )
    )
    
    context = {
        'messages': messages,
        'mobile_number': mobile_number,
        'mpp_name': mpp_name,
        'total_count': messages.count(),
        'stats': stats,
        'page_title': f'WhatsApp Advance Sale Messages - {mpp_name or mobile_number}',
        'data_note': 'Showing only ADVANCE SALE messages'
    }
    
    return render(request, 'whatsapp_analytics/message_detail.html', context)

@login_required(login_url='login')
def whatsapp_export_data(request):
    """Export WhatsApp data to CSV - ONLY ADVANCE SALE"""
    
    # Get filters
    date_filter = request.GET.get('date_filter', '7d')
    mpp_filter = request.GET.get('mpp', '')
    status_filter = request.GET.get('status', '')
    
    # Calculate date range
    end_date = timezone.now()
    if date_filter == 'today':
        start_date = end_date.replace(hour=0, minute=0, second=0, microsecond=0)
    elif date_filter == 'yesterday':
        start_date = end_date - timedelta(days=1)
        start_date = start_date.replace(hour=0, minute=0, second=0, microsecond=0)
        end_date = start_date + timedelta(days=1)
    elif date_filter == '7d':
        start_date = end_date - timedelta(days=7)
    elif date_filter == '30d':
        start_date = end_date - timedelta(days=30)
    elif date_filter == '90d':
        start_date = end_date - timedelta(days=90)
    else:
        start_date = end_date - timedelta(days=7)
    
    # Base queryset - ONLY ADVANCE SALE
    messages = WhatsAppLog.objects.filter(
        created_at__range=[start_date, end_date],
        purpose='ADVANCE_SALE'  # CRITICAL: Only advance sale messages
    ).order_by('-created_at')
    
    if mpp_filter:
        messages = messages.filter(mpp_name__icontains=mpp_filter)
    
    if status_filter:
        messages = messages.filter(status=status_filter)
    
    # Create CSV
    output = StringIO()
    writer = csv.writer(output)
    
    # Write headers
    headers = [
        'Message ID', 'Mobile Number', 'MPP Name', 'Message',
        'Status', 'Purpose', 'Sent Via', 'Created At', 'Sent At',
        'Delivered At', 'Read At', 'Time to Read (min)',
        'Unique Code', 'Advance Sale ID', 'Template Name', 'Error Message'
    ]
    writer.writerow(headers)
    
    # Write data
    for msg in messages:
        time_to_read = ''
        if msg.sent_at and msg.read_at:
            time_diff = (msg.read_at - msg.sent_at).total_seconds() / 60
            time_to_read = round(time_diff, 2)
        
        advance_sale_id = ''
        if msg.advance_sale:
            advance_sale_id = msg.advance_sale.unique_code
        
        row = [
            msg.id,
            msg.mobile_number,
            msg.mpp_name or '',
            msg.message[:100] + '...' if len(msg.message) > 100 else msg.message,
            msg.status,
            msg.purpose,  # Should always be 'ADVANCE_SALE'
            msg.sent_via,
            msg.created_at.strftime('%Y-%m-%d %H:%M:%S'),
            msg.sent_at.strftime('%Y-%m-%d %H:%M:%S') if msg.sent_at else '',
            msg.delivered_at.strftime('%Y-%m-%d %H:%M:%S') if msg.delivered_at else '',
            msg.read_at.strftime('%Y-%m-%d %H:%M:%S') if msg.read_at else '',
            time_to_read,
            msg.unique_code or '',
            advance_sale_id,
            msg.template_name or '',
            msg.error_message or ''
        ]
        writer.writerow(row)
    
    # Prepare response
    response = JsonResponse({
        'csv_data': output.getvalue(),
        'count': messages.count(),
        'filename': f'advance_sale_whatsapp_analytics_{datetime.now().strftime("%Y%m%d_%H%M%S")}.csv',
        'note': 'Only includes ADVANCE_SALE messages'
    })
    
    return response

@login_required(login_url='login')
def whatsapp_get_insights(request):
    """Get advanced insights and recommendations - ONLY ADVANCE SALE"""
    
    # Get last 30 days data - ONLY ADVANCE SALE
    thirty_days_ago = timezone.now() - timedelta(days=30)
    
    # Overall stats - ONLY ADVANCE SALE
    total_messages = WhatsAppLog.objects.filter(
        created_at__gte=thirty_days_ago,
        purpose='ADVANCE_SALE'
    ).count()
    
    read_messages = WhatsAppLog.objects.filter(
        status='READ',
        read_at__gte=thirty_days_ago,
        purpose='ADVANCE_SALE'
    ).count()
    
    # Read time analysis - ONLY ADVANCE SALE
    read_time_stats = WhatsAppLog.objects.filter(
        status='READ',
        sent_at__isnull=False,
        read_at__isnull=False,
        read_at__gte=thirty_days_ago,
        purpose='ADVANCE_SALE'
    ).annotate(
        time_to_read=ExpressionWrapper(
            F('read_at') - F('sent_at'),
            output_field=DurationField()
        )
    ).aggregate(
        avg_time=Avg('time_to_read'),
        median_time=Avg('time_to_read'),  # Simplified median
        percentile_90=Avg('time_to_read')  # Simplified percentile
    )
    
    # Best time to send - ONLY ADVANCE SALE
    best_hours = WhatsAppLog.objects.filter(
        status='READ',
        read_at__gte=thirty_days_ago,
        purpose='ADVANCE_SALE'
    ).annotate(
        hour=ExtractHour('read_at')
    ).values('hour').annotate(
        read_count=Count('id')
    ).order_by('-read_count')[:3]
    
    # Problematic MPPs (never read) - ONLY ADVANCE SALE
    problematic_mpps = WhatsAppLog.objects.filter(
        status='DELIVERED',
        delivered_at__lte=timezone.now() - timedelta(days=7),
        purpose='ADVANCE_SALE'
    ).exclude(
        mobile_number__in=WhatsAppLog.objects.filter(
            status='READ',
            read_at__gte=timezone.now() - timedelta(days=7),
            purpose='ADVANCE_SALE'
        ).values('mobile_number')
    ).values('mpp_name', 'mobile_number').annotate(
        count=Count('id'),
        last_delivered=Max('delivered_at')
    ).order_by('-count')[:10]
    
    # Calculate read rate
    read_rate = round((read_messages / total_messages * 100), 1) if total_messages > 0 else 0
    
    # Calculate average read time
    avg_read_time_minutes = 0
    if read_time_stats['avg_time']:
        avg_read_time_minutes = round(read_time_stats['avg_time'].total_seconds() / 60, 1)
    
    # Format best hours
    best_hours_list = []
    for hour in best_hours:
        if hour['read_count'] > 0:
            best_hours_list.append(f"{hour['hour']}:00 ({hour['read_count']} reads)")
    
    insights = {
        'overall_read_rate': read_rate,
        'avg_read_time_minutes': avg_read_time_minutes,
        'best_sending_hours': best_hours_list if best_hours_list else ["Collect more data for timing recommendations"],
        'problematic_mpps_count': len(problematic_mpps),
        'total_advance_sales_tracked': total_messages,
        'recommendations': [
            f"Best engagement time: {best_hours_list[0]}" if best_hours_list else "Send test messages to find optimal timing",
            f"Follow up with {len(problematic_mpps)} MPPs who haven't read advance sale messages in 7+ days",
            "Consider sending reminder messages 24 hours after delivery if not read",
            f"Current read rate: {read_rate}% - target 70%+"
        ]
    }
    
    return JsonResponse({
        'success': True,
        'insights': insights,
        'problematic_mpps': list(problematic_mpps),
        'data_source': 'ADVANCE_SALE messages only (last 30 days)'
    })

@login_required(login_url='login')
def whatsapp_analytics_data_api(request):
    """API endpoint for dashboard JSON data - ONLY ADVANCE SALE"""
    
    # Get parameters
    date_filter = request.GET.get('date_filter', '7d')
    mpp_filter = request.GET.get('mpp', '')
    status_filter = request.GET.get('status', '')
    page = int(request.GET.get('page', 1))
    page_size = int(request.GET.get('page_size', 10))
    
    # Calculate date range based on filter
    end_date = timezone.now()
    if date_filter == 'today':
        start_date = end_date.replace(hour=0, minute=0, second=0, microsecond=0)
    elif date_filter == 'yesterday':
        start_date = end_date - timedelta(days=1)
        start_date = start_date.replace(hour=0, minute=0, second=0, microsecond=0)
        end_date = start_date + timedelta(days=1)
    elif date_filter == '7d':
        start_date = end_date - timedelta(days=7)
    elif date_filter == '30d':
        start_date = end_date - timedelta(days=30)
    elif date_filter == '90d':
        start_date = end_date - timedelta(days=90)
    else:
        start_date = end_date - timedelta(days=7)
    
    # Base queryset - ONLY ADVANCE SALE
    messages = WhatsAppLog.objects.filter(
        created_at__range=[start_date, end_date],
        purpose='ADVANCE_SALE'  # CRITICAL: Only advance sale messages
    ).order_by('-created_at')
    
    # Apply additional filters
    if mpp_filter:
        messages = messages.filter(mpp_name__icontains=mpp_filter)
    
    if status_filter:
        messages = messages.filter(status=status_filter)
    
    # Pagination
    paginator = Paginator(messages, page_size)
    try:
        page_obj = paginator.page(page)
    except EmptyPage:
        page_obj = paginator.page(paginator.num_pages)
    
    # Basic statistics
    total_messages = messages.count()
    read_messages = messages.filter(status='READ').count()
    delivered_messages = messages.filter(status='DELIVERED').count()
    
    # Calculate read rate
    read_rate = (read_messages / delivered_messages * 100) if delivered_messages > 0 else 0
    
    # Read by hour distribution - ONLY ADVANCE SALE
    read_by_hour = messages.filter(
        status='READ',
        read_at__isnull=False
    ).annotate(
        hour=ExtractHour('read_at')
    ).values('hour').annotate(
        count=Count('id')
    ).order_by('hour')
    
    # Status distribution - ONLY ADVANCE SALE
    status_distribution = messages.values('status').annotate(
        count=Count('id')
    ).order_by('-count')
    
    # Top MPPs by reads - ONLY ADVANCE SALE
    top_mpps = messages.filter(
        status='READ',
        mpp_name__isnull=False
    ).values('mpp_name').annotate(
        read_count=Count('id'),
        avg_time_to_read=Avg(
            ExpressionWrapper(
                F('read_at') - F('sent_at'),
                output_field=DurationField()
            )
        ),
        last_read=Max('read_at')
    ).order_by('-read_count')[:10]
    
    # Never read messages (delivered but not read in 24h+) - ONLY ADVANCE SALE
    never_read = messages.filter(
        status='DELIVERED',
        delivered_at__lte=timezone.now() - timedelta(hours=24)
    ).exclude(
        mobile_number__in=messages.filter(
            status='READ',
            read_at__gte=timezone.now() - timedelta(days=7)
        ).values('mobile_number')
    ).values('mobile_number', 'mpp_name', 'delivered_at').order_by('-delivered_at')[:20]
    
    # Format messages for JSON
    messages_list = []
    for msg in page_obj.object_list:
        # Calculate time to read if available
        time_to_read = None
        if msg.sent_at and msg.read_at:
            time_to_read = round((msg.read_at - msg.sent_at).total_seconds() / 60, 1)
        
        advance_sale_info = ''
        if msg.advance_sale:
            advance_sale_info = f"Sale: {msg.advance_sale.unique_code}"
        
        messages_list.append({
            'id': msg.id,
            'mobile_number': msg.mobile_number,
            'mpp_name': msg.mpp_name,
            'message': msg.message[:100] + '...' if len(msg.message) > 100 else msg.message,
            'status': msg.status,
            'purpose': msg.purpose,
            'advance_sale_info': advance_sale_info,
            'created_at': msg.created_at.isoformat() if msg.created_at else None,
            'sent_at': msg.sent_at.isoformat() if msg.sent_at else None,
            'read_at': msg.read_at.isoformat() if msg.read_at else None,
            'delivered_at': msg.delivered_at.isoformat() if msg.delivered_at else None,
            'time_to_read_minutes': time_to_read,
        })
    
    # Format chart data
    chart_data = {
        'read_by_hour': list(read_by_hour),
        'status_distribution': list(status_distribution)
    }
    
    # Format insights
    insights_data = {
        'top_mpps': list(top_mpps),
        'never_read': list(never_read)
    }
    
    response_data = {
        'success': True,
        'stats': {
            'total_messages': total_messages,
            'read_messages': read_messages,
            'delivered_messages': delivered_messages,
            'read_rate': round(read_rate, 1),
            'data_source': 'ADVANCE_SALE messages only'
        },
        'chart_data': chart_data,
        'insights': insights_data,
        'messages': messages_list,
        'total_count': paginator.count,
        'page': page_obj.number,
        'total_pages': paginator.num_pages,
        'page_size': page_size,
        'start_index': page_obj.start_index(),
        'end_index': page_obj.end_index(),
        'filters_applied': {
            'date_filter': date_filter,
            'mpp_filter': mpp_filter,
            'status_filter': status_filter
        }
    }
    
    return JsonResponse(response_data)

