@login_required
def whatsapp_advance_sale_summary(request):
    """Special view to show advance sale summary with WhatsApp stats"""
    
    # Get filters
    date_filter = request.GET.get('date_filter', '30d')
    
    # Calculate date range
    end_date = timezone.now()
    if date_filter == '7d':
        start_date = end_date - timedelta(days=7)
    elif date_filter == '30d':
        start_date = end_date - timedelta(days=30)
    elif date_filter == '90d':
        start_date = end_date - timedelta(days=90)
    else:
        start_date = end_date - timedelta(days=30)
    
    # Get all advance sales in date range
    advance_sales = AdvanceSale.objects.filter(
        sale_date__range=[start_date.date(), end_date.date()]
    ).order_by('-sale_date')
    
    # Get WhatsApp stats for each advance sale
    sales_with_stats = []
    for sale in advance_sales:
        whatsapp_logs = WhatsAppLog.objects.filter(
            advance_sale=sale,
            purpose='ADVANCE_SALE'
        )
        
        stats = whatsapp_logs.aggregate(
            total=Count('id'),
            read=Count('id', filter=Q(status='READ')),
            delivered=Count('id', filter=Q(status='DELIVERED')),
            sent=Count('id', filter=Q(status='SENT')),
            failed=Count('id', filter=Q(status='FAILED'))
        )
        
        read_rate = 0
        if stats['delivered'] > 0:
            read_rate = round((stats['read'] / stats['delivered']) * 100, 1)
        
        sales_with_stats.append({
            'sale': sale,
            'stats': stats,
            'read_rate': read_rate,
            'has_whatsapp_logs': stats['total'] > 0
        })
    
    # Calculate overall stats
    total_sales = advance_sales.count()
    sales_with_whatsapp = len([s for s in sales_with_stats if s['has_whatsapp_logs']])
    
    context = {
        'page_title': 'Advance Sale WhatsApp Summary',
        'sales_with_stats': sales_with_stats,
        'total_sales': total_sales,
        'sales_with_whatsapp': sales_with_whatsapp,
        'date_filter': date_filter,
        'start_date': start_date,
        'end_date': end_date
    }
    
    return render(request, 'whatsapp_analytics/advance_sale_summary.html', context)

