@login_required(login_url='login')
def process_final_reconciliation(request):
    """Process uploaded final reconciliation sheet"""
    if not request.user.is_finance:
        return JsonResponse({'success': False, 'message': 'Unauthorized'})
    
    if request.method == 'POST' and request.FILES.get('reconciliation_file'):
        try:
            file = request.FILES['reconciliation_file']
            month = request.POST.get('month')
            year = request.POST.get('year')
            cycle_id = request.POST.get('cycle')
            notes = request.POST.get('notes', '')
            
            # Validate inputs
            if not month or not year or not cycle_id:
                return JsonResponse({
                    'success': False,
                    'message': 'Please select month, year, and cycle'
                })
            
            # Get cycle
            try:
                cycle = Cycle.objects.get(id=cycle_id)
                monthly_cycle = cycle.monthly_cycle
            except Cycle.DoesNotExist:
                return JsonResponse({
                    'success': False,
                    'message': 'Invalid cycle selected'
                })
            
            # Create reconciliation sheet record
            reconciliation_sheet = ReconciliationSheet.objects.create(
                uploaded_by=request.user,
                file_name=file.name,
                monthly_cycle=monthly_cycle,
                cycle=cycle,
                excel_file=file,
                status='UPLOADED'
            )
            
            # Process the file
            success, message = process_reconciliation_file(reconciliation_sheet)
            
            if success:
                return JsonResponse({
                    'success': True,
                    'message': 'Reconciliation sheet processed successfully',
                    'sheet_id': reconciliation_sheet.id,
                    'redirect_url': f'/finance/reconciliation-sheet/{reconciliation_sheet.id}/'
                })
            else:
                reconciliation_sheet.status = 'FAILED'
                reconciliation_sheet.save()
                return JsonResponse({
                    'success': False,
                    'message': f'Processing failed: {message}'
                })
                
        except Exception as e:
            return JsonResponse({
                'success': False,
                'message': f'Error processing file: {str(e)}'
            })
    
    return JsonResponse({
        'success': False,
        'message': 'Invalid request'
    })


def process_reconciliation_file(reconciliation_sheet):
    """Process the uploaded reconciliation Excel file with CUMULATIVE LEDGER SYSTEM"""
    try:
        import pandas as pd
        from django.db import transaction
        from datetime import datetime
        
        # Read Excel file
        df = pd.read_excel(reconciliation_sheet.excel_file.path)
        
        # Print debug info
        print("📊 Excel columns found:", df.columns.tolist())
        print("📊 First few rows:")
        print(df.head())
        
        # Standardize column names
        df.columns = df.columns.str.strip()
        
        # Define column mappings with flexible matching
        column_mappings = {
            'Location': ['Location'],
            'MPP Code': ['MPP Code', 'Mpp Code', 'Mppcode'],
            'MPP Name': ['MPP Name', 'Mpp Name', 'Mppname'],
            'Product': ['Product', 'Product Name', 'Stock Item'],
            'Advance Sale Qty': ['Advance Sale Qty', 'Advance Sale', 'Advance Qty'],
            'SAP Entry Qty': ['SAP Entry Qty', 'SAP Entry', 'SAP Qty'],
            'Status': ['Status'],
            'Match Quality': ['Match Quality', 'Match'],
            'To Be Sent To MPP': ['To Be Sent To MPP', 'To be sent to MPP', 'To Send To MPP', 'Send To MPP'],
            'To Be Deducted': ['To Be Deducted', 'To be deducted', 'To Deduct', 'Deduct']
        }
        
        # Create a mapping of actual column names to standardized names
        column_mapping_dict = {}
        available_columns = df.columns.tolist()
        
        for standard_name, possible_names in column_mappings.items():
            for actual_name in available_columns:
                if any(possible.lower() in actual_name.lower() for possible in possible_names):
                    column_mapping_dict[actual_name] = standard_name
                    break
        
        # Check if we found all required columns
        required_columns = [
            'Location', 'MPP Code', 'MPP Name', 'Product', 
            'Advance Sale Qty', 'SAP Entry Qty', 'Status', 
            'Match Quality', 'To Be Sent To MPP', 'To Be Deducted'
        ]
        
        missing_columns = []
        for col in required_columns:
            if col not in column_mapping_dict.values():
                missing_columns.append(col)
        
        if missing_columns:
            return False, f"Missing columns: {', '.join(missing_columns)}. Available columns: {', '.join(available_columns)}"
        
        # Rename columns to standardized names
        df.rename(columns=column_mapping_dict, inplace=True)
        
        # Clean data - handle NaN values
        df = df.fillna({
            'To Be Sent To MPP': 0, 
            'To Be Deducted': 0,
            'Advance Sale Qty': 0,
            'SAP Entry Qty': 0,
            'Status': '',
            'Match Quality': '',
            'Location': '',
            'MPP Code': '',
            'MPP Name': '',
            'Product': ''
        })
        
        # Convert numeric columns
        numeric_columns = ['Advance Sale Qty', 'SAP Entry Qty', 'To Be Sent To MPP', 'To Be Deducted']
        for col in numeric_columns:
            df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0).astype(int)
        
        with transaction.atomic():
            total_records = 0
            over_recorded_count = 0
            under_recorded_count = 0
            perfect_match_count = 0
            not_recorded_count = 0
            
            # Process each row
            for index, row in df.iterrows():
                # Skip empty rows
                if not str(row.get('Location')).strip() and not str(row.get('MPP Code')).strip():
                    continue
                    
                total_records += 1
                
                # Get values with error handling
                location = str(row['Location']).strip() if pd.notna(row['Location']) else ''
                mpp_code = str(row['MPP Code']).strip() if pd.notna(row['MPP Code']) else ''
                mpp_name = str(row['MPP Name']).strip() if pd.notna(row['MPP Name']) else ''
                product_name = str(row['Product']).strip() if pd.notna(row['Product']) else ''
                
                # Get quantities
                advance_qty = int(row['Advance Sale Qty'])
                sap_qty = int(row['SAP Entry Qty'])
                to_send = int(row['To Be Sent To MPP'])
                to_deduct = int(row['To Be Deducted'])
                
                status_text = str(row['Status']).strip() if pd.notna(row['Status']) else ''
                match_quality = str(row['Match Quality']).strip() if pd.notna(row['Match Quality']) else ''
                
                # Get MPP
                mpp = None
                if mpp_code:
                    try:
                        # Try exact match first
                        mpp = MPPWithCode.objects.filter(
                            mpp_transaction_code=mpp_code
                        ).first()
                        # If not found, try partial match
                        if not mpp and mpp_name:
                            mpp = MPPWithCode.objects.filter(
                                name_with_code__icontains=mpp_name
                            ).first()
                    except Exception as e:
                        print(f"Error finding MPP: {e}")
                        pass
                
                # Get Product
                product = None
                if product_name and product_name.strip():
                    try:
                        # Clean product name
                        clean_product_name = product_name.strip().lower()
                        
                        # First try exact name match
                        product = Product.objects.filter(
                            name__iexact=clean_product_name
                        ).first()
                        
                        # If not found, try partial match
                        if not product:
                            product = Product.objects.filter(
                                name__icontains=clean_product_name
                            ).first()
                        
                        # If still not found, try splitting and matching
                        if not product:
                            # Try to match without special characters
                            words = clean_product_name.split()
                            for word in words:
                                if len(word) > 3:  # Only meaningful words
                                    product = Product.objects.filter(
                                        name__icontains=word
                                    ).first()
                                    if product:
                                        break
                        
                    except Exception as e:
                        print(f"Error finding product '{product_name}': {e}")
                        product = None
                
                # Get status - FIXED: Preserve NOT_RECORDED
                status = get_status_code(status_text)
                
                # Update counters based on status
                if status == 'OVER_RECORDED':
                    over_recorded_count += 1
                elif status == 'UNDER_RECORDED':
                    under_recorded_count += 1
                elif status == 'PERFECT_MATCH':
                    perfect_match_count += 1
                elif status == 'NOT_RECORDED':
                    not_recorded_count += 1
                
                # Create reconciliation record
                try:
                    reconciliation_record = ReconciliationRecord.objects.create(
                        reconciliation_sheet=reconciliation_sheet,
                        location=location,
                        mpp_code=mpp_code,
                        mpp_name=mpp_name,
                        mpp=mpp,
                        product_name=product_name,
                        product=product,  # This can be None
                        advance_sale_qty=advance_qty,
                        sap_entry_qty=sap_qty,
                        status=status,
                        match_quality=match_quality,
                        to_be_sent_to_mpp=to_send,
                        to_be_deducted=to_deduct
                    )
                except Exception as e:
                    print(f"❌ Error creating reconciliation record: {e}")
                    print(f"Row data: Location={location}, MPP={mpp_code}, Product={product_name}")
                    raise
                
                # FIXED: SKIP NOT_RECORDED entries from ledger processing
                if status == 'NOT_RECORDED':
                    print(f"⚠️ Skipping NOT_RECORDED entry: {mpp_code} - {product_name}")
                    # Mark as processed but don't update ledger
                    reconciliation_record.is_processed = True
                    reconciliation_record.processed_at = datetime.now()
                    reconciliation_record.save()
                    continue  # Skip to next row
                
                # Process CUMULATIVE LEDGER for MPP+Product+Cycle (ONLY for non-NOT_RECORDED)
                if product and mpp:
                    process_mpp_product_ledger(reconciliation_record, reconciliation_sheet.cycle)
                
                # Process actions - Only if product exists and is NOT a service
                if product and not reconciliation_record.is_service:
                    process_reconciliation_actions(reconciliation_record, reconciliation_sheet.cycle)
                elif not product:
                    print(f"⚠️ Skipping actions for '{product_name}' - product not found in database")
            
            # Update sheet statistics
            reconciliation_sheet.total_records = total_records
            reconciliation_sheet.over_recorded_count = over_recorded_count
            reconciliation_sheet.under_recorded_count = under_recorded_count
            reconciliation_sheet.perfect_match_count = perfect_match_count
            reconciliation_sheet.not_recorded_count = not_recorded_count
            reconciliation_sheet.status = 'PROCESSED'
            reconciliation_sheet.processed_at = datetime.now()
            reconciliation_sheet.save()
            
            # Create notifications (excluding NOT_RECORDED records)
            create_location_notifications(reconciliation_sheet)
            
            return True, f"Processed {total_records} records successfully ({not_recorded_count} NOT_RECORDED skipped)"
            
    except Exception as e:
        import traceback
        error_details = traceback.format_exc()
        print(f"❌ Error processing reconciliation file: {str(e)}")
        print(error_details)
        return False, f"Error: {str(e)}"


def get_status_code(status_text):
    """Convert status text to status code - FIXED: Preserve NOT_RECORDED"""
    if not status_text:
        return 'OVER_RECORDED'
    
    status_text = status_text.strip().upper()
    
    # First check for NOT RECORDED
    if 'NOT RECORDED' in status_text or 'NOT_RECORDED' in status_text:
        return 'NOT_RECORDED'
    
    status_map = {
        'OVER RECORDED': 'OVER_RECORDED',
        'OVER_RECORDED': 'OVER_RECORDED',
        'UNDER RECORDED': 'UNDER_RECORDED',
        'UNDER_RECORDED': 'UNDER_RECORDED',
        'PERFECT MATCH': 'PERFECT_MATCH',
        'PERFECT_MATCH': 'PERFECT_MATCH',
        'NOT RECORDED': 'NOT_RECORDED',
        'NOT_RECORDED': 'NOT_RECORDED'
    }
    
    return status_map.get(status_text, 'OVER_RECORDED')


def process_mpp_product_ledger(record, cycle):
    """Process cumulative ledger for MPP+Product+Cycle combination - FIXED"""
    if not record.mpp or not record.product:
        return
    
    # Skip NOT_RECORDED entries
    if record.status == 'NOT_RECORDED':
        print(f"⚠️ Skipping ledger for NOT_RECORDED: {record.mpp.name_with_code} - {record.product.name}")
        return
    
    try:
        # Get opening balance from previous cycle
        opening_balance = get_mpp_product_opening_balance(cycle, record.mpp, record.product)
        
        print(f"📊 Processing ledger for {record.mpp.name_with_code} - {record.product.name}")
        print(f"   Cycle: {cycle.name}")
        print(f"   Opening balance: {opening_balance}")
        print(f"   Current Advance (Sent): {record.advance_sale_qty}, SAP (Deducted): {record.sap_entry_qty}")
        
        # FIXED: Calculate current difference
        current_difference = record.advance_sale_qty - record.sap_entry_qty
        
        # FIXED: Closing balance calculation
        # opening + advance - sap
        closing_balance = opening_balance + record.advance_sale_qty - record.sap_entry_qty
        
        print(f"   Current Diff (Advance - SAP): {current_difference}")
        print(f"   Closing Balance (opening + advance - sap): {opening_balance} + {record.advance_sale_qty} - {record.sap_entry_qty} = {closing_balance}")
        
        # Get or create ledger entry
        ledger, created = MPPProductLedger.objects.get_or_create(
            mpp=record.mpp,
            product=record.product,
            cycle=cycle,
            defaults={
                'opening_balance': opening_balance,
                'current_advance_sale': record.advance_sale_qty,
                'current_sap_entry': record.sap_entry_qty,
                'current_difference': current_difference,
                'closing_balance': closing_balance,
                'reconciliation_record': record
            }
        )
        
        if not created:
            # Update existing ledger
            ledger.opening_balance = opening_balance
            ledger.current_advance_sale = record.advance_sale_qty
            ledger.current_sap_entry = record.sap_entry_qty
            ledger.current_difference = current_difference
            ledger.closing_balance = closing_balance
            ledger.reconciliation_record = record
            ledger.save()
        
        # Update reconciliation record with FIXED logic
        update_record_with_cumulative_logic(record, ledger)
        
        # Create next cycle ledger
        print(f"   Creating next cycle ledger with opening balance: {ledger.closing_balance}")
        next_ledger = ledger.create_next_cycle_ledger()
        if next_ledger:
            print(f"   ✅ Created ledger for next cycle: Cycle {next_ledger.cycle.cycle_number}")
        
    except Exception as e:
        print(f"❌ Error processing MPP product ledger: {str(e)}")
        import traceback
        traceback.print_exc()
        
def update_record_with_cumulative_logic(record, ledger):
    """Update reconciliation record with CUMULATIVE logic - FIXED"""
    if record.status == 'NOT_RECORDED':
        return
    
    try:
        # FIXED: Calculate cumulative balance correctly
        # Opening + Advance - SAP
        cumulative_balance = ledger.opening_balance + ledger.current_advance_sale - ledger.current_sap_entry
        
        print(f"📝 Updating record with FIXED CUMULATIVE logic:")
        print(f"   Opening: {ledger.opening_balance}")
        print(f"   Advance (Sent to MPP): {ledger.current_advance_sale}")
        print(f"   SAP (Deducted from MPP): {ledger.current_sap_entry}")
        print(f"   Cumulative (opening + advance - sap): {cumulative_balance}")
        
        # Update based on FIXED CUMULATIVE balance
        if cumulative_balance > 0:
            # Positive balance = MPP owes us (to be deducted from MPP)
            record.to_be_deducted = cumulative_balance
            record.to_be_sent_to_mpp = 0
            record.status = 'UNDER_RECORDED'
            print(f"   FIXED CUMULATIVE: MPP owes us {cumulative_balance} (to be deducted)")
        elif cumulative_balance < 0:
            # Negative balance = We owe MPP (to be sent to MPP)
            record.to_be_sent_to_mpp = abs(cumulative_balance)
            record.to_be_deducted = 0
            record.status = 'OVER_RECORDED'
            print(f"   FIXED CUMULATIVE: We owe MPP {abs(cumulative_balance)} (to be sent)")
        else:
            # Zero balance = Perfect reconciliation
            record.to_be_sent_to_mpp = 0
            record.to_be_deducted = 0
            record.status = 'PERFECT_MATCH'
            print(f"   FIXED CUMULATIVE: Perfect reconciliation")
        
        # Update match quality to show correct calculation
        record.match_quality = f"Cumulative: {ledger.opening_balance} + {ledger.current_advance_sale} - {ledger.current_sap_entry} = {cumulative_balance}"
        
        record.save()
        
    except Exception as e:
        print(f"❌ Error updating record: {str(e)}")



def get_mpp_product_opening_balance(current_cycle, mpp, product):
    """Get opening balance for MPP+Product from previous cycle - FIXED for cross-month continuity"""
    try:
        print(f"🔍 Looking for opening balance for {mpp.name_with_code} - {product.name}")
        print(f"   Current cycle: {current_cycle.name} ({current_cycle.monthly_cycle.month} {current_cycle.monthly_cycle.year})")
        
        # First, try to find previous cycle in SAME monthly cycle
        previous_cycle = Cycle.objects.filter(
            monthly_cycle=current_cycle.monthly_cycle,
            cycle_number=current_cycle.cycle_number - 1
        ).first()
        
        if previous_cycle:
            print(f"   Found previous cycle in same month: {previous_cycle.name}")
            previous_ledger = MPPProductLedger.objects.filter(
                mpp=mpp,
                product=product,
                cycle=previous_cycle
            ).first()
            
            if previous_ledger:
                opening_balance = previous_ledger.closing_balance
                print(f"   Previous ledger found in same month. Opening balance: {opening_balance}")
                return opening_balance
            else:
                print(f"   No previous ledger found in same month.")
        else:
            print(f"   No previous cycle in same month. Checking if this is the first cycle of the month.")
        
        # If no previous cycle in same month, check if this is cycle 1
        # If yes, we need to look for the LAST cycle of the PREVIOUS month
        if current_cycle.cycle_number == 1:
            print(f"   This is Cycle 1. Looking for closing balance from last month...")
            
            # Get the current month's monthly cycle
            current_monthly_cycle = current_cycle.monthly_cycle
            
            # Find the previous month
            month_order = ['January', 'February', 'March', 'April', 'May', 'June',
                          'July', 'August', 'September', 'October', 'November', 'December']
            
            current_month_index = month_order.index(current_monthly_cycle.month)
            previous_month_name = month_order[(current_month_index - 1) % 12]
            
            # Adjust year if going from January to December
            previous_year = current_monthly_cycle.year
            if current_monthly_cycle.month == 'January':
                previous_year -= 1
            
            print(f"   Looking for previous month: {previous_month_name} {previous_year}")
            
            # Find the monthly cycle for previous month
            previous_monthly_cycle = MonthlyCycle.objects.filter(
                month=previous_month_name,
                year=previous_year
            ).first()
            
            if previous_monthly_cycle:
                print(f"   Found previous monthly cycle: {previous_monthly_cycle.month} {previous_monthly_cycle.year}")
                
                # Find the LAST cycle of the previous month
                last_cycle_of_previous_month = Cycle.objects.filter(
                    monthly_cycle=previous_monthly_cycle
                ).order_by('-cycle_number').first()
                
                if last_cycle_of_previous_month:
                    print(f"   Found last cycle of previous month: {last_cycle_of_previous_month.name}")
                    
                    # Get the ledger from the last cycle of previous month
                    previous_ledger = MPPProductLedger.objects.filter(
                        mpp=mpp,
                        product=product,
                        cycle=last_cycle_of_previous_month
                    ).first()
                    
                    if previous_ledger:
                        opening_balance = previous_ledger.closing_balance
                        print(f"   Found ledger from last cycle of previous month. Opening balance: {opening_balance}")
                        return opening_balance
                    else:
                        print(f"   No ledger found for last cycle of previous month.")
                else:
                    print(f"   No cycles found in previous month.")
            else:
                print(f"   No monthly cycle found for previous month.")
        
        print(f"   Returning 0 as opening balance (no previous data found)")
        return 0  # No previous cycle or ledger entry
        
    except Exception as e:
        print(f"❌ Error getting opening balance: {e}")
        import traceback
        traceback.print_exc()
        return 0


def update_record_with_cumulative_data(record, ledger):
    """Update reconciliation record with cumulative calculations"""
    # Don't update NOT_RECORDED records
    if record.status == 'NOT_RECORDED':
        print(f"⚠️ Skipping cumulative update for NOT_RECORDED record")
        return
    
    try:
        # Calculate CUMULATIVE status based on opening balance + current difference
        cumulative_difference = ledger.opening_balance + ledger.current_difference
        
        print(f"📝 Updating record with cumulative data:")
        print(f"   Opening: {ledger.opening_balance}")
        print(f"   Current Diff: {ledger.current_difference}")
        print(f"   Cumulative Diff: {cumulative_difference}")
        print(f"   Previous To Send: {record.to_be_sent_to_mpp}")
        print(f"   Previous To Deduct: {record.to_be_deducted}")
        
        # Update Excel's "To Be Sent To MPP" and "To Be Deducted" based on CUMULATIVE balance
        if cumulative_difference > 0:
            # Positive cumulative balance = To be sent to MPP
            record.to_be_sent_to_mpp = cumulative_difference
            record.to_be_deducted = 0
            print(f"   CUMULATIVE: To be sent to MPP: {cumulative_difference}")
        elif cumulative_difference < 0:
            # Negative cumulative balance = To be deducted
            record.to_be_deducted = abs(cumulative_difference)
            record.to_be_sent_to_mpp = 0
            print(f"   CUMULATIVE: To be deducted: {abs(cumulative_difference)}")
        else:
            # Zero balance = Perfect match
            record.to_be_sent_to_mpp = 0
            record.to_be_deducted = 0
            print(f"   CUMULATIVE: Perfect match")
        
        # Update status based on CUMULATIVE difference
        old_status = record.status
        if cumulative_difference > 0:
            record.status = 'OVER_RECORDED'  # SAP > Advance cumulatively
        elif cumulative_difference < 0:
            record.status = 'UNDER_RECORDED'  # SAP < Advance cumulatively
        else:
            record.status = 'PERFECT_MATCH'
        
        print(f"   Status updated: {old_status} → {record.status}")
        
        # Update match quality to show cumulative calculation
        if cumulative_difference != 0:
            record.match_quality = f"Cumulative: {ledger.opening_balance} + ({ledger.current_sap_entry} - {ledger.current_advance_sale}) = {cumulative_difference}"
        else:
            record.match_quality = "Cumulative Perfect Match"
        
        # Save the record
        record.save()
        
        print(f"   ✅ Record updated successfully")
        
    except Exception as e:
        print(f"❌ Error updating record with cumulative data: {str(e)}")


def process_reconciliation_actions(record, cycle):
    """Process actions based on reconciliation record - FIXED: Skip NOT_RECORDED and services"""
    # Skip if no product, if it's a service, or if it's NOT_RECORDED
    if not record.product or record.is_service or record.status == 'NOT_RECORDED':
        print(f"⚠️ Skipping actions for record {record.id} - {'NOT_RECORDED' if record.status == 'NOT_RECORDED' else 'service' if record.is_service else 'no product'}")
        return
    
    try:
        # Update CycleLedger (product-level summary)
        cycle_ledger, created = CycleLedger.objects.get_or_create(
            cycle=cycle,
            product=record.product,
            defaults={
                'opening_balance': get_opening_balance(cycle, record.product),
                'advance_sale_qty': record.advance_sale_qty,
                'sap_entry_qty': record.sap_entry_qty
            }
        )
        
        if not created:
            # Add to existing cycle ledger
            cycle_ledger.advance_sale_qty += record.advance_sale_qty
            cycle_ledger.sap_entry_qty += record.sap_entry_qty
            cycle_ledger.save()
        
        # Create GeneralSale ONLY for products that need to be sent to MPP
        # Use cumulative to_be_sent_to_mpp from updated record
        if record.to_be_sent_to_mpp > 0 and record.mpp:
            print(f"🛒 Creating GeneralSale: {record.mpp.name_with_code} - {record.product.name}: {record.to_be_sent_to_mpp}")
            
            # Check if GeneralSale already exists for this record
            existing_sale = GeneralSale.objects.filter(
                reconciliation_record=record,
                mpp=record.mpp,
                product=record.product,
                cycle=cycle
            ).first()
            
            if existing_sale:
                # Update existing sale
                existing_sale.quantity = record.to_be_sent_to_mpp
                existing_sale.save()
                print(f"   Updated existing GeneralSale #{existing_sale.id}")
            else:
                # Create new GeneralSale
                try:
                    GeneralSale.objects.create(
                        reconciliation_record=record,
                        location=record.location,
                        mpp=record.mpp,
                        product=record.product,
                        quantity=record.to_be_sent_to_mpp,
                        cycle=cycle,
                        status='PENDING'
                    )
                    print(f"   ✅ Created new GeneralSale")
                except Exception as e:
                    print(f"❌ Error creating GeneralSale: {e}")
                    # Check if it's a migration issue
                    if "doesn't exist" in str(e):
                        print("⚠️ Database table doesn't exist. Please run migrations!")
                        print("   Run: python manage.py makemigrations main_app")
                        print("   Run: python manage.py migrate")
    
        # Mark record as processed
        record.is_processed = True
        record.processed_at = datetime.now()
        record.save()
        
    except Exception as e:
        print(f"❌ Error in process_reconciliation_actions: {e}")
        import traceback
        traceback.print_exc()
        
def initialize_cycle_ledgers(cycle):
    """Initialize ledger entries for all MPPs and products at the start of a new cycle"""
    
    try:
        print(f"🚀 Initializing ledger entries for {cycle.name}")
        
        # Get previous cycle
        previous_cycle = Cycle.objects.filter(
            monthly_cycle=cycle.monthly_cycle,
            cycle_number=cycle.cycle_number - 1
        ).first()
        
        with transaction.atomic():
            # If previous cycle exists, carry over closing balances
            if previous_cycle:
                print(f"   Found previous cycle: {previous_cycle.name}")
                
                # Get all ledger entries from previous cycle
                previous_ledgers = MPPProductLedger.objects.filter(
                    cycle=previous_cycle,
                    closing_balance__isnull=False
                ).select_related('mpp', 'product')
                
                created_count = 0
                for prev_ledger in previous_ledgers:
                    # Create new ledger for current cycle with opening balance = previous closing balance
                    MPPProductLedger.objects.get_or_create(
                        mpp=prev_ledger.mpp,
                        product=prev_ledger.product,
                        cycle=cycle,
                        defaults={
                            'opening_balance': prev_ledger.closing_balance,
                            'current_advance_sale': 0,
                            'current_sap_entry': 0,
                            'current_difference': 0,
                            'closing_balance': prev_ledger.closing_balance,
                            'is_reconciled': False
                        }
                    )
                    created_count += 1
                
                print(f"   ✅ Created {created_count} ledger entries from previous cycle")
                
            else:
                print(f"   No previous cycle found. This is the first cycle in the month.")
                # You might want to initialize with 0 balances for all active MPPs and products
                
        return True
        
    except Exception as e:
        print(f"❌ Error initializing cycle ledgers: {e}")
        return False


# Call this function when a new cycle is created or when reconciliation starts
def on_cycle_created(cycle):
    """Handler for when a new cycle is created"""
    initialize_cycle_ledgers(cycle)
    
def get_balance_details(request, entry_id):
    """Get detailed balance information for AJAX request"""
    try:
        ledger_entry = MPPProductLedger.objects.select_related(
            'mpp', 'product', 'cycle', 'cycle__monthly_cycle', 'reconciliation_record'
        ).get(id=entry_id)
        
        # Get previous and next cycle ledgers
        previous_ledger = ledger_entry.get_previous_cycle_ledger()
        next_ledger = MPPProductLedger.objects.filter(
            mpp=ledger_entry.mpp,
            product=ledger_entry.product,
            cycle__monthly_cycle=ledger_entry.cycle.monthly_cycle,
            cycle__cycle_number=ledger_entry.cycle.cycle_number + 1
        ).first()
        
        # Get all ledger history for this MPP+Product
        all_ledgers = MPPProductLedger.objects.filter(
            mpp=ledger_entry.mpp,
            product=ledger_entry.product
        ).select_related('cycle').order_by('cycle__cycle_number')
        
        # Create ledger history timeline
        ledger_history = []
        for ledger in all_ledgers:
            ledger_history.append({
                'cycle': f"{ledger.cycle.monthly_cycle.month} - {ledger.cycle.name}",
                'cycle_number': ledger.cycle.cycle_number,
                'opening': ledger.opening_balance,
                'advance': ledger.current_advance_sale,
                'sap': ledger.current_sap_entry,
                'difference': ledger.current_difference,
                'closing': ledger.closing_balance,
                'is_current': ledger.id == entry_id
            })
        
        context = {
            'ledger': ledger_entry,
            'previous_ledger': previous_ledger,
            'next_ledger': next_ledger,
            'ledger_history': ledger_history,
            'balance_status': ledger_entry.get_balance_status(),
            'reconciliation_record': ledger_entry.reconciliation_record,
        }
        
        return render(request, 'balance_details.html', context)
        
    except MPPProductLedger.DoesNotExist:
        return JsonResponse({'error': 'Ledger entry not found'}, status=404)
    except Exception as e:
        return JsonResponse({'error': str(e)}, status=500)

    
def get_opening_balance(current_cycle, product):
    """Get opening balance from previous cycle for product-level ledger"""
    # Find previous cycle in same monthly cycle
    previous_cycle = Cycle.objects.filter(
        monthly_cycle=current_cycle.monthly_cycle,
        cycle_number=current_cycle.cycle_number - 1
    ).first()
    
    if previous_cycle:
        previous_ledger = CycleLedger.objects.filter(
            cycle=previous_cycle,
            product=product
        ).first()
        
        if previous_ledger:
            return previous_ledger.closing_balance
    
    return 0


def create_location_notifications(reconciliation_sheet):
    """Create notifications for location users - FIXED: Exclude NOT_RECORDED"""
    
    # Group records by location, excluding NOT_RECORDED
    location_records = defaultdict(list)
    
    for record in reconciliation_sheet.records.exclude(status='NOT_RECORDED'):
        if record.location:
            location_records[record.location].append(record)
    
    # Create notifications for each location
    for location, loc_records in location_records.items():
        # Get location users
        location_users = CustomUser.objects.filter(
            location=location,
            is_hod=False  # Only regular users, not HODs
        )
        
        for user in location_users:
            # Create notification
            notification = ReconciliationNotification.objects.create(
                reconciliation_sheet=reconciliation_sheet,
                location_user=user,
                location=location,
                message=generate_notification_message(reconciliation_sheet, loc_records),
                status='SENT',
                sent_at=datetime.now()
            )
            
            print(f"✅ Created notification for {user.email} at {location}")


def generate_notification_message(sheet, records):
    """Generate notification message for location users with cumulative info"""
    over_recorded = sum(1 for r in records if r.status == 'OVER_RECORDED')
    under_recorded = sum(1 for r in records if r.status == 'UNDER_RECORDED')
    perfect_match = sum(1 for r in records if r.status == 'PERFECT_MATCH')
    not_recorded = sum(1 for r in records if r.status == 'NOT_RECORDED')
    
    # Calculate cumulative totals
    total_to_send = sum(r.to_be_sent_to_mpp for r in records if r.status != 'NOT_RECORDED')
    total_to_deduct = sum(r.to_be_deducted for r in records if r.status != 'NOT_RECORDED')
    
    message = f"""Reconciliation for {sheet.monthly_cycle.month} {sheet.monthly_cycle.year} - {sheet.cycle.name}

CUMULATIVE LEDGER SUMMARY:
- Total Records: {len(records)}
- Over Recorded (SAP > Advance): {over_recorded}
- Under Recorded (SAP < Advance): {under_recorded}
- Perfect Match: {perfect_match}
- Not Recorded (Ignored): {not_recorded}

CUMULATIVE ACTIONS REQUIRED:
- Total to be sent to MPP: {total_to_send}
- Total to be deducted: {total_to_deduct}

Note: NOT RECORDED entries are excluded from cumulative calculations.
"""
    return message

