@login_required(login_url='login')
def view_location_reconciliation(request):
    """Location users view their reconciliation data - FIXED: Exclude NOT_RECORDED"""
    if not request.user.location:
        messages.error(request, 'Your account is not assigned to any location')
        return redirect('dashboard')
    
    # Get reconciliation records for user's location, excluding NOT_RECORDED
    records = ReconciliationRecord.objects.filter(
        location=request.user.location,
        is_processed=True
    ).exclude(status='NOT_RECORDED').order_by('-reconciliation_sheet__upload_date', 'mpp_code', 'product_name')
    
    # Group by reconciliation sheet
    sheets = {}
    for record in records:
        sheet_id = record.reconciliation_sheet.id
        if sheet_id not in sheets:
            sheets[sheet_id] = {
                'sheet': record.reconciliation_sheet,
                'records': [],
                'summary': {
                    'total': 0,
                    'over_recorded': 0,
                    'under_recorded': 0,
                    'perfect_match': 0,
                }
            }
        
        sheets[sheet_id]['records'].append(record)
        sheets[sheet_id]['summary']['total'] += 1
        
        if record.status == 'OVER_RECORDED':
            sheets[sheet_id]['summary']['over_recorded'] += 1
        elif record.status == 'UNDER_RECORDED':
            sheets[sheet_id]['summary']['under_recorded'] += 1
        elif record.status == 'PERFECT_MATCH':
            sheets[sheet_id]['summary']['perfect_match'] += 1
    
    return render(request, 'location/reconciliation_view.html', {
        'sheets': sheets.values(),
        'location': request.user.location,
        'title': f'Reconciliation - {request.user.location}'
    })

@login_required(login_url='login')
def acknowledge_reconciliation(request, record_id):
    """Location user acknowledges reconciliation record - FIXED: Don't acknowledge NOT_RECORDED"""
    if request.method != 'POST':
        return JsonResponse({'success': False, 'message': 'Invalid request method'})
    
    try:
        record = ReconciliationRecord.objects.get(id=record_id)
        
        # Check if user has permission (same location)
        if record.location != request.user.location:
            return JsonResponse({'success': False, 'message': 'Unauthorized'})
        
        # FIXED: Don't allow acknowledgment of NOT_RECORDED records
        if record.status == 'NOT_RECORDED':
            return JsonResponse({'success': False, 'message': 'NOT RECORDED entries cannot be acknowledged'})
        
        # Acknowledge the record
        record.is_acknowledged = True
        record.acknowledged_at = datetime.now()
        record.acknowledged_by = request.user
        record.save()
        
        return JsonResponse({'success': True, 'message': 'Record acknowledged successfully'})
    
    except ReconciliationRecord.DoesNotExist:
        return JsonResponse({'success': False, 'message': 'Record not found'})
    except Exception as e:
        return JsonResponse({'success': False, 'message': f'Error: {str(e)}'})

@login_required(login_url='login')
def validate_reconciliation_file(request):
    """Validate reconciliation file without processing"""
    if not request.user.is_finance:
        return JsonResponse({'success': False, 'message': 'Unauthorized'})
    
    if request.method == 'POST' and request.FILES.get('reconciliation_file'):
        try:
            import pandas as pd
            from io import BytesIO
            
            file = request.FILES['reconciliation_file']
            month = request.POST.get('month')
            year = request.POST.get('year')
            cycle_id = request.POST.get('cycle')
            
            # Read Excel file
            df = pd.read_excel(BytesIO(file.read()))
            
            # Check columns
            df.columns = df.columns.str.strip()
            available_columns = df.columns.tolist()
            
            required_columns = [
                'Location', 'MPP Code', 'MPP Name', 'Product', 
                'Advance Sale Qty', 'SAP Entry Qty', 'Status', 
                'Match Quality', 'To Be Sent To MPP', 'To Be Deducted'
            ]
            
            missing_columns = [col for col in required_columns if col not in available_columns]
            
            if missing_columns:
                return JsonResponse({
                    'success': False,
                    'message': f'Missing columns: {", ".join(missing_columns)}',
                    'available_columns': available_columns
                })
            
            # Check data sample
            sample_data = []
            for i in range(min(3, len(df))):
                row = df.iloc[i]
                sample_data.append({
                    'location': str(row['Location']) if 'Location' in df.columns else '',
                    'mpp_code': str(row['MPP Code']) if 'MPP Code' in df.columns else '',
                    'product': str(row['Product']) if 'Product' in df.columns else '',
                    'advance_qty': int(row['Advance Sale Qty']) if 'Advance Sale Qty' in df.columns else 0,
                    'sap_qty': int(row['SAP Entry Qty']) if 'SAP Entry Qty' in df.columns else 0,
                    'status': str(row['Status']) if 'Status' in df.columns else '',
                })
            
            return JsonResponse({
                'success': True,
                'message': 'File validation successful',
                'total_rows': len(df),
                'sample_data': sample_data,
                'columns': available_columns
            })
            
        except Exception as e:
            return JsonResponse({
                'success': False,
                'message': f'Validation error: {str(e)}'
            })
    
    return JsonResponse({
        'success': False,
        'message': 'No file uploaded'
    })

@login_required(login_url='login')
def generate_reconciliation_excel(request, sheet_id):
    """Download the original uploaded Excel file"""
    try:
        # Get the reconciliation sheet
        sheet = get_object_or_404(ReconciliationSheet, id=sheet_id)
        
        # Check if the file exists
        if not sheet.excel_file:
            messages.error(request, "Excel file not found for this sheet.")
            return redirect('view_reconciliation_sheets')
        
        # Get the file path
        file_path = sheet.excel_file.path
        
        # Check if file exists on the server
        if not os.path.exists(file_path):
            # Try to get from storage if using Django's FileField
            if hasattr(sheet.excel_file, 'storage') and hasattr(sheet.excel_file, 'name'):
                try:
                    # Open the file from storage
                    file_content = sheet.excel_file.read()
                    response = HttpResponse(
                        file_content,
                        content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
                    )
                    response['Content-Disposition'] = f'attachment; filename="{sheet.file_name}"'
                    return response
                except Exception as e:
                    messages.error(request, f"Error reading file: {str(e)}")
                    return redirect('view_reconciliation_sheets')
            else:
                messages.error(request, "File not found on server.")
                return redirect('view_reconciliation_sheets')
        
        # Read the file
        with open(file_path, 'rb') as excel_file:
            file_content = excel_file.read()
        
        # Create response with appropriate headers
        response = HttpResponse(
            file_content,
            content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        )
        
        # Set filename for download
        response['Content-Disposition'] = f'attachment; filename="{sheet.file_name}"'
        
        return response
        
    except ReconciliationSheet.DoesNotExist:
        messages.error(request, "Reconciliation sheet not found")
        return redirect('view_reconciliation_sheets')
    except Exception as e:
        messages.error(request, f"Error downloading file: {str(e)}")
        return redirect('view_reconciliation_sheets')
    
