@login_required(login_url='login')
def location_balance_view(request):
    """View for location users to see their MPP opening/closing balances"""
    if not request.user.location:
        messages.error(request, 'Your account is not assigned to any location')
        return redirect('dashboard')
    
    location = request.user.location
    
    # Get filter parameters
    selected_month = request.GET.get('month', '')
    selected_year = request.GET.get('year', '')
    selected_cycle = request.GET.get('cycle', '')
    search_query = request.GET.get('search', '')
    
    # FIX: Default queryset shows ALL ledger entries for the location
    # Only apply filters when explicitly selected
    queryset = MPPProductLedger.objects.filter(
        mpp__bmc_or_mcc__name=location
    ).select_related('mpp', 'product', 'cycle', 'cycle__monthly_cycle').order_by(
        '-cycle__monthly_cycle__year',
        'cycle__monthly_cycle__month',
        '-cycle__cycle_number',
        'mpp__name_with_code',
        'product__name'
    )
    
    # Apply filters ONLY when explicitly provided
    # Month filter
    if selected_month:
        queryset = queryset.filter(cycle__monthly_cycle__month=selected_month)
    
    # Year filter
    if selected_year:
        try:
            queryset = queryset.filter(cycle__monthly_cycle__year=int(selected_year))
        except ValueError:
            pass
    
    # Cycle filter - ONLY apply if explicitly selected
    if selected_cycle:
        queryset = queryset.filter(cycle_id=selected_cycle)
    
    # Search filter
    if search_query:
        queryset = queryset.filter(
            Q(mpp__name_with_code__icontains=search_query) |
            Q(mpp__mpp_transaction_code__icontains=search_query) |
            Q(product__name__icontains=search_query)
        )
    
    # FIX: Get selected cycle object (only if cycle is selected)
    selected_cycle_obj = None
    if selected_cycle:
        selected_cycle_obj = Cycle.objects.filter(id=selected_cycle).first()
    
    # Get ALL cycles for dropdown (not filtered by location)
    all_cycles = Cycle.objects.all().order_by('-monthly_cycle__year', '-cycle_number')    
    # Get unique months and years from ALL cycles
    unique_months = MonthlyCycle.objects.values_list('month', flat=True).distinct().order_by('month')
    unique_years = MonthlyCycle.objects.values_list('year', flat=True).distinct().order_by('-year')
    
    # Filter available cycles based on selected month/year - REMOVE is_active filter
    available_cycles = all_cycles
    
    if selected_month:
        available_cycles = available_cycles.filter(monthly_cycle__month=selected_month)
    
    if selected_year:
        try:
            available_cycles = available_cycles.filter(monthly_cycle__year=int(selected_year))
        except ValueError:
            pass
    
    # Convert cycles to JSON for JavaScript - ADD is_active indicator
    cycles_json = json.dumps([
        {
            'id': cycle.id,
            'name': cycle.name,
            'start_date': cycle.start_date.strftime('%Y-%m-%d'),
            'end_date': cycle.end_date.strftime('%Y-%m-%d'),
            'cycle_number': cycle.cycle_number,
            'is_active': cycle.is_active,
            'display': f"{cycle.name} ({cycle.start_date.strftime('%d')}-{cycle.end_date.strftime('%d')}) {'✓' if cycle.is_active else '✗'}"
        }
        for cycle in available_cycles
    ])
    
    # Calculate statistics
    opening_total = queryset.aggregate(total=Sum('opening_balance'))['total'] or 0
    closing_total = queryset.aggregate(total=Sum('closing_balance'))['total'] or 0
    current_advance = queryset.aggregate(total=Sum('current_advance_sale'))['total'] or 0
    current_sap = queryset.aggregate(total=Sum('current_sap_entry'))['total'] or 0
    current_total = current_sap - current_advance
    
    # Calculate opening to send/deduct
    opening_to_send = queryset.filter(opening_balance__gt=0).aggregate(total=Sum('opening_balance'))['total'] or 0
    opening_to_deduct = queryset.filter(opening_balance__lt=0).aggregate(total=Sum('opening_balance'))['total'] or 0
    
    # Calculate closing to send/deduct
    closing_to_send = queryset.filter(closing_balance__gt=0).aggregate(total=Sum('closing_balance'))['total'] or 0
    closing_to_deduct = queryset.filter(closing_balance__lt=0).aggregate(total=Sum('closing_balance'))['total'] or 0
    
    # Get reconciled count
    reconciled_count = queryset.filter(closing_balance=0).count()
    
    # Get unique MPP and product counts
    mpp_count = queryset.values('mpp').distinct().count()
    product_count = queryset.values('product').distinct().count()
    
    # Pagination
    paginator = Paginator(queryset, 25)
    page_number = request.GET.get('page')
    ledger_entries = paginator.get_page(page_number)
    
    # FIX: Check if we have any data at all
    has_data = MPPProductLedger.objects.filter(
        mpp__bmc_or_mcc__name=location
    ).exists()
    
    context = {
        'location': location,
        'ledger_entries': ledger_entries,
        'selected_month': selected_month,
        'selected_year': selected_year,
        'selected_cycle': selected_cycle,
        'selected_cycle_obj': selected_cycle_obj,
        'search_query': search_query,
        'available_cycles': available_cycles,
        'available_months': unique_months,
        'available_years': unique_years,
        'all_cycles': all_cycles,
        'cycles_json': cycles_json,
        'opening_total': opening_total,
        'closing_total': closing_total,
        'current_advance': current_advance,
        'current_sap': current_sap,
        'current_total': current_total,
        'opening_to_send': opening_to_send,
        'opening_to_deduct': abs(opening_to_deduct),
        'closing_to_send': closing_to_send,
        'closing_to_deduct': abs(closing_to_deduct),
        'mpp_count': mpp_count,
        'product_count': product_count,
        'reconciled_count': reconciled_count,
        'total_to_send': closing_to_send,
        'net_balance': closing_total,
        'has_data': has_data,  # This should now be True if there's any data for the location
    }
    
    return render(request, 'location_balance_view.html', context)

@login_required(login_url='login')
def balance_details_view(request, entry_id):
    """Get detailed balance information for AJAX request"""
    try:
        ledger_entry = MPPProductLedger.objects.select_related(
            'mpp', 'product', 'cycle', 'cycle__monthly_cycle', 'reconciliation_record'
        ).get(id=entry_id)
        
        # Get previous and next cycle ledgers
        previous_ledger = ledger_entry.get_previous_cycle_ledger()
        
        # Find next cycle in same monthly cycle
        next_cycle = Cycle.objects.filter(
            monthly_cycle=ledger_entry.cycle.monthly_cycle,
            cycle_number=ledger_entry.cycle.cycle_number + 1
        ).first()
        
        next_ledger = None
        if next_cycle:
            next_ledger = MPPProductLedger.objects.filter(
                mpp=ledger_entry.mpp,
                product=ledger_entry.product,
                cycle=next_cycle
            ).first()
        
        # Get all ledger history for this MPP+Product
        all_ledgers = MPPProductLedger.objects.filter(
            mpp=ledger_entry.mpp,
            product=ledger_entry.product,
            cycle__monthly_cycle=ledger_entry.cycle.monthly_cycle
        ).select_related('cycle').order_by('cycle__cycle_number')
        
        # Create ledger history timeline
        ledger_history = []
        for ledger in all_ledgers:
            ledger_history.append({
                'cycle': f"{ledger.cycle.monthly_cycle.month} - {ledger.cycle.name}",
                'cycle_number': ledger.cycle.cycle_number,
                'opening': ledger.opening_balance,
                'advance': ledger.current_advance_sale,
                'sap': ledger.current_sap_entry,
                'difference': ledger.current_difference,
                'closing': ledger.closing_balance,
                'is_current': ledger.id == entry_id
            })
        
        context = {
            'ledger': ledger_entry,
            'previous_ledger': previous_ledger,
            'next_ledger': next_ledger,
            'ledger_history': ledger_history,
            'balance_status': ledger_entry.get_balance_status(),
            'reconciliation_record': ledger_entry.reconciliation_record,
        }
        
        return render(request, 'balance_details_modal.html', context)
        
    except MPPProductLedger.DoesNotExist:
        return JsonResponse({'error': 'Ledger entry not found'}, status=404)
    except Exception as e:
        return JsonResponse({'error': str(e)}, status=500)

@login_required(login_url='login')
def export_balance_excel(request):
    """Export balance data to Excel"""
    if not request.user.location:
        return redirect('dashboard')
    
    
    location = request.user.location
    
    # Get filter parameters
    selected_month = request.GET.get('month', '')
    selected_year = request.GET.get('year', '')
    selected_cycle = request.GET.get('cycle', '')
    
    # Base queryset
    queryset = MPPProductLedger.objects.filter(
        mpp__location=location
    ).select_related('mpp', 'product', 'cycle', 'cycle__monthly_cycle')
    
    # Apply filters
    if selected_month:
        queryset = queryset.filter(cycle__monthly_cycle__month=selected_month)
    
    if selected_year:
        queryset = queryset.filter(cycle__monthly_cycle__year=int(selected_year))
    
    if selected_cycle:
        queryset = queryset.filter(cycle_id=selected_cycle)
    
    # Prepare data for Excel
    data = []
    for ledger in queryset:
        data.append({
            'Cycle': f"{ledger.cycle.monthly_cycle.month} {ledger.cycle.monthly_cycle.year} - {ledger.cycle.name}",
            'MPP Code': ledger.mpp.mpp_transaction_code or '',
            'MPP Name': ledger.mpp.name_with_code,
            'Product': ledger.product.name,
            'UOM': ledger.product.uom or '',
            'Opening Balance': ledger.opening_balance,
            'Advance Sale (Current)': ledger.current_advance_sale,
            'SAP Entry (Current)': ledger.current_sap_entry,
            'Current Difference': ledger.current_difference,
            'Closing Balance': ledger.closing_balance,
            'Status': 'To Send' if ledger.closing_balance > 0 else 'To Deduct' if ledger.closing_balance < 0 else 'Reconciled',
            'Action Required': ledger.get_balance_status()
        })
    
    # Create DataFrame
    df = pd.DataFrame(data)
    
    # Create Excel file in memory
    output = BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        df.to_excel(writer, sheet_name='Balance Ledger', index=False)
        
        # Add summary sheet
        summary_data = {
            'Metric': ['Total Records', 'Total Opening Balance', 'Total Closing Balance', 
                      'Total Advance Sale', 'Total SAP Entry', 'To Send Total', 'To Deduct Total'],
            'Value': [len(data), 
                     sum(ledger.opening_balance for ledger in queryset),
                     sum(ledger.closing_balance for ledger in queryset),
                     sum(ledger.current_advance_sale for ledger in queryset),
                     sum(ledger.current_sap_entry for ledger in queryset),
                     sum(ledger.closing_balance for ledger in queryset if ledger.closing_balance > 0),
                     abs(sum(ledger.closing_balance for ledger in queryset if ledger.closing_balance < 0))]
        }
        summary_df = pd.DataFrame(summary_data)
        summary_df.to_excel(writer, sheet_name='Summary', index=False)
    
    output.seek(0)
    
    # Create response
    response = HttpResponse(
        output.getvalue(),
        content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    )
    
    filename = f'balance_ledger_{location}'
    if selected_cycle:
        filename += f'_cycle_{selected_cycle}'
    filename += '.xlsx'
    
    response['Content-Disposition'] = f'attachment; filename="{filename}"'
    
    return response

@login_required(login_url='login')
@require_POST
def create_general_sale(request, mpp_id, product_id, quantity):
    """
    Create a general sale order from the balance ledger.

    POST-only: this used to be a GET link, which could create duplicate orders on
    prefetch / double-click / back-navigation. It is now a CSRF-protected POST form
    and, together with IdempotencyMiddleware (the form sends an idempotency_key),
    a retried submit will not create a second GeneralSale.
    """
    try:
        with transaction.atomic():
            mpp = MPPWithCode.objects.get(id=mpp_id)
            product = Product.objects.get(id=product_id)

            # Get current cycle (you might want to pass this as parameter)
            current_cycle = Cycle.objects.filter(is_active=True).first()

            # Create GeneralSale record
            general_sale = GeneralSale.objects.create(
                mpp=mpp,
                product=product,
                quantity=quantity,
                cycle=current_cycle,
                location=request.user.location,
                status='PENDING'
            )

        messages.success(request, f'Created sale order for {quantity} units of {product.name}')
        return redirect('location_balance_view')

    except Exception as e:
        messages.error(request, f'Error creating sale order: {str(e)}')
        return redirect('location_balance_view')
    

@login_required(login_url='login')    
def get_cycles_by_month_year(request):
    """AJAX endpoint to get cycles for selected month and year - INCLUDES ALL CYCLES (not just active)"""
    month = request.GET.get('month', '')
    year = request.GET.get('year', '')
    
    print(f"\n========== get_cycles_by_month_year CALLED ==========")
    print(f"Month: {month}, Year: {year}")
    
    if not month or not year:
        print("Missing month or year parameter")
        return JsonResponse({'cycles': []})
    
    try:
        year_int = int(year)
    except ValueError:
        print(f"Invalid year: {year}")
        return JsonResponse({'cycles': []})
    
    # Get monthly cycle - IMPORTANT: Don't filter by is_active
    monthly_cycle = MonthlyCycle.objects.filter(
        month=month,
        year=year_int
    ).first()
    
    if not monthly_cycle:
        print(f"No monthly cycle found for {month} {year}")
        return JsonResponse({'cycles': []})
    
    print(f"Found monthly cycle: {monthly_cycle.month} {monthly_cycle.year} (ID: {monthly_cycle.id})")
    
    # Get ALL cycles for this monthly cycle - REMOVE is_active filter
    cycles = Cycle.objects.filter(
        monthly_cycle=monthly_cycle
    ).order_by('cycle_number')
    
    print(f"Found {cycles.count()} cycles (including inactive)")
    
    cycles_data = []
    for cycle in cycles:
        print(f"  • Cycle {cycle.cycle_number}: {cycle.name} (Active: {cycle.is_active})")
        cycles_data.append({
            'id': cycle.id,
            'name': cycle.name,
            'start_date': cycle.start_date.strftime('%d %b'),
            'end_date': cycle.end_date.strftime('%d %b'),
            'cycle_number': cycle.cycle_number,
            'is_active': cycle.is_active,
            'display': f"{cycle.name} ({cycle.start_date.strftime('%d')}-{cycle.end_date.strftime('%d')}) {'✓' if cycle.is_active else '✗'}"
        })
    
    print(f"Returning {len(cycles_data)} cycles")
    print("========== END get_cycles_by_month_year ==========\n")
    
    return JsonResponse({'cycles': cycles_data})

@login_required(login_url='login')
def get_all_months_years(request):
    """Get all unique months and years from the database"""
    
    # Get all unique months and years
    months = MonthlyCycle.objects.values_list('month', flat=True).distinct().order_by('month')
    years = MonthlyCycle.objects.values_list('year', flat=True).distinct().order_by('-year')
    
    # Get min and max years for range
    min_year = MonthlyCycle.objects.aggregate(Min('year'))['year__min']
    max_year = MonthlyCycle.objects.aggregate(Max('year'))['year__max']
    
    return JsonResponse({
        'months': list(months),
        'years': list(years),
        'year_range': {
            'min': min_year,
            'max': max_year
        }
    })
    
    
# -----Download Balance Sheet ---

@login_required(login_url='login')
def download_opening_closing_excel(request):
    """
    Generate Excel report for opening/closing balances for the logged-in user's location
    """
    # Get user's location
    location = request.user.location
    if not location:
        return HttpResponse("No location assigned to user", status=400)
    
    # Get filter parameters (same as UI)
    selected_month = request.GET.get('month', '')
    selected_year = request.GET.get('year', '')
    selected_cycle = request.GET.get('cycle', '')
    search_query = request.GET.get('search', '')
    
    # Base queryset - same logic as location_balance_view
    queryset = MPPProductLedger.objects.filter(
        mpp__bmc_or_mcc__name=location
    ).select_related(
        'mpp', 
        'product', 
        'cycle', 
        'cycle__monthly_cycle',
        'reconciliation_record'
    ).order_by(
        'cycle__monthly_cycle__year',
        'cycle__monthly_cycle__month',
        'cycle__cycle_number',
        'mpp__name_with_code',
        'product__name'
    )
    
    # Apply filters (same as UI)
    if selected_month:
        queryset = queryset.filter(cycle__monthly_cycle__month=selected_month)
    
    if selected_year:
        try:
            queryset = queryset.filter(cycle__monthly_cycle__year=int(selected_year))
        except ValueError:
            pass
    
    if selected_cycle:
        queryset = queryset.filter(cycle_id=selected_cycle)
    
    if search_query:
        queryset = queryset.filter(
            Q(mpp__name_with_code__icontains=search_query) |
            Q(mpp__mpp_transaction_code__icontains=search_query) |
            Q(product__name__icontains=search_query)
        )
    
    # Get selected cycle info for report header
    selected_cycle_obj = None
    if selected_cycle:
        selected_cycle_obj = Cycle.objects.filter(id=selected_cycle).first()
    
    # Create Excel workbook in memory
    wb = Workbook()
    ws = wb.active
    ws.title = "Opening Closing Balance"
    
    # ===== REPORT HEADER SECTION =====
    row_num = 1
    
    # Title
    ws.merge_cells(f'A{row_num}:L{row_num}')
    title_cell = ws.cell(row=row_num, column=1, value="OPENING & CLOSING BALANCE REPORT")
    title_cell.font = Font(size=16, bold=True, color="FFFFFF")
    title_cell.fill = PatternFill(start_color="2F5496", end_color="2F5496", fill_type="solid")
    title_cell.alignment = Alignment(horizontal='center', vertical='center')
    row_num += 1
    
    # Report details
    details = [
        ("Location:", location),
        ("Generated By:", f"{request.user.first_name} {request.user.last_name}"),
        ("Date:", datetime.now().strftime("%Y-%m-%d %H:%M:%S")),
    ]
    
    if selected_month or selected_year:
        period_info = ""
        if selected_month:
            period_info += f"{selected_month}"
        if selected_year:
            if period_info:
                period_info += f" {selected_year}"
            else:
                period_info += f"{selected_year}"
        details.append(("Period:", period_info))
    
    if selected_cycle_obj:
        details.append(("Cycle:", f"{selected_cycle_obj.name}"))
        details.append(("Cycle Dates:", f"{selected_cycle_obj.start_date.strftime('%d %b %Y')} to {selected_cycle_obj.end_date.strftime('%d %b %Y')}"))
        if selected_cycle_obj.sap_number:
            details.append(("SAP Cycle No:", f"{selected_cycle_obj.sap_number}"))
    
    for i, (label, value) in enumerate(details):
        ws.cell(row=row_num, column=1, value=label).font = Font(bold=True)
        ws.cell(row=row_num, column=2, value=value)
        row_num += 1
    
    row_num += 2  # Extra empty row
    
    # ===== COLUMN HEADERS =====
    headers = [
        ("A", "Cycle", 12),
        ("B", "Month", 10),
        ("C", "Cycle Dates", 15),
        ("D", "MPP Code", 15),
        ("E", "MPP Name", 25),
        ("F", "Product Name", 30),
        ("G", "Product Size", 12),
        ("H", "UOM", 8),
        ("I", "Opening Balance", 15),
        ("J", "Advance Sale", 15),
        ("K", "SAP Entry", 15),
        ("L", "Difference", 15),
        ("M", "Closing Balance", 15),
        ("N", "Balance Status", 20),
        ("O", "Action Required", 25),
    ]
    
    # Apply header styling
    header_fill = PatternFill(start_color="366092", end_color="366092", fill_type="solid")
    header_font = Font(color="FFFFFF", bold=True)
    header_border = Border(
        left=Side(style='thin'),
        right=Side(style='thin'),
        top=Side(style='thin'),
        bottom=Side(style='thin')
    )
    header_alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)
    
    for i, (col_letter, header_text, width) in enumerate(headers):
        cell = ws.cell(row=row_num, column=i+1, value=header_text)
        cell.fill = header_fill
        cell.font = header_font
        cell.border = header_border
        cell.alignment = header_alignment
        ws.column_dimensions[col_letter].width = width
    
    row_num += 1
    
    # ===== DATA ROWS =====
    # Define cell styles
    number_format = '#,##0'
    border_thin = Border(
        left=Side(style='thin'),
        right=Side(style='thin'),
        top=Side(style='thin'),
        bottom=Side(style='thin')
    )
    
    # Colors for conditional formatting
    positive_fill = PatternFill(start_color="C6EFCE", end_color="C6EFCE", fill_type="solid")
    negative_fill = PatternFill(start_color="FFC7CE", end_color="FFC7CE", fill_type="solid")
    neutral_fill = PatternFill(start_color="F2F2F2", end_color="F2F2F2", fill_type="solid")
    reconciled_fill = PatternFill(start_color="E2EFDA", end_color="E2EFDA", fill_type="solid")
    
    # Group data by cycle for better organization
    cycle_groups = {}
    for ledger in queryset:
        cycle_key = f"{ledger.cycle.monthly_cycle.month} {ledger.cycle.monthly_cycle.year} - Cycle {ledger.cycle.cycle_number}"
        if cycle_key not in cycle_groups:
            cycle_groups[cycle_key] = []
        cycle_groups[cycle_key].append(ledger)
    
    start_data_row = row_num
    
    # Write data organized by cycle
    for cycle_key, ledgers in cycle_groups.items():
        # Get cycle info from first ledger
        if ledgers:
            first_ledger = ledgers[0]
            cycle = first_ledger.cycle
            
            # Optional: Add cycle header if multiple cycles
            if len(cycle_groups) > 1:
                ws.merge_cells(f'A{row_num}:O{row_num}')
                cycle_header_cell = ws.cell(row=row_num, column=1, 
                                          value=f"▶ {cycle.monthly_cycle.month} {cycle.monthly_cycle.year} - {cycle.name} ({cycle.start_date.strftime('%d')}-{cycle.end_date.strftime('%d')})")
                cycle_header_cell.font = Font(size=11, bold=True, color="FFFFFF")
                cycle_header_cell.fill = PatternFill(start_color="5B9BD5", end_color="5B9BD5", fill_type="solid")
                cycle_header_cell.alignment = Alignment(horizontal='center')
                row_num += 1
        
        # Group ledgers by MPP within this cycle
        mpp_groups = {}
        for ledger in ledgers:
            mpp_id = ledger.mpp.id
            if mpp_id not in mpp_groups:
                mpp_groups[mpp_id] = []
            mpp_groups[mpp_id].append(ledger)
        
        # Write data for each MPP in this cycle
        for mpp_id, mpp_ledgers in mpp_groups.items():
            mpp = mpp_ledgers[0].mpp
            mpp_start_row = row_num
            
            # Write each product ledger entry for this MPP
            for ledger in mpp_ledgers:
                ws.cell(row=row_num, column=1, value=f"Cycle {ledger.cycle.cycle_number}")
                ws.cell(row=row_num, column=2, value=ledger.cycle.monthly_cycle.month[:3])
                ws.cell(row=row_num, column=3, value=f"{ledger.cycle.start_date.strftime('%d')}-{ledger.cycle.end_date.strftime('%d')}")
                ws.cell(row=row_num, column=4, value=ledger.mpp.mpp_transaction_code or "")
                ws.cell(row=row_num, column=5, value=ledger.mpp.name_with_code)
                ws.cell(row=row_num, column=6, value=ledger.product.name)
                ws.cell(row=row_num, column=7, value=ledger.product.size or "")
                ws.cell(row=row_num, column=8, value=ledger.product.uom or "")
                
                # Opening Balance
                opening_cell = ws.cell(row=row_num, column=9, value=ledger.opening_balance)
                opening_cell.number_format = number_format
                if ledger.opening_balance > 0:
                    opening_cell.font = Font(color="006100", bold=True)
                elif ledger.opening_balance < 0:
                    opening_cell.font = Font(color="9C0006", bold=True)
                
                # Current Cycle Details
                ws.cell(row=row_num, column=10, value=ledger.current_advance_sale).number_format = number_format
                ws.cell(row=row_num, column=11, value=ledger.current_sap_entry).number_format = number_format
                
                # Difference
                diff_cell = ws.cell(row=row_num, column=12, value=ledger.current_difference)
                diff_cell.number_format = number_format
                if ledger.current_difference > 0:
                    diff_cell.font = Font(color="006100", bold=True)
                elif ledger.current_difference < 0:
                    diff_cell.font = Font(color="9C0006", bold=True)
                
                # Closing Balance
                closing_cell = ws.cell(row=row_num, column=13, value=ledger.closing_balance)
                closing_cell.number_format = number_format
                if ledger.closing_balance > 0:
                    closing_cell.font = Font(color="006100", bold=True)
                    closing_cell.fill = positive_fill
                elif ledger.closing_balance < 0:
                    closing_cell.font = Font(color="9C0006", bold=True)
                    closing_cell.fill = negative_fill
                else:
                    closing_cell.fill = reconciled_fill
                
                # Status and Action
                status_text = ""
                action_text = ""
                
                if ledger.closing_balance > 0:
                    status_text = "To Be Sent to MPP"
                    action_text = f"Send {ledger.closing_balance} units to MPP"
                elif ledger.closing_balance < 0:
                    status_text = "To Be Deducted from MPP"
                    action_text = f"Deduct {abs(ledger.closing_balance)} units (This will be happen from finance department)"
                else:
                    status_text = "Perfectly Reconciled"
                    action_text = "No action required"
                
                ws.cell(row=row_num, column=14, value=status_text)
                ws.cell(row=row_num, column=15, value=action_text)
                
                # Apply borders to all cells in this row
                for col in range(1, 16):
                    ws.cell(row=row_num, column=col).border = border_thin
                
                row_num += 1
            
            # Add MPP subtotal row (optional)
            if len(mpp_ledgers) > 1:
                # Calculate MPP totals
                mpp_opening_total = sum(l.opening_balance for l in mpp_ledgers)
                mpp_advance_total = sum(l.current_advance_sale for l in mpp_ledgers)
                mpp_sap_total = sum(l.current_sap_entry for l in mpp_ledgers)
                mpp_closing_total = sum(l.closing_balance for l in mpp_ledgers)
                
                # MPP subtotal row
                ws.merge_cells(f'A{row_num}:H{row_num}')
                mpp_subtotal_cell = ws.cell(row=row_num, column=1, value=f"Subtotal for {mpp.name_with_code}")
                mpp_subtotal_cell.font = Font(bold=True)
                mpp_subtotal_cell.fill = PatternFill(start_color="D9E1F2", end_color="D9E1F2", fill_type="solid")
                
                # MPP total values
                ws.cell(row=row_num, column=9, value=mpp_opening_total).number_format = number_format
                ws.cell(row=row_num, column=10, value=mpp_advance_total).number_format = number_format
                ws.cell(row=row_num, column=11, value=mpp_sap_total).number_format = number_format
                ws.cell(row=row_num, column=12, value=mpp_sap_total - mpp_advance_total).number_format = number_format
                ws.cell(row=row_num, column=13, value=mpp_closing_total).number_format = number_format
                
                # Apply formatting to MPP subtotal row
                for col in range(1, 16):
                    cell = ws.cell(row=row_num, column=col)
                    if col <= 8:
                        cell.fill = PatternFill(start_color="D9E1F2", end_color="D9E1F2", fill_type="solid")
                    cell.font = Font(bold=True)
                    cell.border = Border(
                        top=Side(style='medium'),
                        bottom=Side(style='medium'),
                        left=Side(style='thin'),
                        right=Side(style='thin')
                    )
                
                row_num += 1
        
        # Add a separator row after each cycle if multiple cycles
        if len(cycle_groups) > 1:
            for col in range(1, 16):
                ws.cell(row=row_num, column=col).border = border_thin
            row_num += 1
    
    # ===== GRAND TOTALS =====
    if queryset.exists():
        # Calculate grand totals
        grand_totals = {
            'opening': sum(l.opening_balance for l in queryset),
            'advance': sum(l.current_advance_sale for l in queryset),
            'sap': sum(l.current_sap_entry for l in queryset),
            'closing': sum(l.closing_balance for l in queryset),
        }
        
        # Empty row before grand total
        row_num += 1
        
        # Grand total labels
        ws.merge_cells(f'A{row_num}:H{row_num}')
        grand_cell = ws.cell(row=row_num, column=1, value="GRAND TOTAL")
        grand_cell.font = Font(bold=True, size=12, color="FFFFFF")
        grand_cell.fill = PatternFill(start_color="2F5496", end_color="2F5496", fill_type="solid")
        
        # Grand total values
        ws.cell(row=row_num, column=9, value=grand_totals['opening']).number_format = number_format
        ws.cell(row=row_num, column=10, value=grand_totals['advance']).number_format = number_format
        ws.cell(row=row_num, column=11, value=grand_totals['sap']).number_format = number_format
        ws.cell(row=row_num, column=12, value=grand_totals['sap'] - grand_totals['advance']).number_format = number_format
        
        closing_grand_cell = ws.cell(row=row_num, column=13, value=grand_totals['closing'])
        closing_grand_cell.number_format = number_format
        closing_grand_cell.font = Font(bold=True, size=12)
        
        if grand_totals['closing'] > 0:
            closing_grand_cell.font = Font(bold=True, size=12, color="006100")
            closing_grand_cell.fill = positive_fill
        elif grand_totals['closing'] < 0:
            closing_grand_cell.font = Font(bold=True, size=12, color="9C0006")
            closing_grand_cell.fill = negative_fill
        else:
            closing_grand_cell.fill = reconciled_fill
        
        # Summary text
        summary_text = ""
        if grand_totals['closing'] > 0:
            summary_text = f"NET: Send {grand_totals['closing']} units to MPPs"
        elif grand_totals['closing'] < 0:
            summary_text = f"NET: Deduct {abs(grand_totals['closing'])} units from MPPs"
        else:
            summary_text = "NET: Perfectly Reconciled"
        
        ws.merge_cells(f'N{row_num}:O{row_num}')
        summary_cell = ws.cell(row=row_num, column=14, value=summary_text)
        summary_cell.font = Font(bold=True, italic=True)
        summary_cell.alignment = Alignment(horizontal='center')
        
        # Apply formatting to grand total row
        for col in range(1, 16):
            cell = ws.cell(row=row_num, column=col)
            cell.font = Font(bold=True)
            cell.border = Border(
                top=Side(style='double'),
                bottom=Side(style='double'),
                left=Side(style='thin'),
                right=Side(style='thin')
            )
    
    # ===== FORMATTING AND STYLING =====
    
    # Apply number formatting and alignment
    for row in ws.iter_rows(min_row=start_data_row, max_row=row_num, min_col=9, max_col=13):
        for cell in row:
            cell.alignment = Alignment(horizontal='right')
    
    for row in ws.iter_rows(min_row=start_data_row, max_row=row_num, min_col=1, max_col=8):
        for cell in row:
            cell.alignment = Alignment(horizontal='left')
    
    for row in ws.iter_rows(min_row=start_data_row, max_row=row_num, min_col=14, max_col=15):
        for cell in row:
            cell.alignment = Alignment(horizontal='center')
    
    # Conditional formatting for positive/negative values
    positive_rule = CellIsRule(operator='greaterThan', formula=['0'], fill=positive_fill)
    negative_rule = CellIsRule(operator='lessThan', formula=['0'], fill=negative_fill)
    
    # Apply to opening balance column
    ws.conditional_formatting.add(f'I{start_data_row}:I{row_num}', positive_rule)
    ws.conditional_formatting.add(f'I{start_data_row}:I{row_num}', negative_rule)
    
    # Apply to closing balance column
    ws.conditional_formatting.add(f'M{start_data_row}:M{row_num}', positive_rule)
    ws.conditional_formatting.add(f'M{start_data_row}:M{row_num}', negative_rule)
    
    # Apply to difference column
    ws.conditional_formatting.add(f'L{start_data_row}:L{row_num}', positive_rule)
    ws.conditional_formatting.add(f'L{start_data_row}:L{row_num}', negative_rule)
    
    # Auto-filter on headers
    if queryset.exists():
        ws.auto_filter.ref = f"A{start_data_row-1}:O{row_num}"
    
    # Freeze header rows
    ws.freeze_panes = ws[f'A{start_data_row}']
    
    # Adjust row heights for better visibility
    for row in range(1, row_num + 1):
        ws.row_dimensions[row].height = 20
    
    # Adjust specific row heights
    ws.row_dimensions[start_data_row - 1].height = 25  # Header row
    
    # ===== NO DATA HANDLING =====
    if not queryset.exists():
        ws.merge_cells(f'A{row_num}:O{row_num}')
        no_data_cell = ws.cell(row=row_num, column=1, value="No balance data available for the selected filters")
        no_data_cell.font = Font(size=14, italic=True, color="FF0000")
        no_data_cell.alignment = Alignment(horizontal='center', vertical='center')
        ws.row_dimensions[row_num].height = 50
    
    # ===== SAVE AND RETURN =====
    # Generate filename
    filename_parts = [f"Opening_Closing_Balance_{location.replace(' ', '_')}"]
    
    if selected_month:
        filename_parts.append(selected_month[:3])
    if selected_year:
        filename_parts.append(str(selected_year))
    if selected_cycle_obj:
        filename_parts.append(f"Cycle_{selected_cycle_obj.cycle_number}")
    
    filename_parts.append(datetime.now().strftime("%Y%m%d_%H%M%S"))
    filename = "_".join(filename_parts) + ".xlsx"
    
    # Save workbook to BytesIO
    output = BytesIO()
    wb.save(output)
    output.seek(0)
    
    # Create HTTP response
    response = HttpResponse(
        output.getvalue(),
        content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    )
    response['Content-Disposition'] = f'attachment; filename="{filename}"'
    response['Content-Length'] = str(len(output.getvalue()))

    return response


# ============================================================================
# Sale & Stock Report  (monthly-cycle stock statement)
# ----------------------------------------------------------------------------
# Admin-only workflow, wired from the Admin Dashboard sidebar:
#   1. pick a Cycle -> Generate/Refresh statement (Opening/Received/Stock Transfer)
#   2. upload the SAP sale export           -> fills MPP Sale (matched -> entries)
#   3. download the formatted report        -> admin fills Damage / Expire offline
#   4. re-upload the filled report          -> recomputes Closing, finalizes
# Core logic lives in main_app/stock_report.py; these views only orchestrate it,
# wrapped in transaction.atomic() so a failed upload never half-writes.
# ============================================================================
from . import stock_report as stock_report_engine


def _stock_report_forbidden():
    return JsonResponse(
        {"success": False, "error": "You don't have permission to access this."},
        status=403,
    )


def _fmt_dt(value):
    """Format a datetime for display, tolerant of USE_TZ on or off (naive datetimes)."""
    if not value:
        return None
    if not is_naive(value):
        value = localtime(value)
    return value.strftime("%d %b %Y %H:%M")


def _refresh_if_open(cycle, statement):
    """Re-pull Opening / Received / Stock-Transfer from live inventory so the report reflects
    the latest GRN/STN the moment it is opened. Preserves Sale/Damage/Expire. A FINALIZED
    statement is left untouched (it is locked and must not be silently re-opened).

    user=None keeps the original generated_by audit field intact on a view-time refresh.
    """
    if (statement and statement.status != StockStatement.STATUS_FINALIZED
            and not statement.is_manual_override):
        with transaction.atomic():
            return stock_report_engine.generate_statement(cycle, user=None)
    return statement


def _cycle_month_year_groups(cycles):
    """Group cycles under their Month-Year for the cascading picker (newest month first,
    cycles ascending within a month). `cycles` must be ordered newest-first."""
    from collections import OrderedDict
    groups = OrderedDict()
    for c in cycles:
        mc = c.monthly_cycle
        month = mc.month if mc else ""
        year = mc.year if mc else 0
        key = f"{month}|{year}"
        g = groups.get(key)
        if g is None:
            g = {"key": key, "label": (f"{month} {year}" if mc else "—"),
                 "month": month, "year": year, "cycles": []}
            groups[key] = g
        rng = ""
        if c.start_date and c.end_date:
            rng = f"{c.start_date.strftime('%d %b')}–{c.end_date.strftime('%d %b %Y')}"
        g["cycles"].append({"id": c.id, "name": c.name, "cycle_number": c.cycle_number, "range": rng})
    result = list(groups.values())
    for g in result:
        g["cycles"].sort(key=lambda x: x["cycle_number"])
    return result


def _open_location_ids(statement):
    """Set of BMC/MCC ids whose Damage/Expire the admin has opened for the location user."""
    return set(statement.location_states.filter(damage_expire_open=True)
               .values_list("bmc_or_mcc_id", flat=True))


def _serialize_statement(statement):
    """Compact JSON view of a statement + its entries (grouped by BMC/MCC) + unmatched sale rows.
    Restricted to the fixed report product list, in the standard report order."""
    open_ids = _open_location_ids(statement)
    report_idx = stock_report_engine.report_product_index()   # {real name lower: (order, display)}
    entries = (statement.entries
               .select_related("bmc_or_mcc", "product")
               .order_by("bmc_or_mcc__name"))
    groups = {}
    for e in entries:
        ri = report_idx.get(e.product.name.strip().lower())
        if ri is None:
            continue   # only the standard report products are shown
        order, display = ri
        g = groups.setdefault(e.bmc_or_mcc.name, {"bmc": e.bmc_or_mcc.name, "bmc_id": e.bmc_or_mcc_id,
                                                  "open": e.bmc_or_mcc_id in open_ids, "rows": [],
                                                  "totals": {"opening": 0, "received": 0, "received_mcc": 0,
                                                             "transfer": 0, "sale": 0, "damage": 0,
                                                             "expire": 0, "closing": 0}})
        g["rows"].append({
            "id": e.id, "product": display, "_order": order,
            "opening": e.opening_balance, "received": e.received, "received_mcc": e.received_mcc,
            "transfer": e.stock_transfer,
            "sale": e.mpp_sale, "damage": e.damage, "expire": e.expire,
            "closing": e.closing_balance, "remark": e.remark,
        })
        t = g["totals"]
        t["opening"] += e.opening_balance; t["received"] += e.received; t["received_mcc"] += e.received_mcc
        t["transfer"] += e.stock_transfer; t["sale"] += e.mpp_sale
        t["damage"] += e.damage; t["expire"] += e.expire; t["closing"] += e.closing_balance
    for g in groups.values():
        g["rows"].sort(key=lambda r: r.pop("_order"))

    unmatched = [{
        "plant": a.sap_plant, "mcc": a.sap_mcc_name,
        "mpp_code": a.sap_mpp_code, "mpp_name": a.sap_mpp_name,
        "material_code": a.sap_material_code, "material_desc": a.sap_material_desc,
        "quantity": a.quantity,
    } for a in statement.mpp_sales.filter(matched=False).order_by("-quantity")[:500]]

    return {
        "status": statement.status,
        "status_display": statement.get_status_display(),
        "is_manual_override": statement.is_manual_override,
        "override_uploaded_at": _fmt_dt(statement.override_uploaded_at),
        "generated_at": _fmt_dt(statement.generated_at),
        "sale_uploaded_at": _fmt_dt(statement.sale_uploaded_at),
        "finalized_at": _fmt_dt(statement.finalized_at),
        "sale_file_name": statement.sale_file_name,
        "sale_rows_total": statement.sale_rows_total,
        "sale_rows_matched": statement.sale_rows_matched,
        "sale_rows_unmatched": statement.sale_rows_unmatched,
        "entry_count": entries.count(),
        "groups": list(groups.values()),
        "unmatched": unmatched,
        "unmatched_count": statement.mpp_sales.filter(matched=False).count(),
    }


@login_required(login_url='login')
def stock_report_page(request):
    """Render the Sale & Stock Report admin page (cycle picker + action panels)."""
    if not request.user.is_superuser:
        return HttpResponseForbidden("You don't have permission to access the stock report.")
    cycles = (Cycle.objects
              .select_related("monthly_cycle")
              .order_by("-monthly_cycle__year", "-monthly_cycle__id", "-cycle_number"))
    return render(request, "stock_report.html", {"month_years": _cycle_month_year_groups(cycles)})


@login_required(login_url='login')
@require_GET
def stock_report_data(request):
    """Return the current statement for a cycle (JSON), or exists=False if not generated yet."""
    if not request.user.is_superuser:
        return _stock_report_forbidden()
    cycle = get_object_or_404(Cycle, id=request.GET.get("cycle"))
    statement = StockStatement.objects.filter(cycle=cycle).first()
    if not statement:
        return JsonResponse({"success": True, "exists": False, "cycle_name": cycle.name})
    statement = _refresh_if_open(cycle, statement)   # reflect latest GRN/STN instantly
    data = _serialize_statement(statement)
    data.update({"success": True, "exists": True, "cycle_name": cycle.name})
    return JsonResponse(data)


@login_required(login_url='login')
@require_POST
def stock_report_generate(request):
    """Step 1: build/refresh Opening / Received / Stock Transfer for a cycle."""
    if not request.user.is_superuser:
        return _stock_report_forbidden()
    cycle = get_object_or_404(Cycle, id=request.POST.get("cycle"))
    try:
        with transaction.atomic():
            statement = stock_report_engine.generate_statement(cycle, request.user)
        data = _serialize_statement(statement)
        data.update({"success": True, "exists": True,
                     "message": f"Statement generated with {data['entry_count']} entries."})
        return JsonResponse(data)
    except Exception as exc:
        return JsonResponse({"success": False, "error": f"Could not generate statement: {exc}"}, status=400)


@login_required(login_url='login')
@require_POST
def stock_report_upload_sale(request):
    """Step 2: ingest the SAP sale export and fill MPP Sale."""
    if not request.user.is_superuser:
        return _stock_report_forbidden()
    cycle = get_object_or_404(Cycle, id=request.POST.get("cycle"))
    upload = request.FILES.get("file")
    if not upload:
        return JsonResponse({"success": False, "error": "No file uploaded."}, status=400)
    if not upload.name.lower().endswith((".xlsx", ".xls")):
        return JsonResponse({"success": False, "error": "Please upload an .xlsx / .xls file."}, status=400)

    statement = StockStatement.objects.filter(cycle=cycle).first()
    if not statement:
        return JsonResponse({"success": False, "error": "Generate the statement first, then upload the sale file."}, status=400)

    raw = upload.read()
    try:
        with transaction.atomic():
            result = stock_report_engine.ingest_sale(statement, io.BytesIO(raw), filename=upload.name)
            statement.sale_file.save(upload.name, ContentFile(raw), save=True)
        data = _serialize_statement(statement)
        data.update({
            "success": True, "exists": True,
            "message": (f"Sale processed: {result['matched']} of {result['total']} rows matched, "
                        f"{result['unmatched']} unmatched. MPP Sale applied to {result['entries_with_sale']} entries."),
            "result": result,
        })
        return JsonResponse(data)
    except ValueError as exc:
        return JsonResponse({"success": False, "error": str(exc)}, status=400)
    except Exception as exc:
        return JsonResponse({"success": False, "error": f"Could not process the sale file: {exc}"}, status=400)


@login_required(login_url='login')
@require_GET
def stock_report_download(request):
    """Download the whole month's report (one sheet per BMC/MCC with every cycle stacked,
    plus the SMPCL summary) — same layout as the uploaded file."""
    if not request.user.is_superuser:
        return HttpResponseForbidden("You don't have permission to access the stock report.")
    cycle = get_object_or_404(Cycle, id=request.GET.get("cycle"))
    mc = cycle.monthly_cycle
    if not StockStatement.objects.filter(cycle__monthly_cycle=mc).exists():
        return HttpResponseForbidden("Generate the statement first.")
    bio = stock_report_engine.build_month_workbook(mc, include_summary=True)
    safe = re.sub(r"[^A-Za-z0-9_-]+", "_", f"{mc.month}_{mc.year}" if mc else (cycle.name or f"cycle_{cycle.id}"))
    response = HttpResponse(
        bio.getvalue(),
        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )
    response["Content-Disposition"] = f'attachment; filename="Sale_Stock_Report_{safe}.xlsx"'
    return response


@login_required(login_url='login')
@require_GET
def stock_report_download_sale(request):
    """Download the raw SAP sale export that was uploaded for a cycle, exactly as uploaded."""
    if not request.user.is_superuser:
        return HttpResponseForbidden("You don't have permission to access the stock report.")
    cycle = get_object_or_404(Cycle, id=request.GET.get("cycle"))
    statement = StockStatement.objects.filter(cycle=cycle).first()
    if not statement or not statement.sale_file:
        return HttpResponseNotFound("No SAP sale file has been uploaded for this cycle yet.")
    try:
        with statement.sale_file.open("rb") as f:
            content = f.read()
    except (FileNotFoundError, OSError):
        return HttpResponseNotFound("The SAP sale file for this cycle is missing on the server. Please re-upload it.")
    filename = statement.sale_file_name or os.path.basename(statement.sale_file.name)
    if filename.lower().endswith(".xls"):
        content_type = "application/vnd.ms-excel"
    else:
        content_type = "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    response = HttpResponse(content, content_type=content_type)
    response["Content-Disposition"] = f'attachment; filename="{filename.replace(chr(34), "")}"'
    return response


@login_required(login_url='login')
@require_GET
def stock_report_product_options(request):
    """Options for the 'Add Product to Report' modal: the current report order, the
    products not yet on the report, and every location."""
    if not request.user.is_superuser:
        return JsonResponse({"success": False, "error": "Not allowed."}, status=403)
    current = stock_report_engine.report_products()
    in_report = {p.id for p, _d in current}
    pos_of = {p.id: i for i, (p, _d) in enumerate(current)}
    extras = (StockReportProduct.objects
              .select_related("product").prefetch_related("locations")
              .order_by("position", "id"))
    return JsonResponse({
        "success": True,
        "report": [{"position": i, "product_id": p.id, "display": d}
                   for i, (p, d) in enumerate(current)],
        "products": [{"id": p.id, "name": p.name}
                     for p in Product.objects.filter(is_active=True)
                                             .exclude(id__in=in_report).order_by("name")],
        "locations": [{"id": b.id, "name": b.name} for b in BMCOrMCC.objects.order_by("name")],
        "extras": [{
            "product_id": ex.product_id,
            "name": ex.product.name,
            "display": ex.display_name or ex.product.name,
            "position": pos_of.get(ex.product_id, ex.position),
            "locations": [{"id": b.id, "name": b.name} for b in ex.locations.all()],
        } for ex in extras],
    })


@login_required(login_url='login')
@require_POST
def stock_report_add_product(request):
    """Admin adds a NEW product to the Sale & Stock Report: pick the product, where it sits
    in the report order, and whether it applies to every location or just one. Zero entries
    are created on every statement that is still editable, so the product shows up at once;
    freshly generated statements include it automatically via ensure_all_locations()."""
    if not request.user.is_superuser:
        return JsonResponse({"success": False, "error": "Not allowed."}, status=403)
    try:
        payload = json.loads(request.body.decode("utf-8"))
    except (ValueError, AttributeError):
        return JsonResponse({"success": False, "error": "Invalid data."}, status=400)
    product = get_object_or_404(Product, id=payload.get("product_id"))
    # An admin-added product may be saved again (that's an edit); only the fixed base
    # list is off-limits.
    is_extra = StockReportProduct.objects.filter(product=product).exists()
    if not is_extra and product.name.strip().lower() in stock_report_engine.report_product_index():
        return JsonResponse({"success": False,
                             "error": f'"{product.name}" is already on the report.'}, status=400)
    try:
        position = max(0, int(payload.get("position")))
    except (TypeError, ValueError):
        position = len(stock_report_engine.report_products())   # default: at the end
    display = str(payload.get("display_name") or "").strip()[:255]
    scope = (payload.get("scope") or "all").lower()
    bmc = None
    if scope == "one":
        bmc = get_object_or_404(BMCOrMCC, id=payload.get("bmc_id"))
    with transaction.atomic():
        extra, created = StockReportProduct.objects.update_or_create(
            product=product, defaults={"display_name": display, "position": position})
        extra.locations.set([bmc] if bmc else [])
        for st in StockStatement.objects.exclude(status=StockStatement.STATUS_FINALIZED):
            stock_report_engine.ensure_all_locations(st)
    verb = "Added" if created else "Updated"
    where = f"only for {bmc.name}" if bmc else "for all locations"
    return JsonResponse({"success": True,
                         "message": f'{verb} "{display or product.name}" on the report {where}.'})


@login_required(login_url='login')
@require_POST
def stock_report_remove_product(request):
    """Remove an admin-added product from the report (the fixed base list can't be removed).
    All-zero entries are cleaned off non-finalized statements; entries holding data are kept
    (they just stop showing), so re-adding the product brings its numbers straight back."""
    if not request.user.is_superuser:
        return JsonResponse({"success": False, "error": "Not allowed."}, status=403)
    try:
        payload = json.loads(request.body.decode("utf-8"))
    except (ValueError, AttributeError):
        return JsonResponse({"success": False, "error": "Invalid data."}, status=400)
    extra = get_object_or_404(StockReportProduct, product_id=payload.get("product_id"))
    name = extra.display_name or extra.product.name
    with transaction.atomic():
        StockStatementEntry.objects.filter(
            product_id=extra.product_id,
            statement__in=StockStatement.objects.exclude(status=StockStatement.STATUS_FINALIZED),
            opening_balance=0, received=0, received_mcc=0, stock_transfer=0,
            mpp_sale=0, damage=0, expire=0, remark="",
        ).delete()
        extra.delete()
    return JsonResponse({"success": True, "message": f'Removed "{name}" from the report.'})


@login_required(login_url='login')
@require_POST
def stock_report_upload_filled(request):
    """Step 4: read Damage/Expire back from the filled report, recompute Closing, finalize."""
    if not request.user.is_superuser:
        return _stock_report_forbidden()
    cycle = get_object_or_404(Cycle, id=request.POST.get("cycle"))
    upload = request.FILES.get("file")
    if not upload:
        return JsonResponse({"success": False, "error": "No file uploaded."}, status=400)
    if not upload.name.lower().endswith((".xlsx", ".xls")):
        return JsonResponse({"success": False, "error": "Please upload an .xlsx / .xls file."}, status=400)

    statement = StockStatement.objects.filter(cycle=cycle).first()
    if not statement:
        return JsonResponse({"success": False, "error": "Generate the statement first."}, status=400)

    raw = upload.read()
    try:
        with transaction.atomic():
            result = stock_report_engine.ingest_filled_report(statement, io.BytesIO(raw))
        data = _serialize_statement(statement)
        data.update({
            "success": True, "exists": True,
            "message": (f"Report finalized: {result['updated']} entries updated"
                        + (f", {result['unmatched_rows']} rows skipped." if result['unmatched_rows'] else ".")),
            "result": result,
        })
        return JsonResponse(data)
    except Exception as exc:
        return JsonResponse({"success": False, "error": f"Could not process the filled report: {exc}"}, status=400)


@login_required(login_url='login')
@require_POST
def stock_report_upload_full(request):
    """Admin correction upload: overwrite ALL columns of the statement from an uploaded
    report workbook (fix anything that went wrong). Sets the manual-override flag so the
    values stick and are not auto-recomputed from inventory until the admin re-Generates.
    """
    if not request.user.is_superuser:
        return _stock_report_forbidden()
    selected_cycle = get_object_or_404(Cycle, id=request.POST.get("cycle"))
    upload = request.FILES.get("file")
    if not upload:
        return JsonResponse({"success": False, "error": "No file uploaded."}, status=400)
    if not upload.name.lower().endswith((".xlsx", ".xls")):
        return JsonResponse({"success": False, "error": "Please upload an .xlsx / .xls file."}, status=400)

    raw = upload.read()
    try:
        # The reader handles the whole workbook: every location sheet, every cycle block.
        with transaction.atomic():
            result = stock_report_engine.ingest_full_report(io.BytesIO(raw))
        filled = result.get("cycles_filled", {})
        if not filled:
            return JsonResponse({"success": False, "error": (
                "No cycle data found in the file. Each sheet needs a 'Sale Report Cycle-DD-DD "
                "Mon-YYYY' line, and the cycle(s) must exist in the system.")}, status=400)

        # Show the selected cycle if the file filled it, else the first cycle it did fill.
        show_cycle = selected_cycle
        if selected_cycle.name not in filled:
            first_name = next(iter(filled))
            show_cycle = (Cycle.objects.filter(name=first_name,
                          monthly_cycle=selected_cycle.monthly_cycle).first()
                          or Cycle.objects.filter(name=first_name).first() or selected_cycle)
        statement = StockStatement.objects.filter(cycle=show_cycle).first()
        data = _serialize_statement(statement) if statement else {"exists": True, "groups": []}

        cyc_list = ", ".join(f"{k} ({v} rows)" for k, v in filled.items())
        loc_note = ""
        if result.get("unmatched_locations"):
            loc_note = " Unmatched locations: " + ", ".join(result["unmatched_locations"][:6]) + "."
        data.update({
            "success": True, "exists": True,
            "cycle_id": show_cycle.id, "cycle_name": show_cycle.name,
            "message": (f"Uploaded from Excel — filled {len(filled)} cycle(s): {cyc_list}. "
                        f"{result['updated']} entries updated"
                        + (f", {result['created']} created" if result.get('created') else "")
                        + (f", {result['unmatched_rows']} rows skipped." if result['unmatched_rows'] else ".")
                        + loc_note
                        + " Openings carried forward; auto-refresh paused (Generate/Refresh to recompute)."),
            "result": result,
        })
        return JsonResponse(data)
    except Exception as exc:
        return JsonResponse({"success": False, "error": f"Could not process the uploaded report: {exc}"}, status=400)


@login_required(login_url='login')
@require_POST
def stock_report_admin_submit(request):
    """Admin fills Damage / Expire for ONE location within a cycle, inline (no Excel round-trip).

    This is the location-wise + cycle-wise editing path: the admin picks a cycle, then saves
    Damage/Expire for a specific MCC/BMC. Closing recomputes; the SAP-sourced MPP Sale is never
    touched here.
    """
    if not request.user.is_superuser:
        return _stock_report_forbidden()
    try:
        payload = json.loads(request.body.decode("utf-8"))
    except (ValueError, AttributeError):
        return JsonResponse({"success": False, "error": "Invalid data."}, status=400)

    cycle = get_object_or_404(Cycle, id=payload.get("cycle"))
    bmc = get_object_or_404(BMCOrMCC, id=payload.get("bmc"))
    statement = StockStatement.objects.filter(cycle=cycle).first()
    if not statement:
        return JsonResponse({"success": False, "error": "Generate the statement first."}, status=400)
    if statement.status == StockStatement.STATUS_FINALIZED:
        return JsonResponse({"success": False, "error": "Statement is finalized. Click Generate / Refresh to unlock editing."}, status=400)

    def _clean_int(v):
        try:
            return max(0, int(round(float(v)))) if v not in (None, "") else 0
        except (TypeError, ValueError):
            return 0

    updated = 0
    with transaction.atomic():
        allowed = {e.id: e for e in statement.entries.filter(bmc_or_mcc=bmc)}
        for item in payload.get("items", []):
            entry = allowed.get(item.get("id"))
            if not entry:
                continue
            entry.damage = _clean_int(item.get("damage"))
            entry.expire = _clean_int(item.get("expire"))
            remark = item.get("remark")
            if remark is not None:
                entry.remark = str(remark)[:255]
            entry.save()   # recomputes closing
            updated += 1
        stock_report_engine.rechain_month(cycle.monthly_cycle)   # carry closings forward

    data = _serialize_statement(statement)
    data.update({"success": True, "exists": True,
                 "message": f"Saved Damage/Expire for {bmc.name}: {updated} product(s)."})
    return JsonResponse(data)


@login_required(login_url='login')
@require_POST
def stock_report_toggle_lock(request):
    """Admin opens/locks Damage-Expire editing for the location user — per location, or all
    locations of the cycle at once. Only when a location is OPEN can its user fill Damage/Expire.
    """
    if not request.user.is_superuser:
        return _stock_report_forbidden()
    try:
        payload = json.loads(request.body.decode("utf-8"))
    except (ValueError, AttributeError):
        return JsonResponse({"success": False, "error": "Invalid data."}, status=400)

    cycle = get_object_or_404(Cycle, id=payload.get("cycle"))
    statement = StockStatement.objects.filter(cycle=cycle).first()
    if not statement:
        return JsonResponse({"success": False, "error": "Generate the statement first."}, status=400)

    open_flag = bool(payload.get("open"))
    scope = payload.get("scope", "one")   # "one" (a single bmc) or "all"
    if scope == "all":
        bmc_ids = list(statement.entries.values_list("bmc_or_mcc_id", flat=True).distinct())
    else:
        bmc = get_object_or_404(BMCOrMCC, id=payload.get("bmc"))
        bmc_ids = [bmc.id]

    with transaction.atomic():
        for bid in bmc_ids:
            StockStatementLocationState.objects.update_or_create(
                statement=statement, bmc_or_mcc_id=bid,
                defaults={"damage_expire_open": open_flag, "updated_by": request.user},
            )

    verb = "opened" if open_flag else "locked"
    where = "all locations" if scope == "all" else BMCOrMCC.objects.get(id=bmc_ids[0]).name
    data = _serialize_statement(statement)
    data.update({"success": True, "exists": True,
                 "message": f"Damage/Expire {verb} for {where}."})
    return JsonResponse(data)


# ----------------------------------------------------------------------------
# Location-level Sale & Stock Report
# ----------------------------------------------------------------------------
# A location (MCC/BMC) user sees ONLY their own location's rows for a cycle,
# can fill in Damage / Expire for their products (Closing recomputes live), and
# can download their single-sheet report. The SAP sale upload and statement
# generation stay admin-only; the location user only contributes Damage/Expire.
# ----------------------------------------------------------------------------
def _is_location_user(user):
    """A plain MCC/BMC location user — not admin, finance, HOD, purchase or logistics.

    Those roles have their own dashboards and must not see the location stock report.
    """
    return not (user.is_superuser or getattr(user, "is_finance", False)
                or getattr(user, "is_hod", False) or getattr(user, "is_purchase", False)
                or getattr(user, "is_logistic", False))


def _resolve_user_bmc(user):
    """The BMCOrMCC for a location user (user.location matches BMCOrMCC.name)."""
    if not _is_location_user(user):
        return None
    loc = (user.location or "").strip()
    if not loc:
        return None
    return (BMCOrMCC.objects.filter(name__iexact=loc).first()
            or BMCOrMCC.objects.filter(name__icontains=loc).first())


def _serialize_location_statement(statement, bmc):
    """JSON view of one location's rows within a statement (fixed report products, in order)."""
    report_idx = stock_report_engine.report_product_index()
    entries = (statement.entries.filter(bmc_or_mcc=bmc).select_related("product"))
    rows = []
    totals = {"opening": 0, "received": 0, "received_mcc": 0, "transfer": 0,
              "sale": 0, "damage": 0, "expire": 0, "closing": 0}
    for e in entries:
        ri = report_idx.get(e.product.name.strip().lower())
        if ri is None:
            continue
        order, display = ri
        rows.append({
            "id": e.id, "product": display, "_order": order,
            "opening": e.opening_balance, "received": e.received, "received_mcc": e.received_mcc,
            "transfer": e.stock_transfer,
            "sale": e.mpp_sale, "damage": e.damage, "expire": e.expire,
            "closing": e.closing_balance, "remark": e.remark,
        })
        totals["opening"] += e.opening_balance; totals["received"] += e.received
        totals["received_mcc"] += e.received_mcc
        totals["transfer"] += e.stock_transfer; totals["sale"] += e.mpp_sale
        totals["damage"] += e.damage; totals["expire"] += e.expire; totals["closing"] += e.closing_balance
    rows.sort(key=lambda r: r.pop("_order"))
    is_open = bmc.id in _open_location_ids(statement)
    finalized = statement.status == StockStatement.STATUS_FINALIZED
    return {
        "status": statement.status,
        "status_display": statement.get_status_display(),
        "is_open": is_open,
        "editable": is_open and not finalized,   # location user edits only when admin has opened
        "locked_reason": ("This report is finalized and can no longer be edited."
                          if finalized else
                          ("" if is_open else "Damage/Expire is not open yet. Please wait for the admin to open it for your location.")),
        "sale_uploaded_at": _fmt_dt(statement.sale_uploaded_at),
        "finalized_at": _fmt_dt(statement.finalized_at),
        "rows": rows, "totals": totals, "row_count": len(rows),
    }


@login_required(login_url='login')
def location_stock_report(request):
    """Render the location user's Sale & Stock Report page."""
    bmc = _resolve_user_bmc(request.user)
    if bmc is None:
        messages.error(request, "Your account is not linked to any MCC/BMC location.")
        return redirect(get_redirect_url(request.user))
    # Show all cycles; if the admin hasn't generated a statement for the chosen cycle
    # yet, the page shows a "not generated yet" message rather than hiding the cycle.
    cycles = (Cycle.objects
              .select_related("monthly_cycle")
              .order_by("-monthly_cycle__year", "-monthly_cycle__id", "-cycle_number"))
    return render(request, "location/stock_report.html",
                  {"month_years": _cycle_month_year_groups(cycles), "location": bmc.name})


@login_required(login_url='login')
@require_GET
def location_stock_report_data(request):
    """Return the location user's rows for a cycle (JSON)."""
    bmc = _resolve_user_bmc(request.user)
    if bmc is None:
        return JsonResponse({"success": False, "error": "Your account is not linked to any MCC/BMC location."}, status=403)
    cycle = get_object_or_404(Cycle, id=request.GET.get("cycle"))
    statement = StockStatement.objects.filter(cycle=cycle).first()
    if not statement:
        return JsonResponse({"success": True, "exists": False, "cycle_name": cycle.name, "location": bmc.name})
    statement = _refresh_if_open(cycle, statement)   # reflect latest GRN/STN instantly
    data = _serialize_location_statement(statement, bmc)
    data.update({"success": True, "exists": True, "cycle_name": cycle.name, "location": bmc.name})
    return JsonResponse(data)


@login_required(login_url='login')
@require_POST
def location_stock_report_submit(request):
    """Location user submits Damage / Expire for their own products; Closing recomputes."""
    bmc = _resolve_user_bmc(request.user)
    if bmc is None:
        return JsonResponse({"success": False, "error": "Your account is not linked to any MCC/BMC location."}, status=403)
    try:
        payload = json.loads(request.body.decode("utf-8"))
    except (ValueError, AttributeError):
        return JsonResponse({"success": False, "error": "Invalid data."}, status=400)
    items = payload.get("items", [])
    cycle = get_object_or_404(Cycle, id=payload.get("cycle"))
    statement = StockStatement.objects.filter(cycle=cycle).first()
    if not statement:
        return JsonResponse({"success": False, "error": "No statement exists for this cycle yet."}, status=400)
    if statement.status == StockStatement.STATUS_FINALIZED:
        return JsonResponse({"success": False, "error": "This statement is finalized and can no longer be edited."}, status=400)
    if bmc.id not in _open_location_ids(statement):
        return JsonResponse({"success": False, "error": "Damage/Expire is not open for your location yet. Please wait for the admin to open it."}, status=403)

    def _clean_int(v):
        try:
            return max(0, int(round(float(v)))) if v not in (None, "") else 0
        except (TypeError, ValueError):
            return 0

    updated = 0
    with transaction.atomic():
        # Guard: only entries that belong to THIS location can be edited by this user.
        allowed = {e.id: e for e in statement.entries.filter(bmc_or_mcc=bmc)}
        for item in items:
            entry = allowed.get(item.get("id"))
            if not entry:
                continue
            entry.damage = _clean_int(item.get("damage"))
            entry.expire = _clean_int(item.get("expire"))
            remark = item.get("remark")
            if remark is not None:
                entry.remark = str(remark)[:255]
            entry.save()   # recomputes closing
            updated += 1
        stock_report_engine.rechain_month(cycle.monthly_cycle)   # carry closings forward

    data = _serialize_location_statement(statement, bmc)
    data.update({"success": True, "exists": True,
                 "message": f"Saved Damage/Expire for {updated} product(s)."})
    return JsonResponse(data)


@login_required(login_url='login')
@require_GET
def location_stock_report_download(request):
    """Download the location user's report — just the selected cycle by default, or the
    whole month (every cycle stacked) when scope=month, i.e. the 'All cycles' selection."""
    bmc = _resolve_user_bmc(request.user)
    if bmc is None:
        return HttpResponseForbidden("Your account is not linked to any MCC/BMC location.")
    cycle = get_object_or_404(Cycle, id=request.GET.get("cycle"))
    mc = cycle.monthly_cycle
    scope = (request.GET.get("scope") or "cycle").lower()
    if scope in ("month", "all"):
        if not StockStatement.objects.filter(cycle__monthly_cycle=mc).exists():
            return HttpResponseForbidden("No statement exists for this month yet.")
        bio = stock_report_engine.build_month_workbook(mc, only_bmc=bmc, include_summary=False)
        safe_period = re.sub(r"[^A-Za-z0-9_-]+", "_", f"{mc.month}_{mc.year}" if mc else (cycle.name or f"cycle_{cycle.id}"))
    else:
        statement = StockStatement.objects.filter(cycle=cycle).first()
        if not statement:
            return HttpResponseForbidden("No statement exists for this cycle yet.")
        bio = stock_report_engine.build_workbook(statement, only_bmc=bmc, include_summary=False)
        safe_period = re.sub(r"[^A-Za-z0-9_-]+", "_", cycle.name or f"cycle_{cycle.id}")
    safe_loc = re.sub(r"[^A-Za-z0-9_-]+", "_", bmc.name or "location")
    response = HttpResponse(
        bio.getvalue(),
        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )
    response["Content-Disposition"] = f'attachment; filename="Stock_Report_{safe_loc}_{safe_period}.xlsx"'
    return response